def _theme_style(
    *,
    window: str,
    window_text: str,
    base: str,
    button: str,
    highlight: str,
    highlight_text: str,
    menu_bg: str,
    menu_text: str,
    gridline: str,
) -> dict[str, str]:
    return {
        "window": window,
        "window_text": window_text,
        "base": base,
        "alternate_base": button,
        "tooltip_base": menu_bg,
        "tooltip_text": menu_text,
        "button": button,
        "button_text": window_text,
        "bright_text": highlight_text,
        "highlight": highlight,
        "highlight_text": highlight_text,
        "placeholder": QColor(window_text).lighter(150).name().lower(),
        "menu_bg": menu_bg,
        "menu_text": menu_text,
        "gridline": gridline,
        "header_bg": menu_bg,
        "header_text": menu_text,
    }


def _apply_disabled_palette_group(palette: QPalette, colors: dict[str, str]) -> None:
    button_bg = QColor(colors.get("button", colors.get("panel_bg", "#21262d")))
    disabled_bg = button_bg.darker(108)
    disabled_text = QColor(colors.get("placeholder", "#9aa0aa"))
    disabled_group = QPalette.ColorGroup.Disabled
    palette.setColor(disabled_group, QPalette.ColorRole.Button, disabled_bg)
    palette.setColor(disabled_group, QPalette.ColorRole.ButtonText, disabled_text)
    palette.setColor(disabled_group, QPalette.ColorRole.Text, disabled_text)
    palette.setColor(disabled_group, QPalette.ColorRole.WindowText, disabled_text)
    palette.setColor(disabled_group, QPalette.ColorRole.PlaceholderText, disabled_text)


def _application_widget_chrome_stylesheet(colors: dict[str, str]) -> str:
    panel_bg = colors.get("base", colors.get("panel_bg", "#161b22"))
    button_bg = colors.get("button", colors.get("panel_bg", panel_bg))
    disabled_bg = QColor(button_bg).darker(108).name().lower()
    disabled_text = colors.get("placeholder", "#9aa0aa")
    disabled_border = QColor(colors.get("gridline", "#30363d")).darker(120).name().lower()
    track_bg = QColor(panel_bg).darker(102).name().lower()
    handle_bg = QColor(colors.get("gridline", "#30363d")).lighter(115).name().lower()
    handle_hover = colors.get("highlight", "#3d8bfd")
    handle_pressed = QColor(handle_hover).darker(115).name().lower()
    return (
        "QPushButton:disabled {"
        f"background-color: {disabled_bg};"
        f"color: {disabled_text};"
        f"border: 1px solid {disabled_border};"
        "}"
        "QScrollBar:horizontal {"
        "border: none;"
        f"background: {track_bg};"
        "height: 12px;"
        "margin: 0px;"
        "}"
        "QScrollBar::handle:horizontal {"
        f"background: {handle_bg};"
        "min-width: 24px;"
        "border-radius: 6px;"
        "}"
        f"QScrollBar::handle:horizontal:hover {{ background: {handle_hover}; }}"
        f"QScrollBar::handle:horizontal:pressed {{ background: {handle_pressed}; }}"
        "QScrollBar::add-line:horizontal, QScrollBar::sub-line:horizontal {"
        "width: 0px;"
        "}"
        "QScrollBar::add-page:horizontal, QScrollBar::sub-page:horizontal {"
        "background: none;"
        "}"
        "QScrollBar:vertical {"
        "border: none;"
        f"background: {track_bg};"
        "width: 12px;"
        "margin: 0px;"
        "}"
        "QScrollBar::handle:vertical {"
        f"background: {handle_bg};"
        "min-height: 24px;"
        "border-radius: 6px;"
        "}"
        f"QScrollBar::handle:vertical:hover {{ background: {handle_hover}; }}"
        f"QScrollBar::handle:vertical:pressed {{ background: {handle_pressed}; }}"
        "QScrollBar::add-line:vertical, QScrollBar::sub-line:vertical {"
        "height: 0px;"
        "}"
        "QScrollBar::add-page:vertical, QScrollBar::sub-page:vertical {"
        "background: none;"
        "}"
    )


