class _HorizontalDragAdjustLabel(QLabel):
    valueDragged = Signal(int)

    def __init__(self, text: str = "", parent: QWidget | None = None) -> None:
        super().__init__(text, parent)
        self._last_global_x: int | None = None
        self.setCursor(Qt.CursorShape.SizeHorCursor)

    def mousePressEvent(self, event: QMouseEvent) -> None:
        if event.button() == Qt.MouseButton.LeftButton:
            self._last_global_x = int(event.globalPosition().x())
            event.accept()
            return
        super().mousePressEvent(event)

    def mouseMoveEvent(self, event: QMouseEvent) -> None:
        if self._last_global_x is not None and event.buttons() & Qt.MouseButton.LeftButton:
            current_x = int(event.globalPosition().x())
            delta_x = current_x - self._last_global_x
            if delta_x:
                self._last_global_x = current_x
                self.valueDragged.emit(delta_x)
            event.accept()
            return
        super().mouseMoveEvent(event)

    def mouseReleaseEvent(self, event: QMouseEvent) -> None:
        if event.button() == Qt.MouseButton.LeftButton:
            self._last_global_x = None
            event.accept()
            return
        super().mouseReleaseEvent(event)




