class _ElidedLabel(QLabel):

    def __init__(self, text: str = "", parent: QWidget | None = None) -> None:

        super().__init__(parent)

        self._full_text = ""

        self.set_elided_text(text)



    def full_text(self) -> str:

        return self._full_text



    def set_elided_text(self, text: str) -> None:

        self._full_text = text

        self.setToolTip(text)

        self._refresh_elided_text()



    def resizeEvent(self, event) -> None:  # type: ignore[override]

        super().resizeEvent(event)

        if hasattr(self, "_source_comparison_overlay"):

            self._update_source_comparison_overlay_geometry()

        self._refresh_elided_text()



    def _refresh_elided_text(self) -> None:

        available_width = max(24, self.contentsRect().width())

        elided_text = self.fontMetrics().elidedText(self._full_text, Qt.TextElideMode.ElideRight, available_width)

        super().setText(elided_text.replace("…", "..."))




class _HrResultsTableItemProxy:

    def __init__(self, text: str) -> None:

        self._text = text



    def text(self) -> str:

        return self._text





class _SourceResultsTableItem(QTableWidgetItem):

    def __init__(self, text: str, sort_value: float | int | str | tuple[object, ...] | None = None) -> None:

        super().__init__(text)

        self._sort_value = sort_value

        if sort_value is not None:

            self.setData(_SOURCE_TABLE_SORT_ROLE, sort_value)



    def __lt__(self, other: object) -> bool:

        if isinstance(other, _SourceResultsTableItem):

            self_sort_value = self._sort_value

            other_sort_value = other._sort_value

            if self_sort_value is not None and other_sort_value is not None:

                try:

                    return self_sort_value < other_sort_value

                except TypeError:

                    pass

            return self.text() < other.text()

        if isinstance(other, QTableWidgetItem):

            return self.text() < other.text()

        return False


_SKY_EXPLORER_OBJECT_TYPE_TABLE_SORT_ORDER = Qt.SortOrder.AscendingOrder


class _SkyExplorerObjectTypeTableItem(_SourceResultsTableItem):

    def __init__(

        self,

        text: str,

        sort_value: float | int | str | None = None,

        *,

        group_order: int,

        row_rank: int,

    ) -> None:

        super().__init__(text, sort_value)

        self._sky_explorer_group_order = group_order

        self._sky_explorer_row_rank = row_rank


    def __lt__(self, other: object) -> bool:

        if isinstance(other, _SkyExplorerObjectTypeTableItem):

            descending = _SKY_EXPLORER_OBJECT_TYPE_TABLE_SORT_ORDER == Qt.SortOrder.DescendingOrder

            self_group_order = -self._sky_explorer_group_order if descending else self._sky_explorer_group_order

            other_group_order = -other._sky_explorer_group_order if descending else other._sky_explorer_group_order

            if self_group_order != other_group_order:

                return self_group_order < other_group_order

            self_row_rank = -self._sky_explorer_row_rank if descending else self._sky_explorer_row_rank

            other_row_rank = -other._sky_explorer_row_rank if descending else other._sky_explorer_row_rank

            if self_row_rank != other_row_rank:

                return self_row_rank < other_row_rank

            self_sort_value = self._sort_value if self._sort_value is not None else self.text().casefold()

            other_sort_value = other._sort_value if other._sort_value is not None else other.text().casefold()

            try:

                return self_sort_value < other_sort_value

            except TypeError:

                return str(self_sort_value) < str(other_sort_value)

        return super().__lt__(other)


class _SkyExplorerObjectTypeTable(QTableWidget):

    def sortItems(self, column: int, order: Qt.SortOrder = Qt.SortOrder.AscendingOrder) -> None:

        global _SKY_EXPLORER_OBJECT_TYPE_TABLE_SORT_ORDER

        _SKY_EXPLORER_OBJECT_TYPE_TABLE_SORT_ORDER = order

        super().sortItems(column, order)


