    def _moon_tiled_textures_enabled(self) -> bool:

        return not self.moon_debug_disable_tiled_textures and not self.moon_debug_force_global_texture_only

    def _resolved_moon_texture_mode(self, diagnostics: MoonTileDiagnostics) -> str:

        if diagnostics.tiled_albedo_active and diagnostics.tiled_normal_active:

            return "tiled_albedo_tiled_normal"

        if diagnostics.tiled_albedo_active and diagnostics.global_normal_active:

            return "tiled_albedo_global_normal"

        if diagnostics.tiled_albedo_active:

            return "tiled_albedo_only"

        if diagnostics.global_normal_active:

            return "global_albedo_global_normal"

        return "global_albedo_only"

    def _resolved_moon_source_mix_mode(self) -> str:

        if self.moon_debug_force_global_texture_only:

            return "global_only"

        if self.moon_debug_force_tiled_texture_only:

            return "tiled_only_if_available"

        return "global_plus_tiled_edge_fade"

    def _moon_debug_controls_enabled(self) -> bool:

        return bool(self._sky_view_moon_debug_ui_enabled)

    def _moon_debug_mode_active(self) -> bool:

        return self._moon_debug_controls_enabled() and (
            self.moon_debug_overlay_enabled
            or self.moon_debug_render_mode != "normal"
            or self.moon_debug_disable_terrain_normals
            or self.moon_debug_disable_tiled_normals
            or self.moon_debug_force_global_texture_only
            or self.moon_debug_force_tiled_texture_only
            or self.moon_debug_disable_tone_mapping
            or self.moon_debug_disable_earthshine
        )

    @staticmethod
    def _clamp_moon_debug_float(value: float, minimum: float, maximum: float) -> float:

        return max(minimum, min(maximum, float(value)))

    def _resolved_moon_debug_polar_cap_tuning(self, updates: dict[str, float] | None = None) -> dict[str, float]:

        values = {
            "polar_cap_normal_strength": float(self.moon_debug_polar_cap_normal_strength),
            "polar_cap_blend_start_lat_deg": float(self.moon_debug_polar_cap_blend_start_lat_deg),
            "polar_cap_blend_end_lat_deg": float(self.moon_debug_polar_cap_blend_end_lat_deg),
            "polar_cap_blend_curve_power": float(self.moon_debug_polar_cap_blend_curve_power),
            "polar_cap_normal_blend_start_lat_deg": float(self.moon_debug_polar_cap_normal_blend_start_lat_deg),
            "polar_cap_normal_blend_end_lat_deg": float(self.moon_debug_polar_cap_normal_blend_end_lat_deg),
            "polar_cap_albedo_sharpness": float(self.moon_debug_polar_cap_albedo_sharpness),
            "polar_cap_local_contrast": float(self.moon_debug_polar_cap_local_contrast),
            "polar_cap_boundary_match_strength": float(self.moon_debug_polar_cap_boundary_match_strength),
            "polar_cap_core_match_strength": float(self.moon_debug_polar_cap_core_match_strength),
        }
        if updates:
            for key, value in updates.items():
                values[key] = float(value)
        blend_start = self._clamp_moon_debug_float(values["polar_cap_blend_start_lat_deg"], 0.0, 89.0)
        blend_end = self._clamp_moon_debug_float(values["polar_cap_blend_end_lat_deg"], blend_start + 0.1, 90.0)
        normal_blend_start = self._clamp_moon_debug_float(values["polar_cap_normal_blend_start_lat_deg"], blend_start, 89.9)
        normal_blend_end = self._clamp_moon_debug_float(values["polar_cap_normal_blend_end_lat_deg"], normal_blend_start + 0.1, 90.0)
        return {
            "polar_cap_normal_strength": self._clamp_moon_debug_float(values["polar_cap_normal_strength"], 0.0, 0.2),
            "polar_cap_blend_start_lat_deg": blend_start,
            "polar_cap_blend_end_lat_deg": blend_end,
            "polar_cap_blend_curve_power": self._clamp_moon_debug_float(values["polar_cap_blend_curve_power"], 0.1, 4.0),
            "polar_cap_normal_blend_start_lat_deg": normal_blend_start,
            "polar_cap_normal_blend_end_lat_deg": normal_blend_end,
            "polar_cap_albedo_sharpness": self._clamp_moon_debug_float(values["polar_cap_albedo_sharpness"], 0.0, 1.5),
            "polar_cap_local_contrast": self._clamp_moon_debug_float(values["polar_cap_local_contrast"], 0.5, 2.0),
            "polar_cap_boundary_match_strength": self._clamp_moon_debug_float(values["polar_cap_boundary_match_strength"], 0.0, 1.0),
            "polar_cap_core_match_strength": self._clamp_moon_debug_float(values["polar_cap_core_match_strength"], 0.0, 1.0),
        }

    def moon_visual_debug_snapshot(self, rect: QRectF | None = None) -> dict[str, object]:

        return json.loads(json.dumps(self._moon_visual_debug_snapshot(rect)))

    def set_moon_debug_options(
        self,
        *,
        debug_render_mode: str | None = None,
        overlay_enabled: bool | None = None,
        disable_normal_map: bool | None = None,
        force_global_texture_only: bool | None = None,
        force_tiled_texture_only: bool | None = None,
        disable_tiled_normals: bool | None = None,
        disable_tone_mapping: bool | None = None,
        disable_earthshine: bool | None = None,
        polar_cap_normal_strength: float | None = None,
        polar_cap_blend_start_lat_deg: float | None = None,
        polar_cap_blend_end_lat_deg: float | None = None,
        polar_cap_blend_curve_power: float | None = None,
        polar_cap_normal_blend_start_lat_deg: float | None = None,
        polar_cap_normal_blend_end_lat_deg: float | None = None,
        polar_cap_albedo_sharpness: float | None = None,
        polar_cap_local_contrast: float | None = None,
        polar_cap_boundary_match_strength: float | None = None,
        polar_cap_core_match_strength: float | None = None,
    ) -> None:

        did_change = False

        if debug_render_mode is not None:

            resolved_mode = self._normalize_moon_debug_render_mode(debug_render_mode)

            if self.moon_debug_render_mode != resolved_mode:

                self.moon_debug_render_mode = resolved_mode

                did_change = True

        if overlay_enabled is not None:

            resolved_value = bool(overlay_enabled)

            if self.moon_debug_overlay_enabled != resolved_value:

                self.moon_debug_overlay_enabled = resolved_value

                did_change = True

        if disable_normal_map is not None:

            resolved_value = bool(disable_normal_map)

            if self.moon_debug_disable_terrain_normals != resolved_value:

                self.moon_debug_disable_terrain_normals = resolved_value

                did_change = True

        if disable_tone_mapping is not None:

            resolved_value = bool(disable_tone_mapping)

            if self.moon_debug_disable_tone_mapping != resolved_value:

                self.moon_debug_disable_tone_mapping = resolved_value

                did_change = True

        if disable_tiled_normals is not None:

            resolved_value = bool(disable_tiled_normals)

            if self.moon_debug_disable_tiled_normals != resolved_value:

                self.moon_debug_disable_tiled_normals = resolved_value

                did_change = True

        if disable_earthshine is not None:

            resolved_value = bool(disable_earthshine)

            if self.moon_debug_disable_earthshine != resolved_value:

                self.moon_debug_disable_earthshine = resolved_value

                did_change = True

        if force_global_texture_only is not None:

            resolved_value = bool(force_global_texture_only)

            if self.moon_debug_force_global_texture_only != resolved_value:

                self.moon_debug_force_global_texture_only = resolved_value

                did_change = True

            if self.moon_debug_disable_tiled_textures != resolved_value:

                self.moon_debug_disable_tiled_textures = resolved_value

                did_change = True

            if resolved_value and self.moon_debug_force_tiled_texture_only:

                self.moon_debug_force_tiled_texture_only = False

                did_change = True

        if force_tiled_texture_only is not None:

            resolved_value = bool(force_tiled_texture_only)

            if self.moon_debug_force_tiled_texture_only != resolved_value:

                self.moon_debug_force_tiled_texture_only = resolved_value

                did_change = True

            if resolved_value:

                if self.moon_debug_force_global_texture_only:

                    self.moon_debug_force_global_texture_only = False

                    did_change = True

                if self.moon_debug_disable_tiled_textures:

                    self.moon_debug_disable_tiled_textures = False

                    did_change = True

        polar_cap_updates: dict[str, float] = {}
        if polar_cap_normal_strength is not None:
            polar_cap_updates["polar_cap_normal_strength"] = float(polar_cap_normal_strength)
        if polar_cap_blend_start_lat_deg is not None:
            polar_cap_updates["polar_cap_blend_start_lat_deg"] = float(polar_cap_blend_start_lat_deg)
        if polar_cap_blend_end_lat_deg is not None:
            polar_cap_updates["polar_cap_blend_end_lat_deg"] = float(polar_cap_blend_end_lat_deg)
        if polar_cap_blend_curve_power is not None:
            polar_cap_updates["polar_cap_blend_curve_power"] = float(polar_cap_blend_curve_power)
        if polar_cap_normal_blend_start_lat_deg is not None:
            polar_cap_updates["polar_cap_normal_blend_start_lat_deg"] = float(polar_cap_normal_blend_start_lat_deg)
        if polar_cap_normal_blend_end_lat_deg is not None:
            polar_cap_updates["polar_cap_normal_blend_end_lat_deg"] = float(polar_cap_normal_blend_end_lat_deg)
        if polar_cap_albedo_sharpness is not None:
            polar_cap_updates["polar_cap_albedo_sharpness"] = float(polar_cap_albedo_sharpness)
        if polar_cap_local_contrast is not None:
            polar_cap_updates["polar_cap_local_contrast"] = float(polar_cap_local_contrast)
        if polar_cap_boundary_match_strength is not None:
            polar_cap_updates["polar_cap_boundary_match_strength"] = float(polar_cap_boundary_match_strength)
        if polar_cap_core_match_strength is not None:
            polar_cap_updates["polar_cap_core_match_strength"] = float(polar_cap_core_match_strength)
        if polar_cap_updates:
            for key, resolved_value in self._resolved_moon_debug_polar_cap_tuning(polar_cap_updates).items():
                attribute_name = f"moon_debug_{key}"
                current_value = float(getattr(self, attribute_name))
                if not math.isclose(current_value, resolved_value, rel_tol=0.0, abs_tol=1.0e-6):
                    setattr(self, attribute_name, resolved_value)
                    did_change = True

        if did_change:

            self._sky_view_moon_source_mix_mode = self._resolved_moon_source_mix_mode()

            self.update()

    def _moon_focus_background_presentation(
        self,
        sky_object: SkyAtlasObject,
        visibility_alpha: float,
        magnitude: float,
    ) -> tuple[float, float]:

        zoom_t = self._moon_focus_zoom_fraction()

        if zoom_t <= 0.0 or sky_object == self._selected_object or self._is_moon_sky_object(sky_object):

            return max(0.0, min(1.0, float(visibility_alpha))), 1.0

        resolved_visibility_alpha = max(0.0, min(1.0, float(visibility_alpha)))

        extreme_zoom_t = self._moon_focus_extreme_zoom_fraction()

        if sky_object.object_type.casefold() == "star":

            faint_weight = max(0.0, min(1.0, (float(magnitude) - 1.2) / 5.8))

            alpha_scale = 1.0 - zoom_t * (0.26 + 0.56 * faint_weight)

            size_scale = 1.0 - zoom_t * (0.14 + 0.34 * faint_weight)

            if extreme_zoom_t > 0.0:

                alpha_scale *= 1.0 - extreme_zoom_t * (0.56 + 0.34 * faint_weight)

                size_scale *= 1.0 - extreme_zoom_t * (0.42 + 0.24 * faint_weight)

        else:

            alpha_scale = 1.0 - zoom_t * 0.82

            size_scale = 1.0 - zoom_t * 0.42

            if extreme_zoom_t > 0.0:

                alpha_scale *= 1.0 - extreme_zoom_t * 0.9

                size_scale *= 1.0 - extreme_zoom_t * 0.58

                if extreme_zoom_t >= 0.82 and not sky_object.searchable:

                    alpha_scale = 0.0

                    size_scale *= 0.38

        return resolved_visibility_alpha * max(0.0, alpha_scale), max(0.38, size_scale)

    def set_selected_object(self, sky_object: SkyAtlasObject | None, *, center: bool = False) -> None:

        self._selected_object = sky_object

        if sky_object is not None and not self._is_moon_sky_object(sky_object):

            self._moon_focus_zoom_latched = False

        if sky_object is not None and center:

            self.center_on_object(sky_object)

        else:

            self._emit_info_for_object(sky_object)

            self._sync_camera_targets_to_current()

            self.update()

    def center_on_object(self, sky_object: SkyAtlasObject) -> None:

        self._selected_object = sky_object

        if not self._is_moon_sky_object(sky_object):

            self._moon_focus_zoom_latched = False

        self._emit_info_for_object(sky_object)

        rect = self._view_rect()

        self._set_camera_target(
            float(sky_object.ra_deg) % 360.0,
            self._clamped_center_dec(float(sky_object.dec_deg), self._field_height_deg(rect)),
            self._field_width_deg,
            animate=True,
        )

    def reset_view(self) -> None:

        self._set_camera_target(
            self._default_center_ra_deg,
            self._default_center_dec_deg,
            self._default_field_width_deg,
            animate=True,
        )

    def initializeGL(self) -> None:

        context = self.context()

        if context is None:

            return

        functions = QOpenGLFunctions_2_0()

        functions.initializeOpenGLFunctions()

        self._gl_functions = functions

        self._connect_gl_context_destroyed_cleanup()

        self._release_gpu_star_textures()

        self._gl_star_field_layer.release()

        self._star_renderer.release()

        self._sky_view_star_renderer_disabled_for_session = False

        if not self._sky_view_star_renderer_disabled_for_session:

            try:

                default_fbo = int(self.defaultFramebufferObject()) if hasattr(self, "defaultFramebufferObject") else 0

                self._star_renderer.initialize(self._gl_functions, default_framebuffer=default_fbo)

                dpr = max(1.0, float(self.devicePixelRatioF()))

                self._star_renderer.resize(
                    max(1, int(math.ceil(self.width() * dpr))),
                    max(1, int(math.ceil(self.height() * dpr))),
                    dpr,
                )

            except Exception as exc:

                self._sky_view_star_renderer_disabled_for_session = True

                self._star_renderer.release()

                logging.getLogger(__name__).warning("Sky View unified star renderer disabled: %s", exc)

        if self._sky_view_gl_stars_requested and not self._sky_view_gl_stars_disabled_for_session:

            try:

                self._gl_star_field_layer.initialize(self._gl_functions)

            except Exception as exc:

                self._disable_gl_stars_for_session(exc)

        self._gl_atmosphere_mask_layer.release()

        if self._sky_view_gl_atmosphere_requested and not self._sky_view_gl_atmosphere_disabled_for_session:

            try:

                self._gl_atmosphere_mask_layer.initialize(self._gl_functions)

            except Exception as exc:

                self._disable_gl_atmosphere_for_session(exc)

        self._gl_milky_way_layer.release()

        self._sky_view_gl_milky_way_init_attempted = False

        self._sky_view_gl_milky_way_init_succeeded = False

        if (self._sky_view_gl_milky_way_requested or self._milky_way_renderer_mode == "opengl") and not self._sky_view_gl_milky_way_disabled_for_session:

            self._sky_view_gl_milky_way_init_attempted = True

            try:

                self._gl_milky_way_layer.initialize(self._gl_functions)

                self._sky_view_gl_milky_way_init_succeeded = True

            except Exception as exc:

                self._disable_gl_milky_way_for_session(exc)

        self._gl_moon_renderer.release()

        if not self._sky_view_moon_disabled_for_session:

            try:

                self._gl_moon_renderer.initialize(self._gl_functions)

            except Exception as exc:

                self._disable_moon_renderer_for_session(exc)

    def set_observer_context(
        self,
        latitude_deg: float | None,
        longitude_deg: float | None,
        elevation_m: float | None,
        *,
        site_name: str = "",
        configured: bool,
    ) -> None:
            # This path expands each submitted star into a quad on the CPU and uploads
            # plain vertices. On this Qt/PySide stack we only have
            # QOpenGLFunctions_2_0, so the retained renderer stays on an expanded-quad
            # VBO design instead of depending on instancing support that is not
            # exposed here.

        previous_observer = (
            self._observer_latitude_deg,
            self._observer_longitude_deg,
            self._observer_elevation_m,
        )

        self._observer_latitude_deg = 0.0 if latitude_deg is None else max(-90.0, min(90.0, float(latitude_deg)))

        self._observer_longitude_deg = 0.0 if longitude_deg is None else ((float(longitude_deg) + 180.0) % 360.0) - 180.0

        self._observer_elevation_m = 0.0 if elevation_m is None else float(elevation_m)

        self._observer_site_name = str(site_name or "").strip()

        self._observer_site_configured = bool(configured)

        current_observer = (
            self._observer_latitude_deg,
            self._observer_longitude_deg,
            self._observer_elevation_m,
        )

        if current_observer != previous_observer:

            self._moon_ephemeris_sampler.invalidate(preserve_last_state=False)

        self._clear_projected_grid_caches()

        self._clear_rendered_ground_layer_cache()

        self._sync_horizon_transform_matrices()

        self._refresh_equatorial_center_from_camera()

        self.update()

    def set_observation_time(self, observation_time: datetime) -> None:

        resolved_time = observation_time.replace(tzinfo=UTC) if observation_time.tzinfo is None else observation_time.astimezone(UTC)

        self._observation_time_utc = resolved_time

        self._moon_ephemeris_sampler.invalidate()

        self._clear_projected_grid_caches()

        self._clear_rendered_ground_layer_cache()

        self._sync_horizon_transform_matrices()

        self._refresh_equatorial_center_from_camera()

        self.update()

    def set_simulation_frame_time(self, observation_time: datetime, *, time_rate: float, playing: bool) -> None:

        benchmark_recorder = get_benchmark_recorder() if BENCHMARK_ENABLED else None

        wall_time = perf_counter()

        previous_wall_time = self._sky_view_benchmark_last_simulation_wall_time

        previous_observation_time = self._sky_view_benchmark_last_simulation_observation_time

        benchmark_token = benchmark_recorder.start_section("time_simulation.canvas_frame_update") if benchmark_recorder is not None else None

        resolved_time = observation_time.replace(tzinfo=UTC) if observation_time.tzinfo is None else observation_time.astimezone(UTC)

        benchmark_stage_token = benchmark_recorder.start_section("time_simulation.time_value_update") if benchmark_recorder is not None else None

        self._observation_time_utc = resolved_time
        self._sky_view_simulation_time_rate = float(time_rate)
        self._sky_view_simulation_playing = bool(playing)

        if benchmark_recorder is not None:

            benchmark_recorder.stop_section(benchmark_stage_token)

        grid_cache_invalidated = False

        if self._show_equatorial_grid:

            benchmark_stage_token = benchmark_recorder.start_section("time_simulation.cache_invalidation", metadata={"cache": "projected_grid"}) if benchmark_recorder is not None else None

            self._clear_projected_grid_caches()

            grid_cache_invalidated = True

            if benchmark_recorder is not None:

                benchmark_recorder.stop_section(benchmark_stage_token, metadata={"projected_grid": True})

        benchmark_stage_token = benchmark_recorder.start_section("time_simulation.coordinate_sync") if benchmark_recorder is not None else None
        self._sync_horizon_transform_matrices()

        self._refresh_equatorial_center_from_camera()

        if benchmark_recorder is not None:

            benchmark_recorder.stop_section(benchmark_stage_token)

        benchmark_stage_token = benchmark_recorder.start_section("time_simulation.repaint_schedule") if benchmark_recorder is not None else None
        self.update()

        if benchmark_recorder is not None:

            benchmark_recorder.stop_section(benchmark_stage_token)

        wall_interval_seconds = None if previous_wall_time is None else wall_time - previous_wall_time

        time_step_seconds = None if previous_observation_time is None else (resolved_time - previous_observation_time).total_seconds()

        self._sky_view_benchmark_last_simulation_wall_time = wall_time

        self._sky_view_benchmark_last_simulation_observation_time = resolved_time

        if benchmark_recorder is not None:

            metadata = {

                "time_rate": float(time_rate),

                "playing": bool(playing),

                "wall_interval_seconds": wall_interval_seconds,

                "time_step_seconds": time_step_seconds,

                "grid_cache_invalidated": grid_cache_invalidated,

                "repaint_scheduled": True,

            }

            benchmark_recorder.mark_event("time_simulation.canvas_frame_update", metadata=metadata)

            benchmark_recorder.stop_section(benchmark_token, metadata=metadata)

