        resolved_name = cls._normalize_milky_way_tone_preset_name(preset_name)

        preset_values = cls._SKY_VIEW_MILKY_WAY_TONE_PRESETS.get(resolved_name)

        if preset_values is None:

            preset_values = cls._SKY_VIEW_MILKY_WAY_TONE_PRESETS["atlas"]

        return dict(preset_values)

