            f"source:{source_summary},"
            f"mipmaps:{int(getattr(self._gl_milky_way_layer, 'last_texture_has_mipmaps', False))},"
            f"asset_ms:{1000.0 * getattr(self, '_sky_view_gl_milky_way_last_asset_resolve_seconds', 0.0):.2f},"
            f"mesh_build_ms:{1000.0 * self._sky_view_gl_milky_way_last_mesh_build_seconds:.2f},"
            f"tile_select_ms:{1000.0 * getattr(self, '_sky_view_gl_milky_way_last_tile_request_seconds', 0.0):.2f},"
            f"tile_lookup_ms:{1000.0 * getattr(self._gl_milky_way_layer, 'last_tile_cache_lookup_seconds', 0.0):.2f},"
            f"tile_read_ms:{1000.0 * getattr(self._gl_milky_way_layer, 'last_tile_file_read_seconds', 0.0):.2f},"
            f"tile_decode_successes:{getattr(self._gl_milky_way_layer, 'last_tile_decode_success_count', 0)},"
            f"tile_decode_failures:{getattr(self._gl_milky_way_layer, 'last_tile_decode_failure_count', 0)},"
            f"tile_decode_failure_path:{getattr(self._gl_milky_way_layer, 'last_tile_decode_failure_path', 'none')},"
            f"tile_decode_failure_reason:{getattr(self._gl_milky_way_layer, 'last_tile_decode_failure_reason', 'none')},"
            f"tile_decode_ms:{1000.0 * getattr(self._gl_milky_way_layer, 'last_tile_decode_seconds', 0.0):.2f},"
            f"tile_convert_ms:{1000.0 * getattr(self._gl_milky_way_layer, 'last_tile_convert_seconds', 0.0):.2f},"
