            f"tile_prepare_total_ms:{1000.0 * getattr(self._gl_milky_way_layer, 'last_tile_prepare_total_seconds', 0.0):.2f},"
            f"gpu_tile_cache_hits:{getattr(self._gl_milky_way_layer, 'last_tile_cache_hits', 0)},"
            f"gpu_tile_cache_misses:{getattr(self._gl_milky_way_layer, 'last_tile_cache_misses', 0)},"
