@dataclass(frozen=True)
class _LegacySkyViewObservingSiteSelection:

    site_name: str

    latitude_deg: float

    longitude_deg: float

    elevation_m: float | None


class _LegacySkyViewLocationMapWidget(QWidget):

    selectionChanged = Signal(float, float)

    _MIN_ZOOM_LEVEL = 1.0

    _MAX_ZOOM_LEVEL = 24.0

    def __init__(
        self,
        latitude_deg: float = 0.0,
        longitude_deg: float = 0.0,
        parent: QWidget | None = None,
    ) -> None:

        super().__init__(parent)

        self.setMinimumSize(520, 320)

        self.setMouseTracking(True)

        normalized_latitude = max(-90.0, min(90.0, float(latitude_deg)))

        normalized_longitude = self._normalize_longitude(longitude_deg)

        self._selected_latitude_deg = normalized_latitude

        self._selected_longitude_deg = normalized_longitude

        self._center_latitude_deg = normalized_latitude

        self._center_longitude_deg = normalized_longitude

        self._zoom_level = 1.35

        self._drag_origin: QPointF | None = None

        self._drag_center_latitude_deg = self._center_latitude_deg

        self._drag_center_longitude_deg = self._center_longitude_deg

        self._drag_moved = False

    def minimumSizeHint(self) -> QSize:

        return QSize(520, 320)

    def selected_location(self) -> tuple[float, float]:

        return self._selected_latitude_deg, self._selected_longitude_deg

    def zoom_in(self) -> None:

        self.set_zoom_level(self._zoom_level * 1.35)

    def zoom_out(self) -> None:

        self.set_zoom_level(self._zoom_level / 1.35)

    def reset_view(self) -> None:

        self._center_latitude_deg = self._selected_latitude_deg

        self._center_longitude_deg = self._selected_longitude_deg

        self._zoom_level = 1.35

        self._clamp_center()

        self.update()

    def set_zoom_level(self, zoom_level: float) -> None:

        resolved_zoom = max(self._MIN_ZOOM_LEVEL, min(self._MAX_ZOOM_LEVEL, float(zoom_level)))

        if abs(resolved_zoom - self._zoom_level) <= 1.0e-6:

            return

        self._zoom_level = resolved_zoom

        self._clamp_center()

        self.update()

    def set_selected_location(
        self,
        latitude_deg: float,
        longitude_deg: float,
        *,
        recenter: bool,
    ) -> None:

        normalized_latitude = max(-90.0, min(90.0, float(latitude_deg)))

        normalized_longitude = self._normalize_longitude(longitude_deg)

        changed = (
            abs(normalized_latitude - self._selected_latitude_deg) > 1.0e-6
            or abs(normalized_longitude - self._selected_longitude_deg) > 1.0e-6
        )

        self._selected_latitude_deg = normalized_latitude

        self._selected_longitude_deg = normalized_longitude

        if recenter:

            self._center_latitude_deg = normalized_latitude

            self._center_longitude_deg = normalized_longitude

            self._clamp_center()

        self.update()

        if changed:

            self.selectionChanged.emit(self._selected_latitude_deg, self._selected_longitude_deg)

    def location_to_viewport(self, latitude_deg: float, longitude_deg: float) -> QPointF:

        map_rect = self._map_rect()

        return self._location_to_viewport(
            float(latitude_deg),
            float(longitude_deg),
            map_rect,
            wrap_longitude=True,
        )

    def viewport_to_location(self, point: QPointF) -> tuple[float, float]:

        return self._viewport_to_location(point, self._map_rect())

    def paintEvent(self, event: QEvent) -> None:

        _ = event

        painter = QPainter(self)

        painter.setRenderHint(QPainter.RenderHint.Antialiasing, True)

        frame_rect = QRectF(self.rect()).adjusted(0.5, 0.5, -0.5, -0.5)

        frame_path = QPainterPath()

        frame_path.addRoundedRect(frame_rect, 18.0, 18.0)

        background_gradient = QLinearGradient(frame_rect.topLeft(), frame_rect.bottomLeft())

        background_gradient.setColorAt(0.0, QColor(3, 11, 23))

        background_gradient.setColorAt(0.55, QColor(5, 20, 39))

        background_gradient.setColorAt(1.0, QColor(2, 8, 18))

        painter.fillPath(frame_path, background_gradient)

        painter.setPen(QPen(QColor(125, 211, 252, 64), 1.0))

        painter.drawPath(frame_path)

        painter.save()

        painter.setClipPath(frame_path)

        map_rect = self._map_rect()

        ocean_gradient = QLinearGradient(map_rect.topLeft(), map_rect.bottomRight())

        ocean_gradient.setColorAt(0.0, QColor(5, 16, 31))

        ocean_gradient.setColorAt(0.5, QColor(7, 27, 48))

        ocean_gradient.setColorAt(1.0, QColor(3, 12, 24))

        painter.fillRect(map_rect, ocean_gradient)

        self._draw_ambient_stars(painter, map_rect)

        self._draw_graticule(painter, map_rect)

        self._draw_landmasses(painter, map_rect)

        self._draw_selection_marker(painter, map_rect)

        painter.restore()

        title_rect = QRectF(frame_rect.left() + 18.0, frame_rect.top() + 12.0, 260.0, 32.0)

        painter.setPen(QColor("#e2e8f0"))

        painter.setFont(QFont(self.font().family(), 10, QFont.Weight.DemiBold))

        painter.drawText(title_rect, Qt.AlignmentFlag.AlignLeft | Qt.AlignmentFlag.AlignVCenter, "Observer Map")

        subtitle_rect = QRectF(frame_rect.left() + 18.0, frame_rect.bottom() - 34.0, frame_rect.width() - 36.0, 22.0)

        painter.setPen(QColor(191, 219, 254, 176))

        painter.setFont(QFont(self.font().family(), 8))

        painter.drawText(
            subtitle_rect,
            Qt.AlignmentFlag.AlignLeft | Qt.AlignmentFlag.AlignVCenter,
            "Drag to pan. Click to place the marker. Mouse wheel or the +/- controls adjust zoom.",
        )

        painter.end()

    def mousePressEvent(self, event: QMouseEvent) -> None:

        if event.button() != Qt.MouseButton.LeftButton:

            super().mousePressEvent(event)

            return

        if not self._map_rect().contains(event.position()):

            event.ignore()

            return

        self._drag_origin = QPointF(event.position())

        self._drag_center_latitude_deg = self._center_latitude_deg

        self._drag_center_longitude_deg = self._center_longitude_deg

        self._drag_moved = False

        self.setCursor(Qt.CursorShape.ClosedHandCursor)

        event.accept()

    def mouseMoveEvent(self, event: QMouseEvent) -> None:

        if self._drag_origin is None or not (event.buttons() & Qt.MouseButton.LeftButton):

            super().mouseMoveEvent(event)

            return

        map_rect = self._map_rect()

        if map_rect.width() <= 0.0 or map_rect.height() <= 0.0:

            return

        delta = QPointF(event.position() - self._drag_origin)

        if abs(delta.x()) >= 3.0 or abs(delta.y()) >= 3.0:

            self._drag_moved = True

        lon_shift = (float(delta.x()) / map_rect.width()) * self._visible_longitude_span_deg()

        lat_shift = (float(delta.y()) / map_rect.height()) * self._visible_latitude_span_deg()

        self._center_longitude_deg = self._normalize_longitude(self._drag_center_longitude_deg - lon_shift)

        self._center_latitude_deg = self._drag_center_latitude_deg + lat_shift

        self._clamp_center()

        self.update()

        event.accept()

    def mouseReleaseEvent(self, event: QMouseEvent) -> None:

        if event.button() != Qt.MouseButton.LeftButton:

            super().mouseReleaseEvent(event)

            return

        map_rect = self._map_rect()

        click_origin = self._drag_origin

        self._drag_origin = None

        self.setCursor(Qt.CursorShape.ArrowCursor)

        if click_origin is None:

            event.ignore()

            return

        if not self._drag_moved and map_rect.contains(event.position()):

            latitude_deg, longitude_deg = self._viewport_to_location(event.position(), map_rect)

            self.set_selected_location(latitude_deg, longitude_deg, recenter=False)

        event.accept()

    def wheelEvent(self, event: QWheelEvent) -> None:

        steps = float(event.angleDelta().y()) / 120.0

        if abs(steps) <= 1.0e-6:

            super().wheelEvent(event)

            return

        self.set_zoom_level(self._zoom_level * (1.2 ** steps))

        event.accept()

    @staticmethod
    def _normalize_longitude(longitude_deg: float) -> float:

        return ((float(longitude_deg) + 180.0) % 360.0) - 180.0

    def _clamp_center(self) -> None:

        latitude_margin = self._visible_latitude_span_deg() / 2.0

        max_center_latitude = max(0.0, 90.0 - latitude_margin)

        self._center_latitude_deg = max(-max_center_latitude, min(max_center_latitude, self._center_latitude_deg))

        self._center_longitude_deg = self._normalize_longitude(self._center_longitude_deg)

    def _map_rect(self) -> QRectF:

        outer_rect = QRectF(self.rect()).adjusted(16.0, 18.0, -16.0, -24.0)

        if outer_rect.width() <= 0.0 or outer_rect.height() <= 0.0:

            return QRectF()

        width = outer_rect.width()

        height = width / 2.0

        if height > outer_rect.height():

            height = outer_rect.height()

            width = height * 2.0

        origin_x = outer_rect.left() + (outer_rect.width() - width) / 2.0

        origin_y = outer_rect.top() + (outer_rect.height() - height) / 2.0

        return QRectF(origin_x, origin_y, width, height)

    def _visible_longitude_span_deg(self) -> float:

        return 360.0 / self._zoom_level

    def _visible_latitude_span_deg(self) -> float:

        return self._visible_longitude_span_deg() / 2.0

    def _location_to_viewport(
        self,
        latitude_deg: float,
        longitude_deg: float,
        map_rect: QRectF,
        *,
        wrap_longitude: bool,
    ) -> QPointF:

        if wrap_longitude:

            delta_longitude = self._normalize_longitude(float(longitude_deg) - self._center_longitude_deg)

        else:

            delta_longitude = float(longitude_deg) - self._center_longitude_deg

        x_value = map_rect.center().x() + (delta_longitude / self._visible_longitude_span_deg()) * map_rect.width()

        y_value = map_rect.center().y() - ((float(latitude_deg) - self._center_latitude_deg) / self._visible_latitude_span_deg()) * map_rect.height()

        return QPointF(x_value, y_value)

    def _viewport_to_location(self, point: QPointF, map_rect: QRectF) -> tuple[float, float]:

        longitude_deg = self._center_longitude_deg + (
            ((float(point.x()) - map_rect.center().x()) / map_rect.width()) * self._visible_longitude_span_deg()
        )

        latitude_deg = self._center_latitude_deg - (
            ((float(point.y()) - map_rect.center().y()) / map_rect.height()) * self._visible_latitude_span_deg()
        )

        return max(-90.0, min(90.0, latitude_deg)), self._normalize_longitude(longitude_deg)

    def _draw_ambient_stars(self, painter: QPainter, map_rect: QRectF) -> None:

        painter.save()

        painter.setPen(Qt.PenStyle.NoPen)

        for index in range(36):

            x_fraction = (math.sin((index + 1) * 12.9898) * 0.5) + 0.5

            y_fraction = (math.cos((index + 1) * 4.4173) * 0.5) + 0.5

            alpha = 36 + int((index % 5) * 10)

            painter.setBrush(QColor(191, 219, 254, alpha))

            star_x = map_rect.left() + (map_rect.width() * x_fraction)

            star_y = map_rect.top() + (map_rect.height() * y_fraction)

            radius = 0.9 + ((index % 3) * 0.35)

            painter.drawEllipse(QPointF(star_x, star_y), radius, radius)

        painter.restore()

    def _draw_graticule(self, painter: QPainter, map_rect: QRectF) -> None:

        span_longitude = self._visible_longitude_span_deg()

        span_latitude = self._visible_latitude_span_deg()

        if span_longitude <= 18.0:

            grid_step = 5.0

        elif span_longitude <= 45.0:

            grid_step = 10.0

        elif span_longitude <= 90.0:

            grid_step = 15.0

        else:

            grid_step = 30.0

        painter.save()

        painter.setPen(QPen(QColor(148, 163, 184, 56), 1.0))

        min_latitude = self._center_latitude_deg - (span_latitude / 2.0)

        max_latitude = self._center_latitude_deg + (span_latitude / 2.0)

        min_longitude = self._center_longitude_deg - (span_longitude / 2.0)

        max_longitude = self._center_longitude_deg + (span_longitude / 2.0)

        latitude = math.floor(min_latitude / grid_step) * grid_step

        while latitude <= max_latitude + 1.0e-6:

            start_point = self._location_to_viewport(latitude, min_longitude, map_rect, wrap_longitude=False)

            end_point = self._location_to_viewport(latitude, max_longitude, map_rect, wrap_longitude=False)

            painter.drawLine(start_point, end_point)

            latitude += grid_step

        longitude = math.floor(min_longitude / grid_step) * grid_step

        while longitude <= max_longitude + 1.0e-6:

            start_point = self._location_to_viewport(min_latitude, longitude, map_rect, wrap_longitude=False)

            end_point = self._location_to_viewport(max_latitude, longitude, map_rect, wrap_longitude=False)

            painter.drawLine(start_point, end_point)

            longitude += grid_step

        painter.restore()

    def _draw_landmasses(self, painter: QPainter, map_rect: QRectF) -> None:

        painter.save()

        painter.setPen(QPen(QColor(125, 211, 252, 72), 1.2))

        painter.setBrush(QColor(15, 40, 60, 214))

        for polygon in _SKY_VIEW_LOCATION_LANDMASSES:

            for longitude_shift in (-360.0, 0.0, 360.0):

                land_path = QPainterPath()

                first_point: QPointF | None = None

                for longitude_deg, latitude_deg in polygon:

                    point = self._location_to_viewport(
                        latitude_deg,
                        longitude_deg + longitude_shift,
                        map_rect,
                        wrap_longitude=False,
                    )

                    if first_point is None:

                        land_path.moveTo(point)

                        first_point = point

                    else:

                        land_path.lineTo(point)

                if first_point is None:

                    continue

                land_path.closeSubpath()

                bounds = land_path.boundingRect()

                if bounds.right() < map_rect.left() - 40.0 or bounds.left() > map_rect.right() + 40.0:

                    continue

                painter.drawPath(land_path)

        painter.restore()

    def _draw_selection_marker(self, painter: QPainter, map_rect: QRectF) -> None:

        marker_point = self._location_to_viewport(
            self._selected_latitude_deg,
            self._selected_longitude_deg,
            map_rect,
            wrap_longitude=True,
        )

        if not map_rect.adjusted(-12.0, -12.0, 12.0, 12.0).contains(marker_point):

            return

        glow_gradient = QRadialGradient(marker_point, 16.0)

        glow_gradient.setColorAt(0.0, QColor(125, 211, 252, 110))

        glow_gradient.setColorAt(1.0, QColor(125, 211, 252, 0))

        painter.save()

        painter.setPen(Qt.PenStyle.NoPen)

        painter.setBrush(glow_gradient)

        painter.drawEllipse(marker_point, 16.0, 16.0)

        painter.setPen(QPen(QColor("#f8fafc"), 1.6))

        painter.setBrush(QColor("#38bdf8"))

        painter.drawEllipse(marker_point, 5.0, 5.0)

        painter.setBrush(Qt.BrushStyle.NoBrush)

        painter.setPen(QPen(QColor(191, 219, 254, 180), 1.2))

        painter.drawEllipse(marker_point, 10.0, 10.0)

        painter.restore()


