    def _add_sky_view_parameter_row(
        self,
        layout: QGridLayout,
        row: int,
        title: str,
        value_label: QLabel,
    ) -> None:

        key_label = QLabel(title.upper())

        key_label.setObjectName("skyViewParameterKey")

        key_label.setAlignment(Qt.AlignmentFlag.AlignTop | Qt.AlignmentFlag.AlignLeft)

        value_label.setObjectName("skyViewParameterValue")

        value_label.setTextInteractionFlags(Qt.TextInteractionFlag.TextSelectableByMouse)

        value_label.setWordWrap(True)

        layout.addWidget(key_label, row, 0, alignment=Qt.AlignmentFlag.AlignTop)

        layout.addWidget(value_label, row, 1)

    def _sync_sky_view_object_panel(self, sky_object: SkyAtlasObject | None) -> None:

        if not hasattr(self, "_sky_view_object_name_label"):

            return

        if hasattr(self, "_sky_view_object_panel"):

            self._sky_view_object_panel.setVisible(sky_object is not None)

        if sky_object is None:

            self._sky_view_object_name_label.setText("No object selected")

            self._sky_view_object_catalog_label.setText("")

            self._sky_view_object_type_pill.setText("")

            self._sky_view_magnitude_value_label.setText("-")

            self._sky_view_altitude_value_label.setText("-")

            self._sky_view_azimuth_value_label.setText("-")

            self._sky_view_ra_value_label.setText("-")

            self._sky_view_dec_value_label.setText("-")

            self._sky_view_constellation_value_label.setText("-")

        else:

            self._sky_view_object_name_label.setText(sky_object.name)

            self._sky_view_object_catalog_label.setText(self._format_sky_view_secondary_names(sky_object))

            self._sky_view_object_type_pill.setText(sky_object.object_type or "Object")

            self._sky_view_magnitude_value_label.setText(self._format_sky_view_magnitude_value(sky_object.magnitude))

            altitude_deg, azimuth_deg = self._sky_view_object_alt_az_degrees(sky_object)

            self._sky_view_altitude_value_label.setText(self._format_sky_view_altitude_value(altitude_deg))

            self._sky_view_azimuth_value_label.setText(self._format_sky_view_azimuth_value(azimuth_deg))

            self._sky_view_ra_value_label.setText(self._format_sky_view_ra_value(sky_object.ra_deg))

            self._sky_view_dec_value_label.setText(self._format_sky_view_dec_value(sky_object.dec_deg))

            self._sky_view_constellation_value_label.setText(sky_object.constellation or "-")

    @staticmethod
    def _format_sky_view_secondary_names(sky_object: SkyAtlasObject) -> str:

        seen = {sky_object.name.casefold()}

        secondary_names: list[str] = []

        for alias in sky_object.aliases:

            normalized = alias.strip()

            if not normalized or normalized.casefold() in seen:

                continue

            seen.add(normalized.casefold())

            secondary_names.append(normalized)

        if not secondary_names and sky_object.catalog:

            secondary_names.append(sky_object.catalog)

        if not secondary_names:

            return "No alternate names listed"

        return " • ".join(secondary_names[:4])

    @staticmethod
    def _format_sky_view_magnitude_value(magnitude: float | None) -> str:

        return "-" if magnitude is None else f"{magnitude:.2f} mag"

    @staticmethod
    def _format_sky_view_altitude_value(altitude_deg: float | None) -> str:

        return "-" if altitude_deg is None else f"{altitude_deg:+.1f}°"

    @staticmethod
    def _format_sky_view_azimuth_value(azimuth_deg: float | None) -> str:

        if azimuth_deg is None:

            return "-"

        directions = ("N", "NE", "E", "SE", "S", "SW", "W", "NW")

        direction = directions[int(((float(azimuth_deg) + 22.5) % 360.0) // 45.0)]

        return f"{float(azimuth_deg):.1f}° {direction}"

    @staticmethod
    def _format_sky_view_ra_value(ra_deg: float) -> str:

        total_seconds = (float(ra_deg) % 360.0) / 15.0 * 3600.0

        hours = int(total_seconds // 3600.0)

        minutes = int((total_seconds % 3600.0) // 60.0)

        seconds = total_seconds - (hours * 3600.0) - (minutes * 60.0)

        return f"{hours:02d}h {minutes:02d}m {seconds:04.1f}s"

    @staticmethod
    def _format_sky_view_dec_value(dec_deg: float) -> str:

        clamped_dec = max(-90.0, min(90.0, float(dec_deg)))

        sign = "+" if clamped_dec >= 0.0 else "-"

        total_seconds = abs(clamped_dec) * 3600.0

        degrees = int(total_seconds // 3600.0)

        minutes = int((total_seconds % 3600.0) // 60.0)

        seconds = total_seconds - (degrees * 3600.0) - (minutes * 60.0)

        return f"{sign}{degrees:02d}d {minutes:02d}m {seconds:04.1f}s"

    def _sky_view_object_alt_az_degrees(self, sky_object: SkyAtlasObject) -> tuple[float | None, float | None]:

        if not hasattr(self, "_sky_view_canvas"):

            return None, None

        horizon_vector = self._sky_view_canvas._vector_normalize(
            self._sky_view_canvas._equatorial_to_horizon_vector(sky_object.ra_deg, sky_object.dec_deg)
        )

        east, north, up = horizon_vector

        azimuth_deg = math.degrees(math.atan2(east, north)) % 360.0

        altitude_deg = math.degrees(math.asin(max(-1.0, min(1.0, up))))

        return altitude_deg, azimuth_deg

    def _sky_view_catalog_progress(self, message: str, percent: float | None) -> None:

        if hasattr(self, "_sky_view_status_label"):

            self._sky_view_status_label.setText(str(message))

        progress_dialog = getattr(self, "_sky_view_catalog_progress_dialog", None)

        if progress_dialog is not None:

            progress_dialog.setLabelText(str(message))

            if percent is None:

                progress_dialog.setRange(0, 0)

            else:

                progress_dialog.setRange(0, 100)

                progress_dialog.setValue(max(0, min(100, int(round(float(percent))))))

        QApplication.processEvents(QEventLoop.ProcessEventsFlag.ExcludeUserInputEvents)

    def _ensure_sky_view_scientific_catalog_loaded(self, *, use_wait_cursor: bool = True) -> None:

        if self._settings is None:

            root_path = Path(self._root_path_input.text()).expanduser()

            self._settings = AppSettings.from_root(root_path if root_path.exists() else Path.cwd())

        display_settings = SkyAtlasDisplaySettings.from_app_settings(self._settings)

        needed_star_limit = max(9.5, float(display_settings.star_magnitude_limit))

        loaded_star_limit = float(getattr(self, "_sky_view_loaded_star_magnitude_limit", 0.0) or 0.0)

        loaded_catalogs = frozenset(getattr(self, "_sky_view_loaded_deep_sky_catalogs", frozenset()) or frozenset())

        needed_catalogs = display_settings.enabled_deep_sky_catalogs()

        catalogs_up_to_date = needed_catalogs.issubset(loaded_catalogs)

        if (
            self._sky_view_scientific_catalog_loaded
            and loaded_star_limit + 1.0e-6 >= needed_star_limit
            and catalogs_up_to_date
        ):

            return

        self._sky_view_status_label.setText("Loading the cached Hipparcos sky catalog for Sky Atlas...")

        self._refresh_sky_view_overlay_geometry()

        # Avoid a nested paint while the canvas may still be mid-frame / mode-switch.
        QApplication.processEvents(QEventLoop.ProcessEventsFlag.ExcludeUserInputEvents)

        if use_wait_cursor:

            QApplication.setOverrideCursor(Qt.CursorShape.WaitCursor)

        progress_dialog = self._create_sky_view_loading_progress_dialog("Loading Sky Atlas catalogs...")

        progress_dialog.show()

        self._sky_view_catalog_progress_dialog = progress_dialog

        QApplication.processEvents(QEventLoop.ProcessEventsFlag.ExcludeUserInputEvents)

        try:

            self._sky_view_catalog_objects = load_sky_atlas_objects(
                application_install_path(),
                download_if_missing=True,
                maximum_scientific_magnitude=needed_star_limit,
                enabled_deep_sky_catalogs=needed_catalogs,
                progress_callback=self._sky_view_catalog_progress,
            )

            self._sky_view_scientific_catalog_loaded = any(
                item.catalog.casefold() == "hipparcos" for item in self._sky_view_catalog_objects
            )

            self._sky_view_loaded_star_magnitude_limit = needed_star_limit

            self._sky_view_loaded_deep_sky_catalogs = needed_catalogs

            self._sky_view_scientific_catalog_error = None

        except Exception as exc:

            # Keep Messier / packaged targets even when Hipparcos/Tycho download fails.
            try:

                self._sky_view_catalog_objects = load_sky_atlas_objects(
                    None,
                    enabled_deep_sky_catalogs=needed_catalogs,
                )

            except Exception:

                self._sky_view_catalog_objects = load_local_sky_atlas_objects()

            self._sky_view_scientific_catalog_loaded = False

            self._sky_view_loaded_star_magnitude_limit = 0.0

            self._sky_view_loaded_deep_sky_catalogs = frozenset()

            self._sky_view_scientific_catalog_error = str(exc).strip() or exc.__class__.__name__

        finally:

            self._sky_view_catalog_progress_dialog = None

            progress_dialog.close()

            progress_dialog.deleteLater()

            if use_wait_cursor:

                QApplication.restoreOverrideCursor()

        self._sky_view_canvas.set_objects(self._sky_view_catalog_objects)

        self._sync_sky_view_object_panel(self._sky_view_canvas.selected_object())

        self._refresh_sky_view_search_results(select_first=False)

        self._refresh_sky_view_overlay_geometry()

        self._sky_view_status_label.setText(self._sky_view_status_summary())

    def _create_sky_view_loading_progress_dialog(self, message: str) -> QProgressDialog:

        progress_dialog = QProgressDialog(message, "", 0, 0, self)

        progress_dialog.setWindowTitle("Sky Atlas")

        progress_dialog.setWindowFlag(Qt.WindowType.WindowCloseButtonHint, False)

        progress_dialog.setWindowFlag(Qt.WindowType.WindowMaximizeButtonHint, False)

        progress_dialog.setWindowFlag(Qt.WindowType.WindowMinimizeButtonHint, False)

        progress_dialog.setCancelButton(None)

        progress_dialog.setWindowModality(Qt.WindowModality.WindowModal)

        progress_dialog.setMinimumDuration(0)

        progress_dialog.setRange(0, 0)

        progress_dialog.setAutoClose(False)

        progress_dialog.setAutoReset(False)

        return progress_dialog

    def _prepare_sky_view_mode(self) -> None:

        if not hasattr(self, "_sky_view_canvas"):

            return

        needs_catalog = not self._sky_view_scientific_catalog_loaded

        progress_dialog: QProgressDialog | None = None

        canvas = self._sky_view_canvas

        updates_were_enabled = canvas.updatesEnabled()

        canvas.setUpdatesEnabled(False)

        if needs_catalog:

            progress_dialog = self._create_sky_view_loading_progress_dialog("Loading Sky Atlas...")

            progress_dialog.show()

            QApplication.processEvents(QEventLoop.ProcessEventsFlag.ExcludeUserInputEvents)

        try:

            if progress_dialog is not None:

                progress_dialog.setLabelText("Loading star catalog...")

                QApplication.processEvents(QEventLoop.ProcessEventsFlag.ExcludeUserInputEvents)

            self._ensure_sky_view_scientific_catalog_loaded(use_wait_cursor=False)

            self._sync_sky_view_canvas_context()

            if progress_dialog is not None:

                progress_dialog.setLabelText("Preparing Milky Way textures...")

                QApplication.processEvents(QEventLoop.ProcessEventsFlag.ExcludeUserInputEvents)

            canvas.prepare_startup_milky_way_cache()

        finally:

            if progress_dialog is not None:

                progress_dialog.close()

                progress_dialog.deleteLater()

            canvas.setUpdatesEnabled(updates_were_enabled)

            if updates_were_enabled:

                canvas.update()

    def _handle_sky_view_search_changed(self, _value: object) -> None:

        self._refresh_sky_view_search_results(select_first=True)

    def _refresh_sky_view_search_results(self, *, select_first: bool) -> None:

        query = self._sky_view_search_input.text().strip()

        magnitude_limit = float(self._sky_view_magnitude_limit_spin.value())

        catalog_results = search_sky_atlas_objects(
            self._sky_view_catalog_objects,
            query,
            limit=24,
            magnitude_limit=magnitude_limit,
            deep_sky_magnitude_limit=float(
                getattr(self._sky_view_canvas, "_object_magnitude_limit", max(16.0, magnitude_limit))
            ),
        )

        special_results = self._sky_view_special_search_results(query, magnitude_limit=magnitude_limit)

        combined_results: list[SkyAtlasObject] = []

        seen_keys: set[tuple[str, float, float]] = set()

        for sky_object in (*special_results, *catalog_results):

            object_key = (
                sky_object.name.casefold(),
                round(float(sky_object.ra_deg), 6),
                round(float(sky_object.dec_deg), 6),
            )

            if object_key in seen_keys:

                continue

            seen_keys.add(object_key)

            combined_results.append(sky_object)

            if len(combined_results) >= 24:

                break

        self._sky_view_search_results = tuple(combined_results)

        selected_object = self._sky_view_canvas.selected_object()

        if query:

            if self._sky_view_search_results:

                if select_first or selected_object is None or selected_object not in self._sky_view_search_results:

                    selected_object = self._sky_view_search_results[0]

                    self._sky_view_canvas.set_selected_object(selected_object, center=True)

                self._sync_sky_view_object_panel(selected_object)

                self._sky_view_status_label.setText(
                    f"Search matched {len(self._sky_view_search_results)} sky objects. Centered on {selected_object.name}."
                )

                self._sky_view_detail_label.setText(self._format_sky_view_object_details(selected_object))

                self._refresh_sky_view_overlay_geometry()

                return

            self._sky_view_canvas.set_selected_object(None)

            self._sync_sky_view_object_panel(None)

            self._sky_view_detail_label.setText("")

            self._sky_view_status_label.setText(f"No sky objects match '{query}'.")

            self._refresh_sky_view_overlay_geometry()

            return

        if selected_object is None:

            self._sky_view_detail_label.setText("")

        self._sync_sky_view_object_panel(selected_object)

        self._sky_view_status_label.setText(self._sky_view_status_summary())

        self._refresh_sky_view_overlay_geometry()

    def _refresh_sky_view_overlay_geometry(self) -> None:

        overlay_container = getattr(self, "_sky_view_overlay_container", None)

        if isinstance(overlay_container, _SkyAtlasOverlayContainer):

            overlay_container.reposition_overlays()

            self._reposition_sky_view_fullscreen_popup()

            self._reposition_sky_view_location_dialog_overlay()

    def _set_sky_view_popup_active(self, active: bool) -> None:

        overlay_container = getattr(self, "_sky_view_overlay_container", None)

        if isinstance(overlay_container, _SkyAtlasOverlayContainer):

            overlay_container.set_popup_active(active)

    def _show_sky_view_popup_menu(self, button: QWidget, menu: QMenu) -> None:

        if menu is getattr(self, "_sky_view_date_time_menu", None):

            self._prepare_sky_view_date_time_menu()

        elif menu is getattr(self, "_sky_view_location_menu", None):

            self._prepare_sky_view_location_menu()

        self._prepare_sky_view_popup_menu_size(menu)

        if self._should_use_sky_view_fullscreen_popup_overlay(button) and self._show_sky_view_fullscreen_popup(button, menu):

            return

        self._hide_sky_view_fullscreen_popup()

        self._set_sky_view_popup_active(True)

        menu.ensurePolished()

        popup_size = menu.sizeHint()

        screen = button.screen()

        available_geometry = screen.availableGeometry() if screen is not None else QRect(0, 0, popup_size.width(), popup_size.height())

        button_top_left = button.mapToGlobal(QPoint(0, 0))

        button_bottom_left = button.mapToGlobal(QPoint(0, button.height()))

        popup_x = int(round(button_top_left.x() + (button.width() - popup_size.width()) / 2.0))

        popup_x = max(available_geometry.left() + 8, min(popup_x, available_geometry.right() - popup_size.width() - 8))

        popup_y = button_top_left.y() - popup_size.height() - 12

        if popup_y < available_geometry.top() + 8:

            popup_y = button_bottom_left.y() + 12

        popup_y = max(available_geometry.top() + 8, min(popup_y, available_geometry.bottom() - popup_size.height() - 8))

        popup_point = QPoint(popup_x, popup_y)

        menu.popup(popup_point)

    def _show_sky_view_search_popup(self) -> None:

        self._show_sky_view_popup_menu(self._sky_view_search_button, self._sky_view_search_menu)

        QTimer.singleShot(0, self._sky_view_search_input.setFocus)

    def _show_sky_view_date_time_popup(self) -> None:

        self._show_sky_view_popup_menu(self._sky_view_date_time_button, self._sky_view_date_time_menu)

        QTimer.singleShot(0, self._sky_view_date_time_edit.setFocus)

    def _show_sky_view_location_popup(self) -> None:

        self._prepare_sky_view_location_menu()

        self._show_sky_view_popup_menu(self._sky_view_location_button, self._sky_view_location_menu)

    def _open_sky_view_location_dialog_from_popup(self) -> None:

        self._close_sky_view_popup(self._sky_view_location_menu)

        QTimer.singleShot(0, self._open_sky_view_location_dialog)

    def _open_sky_view_location_dialog(self) -> None:

        existing_dialog = getattr(self, "_sky_view_location_dialog", None)

        if existing_dialog is not None and not qt_object_is_valid(existing_dialog):

            self._sky_view_location_dialog = None

            existing_dialog = None

        if existing_dialog is not None:

            if not existing_dialog.isVisible():

                if getattr(self, "_sky_view_location_dialog_embedded", False):

                    self._show_sky_view_location_dialog_overlay(existing_dialog)

                else:

                    existing_dialog.open()

            existing_dialog.raise_()

            existing_dialog.activateWindow()

            return

        settings = getattr(self, "_settings", None)

        if settings is None:

            root_path = Path(self._root_path_input.text()).expanduser()

            self._settings = AppSettings.from_root(root_path if root_path.exists() else Path.cwd())

            settings = self._settings

        embed_dialog = self._should_embed_sky_view_location_dialog()

        parent_widget = self._sky_view_location_dialog_overlay if embed_dialog else self

        dialog = _SkyViewLocationDialog(settings, parent=parent_widget)

        dialog.setWindowModality(Qt.WindowModality.NonModal if embed_dialog else Qt.WindowModality.WindowModal)

        dialog.setAttribute(Qt.WidgetAttribute.WA_DeleteOnClose, True)

        dialog.finished.connect(lambda result, dialog_ref=dialog: self._handle_sky_view_location_dialog_finished(dialog_ref, result))

        dialog.finished.connect(lambda _result: self._hide_sky_view_location_dialog_overlay())

        dialog.destroyed.connect(lambda _obj=None, dialog_ref=dialog: self._forget_sky_view_location_dialog(dialog_ref))

        self._sky_view_location_dialog = dialog

        self._sky_view_location_dialog_embedded = embed_dialog

        if embed_dialog:

            self._show_sky_view_location_dialog_overlay(dialog)

            return

        dialog.open()

        dialog.raise_()

        dialog.activateWindow()

    def _handle_sky_view_location_dialog_finished(self, dialog: _SkyViewLocationDialog, result: int) -> None:

        if not qt_object_is_valid(dialog):

            return

        if int(result) != int(QDialog.DialogCode.Accepted):

            return

        selection = dialog.selection()

        self._apply_sky_view_observing_site(
            selection.site_name,
            selection.latitude_deg,
            selection.longitude_deg,
            selection.elevation_m,
            observing_site_presets=list(dialog.saved_site_presets()),
            preserve_saved_presets=False,
        )

    def _forget_sky_view_location_dialog(self, dialog: _SkyViewLocationDialog) -> None:

        existing_dialog = getattr(self, "_sky_view_location_dialog", None)

        if existing_dialog is dialog:

            self._sky_view_location_dialog = None

            self._hide_sky_view_location_dialog_overlay()

    def _prepare_sky_view_location_menu(self) -> None:

        settings = self._ensure_sky_view_settings_loaded()

        current_site_name = settings.site_name.strip()

        current_latitude = settings.observing_site_latitude_deg

        current_longitude = settings.observing_site_longitude_deg

        current_elevation = settings.observing_site_elevation_m

        if current_latitude is not None and current_longitude is not None:

            current_label = self._observing_site_button_text(
                current_site_name,
                current_latitude,
                current_longitude,
                current_elevation,
            )

            self._sky_view_location_current_label.setText(f"Current site\n{current_label}")

        else:

            self._sky_view_location_current_label.setText(
                "Current site\nNo observing site configured yet. Choose a saved site below or open the exact map manager."
            )

        self._clear_layout_widgets(self._sky_view_location_presets_layout)

        presets = settings.observing_site_presets or []

        if presets:

            for preset in presets:

                preset_button = QPushButton(
                    self._observing_site_button_text(
                        preset.name,
                        preset.latitude_deg,
                        preset.longitude_deg,
                        preset.elevation_m,
                    )
                )

                preset_button.clicked.connect(
                    lambda _checked=False, site_preset=preset: self._handle_sky_view_saved_site_selected(site_preset)
                )

                self._sky_view_location_presets_layout.addWidget(preset_button)

        else:

            empty_label = QLabel("No saved quick-switch sites yet.")

            empty_label.setWordWrap(True)

            self._sky_view_location_presets_layout.addWidget(empty_label)

    def _handle_sky_view_saved_site_selected(self, preset: ObservingSitePreset) -> None:

        self._close_sky_view_popup(self._sky_view_location_menu)

        self._apply_sky_view_observing_site(
            preset.name,
            preset.latitude_deg,
            preset.longitude_deg,
            preset.elevation_m,
        )

    def _sync_sky_view_canvas_context(self) -> None:

        if not hasattr(self, "_sky_view_canvas"):

            return

        settings = getattr(self, "_settings", None)

        latitude_deg = None if settings is None else settings.observing_site_latitude_deg

        longitude_deg = None if settings is None else settings.observing_site_longitude_deg

        elevation_m = None if settings is None else settings.observing_site_elevation_m

        observer_configured = latitude_deg is not None and longitude_deg is not None

        site_name = "" if settings is None else settings.site_name.strip()

        self._sky_view_canvas.set_observer_context(
            latitude_deg,
            longitude_deg,
            elevation_m,
            site_name=site_name,
            configured=observer_configured,
        )

        self._sky_view_canvas.set_observation_time(self._current_sky_view_observation_time())

        self._sky_view_canvas.set_show_equatorial_grid(self._sky_view_equatorial_grid_button.isChecked())

        self._sky_view_canvas.set_show_alt_az_grid(self._sky_view_alt_az_grid_button.isChecked())

        self._sky_view_constellation_enabled_checkbox.blockSignals(True)

        self._sky_view_constellation_enabled_checkbox.setChecked(self._sky_view_constellation_button.isChecked())

        self._sky_view_constellation_enabled_checkbox.blockSignals(False)

        self._sky_view_canvas.set_show_constellation_lines(self._sky_view_constellation_button.isChecked())

        self._sky_view_canvas.set_constellation_line_segments_visible(self._sky_view_constellation_lines_checkbox.isChecked())

        self._sky_view_canvas.set_constellation_labels_visible(self._sky_view_constellation_labels_checkbox.isChecked())

        self._sky_view_canvas.set_constellation_line_width(self._sky_view_constellation_line_width_slider.value() / 10.0)

        self._sky_view_canvas.set_constellation_line_opacity(self._sky_view_constellation_line_opacity_slider.value() / 100.0)

        self._sky_view_canvas.set_constellation_label_opacity(self._sky_view_constellation_label_opacity_slider.value() / 100.0)

        self._sky_view_canvas.set_constellation_label_size(float(self._sky_view_constellation_label_size_slider.value()))

        constellation_color = self._sky_view_constellation_color_combo.currentData()

        self._sky_view_canvas.set_constellation_color(str(constellation_color) if isinstance(constellation_color, str) else "#dfe7f2")

        self._sky_view_canvas.set_show_ground(self._sky_view_ground_button.isChecked())

        self._sky_view_canvas.set_star_bloom_strength(self._sky_view_bloom_strength_spin.value())

        self._sky_view_canvas.set_milky_way_enabled(self._sky_view_milky_way_enabled_checkbox.isChecked())

        self._sky_view_canvas.set_milky_way_opacity(self._sky_view_milky_way_opacity_slider.value() / 100.0)

        tone_preset = self._sky_view_milky_way_tone_preset_combo.currentData()

        self._sky_view_canvas.set_milky_way_tone_preset(str(tone_preset) if isinstance(tone_preset, str) else "atlas")

        self._sky_view_canvas.set_milky_way_brightness(self._sky_view_milky_way_brightness_slider.value() / 100.0)

        self._sky_view_canvas.set_milky_way_contrast(self._sky_view_milky_way_contrast_slider.value() / 100.0)

        self._sky_view_canvas.set_milky_way_saturation(self._sky_view_milky_way_saturation_slider.value() / 100.0)

        self._sky_view_canvas.set_milky_way_black_point(self._sky_view_milky_way_black_point_slider.value() / 100.0)

        self._sky_view_canvas.set_milky_way_gamma(self._sky_view_milky_way_gamma_slider.value() / 100.0)

        render_mode = self._sky_view_milky_way_render_mode_combo.currentData()

        self._sky_view_canvas.set_milky_way_render_mode(str(render_mode) if isinstance(render_mode, str) else "full")

        resolution_mode = self._sky_view_milky_way_resolution_combo.currentData()

        self._sky_view_canvas.set_milky_way_resolution_mode(str(resolution_mode) if isinstance(resolution_mode, str) else "high")

        self._sky_view_canvas.set_milky_way_flip_horizontal(self._sky_view_milky_way_flip_checkbox.isChecked())

        self._sky_view_canvas.set_custom_sky_overlays_enabled(self._sky_view_custom_overlay_enabled_checkbox.isChecked())

        self._sky_view_canvas.set_custom_sky_overlay_opacity(self._sky_view_custom_overlay_opacity_slider.value() / 100.0)

        self._sky_view_canvas.set_custom_sky_overlay_brightness(self._sky_view_custom_overlay_brightness_slider.value() / 100.0)

        self._sky_view_canvas.set_custom_sky_overlay_saturation(self._sky_view_custom_overlay_saturation_slider.value() / 100.0)

        if hasattr(self, "_sky_view_custom_overlay_feather_slider"):

            self._sky_view_canvas.set_custom_sky_overlay_feather(self._sky_view_custom_overlay_feather_slider.value() / 100.0)

        spike_style = self._sky_view_spike_style_combo.currentData()

        self._sky_view_canvas.set_star_spike_style(str(spike_style) if isinstance(spike_style, str) else "subtle")

        if self._sky_view_canvas._moon_debug_controls_enabled():

            self._apply_sky_view_moon_debug_controls_to_canvas()

    def _show_sky_view_custom_overlay_popup(self) -> None:

        self._refresh_sky_view_custom_overlay_survey_selector()

        self._show_sky_view_popup_menu(self._sky_view_custom_overlay_button, self._sky_view_custom_overlay_menu)

    def _show_sky_view_options_popup(self) -> None:

        self._show_sky_view_popup_menu(self._sky_view_options_button, self._sky_view_options_menu)


        self._sync_sky_view_canvas_context()

    def _show_sky_atlas_settings_dialog(self) -> None:

        settings = self._ensure_sky_view_settings_loaded()

        dialog = SkyAtlasSettingsDialog(settings, parent=self)

        dialog.settingsChanged.connect(self._handle_sky_atlas_display_settings_preview)

        if dialog.exec() != QDialog.DialogCode.Accepted:

            self._apply_sky_atlas_display_settings_from_disk()

            return

        display_settings = dialog.current_settings()

        self._persist_sky_atlas_display_settings(display_settings)

        self._apply_sky_atlas_display_settings(display_settings, reload_catalogs=True)

    def _handle_sky_atlas_display_settings_preview(self, display_settings: object) -> None:

        if not isinstance(display_settings, SkyAtlasDisplaySettings):

            return

        self._apply_sky_atlas_display_settings(display_settings, reload_catalogs=False)

    def _persist_sky_atlas_display_settings(self, display_settings: SkyAtlasDisplaySettings) -> None:

        settings = self._ensure_sky_view_settings_loaded()

        self._settings = replace(
            settings,
            sky_atlas_star_magnitude_limit=float(display_settings.star_magnitude_limit),
            sky_atlas_star_brightness=float(display_settings.star_brightness),
            sky_atlas_star_size=float(display_settings.star_size),
            sky_atlas_star_magnitude_size_contrast=float(display_settings.star_magnitude_size_contrast),
            sky_atlas_star_twinkle=float(display_settings.star_twinkle),
            sky_atlas_show_messier=bool(display_settings.show_messier),
            sky_atlas_show_ngc=bool(display_settings.show_ngc),
            sky_atlas_show_ic=bool(display_settings.show_ic),
            sky_atlas_show_vdb=bool(display_settings.show_vdb),
            sky_atlas_show_ldn=bool(display_settings.show_ldn),
            sky_atlas_show_lbn=bool(display_settings.show_lbn),
            sky_atlas_object_magnitude_limit=float(display_settings.object_magnitude_limit),
            sky_atlas_object_label_magnitude_limit=float(display_settings.object_label_magnitude_limit),
        )

        self._save_settings_snapshot()

    def _apply_sky_atlas_display_settings_from_disk(self) -> None:

        settings = self._ensure_sky_view_settings_loaded()

        self._apply_sky_atlas_display_settings(
            SkyAtlasDisplaySettings.from_app_settings(settings),
            reload_catalogs=False,
        )

    def _apply_sky_atlas_display_settings(
        self,
        display_settings: SkyAtlasDisplaySettings,
        *,
        reload_catalogs: bool,
    ) -> None:

        if hasattr(self, "_sky_view_canvas") and self._sky_view_canvas is not None:

            self._sky_view_canvas.apply_sky_atlas_display_settings(display_settings)

        if not reload_catalogs or not hasattr(self, "_sky_view_canvas"):

            return

        settings = self._ensure_sky_view_settings_loaded()

        QApplication.setOverrideCursor(Qt.CursorShape.WaitCursor)

        progress_dialog = self._create_sky_view_loading_progress_dialog("Updating Sky Atlas catalogs...")

        progress_dialog.show()

        self._sky_view_catalog_progress_dialog = progress_dialog

        QApplication.processEvents(QEventLoop.ProcessEventsFlag.ExcludeUserInputEvents)

        try:

            self._sky_view_catalog_objects = load_sky_atlas_objects(
                application_install_path(),
                download_if_missing=True,
                maximum_scientific_magnitude=max(
                    9.5,
                    float(display_settings.star_magnitude_limit),
                ),
                enabled_deep_sky_catalogs=display_settings.enabled_deep_sky_catalogs(),
                progress_callback=self._sky_view_catalog_progress,
            )

            self._sky_view_scientific_catalog_loaded = any(
                item.catalog.casefold() == "hipparcos" for item in self._sky_view_catalog_objects
            )

            self._sky_view_loaded_star_magnitude_limit = max(
                9.5,
                float(display_settings.star_magnitude_limit),
            )

            self._sky_view_loaded_deep_sky_catalogs = display_settings.enabled_deep_sky_catalogs()

            self._sky_view_canvas.set_objects(self._sky_view_catalog_objects)

            if hasattr(self, "_sky_view_magnitude_limit_spin"):

                self._sky_view_magnitude_limit_spin.blockSignals(True)

                self._sky_view_magnitude_limit_spin.setValue(float(display_settings.star_magnitude_limit))

                self._sky_view_magnitude_limit_spin.blockSignals(False)

            self._refresh_sky_view_search_results(select_first=False)

            if hasattr(self, "_sky_view_status_label"):

                self._sky_view_status_label.setText(self._sky_view_status_summary())

        except Exception as exc:

            self._sky_view_scientific_catalog_error = str(exc)

            self.statusBar().showMessage(f"Sky Atlas catalog update failed: {exc}", 6000)

        finally:

            self._sky_view_catalog_progress_dialog = None

            progress_dialog.close()

            progress_dialog.deleteLater()

            QApplication.restoreOverrideCursor()

    def _apply_sky_view_observing_site(
        self,
        site_name: str,
        latitude_deg: float,
        longitude_deg: float,
        elevation_m: float | None,
        observing_site_presets: Sequence[ObservingSitePreset] | None = None,
        *,
        preserve_saved_presets: bool = True,
    ) -> None:

        settings = self._ensure_sky_view_settings_loaded()

        if preserve_saved_presets and observing_site_presets is None:

            resolved_presets = self._normalized_observing_site_presets(settings.observing_site_presets)

        else:

            resolved_presets = self._normalized_observing_site_presets(observing_site_presets)

        self._settings = replace(
            settings,
            site_name=str(site_name or "").strip(),
            observing_site_latitude_deg=max(-90.0, min(90.0, float(latitude_deg))),
            observing_site_longitude_deg=max(-180.0, min(180.0, float(longitude_deg))),
            observing_site_elevation_m=(None if elevation_m is None else max(-500.0, min(12000.0, float(elevation_m)))),
            observing_site_presets=resolved_presets,
        )

        self._save_settings_snapshot()

        self._refresh_sky_view_observer_site_state()

        site_label = self._settings.site_name.strip() if self._settings is not None else ""

        if site_label:

            self.statusBar().showMessage(f"Saved observer location for {site_label}.", 4000)

        else:

            self.statusBar().showMessage("Saved observer location for Sky View.", 4000)

    def _ensure_sky_view_settings_loaded(self) -> AppSettings:

        settings = getattr(self, "_settings", None)

        if settings is not None:

            return settings

        root_path = Path(self._root_path_input.text()).expanduser()

        self._settings = AppSettings.from_root(root_path if root_path.exists() else Path.cwd())

        return self._settings

    @staticmethod
    def _normalized_observing_site_presets(
        presets: Sequence[ObservingSitePreset] | None,
    ) -> list[ObservingSitePreset] | None:

        if not presets:

            return None

        normalized_presets: list[ObservingSitePreset] = []

        seen_keys: set[tuple[str, float, float, float | None]] = set()

        for preset in presets:

            normalized_preset = ObservingSitePreset(
                name=str(preset.name or "").strip(),
                latitude_deg=max(-90.0, min(90.0, float(preset.latitude_deg))),
                longitude_deg=max(-180.0, min(180.0, float(preset.longitude_deg))),
                elevation_m=(None if preset.elevation_m is None else max(-500.0, min(12000.0, float(preset.elevation_m)))),
            )

            preset_key = (
                normalized_preset.name.casefold(),
                round(normalized_preset.latitude_deg, 6),
                round(normalized_preset.longitude_deg, 6),
                None if normalized_preset.elevation_m is None else round(normalized_preset.elevation_m, 2),
            )

            if preset_key in seen_keys:

                continue

            seen_keys.add(preset_key)

            normalized_presets.append(normalized_preset)

        return normalized_presets or None

    @staticmethod
    def _observing_site_button_text(
        site_name: str,
        latitude_deg: float,
        longitude_deg: float,
        elevation_m: float | None,
    ) -> str:

        latitude_suffix = "N" if latitude_deg >= 0.0 else "S"

        longitude_suffix = "E" if longitude_deg >= 0.0 else "W"

        site_label = str(site_name or "").strip()

        if not site_label:

            site_label = "Unnamed site"

        elevation_text = "-" if elevation_m is None else f"{float(elevation_m):.0f} m"

        return (
            f"{site_label}\n"
            f"{abs(float(latitude_deg)):.4f} deg {latitude_suffix}, {abs(float(longitude_deg)):.4f} deg {longitude_suffix}"
            f"  |  Elev {elevation_text}"
        )

    @staticmethod
    def _clear_layout_widgets(layout: QVBoxLayout) -> None:

        while layout.count() > 0:

            item = layout.takeAt(0)

            widget = item.widget()

            if widget is not None:

                widget.deleteLater()

    def _refresh_sky_view_observer_site_state(self) -> None:

        if not hasattr(self, "_sky_view_canvas"):

            return

        self._sync_sky_view_canvas_context()

        selected_object = self._sky_view_canvas.selected_object()

        self._sync_sky_view_object_panel(selected_object)

        if hasattr(self, "_sky_view_detail_label"):

            self._sky_view_detail_label.setText(
                "" if selected_object is None else self._format_sky_view_object_details(selected_object)
            )

        self._prepare_sky_view_date_time_menu()

        self._refresh_sky_view_overlay_geometry()

    def _current_sky_view_observation_time(self) -> datetime:

        simulation_clock = getattr(self, "_sky_view_simulation_clock", None)

        if isinstance(simulation_clock, SkyViewSimulationClock):

            observation_time = simulation_clock.simulation_time()

            self._sky_view_observation_time_utc = observation_time

            return observation_time

        observation_time = getattr(self, "_sky_view_observation_time_utc", None)

        if isinstance(observation_time, datetime):

            return observation_time.replace(tzinfo=UTC) if observation_time.tzinfo is None else observation_time.astimezone(UTC)

        observation_time = datetime.now(UTC)

        self._sky_view_observation_time_utc = observation_time

        return observation_time

    def _set_sky_view_observation_time(self, observation_time: datetime) -> None:

        resolved_time = observation_time.replace(tzinfo=UTC) if observation_time.tzinfo is None else observation_time.astimezone(UTC)

        simulation_clock = getattr(self, "_sky_view_simulation_clock", None)

        if isinstance(simulation_clock, SkyViewSimulationClock):

            resolved_time = simulation_clock.set_time(resolved_time)

        self._sky_view_observation_time_utc = resolved_time

        self._sky_view_time_flow_last_monotonic = monotonic()

        if hasattr(self, "_sky_view_canvas"):

            self._sky_view_canvas.set_observation_time(resolved_time)

            selected_object = self._sky_view_canvas.selected_object()

            self._sync_sky_view_object_panel(selected_object)

            if hasattr(self, "_sky_view_detail_label"):

                self._sky_view_detail_label.setText(
                    "" if selected_object is None else self._format_sky_view_object_details(selected_object)
                )

        self._prepare_sky_view_date_time_menu()

        self._refresh_sky_view_overlay_geometry()

    def _set_sky_view_observation_time_now(self) -> None:

        self._set_sky_view_observation_time(datetime.now(UTC))

    def _nudge_sky_view_observation_time(self, delta: timedelta) -> None:

        self._set_sky_view_observation_time(self._current_sky_view_observation_time() + delta)

    def _handle_sky_view_date_time_changed(self, value: QDateTime) -> None:

        self._set_sky_view_observation_time(datetime.fromtimestamp(value.toSecsSinceEpoch(), UTC))

    def _prepare_sky_view_date_time_menu(self) -> None:

        selected_utc = self._current_sky_view_observation_time()

        if hasattr(self, "_sky_view_date_time_edit"):

            current_qdatetime = self._sky_view_date_time_edit.dateTime()

            editor_is_live_editing = self._sky_view_date_time_menu.isVisible() and self._sky_view_date_time_edit.hasFocus()

            if not editor_is_live_editing and current_qdatetime.toSecsSinceEpoch() != int(selected_utc.timestamp()):

                self._sky_view_date_time_edit.blockSignals(True)

                self._sky_view_date_time_edit.setDateTime(
                    QDateTime.fromSecsSinceEpoch(int(selected_utc.timestamp()), QTimeZone.utc())
                )

                self._sky_view_date_time_edit.blockSignals(False)

        self._sync_sky_view_time_flow_button()

    def _sync_sky_view_toolbar_icons(self) -> None:

        self._sky_view_search_button.setIcon(self._create_sky_view_toolbar_icon("search"))

        self._sky_view_date_time_button.setIcon(self._create_sky_view_toolbar_icon("datetime"))

        self._sync_sky_view_time_flow_button()

        self._sky_view_location_button.setIcon(self._create_sky_view_toolbar_icon("location"))

        self._sky_view_equatorial_grid_button.setIcon(self._create_sky_view_toolbar_icon("equatorial-grid"))

        self._sky_view_alt_az_grid_button.setIcon(self._create_sky_view_toolbar_icon("altaz-grid"))

        self._sky_view_constellation_button.setIcon(self._create_sky_view_toolbar_icon("constellation"))

        self._sky_view_ground_button.setIcon(self._create_sky_view_toolbar_icon("ground"))

        self._sky_view_custom_overlay_button.setIcon(self._create_sky_view_toolbar_icon("mosaic"))

        self._sky_view_settings_button.setIcon(self._create_sky_view_toolbar_icon("gear"))

        self._sky_view_options_button.setIcon(self._create_sky_view_toolbar_icon("options"))

        host_window = self.window()

        full_screen_icon = "fullscreen-exit" if isinstance(host_window, QMainWindow) and host_window.isFullScreen() else "fullscreen"

        self._sky_view_full_screen_button.setIcon(self._create_sky_view_toolbar_icon(full_screen_icon))

    def _create_sky_view_toolbar_icon(self, kind: str) -> QIcon:

        pixmap = QPixmap(24, 24)

        pixmap.fill(Qt.GlobalColor.transparent)

        painter = QPainter(pixmap)

        painter.setRenderHint(QPainter.RenderHint.Antialiasing, True)

        color = QColor("#f8fafc")

        pen = QPen(color, 1.9)

        pen.setCosmetic(True)

        painter.setPen(pen)

        painter.setBrush(Qt.BrushStyle.NoBrush)

        normalized_kind = str(kind or "search").strip().casefold()

        if normalized_kind == "search":

            painter.drawEllipse(QRectF(4.5, 4.5, 10.0, 10.0))

            painter.drawLine(QPointF(13.2, 13.2), QPointF(18.8, 18.8))

        elif normalized_kind == "datetime":

            painter.drawEllipse(QRectF(3.5, 3.5, 17.0, 17.0))

            painter.drawLine(QPointF(12.0, 7.5), QPointF(12.0, 12.4))

            painter.drawLine(QPointF(12.0, 12.0), QPointF(15.8, 14.6))

        elif normalized_kind == "time-play":

            play_path = QPainterPath()

            play_path.moveTo(8.0, 5.5)

            play_path.lineTo(18.0, 12.0)

            play_path.lineTo(8.0, 18.5)

            play_path.closeSubpath()

            painter.setBrush(color)

            painter.drawPath(play_path)

        elif normalized_kind == "time-pause":

            painter.setBrush(color)

            painter.drawRoundedRect(QRectF(7.0, 5.0, 3.8, 14.0), 1.2, 1.2)

            painter.drawRoundedRect(QRectF(13.2, 5.0, 3.8, 14.0), 1.2, 1.2)

        elif normalized_kind == "location":

            pin_path = QPainterPath()

            pin_path.moveTo(12.0, 20.0)

            pin_path.cubicTo(8.5, 16.3, 6.3, 13.2, 6.3, 9.7)

            pin_path.cubicTo(6.3, 6.0, 8.9, 3.5, 12.0, 3.5)

            pin_path.cubicTo(15.1, 3.5, 17.7, 6.0, 17.7, 9.7)

            pin_path.cubicTo(17.7, 13.2, 15.5, 16.3, 12.0, 20.0)

            painter.drawPath(pin_path)

            painter.drawEllipse(QRectF(10.0, 7.8, 4.0, 4.0))

        elif normalized_kind == "options":

            painter.drawLine(QPointF(5.0, 7.0), QPointF(19.0, 7.0))

            painter.drawLine(QPointF(5.0, 12.0), QPointF(19.0, 12.0))

            painter.drawLine(QPointF(5.0, 17.0), QPointF(19.0, 17.0))

            painter.setBrush(color)

            painter.drawEllipse(QRectF(8.0, 5.0, 4.0, 4.0))

            painter.drawEllipse(QRectF(13.5, 10.0, 4.0, 4.0))

            painter.drawEllipse(QRectF(9.5, 15.0, 4.0, 4.0))

        elif normalized_kind == "gear":

            painter.drawEllipse(QRectF(8.2, 8.2, 7.6, 7.6))

            painter.drawEllipse(QRectF(10.4, 10.4, 3.2, 3.2))

            for angle_deg in (0.0, 45.0, 90.0, 135.0, 180.0, 225.0, 270.0, 315.0):

                angle_rad = math.radians(angle_deg)

                inner_x = 12.0 + math.cos(angle_rad) * 4.6

                inner_y = 12.0 + math.sin(angle_rad) * 4.6

                outer_x = 12.0 + math.cos(angle_rad) * 8.2

                outer_y = 12.0 + math.sin(angle_rad) * 8.2

                painter.drawLine(QPointF(inner_x, inner_y), QPointF(outer_x, outer_y))

        elif normalized_kind == "ground":

            painter.drawArc(QRectF(4.0, 9.5, 16.0, 8.5), 0, 180 * 16)

            painter.drawLine(QPointF(4.0, 14.0), QPointF(20.0, 14.0))

            painter.drawLine(QPointF(12.0, 7.0), QPointF(12.0, 11.0))

        elif normalized_kind == "mosaic":

            painter.drawRoundedRect(QRectF(4.0, 5.0, 7.0, 7.0), 1.2, 1.2)

            painter.drawRoundedRect(QRectF(13.0, 5.0, 7.0, 7.0), 1.2, 1.2)

            painter.drawRoundedRect(QRectF(4.0, 13.0, 7.0, 7.0), 1.2, 1.2)

            painter.drawRoundedRect(QRectF(13.0, 13.0, 7.0, 7.0), 1.2, 1.2)

        elif normalized_kind == "equatorial-grid":

            painter.drawEllipse(QRectF(4.5, 4.5, 15.0, 15.0))

            painter.drawLine(QPointF(12.0, 4.5), QPointF(12.0, 19.5))

            painter.drawLine(QPointF(4.5, 12.0), QPointF(19.5, 12.0))

            painter.drawArc(QRectF(7.0, 4.5, 10.0, 15.0), 90 * 16, 180 * 16)

        elif normalized_kind == "altaz-grid":

            painter.drawArc(QRectF(4.0, 8.5, 16.0, 10.0), 0, 180 * 16)

            painter.drawLine(QPointF(6.0, 17.0), QPointF(18.0, 17.0))

            painter.drawLine(QPointF(12.0, 5.0), QPointF(12.0, 17.0))

            painter.drawLine(QPointF(7.5, 9.0), QPointF(12.0, 5.0))

            painter.drawLine(QPointF(16.5, 9.0), QPointF(12.0, 5.0))

        elif normalized_kind == "constellation":

            painter.drawEllipse(QRectF(5.0, 6.0, 2.5, 2.5))

            painter.drawEllipse(QRectF(10.7, 4.5, 2.5, 2.5))

            painter.drawEllipse(QRectF(16.3, 7.8, 2.5, 2.5))

            painter.drawEllipse(QRectF(8.0, 15.0, 2.5, 2.5))

            painter.drawLine(QPointF(6.2, 7.2), QPointF(12.0, 5.8))

            painter.drawLine(QPointF(12.0, 5.8), QPointF(17.5, 9.0))

            painter.drawLine(QPointF(12.0, 5.8), QPointF(9.3, 16.2))

        elif normalized_kind == "grid":

            for x_value in (6.0, 12.0, 18.0):

                painter.drawLine(QPointF(x_value, 5.0), QPointF(x_value, 19.0))

            for y_value in (6.0, 12.0, 18.0):

                painter.drawLine(QPointF(5.0, y_value), QPointF(19.0, y_value))

        elif normalized_kind == "fullscreen-exit":

            painter.drawLine(QPointF(6.0, 10.0), QPointF(6.0, 6.0))

            painter.drawLine(QPointF(6.0, 6.0), QPointF(10.0, 6.0))

            painter.drawLine(QPointF(18.0, 10.0), QPointF(18.0, 6.0))

            painter.drawLine(QPointF(18.0, 6.0), QPointF(14.0, 6.0))

            painter.drawLine(QPointF(6.0, 14.0), QPointF(6.0, 18.0))

            painter.drawLine(QPointF(6.0, 18.0), QPointF(10.0, 18.0))

            painter.drawLine(QPointF(18.0, 14.0), QPointF(18.0, 18.0))

            painter.drawLine(QPointF(18.0, 18.0), QPointF(14.0, 18.0))

        else:

            painter.drawLine(QPointF(4.5, 9.0), QPointF(4.5, 4.5))

            painter.drawLine(QPointF(4.5, 4.5), QPointF(9.0, 4.5))

            painter.drawLine(QPointF(19.5, 9.0), QPointF(19.5, 4.5))

            painter.drawLine(QPointF(19.5, 4.5), QPointF(15.0, 4.5))

            painter.drawLine(QPointF(4.5, 15.0), QPointF(4.5, 19.5))

            painter.drawLine(QPointF(4.5, 19.5), QPointF(9.0, 19.5))

            painter.drawLine(QPointF(19.5, 15.0), QPointF(19.5, 19.5))

            painter.drawLine(QPointF(19.5, 19.5), QPointF(15.0, 19.5))

        painter.end()

        return QIcon(pixmap)

    def _sky_view_status_summary(self) -> str:

        if self._sky_view_scientific_catalog_error:

            return (

                "Using the packaged named-target atlas only. "

                f"Hipparcos loading failed: {self._sky_view_scientific_catalog_error}."

            )

        hipparcos_count = sum(1 for item in self._sky_view_catalog_objects if item.catalog.casefold() == "hipparcos")

        if hipparcos_count > 0:

            return f"Loaded {len(self._sky_view_catalog_objects):,} sky objects including {hipparcos_count:,} Hipparcos stars."

        return "Showing packaged named targets. Open Sky View to load the downloaded Hipparcos all-sky star catalog."

    def _handle_sky_view_canvas_activated(self, sky_object: SkyAtlasObject) -> None:

        self._sync_sky_view_object_panel(sky_object)

        self._sky_view_detail_label.setText(self._format_sky_view_object_details(sky_object))

        self._sky_view_status_label.setText(f"Selected {sky_object.name}.")

        self._refresh_sky_view_overlay_geometry()

    def _handle_sky_view_canvas_object_info_changed(self, sky_object: SkyAtlasObject | None) -> None:

        _ = sky_object

        selected_object = self._sky_view_canvas.selected_object()

        self._sync_sky_view_object_panel(selected_object)

        if selected_object is None:

            self._sky_view_status_label.setText(self._sky_view_status_summary())

        self._refresh_sky_view_overlay_geometry()

    def _handle_sky_view_canvas_info_changed(self, text: str) -> None:

        _ = text

        selected_object = self._sky_view_canvas.selected_object()

        self._sky_view_detail_label.setText(
            "" if selected_object is None else self._format_sky_view_object_details(selected_object)
        )

        self._refresh_sky_view_overlay_geometry()

    def _handle_reset_sky_view(self) -> None:

        self._sky_view_canvas.reset_view()

        current_query = self._sky_view_search_input.text().strip()

        self._sky_view_search_input.blockSignals(True)

        self._sky_view_search_input.clear()

        self._sky_view_search_input.blockSignals(False)

        if current_query:

            self._sky_view_canvas.set_selected_object(None)

        self._refresh_sky_view_search_results(select_first=False)

    def _handle_sky_view_ground_toggled(self, checked: bool) -> None:

        self._sky_view_canvas.set_show_ground(checked)

    def _handle_sky_view_custom_overlay_enabled_toggled(self, checked: bool) -> None:

        self._sky_view_canvas.set_custom_sky_overlays_enabled(checked)

        self._persist_sky_view_custom_overlay_settings()

    def _handle_sky_view_custom_overlay_opacity_changed(self, value: int) -> None:

        self._sky_view_custom_overlay_opacity_value_label.setText(f"{int(value)}%")

        self._sky_view_canvas.set_custom_sky_overlay_opacity(float(value) / 100.0)

        self._persist_sky_view_custom_overlay_settings()

    def _handle_sky_view_custom_overlay_brightness_changed(self, value: int) -> None:

        self._sky_view_custom_overlay_brightness_value_label.setText(f"{float(value) / 100.0:.2f}x")

        self._sky_view_canvas.set_custom_sky_overlay_brightness(float(value) / 100.0)

        self._persist_sky_view_custom_overlay_settings()

    def _handle_sky_view_custom_overlay_saturation_changed(self, value: int) -> None:

        self._sky_view_custom_overlay_saturation_value_label.setText(f"{float(value) / 100.0:.2f}x")

        self._sky_view_canvas.set_custom_sky_overlay_saturation(float(value) / 100.0)

        self._persist_sky_view_custom_overlay_settings()

    def _handle_sky_view_custom_overlay_feather_changed(self, value: int) -> None:

        self._sky_view_custom_overlay_feather_value_label.setText(f"{int(value)}%")

        self._sky_view_canvas.set_custom_sky_overlay_feather(float(value) / 100.0)

        self._persist_sky_view_custom_overlay_settings()

    def _persist_sky_view_custom_overlay_settings(self) -> None:

        settings = self._ensure_sky_view_settings_loaded()

        self._settings = replace(
            settings,
            sky_atlas_custom_overlays_enabled=self._sky_view_custom_overlay_enabled_checkbox.isChecked(),
            sky_atlas_custom_overlay_opacity=self._sky_view_custom_overlay_opacity_slider.value() / 100.0,
            sky_atlas_custom_overlay_brightness=self._sky_view_custom_overlay_brightness_slider.value() / 100.0,
            sky_atlas_custom_overlay_saturation=self._sky_view_custom_overlay_saturation_slider.value() / 100.0,
            sky_atlas_custom_overlay_feather=self._sky_view_custom_overlay_feather_slider.value() / 100.0,
            sky_atlas_custom_overlay_surveys=list(settings.sky_atlas_custom_overlay_surveys or []),
            sky_atlas_custom_overlay_active_survey_id=settings.sky_atlas_custom_overlay_active_survey_id,
        )

        self._save_settings_snapshot()

    def _apply_sky_view_custom_overlay_settings_from_disk(self) -> None:

        settings = self._ensure_sky_view_settings_loaded()

        self._sky_view_custom_overlay_enabled_checkbox.blockSignals(True)

        self._sky_view_custom_overlay_opacity_slider.blockSignals(True)

        self._sky_view_custom_overlay_brightness_slider.blockSignals(True)

        self._sky_view_custom_overlay_saturation_slider.blockSignals(True)

        self._sky_view_custom_overlay_feather_slider.blockSignals(True)

        self._sky_view_custom_overlay_enabled_checkbox.setChecked(bool(settings.sky_atlas_custom_overlays_enabled))

        self._sky_view_custom_overlay_opacity_slider.setValue(int(round(max(0.0, min(1.0, float(settings.sky_atlas_custom_overlay_opacity))) * 100.0)))

        self._sky_view_custom_overlay_brightness_slider.setValue(int(round(max(0.35, min(2.0, float(settings.sky_atlas_custom_overlay_brightness))) * 100.0)))

        self._sky_view_custom_overlay_saturation_slider.setValue(int(round(max(0.0, min(2.4, float(settings.sky_atlas_custom_overlay_saturation))) * 100.0)))

        self._sky_view_custom_overlay_feather_slider.setValue(int(round(max(0.0, min(1.0, float(settings.sky_atlas_custom_overlay_feather))) * 100.0)))

        self._sky_view_custom_overlay_enabled_checkbox.blockSignals(False)

        self._sky_view_custom_overlay_opacity_slider.blockSignals(False)

        self._sky_view_custom_overlay_brightness_slider.blockSignals(False)

        self._sky_view_custom_overlay_saturation_slider.blockSignals(False)

        self._sky_view_custom_overlay_feather_slider.blockSignals(False)

        self._sky_view_custom_overlay_opacity_value_label.setText(f"{self._sky_view_custom_overlay_opacity_slider.value()}%")

        self._sky_view_custom_overlay_brightness_value_label.setText(
            f"{self._sky_view_custom_overlay_brightness_slider.value() / 100.0:.2f}x"
        )

        self._sky_view_custom_overlay_saturation_value_label.setText(
            f"{self._sky_view_custom_overlay_saturation_slider.value() / 100.0:.2f}x"
        )

        self._sky_view_custom_overlay_feather_value_label.setText(
            f"{self._sky_view_custom_overlay_feather_slider.value()}%"
        )

        self._reload_sky_view_custom_overlays_on_canvas(sky_atlas_custom_overlays_for_active_survey(settings))

        self._refresh_sky_view_custom_overlay_survey_selector()

    def _reload_sky_view_custom_overlays_on_canvas(
        self,
        overlay_records: Sequence[SkyAtlasCustomOverlayRecord] | None,
    ) -> int:

        loaded_overlays: list[LoadedSkyAtlasCustomOverlay] = []

        for record in overlay_records or []:

            loaded_overlay = load_overlay_record(record)

            if loaded_overlay is not None:

                loaded_overlays.append(loaded_overlay)

        self._sky_view_canvas.set_custom_sky_overlay_entries(loaded_overlays)

        if overlay_records and not loaded_overlays:

            self.statusBar().showMessage(
                "Custom overlay saved, but it could not be loaded for display. Check the cached image and WCS files.",
                8000,
            )

        return len(loaded_overlays)

    def _survey_menu_label(self, survey: SkyAtlasCustomOverlaySurvey) -> str:
        filter_name = str(survey.filter_name or "").strip()
        if filter_name:
            return f"{survey.name} ({filter_name})"
        return survey.name

    def _refresh_sky_view_custom_overlay_survey_selector(self) -> None:

        if not hasattr(self, "_sky_view_custom_overlay_survey_combo"):

            return

        settings = self._ensure_sky_view_settings_loaded()

        surveys = sky_atlas_custom_overlay_surveys_for_settings(settings)

        active_survey_id = settings.sky_atlas_custom_overlay_active_survey_id

        if surveys and active_survey_id not in {survey.survey_id for survey in surveys}:

            active_survey_id = surveys[0].survey_id

        combo = self._sky_view_custom_overlay_survey_combo

        combo.blockSignals(True)

        combo.clear()

        if not surveys:

            combo.addItem("No surveys yet", "")

            combo.setEnabled(False)

            combo.blockSignals(False)

            return

        combo.setEnabled(True)

        active_index = 0

        for index, survey in enumerate(surveys):

            combo.addItem(self._survey_menu_label(survey), survey.survey_id)

            if survey.survey_id == active_survey_id:

                active_index = index

        combo.setCurrentIndex(active_index)

        combo.blockSignals(False)

    def _handle_sky_view_custom_overlay_survey_combo_changed(self, index: int) -> None:

        if index < 0:

            return

        combo = self._sky_view_custom_overlay_survey_combo

        survey_id = combo.itemData(index)

        if not survey_id:

            return

        self._select_sky_view_custom_overlay_survey(str(survey_id))

    def _select_sky_view_custom_overlay_survey(self, survey_id: str) -> None:

        settings = self._ensure_sky_view_settings_loaded()

        surveys = sky_atlas_custom_overlay_surveys_for_settings(settings)

        if not any(survey.survey_id == survey_id for survey in surveys):

            return

        self._settings = replace(
            settings,
            sky_atlas_custom_overlay_active_survey_id=survey_id,
            sky_atlas_custom_overlays_enabled=True,
        )

        self._save_settings_snapshot()

        self._sky_view_custom_overlay_enabled_checkbox.blockSignals(True)

        self._sky_view_custom_overlay_enabled_checkbox.setChecked(True)

        self._sky_view_custom_overlay_enabled_checkbox.blockSignals(False)

        self._sky_view_canvas.set_custom_sky_overlays_enabled(True)

        loaded_count = self._reload_sky_view_custom_overlays_on_canvas(
            sky_atlas_custom_overlays_for_active_survey(self._settings)
        )

        self._refresh_sky_view_custom_overlay_survey_selector()

        survey_name = next(
            (self._survey_menu_label(survey) for survey in surveys if survey.survey_id == survey_id),
            "survey",
        )

        if loaded_count > 0:

            self.statusBar().showMessage(f"Showing custom sky map survey {survey_name}.", 5000)

        else:

            self.statusBar().showMessage(
                f"Selected survey {survey_name}, but its images could not be loaded.",
                6000,
            )

    def _open_sky_view_custom_overlay_surveys_dialog(self) -> None:

        existing_dialog = getattr(self, "_sky_atlas_custom_overlay_surveys_dialog", None)

        if existing_dialog is not None and existing_dialog.isVisible():

            existing_dialog.raise_()

            existing_dialog.activateWindow()

            return

        settings = self._ensure_sky_view_settings_loaded()

        dialog = SkyAtlasCustomOverlaySurveysDialog(settings, parent=self)

        dialog.finished.connect(
            lambda result, dialog_ref=dialog: self._handle_sky_view_custom_overlay_surveys_dialog_finished(
                dialog_ref,
                result,
            )
        )

        dialog.destroyed.connect(
            lambda _obj=None, dialog_ref=dialog: self._forget_sky_view_custom_overlay_surveys_dialog(dialog_ref)
        )

        self._sky_atlas_custom_overlay_surveys_dialog = dialog

        dialog.show()

    def _handle_sky_view_custom_overlay_surveys_dialog_finished(
        self,
        dialog: SkyAtlasCustomOverlaySurveysDialog,
        result: int,
    ) -> None:

        if result != int(QDialog.DialogCode.Accepted):

            return

        settings = self._ensure_sky_view_settings_loaded()

        previous_survey_ids = {
            survey.survey_id for survey in sky_atlas_custom_overlay_surveys_for_settings(settings)
        }

        from photometry_app.core.sky_atlas_survey_storage import sync_surveys_to_disk

        updated_surveys = sync_surveys_to_disk(
            dialog.surveys,
            previous_survey_ids=previous_survey_ids,
        )

        active_survey_id = settings.sky_atlas_custom_overlay_active_survey_id

        survey_ids = {survey.survey_id for survey in updated_surveys}

        if active_survey_id not in survey_ids:

            active_survey_id = updated_surveys[0].survey_id if updated_surveys else None

        self._settings = replace(
            settings,
            sky_atlas_custom_overlay_surveys=updated_surveys or None,
            sky_atlas_custom_overlay_active_survey_id=active_survey_id,
            sky_atlas_custom_overlays=None,
            sky_atlas_custom_overlays_enabled=bool(updated_surveys) or settings.sky_atlas_custom_overlays_enabled,
        )

        self._save_settings_snapshot()

        if updated_surveys:

            self._sky_view_custom_overlay_enabled_checkbox.blockSignals(True)

            self._sky_view_custom_overlay_enabled_checkbox.setChecked(True)

            self._sky_view_custom_overlay_enabled_checkbox.blockSignals(False)

            self._sky_view_canvas.set_custom_sky_overlays_enabled(True)

        loaded_count = self._reload_sky_view_custom_overlays_on_canvas(
            sky_atlas_custom_overlays_for_active_survey(self._settings)
        )

        self._refresh_sky_view_custom_overlay_survey_selector()

        if updated_surveys and loaded_count > 0:

            self.statusBar().showMessage("Custom sky map surveys updated.", 5000)

        elif updated_surveys:

            self.statusBar().showMessage("Custom sky map surveys saved.", 5000)

    def _forget_sky_view_custom_overlay_surveys_dialog(
        self,
        dialog: SkyAtlasCustomOverlaySurveysDialog,
    ) -> None:

        existing_dialog = getattr(self, "_sky_atlas_custom_overlay_surveys_dialog", None)

        if existing_dialog is dialog:

            self._sky_atlas_custom_overlay_surveys_dialog = None

