    def _sync_sky_view_milky_way_tone_preset_combo(self) -> None:

        preset_name = self._sky_view_canvas.milky_way_tone_preset()

        target_index = self._sky_view_milky_way_tone_preset_combo.findData(preset_name)

        if target_index < 0:

            target_index = self._sky_view_milky_way_tone_preset_combo.findData("custom")

        if target_index < 0 or self._sky_view_milky_way_tone_preset_combo.currentIndex() == target_index:

            return

        self._sky_view_milky_way_tone_preset_combo.blockSignals(True)

        self._sky_view_milky_way_tone_preset_combo.setCurrentIndex(target_index)

        self._sky_view_milky_way_tone_preset_combo.blockSignals(False)

    def _handle_sky_view_milky_way_tone_preset_changed(self, _index: int) -> None:

        preset_name = self._sky_view_milky_way_tone_preset_combo.currentData()

        if not isinstance(preset_name, str) or preset_name == "custom":

            return

        preset_values = _SkyAtlasViewWidget._milky_way_tone_preset_values(preset_name)

        self._sky_view_milky_way_brightness_slider.setValue(int(round(float(preset_values["brightness"]) * 100.0)))

        self._sky_view_milky_way_contrast_slider.setValue(int(round(float(preset_values["contrast"]) * 100.0)))

        self._sky_view_milky_way_saturation_slider.setValue(int(round(float(preset_values["saturation"]) * 100.0)))

        self._sky_view_milky_way_black_point_slider.setValue(int(round(float(preset_values["black_point"]) * 100.0)))

        self._sky_view_milky_way_gamma_slider.setValue(int(round(float(preset_values["gamma"]) * 100.0)))

        self._sky_view_canvas.set_milky_way_tone_preset(preset_name)

        self._sync_sky_view_milky_way_tone_preset_combo()

