    def _handle_toggle_sky_view_full_screen(self) -> None:

        host_window = self.window()

        if not isinstance(host_window, QMainWindow):

            return

        if host_window.isFullScreen():

            host_window.showNormal()

            return

        host_window.showFullScreen()

    def _ensure_sky_view_full_window_presentation(self) -> None:

        if self.isFullScreen() or self.isMaximized():

            return

        self.showMaximized()

    def _format_sky_view_object_details(self, sky_object: SkyAtlasObject) -> str:

        magnitude = "-" if sky_object.magnitude is None else f"{sky_object.magnitude:.2f}"

        if not sky_object.searchable:

            return f"Field star | Mag {magnitude} | RA {sky_object.ra_deg:.4f} deg, Dec {sky_object.dec_deg:.4f} deg"

        aliases = ", ".join(sky_object.aliases[:4]) if sky_object.aliases else "No aliases"

        constellation = sky_object.constellation or "Unknown constellation"

        description = sky_object.description or "No description available."

        return (
            f"{sky_object.name} | {sky_object.object_type} | Mag {magnitude} | "
            f"RA {sky_object.ra_deg:.4f} deg, Dec {sky_object.dec_deg:.4f} deg | "
            f"{constellation} | {aliases}. {description}"
        )

