    def _set_sky_explorer_object_type_mode(self, mode: str, *, preserve_selection: bool) -> None:

        normalized_mode = str(mode or "simple").strip().lower()

        if normalized_mode not in {"simple", "advanced", "scientific"}:

            normalized_mode = "simple"

        self._sky_explorer_object_type_mode = normalized_mode

        self._populate_sky_explorer_object_type_table(preserve_selection=preserve_selection)

        self._sync_sky_explorer_object_type_mode_button()

    def _cycle_sky_explorer_object_type_mode(self) -> None:

        current_mode = self._current_sky_explorer_object_type_mode()

        next_mode = {

            "simple": "advanced",

            "advanced": "scientific",

            "scientific": "simple",

        }.get(current_mode, "simple")

        self._set_sky_explorer_object_type_mode(next_mode, preserve_selection=True)

        self._refresh_sky_explorer_filtered_view(preserve_selection=True, select_first_row=False)

