    def _sky_explorer_object_type_colors_for_key(

        self,

        key: str,

        *,

        definition: SkyExplorerObjectTypeDefinition | None = None,

    ) -> tuple[str, str]:

        override = self._sky_explorer_object_type_color_overrides.get(key)

        if override is not None:

            return override

        resolved_definition = definition if definition is not None else _SKY_EXPLORER_OBJECT_TYPE_DEFINITION_BY_KEY.get(key)

        if resolved_definition is not None:

            group_color = self._sky_explorer_object_group_color_overrides.get(resolved_definition.group_key)

            if isinstance(group_color, str) and group_color:

                stroke_color, fill_color = sky_explorer_object_type_colors_for_group_hue(key, resolved_definition.group_key, group_color)

                return self._sky_explorer_apply_marker_color_relation(stroke_color, fill_color)

            return self._sky_explorer_apply_marker_color_relation(resolved_definition.stroke_color, resolved_definition.fill_color)

        return self._sky_explorer_apply_marker_color_relation("#111827", "#f8fafc")

    def _sky_explorer_apply_marker_color_relation(self, stroke_color: str, fill_color: str) -> tuple[str, str]:

        relation = str(getattr(self._ensure_settings(), "sky_explorer_marker_color_relation", "stroke_dark_fill_bright") or "stroke_dark_fill_bright").strip().lower()

        if relation == "stroke_bright_fill_dark":

            return fill_color, stroke_color

        return stroke_color, fill_color

    def _sky_explorer_object_type_text_color_for_key(

        self,

        key: str,

        *,

        stroke_color: str | None = None,

        fill_color: str | None = None,

    ) -> str:

        override = self._sky_explorer_object_type_text_color_overrides.get(key)

        if isinstance(override, str) and override:

            return override

        resolved_definition = _SKY_EXPLORER_OBJECT_TYPE_DEFINITION_BY_KEY.get(key)

        resolved_stroke = stroke_color if isinstance(stroke_color, str) and stroke_color else ""

        resolved_fill = fill_color if isinstance(fill_color, str) and fill_color else ""

        if not resolved_stroke:

            resolved_stroke, resolved_fill = self._sky_explorer_object_type_colors_for_key(key, definition=resolved_definition)

        elif not resolved_fill:

            _stroke, resolved_fill = self._sky_explorer_object_type_colors_for_key(key, definition=resolved_definition)

        candidates = [color for color in (resolved_stroke, resolved_fill) if isinstance(color, str) and color]

        if candidates:

            prefer_bright = str(getattr(self._ensure_settings(), "sky_explorer_text_color_relation", "dark") or "dark").strip().lower() == "bright"

            return max(candidates, key=self._relative_color_luminance) if prefer_bright else min(candidates, key=self._relative_color_luminance)

        if resolved_stroke:

            return resolved_stroke

        if resolved_definition is not None:

            return resolved_definition.stroke_color

        return "#111827"

    def _relative_color_luminance(self, color_value: str) -> float:

        color = QColor(color_value)

        if not color.isValid():

            return 0.0

        return 0.2126 * color.redF() + 0.7152 * color.greenF() + 0.0722 * color.blueF()

    def _sky_explorer_object_type_font_for_key(self, key: str) -> QFont | None:

        override = self._sky_explorer_object_type_font_overrides.get(key)

        if override is None:

            return None

        return QFont(override)

    def _sky_explorer_font_summary(self, font: QFont | None) -> str:

        resolved_font = QFont(font) if font is not None else QFont(self.font())

        point_size = resolved_font.pointSizeF()

        if point_size > 0.0:

            size_label = f"{point_size:g} pt"

        elif resolved_font.pixelSize() > 0:

            size_label = f"{resolved_font.pixelSize()} px"

        else:

            size_label = "Default size"

        style_parts: list[str] = []

        if resolved_font.bold():

            style_parts.append("Bold")

        if resolved_font.italic():

            style_parts.append("Italic")

        if resolved_font.underline():

            style_parts.append("Underline")

        if resolved_font.strikeOut():

            style_parts.append("Strikeout")

        family_label = resolved_font.family() or "Default"

        if style_parts:

            return f"{family_label}, {size_label}, {' '.join(style_parts)}"

        return f"{family_label}, {size_label}"

    def _sync_sky_explorer_text_style_button(self, button: QPushButton, color_value: str) -> None:

        button.setText(color_value.upper())

        button.setStyleSheet(

            "QPushButton {"

            f"background-color: {color_value};"

            f"color: {self._contrast_text_color(color_value)};"

            "border: 1px solid rgba(15, 23, 42, 0.45);"

            "border-radius: 4px;"

            "padding: 4px 10px;"

            "font-weight: 600;"

            "}"

        )

    def _edit_sky_explorer_text_style(self, *, current_font: QFont | None, current_color: str) -> tuple[QFont, str] | None:

        dialog = QDialog(self)

        dialog.setWindowTitle("Edit Sky Explorer Text Style")

        dialog.setModal(True)

        layout = QVBoxLayout(dialog)

        layout.setContentsMargins(12, 12, 12, 12)

        layout.setSpacing(10)

        form_layout = QFormLayout()

        form_layout.setContentsMargins(0, 0, 0, 0)

        form_layout.setSpacing(8)

        base_font = QFont(current_font) if current_font is not None else QFont(self.font())

        font_families = sorted({str(family) for family in QFontDatabase().families() if str(family).strip()}, key=str.casefold)

        current_family = base_font.family().strip() or self.font().family().strip()

        if current_family and current_family not in font_families:

            font_families.append(current_family)

            font_families.sort(key=str.casefold)

        font_family_combo = QComboBox(dialog)

        for family in font_families:

            font_family_combo.addItem(family, family)

            font_family_combo.setItemData(font_family_combo.count() - 1, QFont(family), Qt.ItemDataRole.FontRole)

        if current_family:

            family_index = font_family_combo.findData(current_family)

            if family_index >= 0:

                font_family_combo.setCurrentIndex(family_index)

        size_spin = QSpinBox(dialog)

        size_spin.setRange(6, 96)

        size_spin.setSuffix(" pt")

        base_size = base_font.pointSizeF() if base_font.pointSizeF() > 0.0 else float(max(6, self.font().pointSize()))

        size_spin.setValue(max(6, int(round(base_size))))

        bold_checkbox = QCheckBox("Bold", dialog)

        bold_checkbox.setChecked(base_font.bold())

        italic_checkbox = QCheckBox("Italic", dialog)

        italic_checkbox.setChecked(base_font.italic())

        underline_checkbox = QCheckBox("Underline", dialog)

        underline_checkbox.setChecked(base_font.underline())

        strikeout_checkbox = QCheckBox("Strikeout", dialog)

        strikeout_checkbox.setChecked(base_font.strikeOut())

        color_button = QPushButton(dialog)

        selected_color_value = current_color.lower()

        self._sync_sky_explorer_text_style_button(color_button, selected_color_value)

        preview_label = QLabel("Sky Explorer label preview", dialog)

        preview_label.setAlignment(Qt.AlignmentFlag.AlignCenter)

        preview_label.setMinimumHeight(56)

        preview_label.setFrameStyle(QLabel.Shape.Panel | QLabel.Shadow.Sunken)

        def build_preview_font() -> QFont:

            preview_font = QFont(str(font_family_combo.currentData() or font_family_combo.currentText() or base_font.family()))

            preview_font.setPointSize(size_spin.value())

            preview_font.setBold(bold_checkbox.isChecked())

            preview_font.setItalic(italic_checkbox.isChecked())

            preview_font.setUnderline(underline_checkbox.isChecked())

            preview_font.setStrikeOut(strikeout_checkbox.isChecked())

            return preview_font

        def sync_preview() -> None:

            preview_label.setFont(build_preview_font())

            preview_label.setStyleSheet(

                "QLabel {"

                f"background-color: {selected_color_value};"

                f"color: {self._contrast_text_color(selected_color_value)};"

                "border: 1px solid rgba(15, 23, 42, 0.4);"

                "border-radius: 4px;"

                "padding: 6px 8px;"

                "}"

            )

        def choose_color() -> None:

            nonlocal selected_color_value

            chosen_color = QColorDialog.getColor(QColor(selected_color_value), dialog, "Choose Sky Explorer Text Color")

            if not chosen_color.isValid():

                return

            selected_color_value = chosen_color.name().lower()

            self._sync_sky_explorer_text_style_button(color_button, selected_color_value)

            sync_preview()

        color_button.clicked.connect(choose_color)

        font_family_combo.currentIndexChanged.connect(lambda _index: sync_preview())

        size_spin.valueChanged.connect(lambda _value: sync_preview())

        bold_checkbox.toggled.connect(lambda _checked: sync_preview())

        italic_checkbox.toggled.connect(lambda _checked: sync_preview())

        underline_checkbox.toggled.connect(lambda _checked: sync_preview())

        strikeout_checkbox.toggled.connect(lambda _checked: sync_preview())

        style_row = QWidget(dialog)

        style_row_layout = QHBoxLayout(style_row)

        style_row_layout.setContentsMargins(0, 0, 0, 0)

        style_row_layout.setSpacing(8)

        style_row_layout.addWidget(bold_checkbox)

        style_row_layout.addWidget(italic_checkbox)

        style_row_layout.addWidget(underline_checkbox)

        style_row_layout.addWidget(strikeout_checkbox)

        style_row_layout.addStretch(1)

        form_layout.addRow("Font", font_family_combo)

        form_layout.addRow("Size", size_spin)

        form_layout.addRow("Style", style_row)

        form_layout.addRow("Color", color_button)

        layout.addLayout(form_layout)

        layout.addWidget(preview_label)

        buttons = QDialogButtonBox(QDialogButtonBox.StandardButton.Ok | QDialogButtonBox.StandardButton.Cancel, dialog)

        buttons.accepted.connect(dialog.accept)

        buttons.rejected.connect(dialog.reject)

        layout.addWidget(buttons)

        sync_preview()

        if dialog.exec() != int(QDialog.DialogCode.Accepted):

            return None

        return build_preview_font(), selected_color_value

    def _update_sky_explorer_color_table_item(

        self,

        item: QTableWidgetItem,

        color_value: str,

        *,

        key: str,

    ) -> None:

        item.setFlags(Qt.ItemFlag.ItemIsEnabled)

        item.setData(_SKY_EXPLORER_QUERY_OBJECT_TYPE_ROLE, key)

        item.setText(color_value.upper())

        item.setTextAlignment(Qt.AlignmentFlag.AlignCenter)

        item.setBackground(QBrush(QColor(color_value)))

        item.setForeground(QBrush(QColor(self._contrast_text_color(color_value))))

    def _update_sky_explorer_text_style_table_item(

        self,

        item: QTableWidgetItem,

        *,

        key: str,

        text_color: str,

        text_font: QFont | None,

    ) -> None:

        item.setFlags(Qt.ItemFlag.ItemIsEnabled)

        item.setData(_SKY_EXPLORER_QUERY_OBJECT_TYPE_ROLE, key)

        item.setText(self._sky_explorer_font_summary(text_font))

        item.setTextAlignment(Qt.AlignmentFlag.AlignCenter)

        item.setBackground(QBrush(QColor(text_color)))

        item.setForeground(QBrush(QColor(self._contrast_text_color(text_color))))

        item.setFont(QFont(self.font()))

    def _handle_sky_explorer_object_type_table_clicked(self, row_index: int, column_index: int) -> None:

        if column_index not in {

            _SKY_EXPLORER_STROKE_COLOR_COLUMN,

            _SKY_EXPLORER_FILL_COLOR_COLUMN,

            _SKY_EXPLORER_TEXT_COLUMN,

        }:

            return

        key_item = self._sky_explorer_object_type_table.item(row_index, _SKY_EXPLORER_OBJECT_TYPE_COLUMN)

        if key_item is None:

            return

        item_key = key_item.data(_SKY_EXPLORER_QUERY_OBJECT_TYPE_ROLE)

        if not isinstance(item_key, str) or not item_key:

            return

        definition = _SKY_EXPLORER_OBJECT_TYPE_DEFINITION_BY_KEY.get(item_key)

        stroke_color, fill_color = self._sky_explorer_object_type_colors_for_key(item_key, definition=definition)

        text_color = self._sky_explorer_object_type_text_color_for_key(item_key, stroke_color=stroke_color, fill_color=fill_color)

        text_font = self._sky_explorer_object_type_font_for_key(item_key)

        if column_index == _SKY_EXPLORER_TEXT_COLUMN:

            edited_style = self._edit_sky_explorer_text_style(current_font=text_font, current_color=text_color)

            if edited_style is None:

                return

            text_font, text_color = edited_style

            self._sky_explorer_object_type_font_overrides[item_key] = QFont(text_font)

            self._sky_explorer_object_type_text_color_overrides[item_key] = text_color

        else:

            current_color = {

                _SKY_EXPLORER_STROKE_COLOR_COLUMN: stroke_color,

                _SKY_EXPLORER_FILL_COLOR_COLUMN: fill_color,

            }[column_index]

            selected_color = QColorDialog.getColor(QColor(current_color), self, "Choose Sky Explorer Color")

            if not selected_color.isValid():

                return

            selected_color_name = selected_color.name().lower()

            if column_index == _SKY_EXPLORER_STROKE_COLOR_COLUMN:

                stroke_color = selected_color_name

                self._sky_explorer_object_type_color_overrides[item_key] = (stroke_color, fill_color)

            elif column_index == _SKY_EXPLORER_FILL_COLOR_COLUMN:

                fill_color = selected_color_name

                self._sky_explorer_object_type_color_overrides[item_key] = (stroke_color, fill_color)

        self._sky_explorer_object_type_table.blockSignals(True)

        try:

            stroke_item = self._sky_explorer_object_type_table.item(row_index, _SKY_EXPLORER_STROKE_COLOR_COLUMN)

            fill_item = self._sky_explorer_object_type_table.item(row_index, _SKY_EXPLORER_FILL_COLOR_COLUMN)

            text_item = self._sky_explorer_object_type_table.item(row_index, _SKY_EXPLORER_TEXT_COLUMN)

            if stroke_item is not None:

                self._update_sky_explorer_color_table_item(stroke_item, stroke_color, key=item_key)

            if fill_item is not None:

                self._update_sky_explorer_color_table_item(fill_item, fill_color, key=item_key)

            if text_item is not None:

                self._update_sky_explorer_text_style_table_item(

                    text_item,

                    key=item_key,

                    text_color=text_color,

                    text_font=text_font,

                )

        finally:

            self._sky_explorer_object_type_table.blockSignals(False)

        self._persist_sky_explorer_style_settings()

        self._sync_sky_explorer_select_all_button()

        self._refresh_sky_explorer_image_view(reset_view=False, focus_selected=False)

    def _load_sky_explorer_style_settings_from_settings(self) -> None:

        self._sky_explorer_object_type_color_overrides = {}

        self._sky_explorer_object_group_color_overrides = {}

        self._sky_explorer_object_type_text_color_overrides = {}

        self._sky_explorer_object_type_font_overrides = {}

        settings = getattr(self, "_settings", None)

        if settings is None:

            return

        for key, colors in (settings.sky_explorer_object_type_color_overrides or {}).items():

            if not isinstance(key, str) or not isinstance(colors, (tuple, list)) or len(colors) != 2:

                continue

            self._sky_explorer_object_type_color_overrides[key] = (str(colors[0]).strip().lower(), str(colors[1]).strip().lower())

        for key, color in (settings.sky_explorer_object_group_color_overrides or {}).items():

            if isinstance(key, str) and isinstance(color, str) and key.strip() and color.strip():

                self._sky_explorer_object_group_color_overrides[key.strip()] = color.strip().lower()

        for key, text_color in (settings.sky_explorer_object_type_text_color_overrides or {}).items():

            if isinstance(key, str) and isinstance(text_color, str) and key.strip() and text_color.strip():

                self._sky_explorer_object_type_text_color_overrides[key] = text_color.strip().lower()

        for key, font_string in (settings.sky_explorer_object_type_font_overrides or {}).items():

            if not isinstance(key, str) or not isinstance(font_string, str) or not key.strip() or not font_string.strip():

                continue

            font = QFont()

            if font.fromString(font_string):

                self._sky_explorer_object_type_font_overrides[key] = font

    def _persist_sky_explorer_style_settings(self) -> None:

        settings = self._ensure_settings()

        settings.sky_explorer_object_type_color_overrides = dict(self._sky_explorer_object_type_color_overrides)

        settings.sky_explorer_object_group_color_overrides = dict(self._sky_explorer_object_group_color_overrides)

        settings.sky_explorer_object_type_text_color_overrides = dict(self._sky_explorer_object_type_text_color_overrides)

        settings.sky_explorer_object_type_font_overrides = {

            key: font.toString()

            for key, font in self._sky_explorer_object_type_font_overrides.items()

            if isinstance(key, str) and key and isinstance(font, QFont)

        }

        self._save_settings_snapshot()

    def _sky_explorer_manual_search_radius_arcsec(self) -> float:

        settings = self._ensure_settings()

        return min(300.0, max(1.0, float(getattr(settings, "sky_explorer_simbad_search_radius_arcsec", 10.0))))

    def _sky_explorer_object_type_group_sort_value(self, definition: SkyExplorerObjectTypeDefinition) -> int:

        try:

            return _SKY_EXPLORER_OBJECT_TYPE_GROUP_ORDER.index(definition.group_key)

        except ValueError:

            return len(_SKY_EXPLORER_OBJECT_TYPE_GROUP_ORDER)

    def _sky_explorer_object_type_table_item(

        self,

        text: str,

        sort_value: float | int | str | None,

        *,

        group_order: int,

        row_rank: int,

    ) -> _SkyExplorerObjectTypeTableItem:

        return _SkyExplorerObjectTypeTableItem(text, sort_value, group_order=group_order, row_rank=row_rank)

    def _style_sky_explorer_group_table_item(self, item: QTableWidgetItem) -> None:

        palette = self._sky_explorer_object_type_table.palette()

        background_color = QColor(palette.color(QPalette.ColorRole.AlternateBase)).lighter(112)

        foreground_color = QColor(palette.color(QPalette.ColorRole.Text))

        group_font = QFont(self.font())

        group_font.setBold(True)

        item.setBackground(QBrush(background_color))

        item.setForeground(QBrush(foreground_color))

        item.setFont(group_font)

    def _add_sky_explorer_object_type_group_row(

        self,

        row_index: int,

        *,

        group_key: str,

        group_title: str,

        group_order: int,

        member_count: int,

    ) -> None:

        description = f"{member_count} object type" if member_count == 1 else f"{member_count} object types"

        values: dict[int, tuple[str, float | int | str | None]] = {

            _SKY_EXPLORER_STROKE_COLOR_COLUMN: ("", ""),

            _SKY_EXPLORER_FILL_COLOR_COLUMN: ("", ""),

            _SKY_EXPLORER_TEXT_COLUMN: ("", ""),

            _SKY_EXPLORER_GROUP_COLUMN: (group_title, group_title.casefold()),

            _SKY_EXPLORER_OBJECT_TYPE_COLUMN: (group_title, group_title.casefold()),

            _SKY_EXPLORER_DESCRIPTION_COLUMN: (description, member_count),

        }

        for column_index in range(self._sky_explorer_object_type_table.columnCount()):

            text, sort_value = values.get(column_index, ("", ""))

            item = self._sky_explorer_object_type_table_item(text, sort_value, group_order=group_order, row_rank=0)

            item.setFlags(Qt.ItemFlag.ItemIsEnabled)

            item.setData(_SKY_EXPLORER_QUERY_GROUP_ROLE, group_key)

            item.setTextAlignment(Qt.AlignmentFlag.AlignCenter if column_index != _SKY_EXPLORER_DESCRIPTION_COLUMN else Qt.AlignmentFlag.AlignLeft | Qt.AlignmentFlag.AlignVCenter)

            self._style_sky_explorer_group_table_item(item)

            if column_index == _SKY_EXPLORER_OBJECT_TYPE_COLUMN:

                item.setFlags(Qt.ItemFlag.ItemIsEnabled | Qt.ItemFlag.ItemIsUserCheckable)

                item.setCheckState(Qt.CheckState.Unchecked)

            self._sky_explorer_object_type_table.setItem(row_index, column_index, item)

        self._sky_explorer_object_type_table.setRowHeight(row_index, max(26, self._sky_explorer_object_type_table.verticalHeader().defaultSectionSize()))

    def _enabled_sky_explorer_query_layers(self) -> tuple[str, ...]:

        settings = self._ensure_settings()

        enabled_layers = {str(layer).strip().lower() for layer in getattr(settings, "sky_explorer_enabled_layers", ())}

        return tuple(layer_key for layer_key in SKY_EXPLORER_LAYER_ORDER if layer_key in enabled_layers)

    def _selected_sky_explorer_query_layers(self, selected_object_type_keys: Sequence[str]) -> tuple[str, ...]:

        requested_layers = set(sky_explorer_query_layers_for_object_types(selected_object_type_keys))

        enabled_layers = set(self._enabled_sky_explorer_query_layers())

        return tuple(

            layer_key

            for layer_key in SKY_EXPLORER_LAYER_ORDER

            if layer_key in requested_layers and layer_key in enabled_layers

        )

    def _populate_sky_explorer_object_type_table(self, *, preserve_selection: bool = False) -> None:

        selected_keys = set(self._selected_sky_explorer_object_type_keys()) if preserve_selection else set()

        definitions = sky_explorer_object_type_definitions_for_mode(self._current_sky_explorer_object_type_mode())

        definitions_by_group: dict[str, list[SkyExplorerObjectTypeDefinition]] = {}

        for definition in definitions:

            definitions_by_group.setdefault(definition.group_key, []).append(definition)

        ordered_groups = sorted(

            definitions_by_group.values(),

            key=lambda group_definitions: self._sky_explorer_object_type_group_sort_value(group_definitions[0]) if group_definitions else len(_SKY_EXPLORER_OBJECT_TYPE_GROUP_ORDER),

        )

        sorting_enabled = self._sky_explorer_object_type_table.isSortingEnabled()

        sort_section = self._sky_explorer_object_type_table.horizontalHeader().sortIndicatorSection()

        sort_order = self._sky_explorer_object_type_table.horizontalHeader().sortIndicatorOrder()

        self._sky_explorer_object_type_table.blockSignals(True)

        self._sky_explorer_object_type_table.setSortingEnabled(False)

        self._sky_explorer_object_type_table.clearContents()

        self._sky_explorer_object_type_table.setRowCount(len(definitions) + len(ordered_groups))

        row_index = 0

        for group_definitions in ordered_groups:

            if not group_definitions:

                continue

            group_definition = group_definitions[0]

            group_order = self._sky_explorer_object_type_group_sort_value(group_definition)

            self._add_sky_explorer_object_type_group_row(

                row_index,

                group_key=group_definition.group_key,

                group_title=group_definition.group_title,

                group_order=group_order,

                member_count=len(group_definitions),

            )

            row_index += 1

            for definition in group_definitions:

                stroke_color, fill_color = self._sky_explorer_object_type_colors_for_key(definition.key, definition=definition)

                text_color = self._sky_explorer_object_type_text_color_for_key(definition.key, stroke_color=stroke_color, fill_color=fill_color)

                text_font = self._sky_explorer_object_type_font_for_key(definition.key)

                stroke_color_item = self._sky_explorer_object_type_table_item("", None, group_order=group_order, row_rank=1)

                self._update_sky_explorer_color_table_item(stroke_color_item, stroke_color, key=definition.key)

                stroke_color_item.setData(_SKY_EXPLORER_QUERY_GROUP_ROLE, definition.group_key)

                self._sky_explorer_object_type_table.setItem(row_index, _SKY_EXPLORER_STROKE_COLOR_COLUMN, stroke_color_item)

                fill_color_item = self._sky_explorer_object_type_table_item("", None, group_order=group_order, row_rank=1)

                self._update_sky_explorer_color_table_item(fill_color_item, fill_color, key=definition.key)

                fill_color_item.setData(_SKY_EXPLORER_QUERY_GROUP_ROLE, definition.group_key)

                self._sky_explorer_object_type_table.setItem(row_index, _SKY_EXPLORER_FILL_COLOR_COLUMN, fill_color_item)

                text_item = self._sky_explorer_object_type_table_item("", None, group_order=group_order, row_rank=1)

                self._update_sky_explorer_text_style_table_item(

                    text_item,

                    key=definition.key,

                    text_color=text_color,

                    text_font=text_font,

                )

                text_item.setData(_SKY_EXPLORER_QUERY_GROUP_ROLE, definition.group_key)

                self._sky_explorer_object_type_table.setItem(row_index, _SKY_EXPLORER_TEXT_COLUMN, text_item)

                group_item = self._sky_explorer_object_type_table_item(

                    definition.group_title,

                    definition.title.casefold(),

                    group_order=group_order,

                    row_rank=1,

                )

                group_item.setFlags(Qt.ItemFlag.ItemIsEnabled)

                group_item.setData(_SKY_EXPLORER_QUERY_OBJECT_TYPE_ROLE, definition.key)

                group_item.setData(_SKY_EXPLORER_QUERY_GROUP_ROLE, definition.group_key)

                self._sky_explorer_object_type_table.setItem(row_index, _SKY_EXPLORER_GROUP_COLUMN, group_item)

                type_item = self._sky_explorer_object_type_table_item(definition.title, definition.title.casefold(), group_order=group_order, row_rank=1)

                type_item.setFlags(Qt.ItemFlag.ItemIsEnabled | Qt.ItemFlag.ItemIsUserCheckable)

                type_item.setData(_SKY_EXPLORER_QUERY_OBJECT_TYPE_ROLE, definition.key)

                type_item.setData(_SKY_EXPLORER_QUERY_GROUP_ROLE, definition.group_key)

                is_checked = definition.key in selected_keys if definition.key in selected_keys else definition.default_checked

                type_item.setCheckState(Qt.CheckState.Checked if is_checked else Qt.CheckState.Unchecked)

                self._sky_explorer_object_type_table.setItem(row_index, _SKY_EXPLORER_OBJECT_TYPE_COLUMN, type_item)

                description_item = self._sky_explorer_object_type_table_item(definition.description, definition.description.casefold(), group_order=group_order, row_rank=1)

                description_item.setFlags(Qt.ItemFlag.ItemIsEnabled)

                description_item.setData(_SKY_EXPLORER_QUERY_OBJECT_TYPE_ROLE, definition.key)

                description_item.setData(_SKY_EXPLORER_QUERY_GROUP_ROLE, definition.group_key)

                self._sky_explorer_object_type_table.setItem(row_index, _SKY_EXPLORER_DESCRIPTION_COLUMN, description_item)

                row_index += 1

        self._sync_sky_explorer_group_check_states()

        self._sky_explorer_object_type_table.setSortingEnabled(sorting_enabled)

        if sorting_enabled and sort_section >= 0:

            self._sky_explorer_object_type_table.sortItems(sort_section, sort_order)

        self._sky_explorer_object_type_table.blockSignals(False)

        self._sync_sky_explorer_select_all_button()

    def _sync_sky_explorer_select_all_button(self) -> None:

        self._sync_sky_explorer_group_check_states()

        object_type_count = 0

        checked_count = 0

        for row_index in range(self._sky_explorer_object_type_table.rowCount()):

            item = self._sky_explorer_object_type_table.item(row_index, _SKY_EXPLORER_OBJECT_TYPE_COLUMN)

            if item is None or not isinstance(item.data(_SKY_EXPLORER_QUERY_OBJECT_TYPE_ROLE), str):

                continue

            object_type_count += 1

            if item.checkState() == Qt.CheckState.Checked:

                checked_count += 1

        self._sky_explorer_select_all_button.setEnabled(object_type_count > 0)

        self._sky_explorer_select_all_button.setText("Unselect All" if object_type_count > 0 and checked_count == object_type_count else "Select All")

    def _sync_sky_explorer_group_check_states(self) -> None:

        group_items: dict[str, QTableWidgetItem] = {}

        member_totals: dict[str, int] = {}

        member_checked: dict[str, int] = {}

        for row_index in range(self._sky_explorer_object_type_table.rowCount()):

            item = self._sky_explorer_object_type_table.item(row_index, _SKY_EXPLORER_OBJECT_TYPE_COLUMN)

            if item is None:

                continue

            group_key = item.data(_SKY_EXPLORER_QUERY_GROUP_ROLE)

            if not isinstance(group_key, str) or not group_key:

                continue

            object_type_key = item.data(_SKY_EXPLORER_QUERY_OBJECT_TYPE_ROLE)

            if isinstance(object_type_key, str) and object_type_key:

                member_totals[group_key] = member_totals.get(group_key, 0) + 1

                if item.checkState() == Qt.CheckState.Checked:

                    member_checked[group_key] = member_checked.get(group_key, 0) + 1

            else:

                group_items[group_key] = item

        previous_block_state = self._sky_explorer_object_type_table.blockSignals(True)

        try:

            for group_key, group_item in group_items.items():

                total_count = member_totals.get(group_key, 0)

                checked_count = member_checked.get(group_key, 0)

                if total_count > 0 and checked_count == total_count:

                    group_item.setCheckState(Qt.CheckState.Checked)

                elif checked_count > 0:

                    group_item.setCheckState(Qt.CheckState.PartiallyChecked)

                else:

                    group_item.setCheckState(Qt.CheckState.Unchecked)

        finally:

            self._sky_explorer_object_type_table.blockSignals(previous_block_state)

    def _set_sky_explorer_group_checked(self, group_key: str, check_state: Qt.CheckState) -> None:

        target_state = Qt.CheckState.Checked if check_state != Qt.CheckState.Unchecked else Qt.CheckState.Unchecked

        previous_block_state = self._sky_explorer_object_type_table.blockSignals(True)

        try:

            for row_index in range(self._sky_explorer_object_type_table.rowCount()):

                item = self._sky_explorer_object_type_table.item(row_index, _SKY_EXPLORER_OBJECT_TYPE_COLUMN)

                if item is None:

                    continue

                if item.data(_SKY_EXPLORER_QUERY_GROUP_ROLE) != group_key:

                    continue

                object_type_key = item.data(_SKY_EXPLORER_QUERY_OBJECT_TYPE_ROLE)

                if isinstance(object_type_key, str) and object_type_key:

                    item.setCheckState(target_state)

        finally:

            self._sky_explorer_object_type_table.blockSignals(previous_block_state)

        self._sync_sky_explorer_group_check_states()

        self._sync_sky_explorer_select_all_button()

        self._refresh_sky_explorer_filtered_view(preserve_selection=True, select_first_row=False)

    def _toggle_sky_explorer_select_all(self) -> None:

        row_count = self._sky_explorer_object_type_table.rowCount()

        if row_count <= 0:

            return

        should_select_all = self._sky_explorer_select_all_button.text() == "Select All"

        self._sky_explorer_object_type_table.blockSignals(True)

        try:

            for row_index in range(row_count):

                item = self._sky_explorer_object_type_table.item(row_index, _SKY_EXPLORER_OBJECT_TYPE_COLUMN)

                if item is None or not isinstance(item.data(_SKY_EXPLORER_QUERY_OBJECT_TYPE_ROLE), str):

                    continue

                item.setCheckState(Qt.CheckState.Checked if should_select_all else Qt.CheckState.Unchecked)

        finally:

            self._sky_explorer_object_type_table.blockSignals(False)

        self._sync_sky_explorer_select_all_button()

        self._refresh_sky_explorer_filtered_view(preserve_selection=True, select_first_row=False)

    def _selected_sky_explorer_object_type_keys(self) -> tuple[str, ...]:

        selected_keys: list[str] = []

        for row_index in range(self._sky_explorer_object_type_table.rowCount()):

            item = self._sky_explorer_object_type_table.item(row_index, _SKY_EXPLORER_OBJECT_TYPE_COLUMN)

            if item is not None and item.checkState() == Qt.CheckState.Checked:

                item_key = item.data(_SKY_EXPLORER_QUERY_OBJECT_TYPE_ROLE)

                if isinstance(item_key, str) and item_key:

                    selected_keys.append(item_key)

        return tuple(selected_keys)

    def _should_enable_dense_sky_explorer_galaxy_catalog(self, selected_object_type_keys: Sequence[str]) -> bool:

        if self._current_sky_explorer_object_type_mode() != "scientific":

            return False

        selected_keys = {str(key or "").strip() for key in selected_object_type_keys if str(key or "").strip()}

        scientific_keys = {

            definition.key

            for definition in sky_explorer_object_type_definitions_for_mode("scientific")

        }

        return bool(scientific_keys) and selected_keys == scientific_keys

    def _filtered_sky_explorer_objects(self) -> tuple[SkyExplorerObject, ...]:

        result = self._current_sky_explorer_result

        selected_keys = set(self._selected_sky_explorer_object_type_keys())

        visible_objects: list[SkyExplorerObject] = []

        if result is not None and selected_keys:

            visible_objects.extend(

                sky_object

                for sky_object in self._sky_explorer_result_objects_after_view_filters(result)

                if selected_keys.intersection(sky_explorer_object_type_keys_for_object(sky_object))

            )

        visible_objects.extend(self._sky_explorer_mag_limit_table_objects())

        visible_identities = {self._sky_explorer_object_identity(sky_object) for sky_object in visible_objects}

        for sky_object in self._sky_explorer_detected_table_objects():

            identity = self._sky_explorer_object_identity(sky_object)

            if identity in visible_identities:

                continue

            visible_objects.append(sky_object)

            visible_identities.add(identity)

        return tuple(visible_objects)

    def _sky_explorer_result_objects_after_view_filters(self, result: SkyExplorerResult) -> tuple[SkyExplorerObject, ...]:

        if not self._sky_explorer_hide_unknown_magnitude_enabled():

            return result.objects

        return tuple(

            sky_object

            for sky_object in result.objects

            if _sky_explorer_numeric_magnitude(sky_object) is not None

        )

    def _sky_explorer_hide_unknown_magnitude_enabled(self) -> bool:

        return bool(self._ensure_settings().sky_explorer_hide_objects_without_magnitude)

    def _sync_sky_explorer_filter_actions(self) -> None:

        previous_block_state = self._sky_explorer_hide_unknown_magnitude_action.blockSignals(True)

        try:

            self._sky_explorer_hide_unknown_magnitude_action.setChecked(self._sky_explorer_hide_unknown_magnitude_enabled())

        finally:

            self._sky_explorer_hide_unknown_magnitude_action.blockSignals(previous_block_state)

    def _handle_sky_explorer_hide_unknown_magnitude_toggled(self, checked: bool) -> None:

        settings = self._ensure_settings()

        enabled = bool(checked)

        if settings.sky_explorer_hide_objects_without_magnitude != enabled:

            settings.sky_explorer_hide_objects_without_magnitude = enabled

            self._save_settings_snapshot()

        self._refresh_sky_explorer_status_summary()

        self._refresh_sky_explorer_filtered_view(preserve_selection=True, select_first_row=False)

    def _sky_explorer_status_summary_text(self, result: SkyExplorerResult | None) -> str:

        if result is None:

            return ""

        summary_text = result.summary_text

        if self._sky_explorer_hide_unknown_magnitude_enabled():

            return f"{summary_text} Objects without magnitude are hidden."

        return summary_text

    def _refresh_sky_explorer_status_summary(self) -> None:

        summary_text = self._sky_explorer_status_summary_text(self._current_sky_explorer_result)

        if not summary_text:

            return

        self._sky_explorer_status_label.setText(summary_text)

        self.statusBar().showMessage(summary_text, 5000)

    def _refresh_sky_explorer_filtered_view(self, *, preserve_selection: bool, select_first_row: bool) -> None:

        previous_selections = self._selected_sky_explorer_objects() if preserve_selection else ()

        previous_primary = self._selected_sky_explorer_object() if preserve_selection else None

        visible_objects = self._filtered_sky_explorer_objects()

        self._current_sky_explorer_visible_objects = tuple(visible_objects)

        self._populate_sky_explorer_results_table(visible_objects)

        restored_objects: list[SkyExplorerObject] = []

        if previous_selections:

            for previous in previous_selections:

                for sky_object in visible_objects:

                    if self._sky_explorer_objects_match(sky_object, previous):

                        restored_objects.append(sky_object)

                        break

        selected_object: SkyExplorerObject | None = None

        if previous_primary is not None:

            for sky_object in restored_objects or visible_objects:

                if self._sky_explorer_objects_match(sky_object, previous_primary):

                    selected_object = sky_object

                    break

        if selected_object is None and restored_objects:

            selected_object = restored_objects[0]

        if selected_object is None and select_first_row and visible_objects:

            selected_object = visible_objects[0]

            restored_objects = [selected_object]

        if selected_object is None:

            self._sky_explorer_results_table.clearSelection()

            result = self._current_sky_explorer_result

            self._sky_explorer_details_output.setPlainText(

                self._format_sky_explorer_result_summary(result) if isinstance(result, SkyExplorerResult) else ""

            )

            self._refresh_sky_explorer_image_view(reset_view=False, focus_selected=False)

            self._sync_sky_explorer_image_controls()

            return

        if restored_objects:

            self._select_sky_explorer_result_objects(restored_objects, current_object=selected_object)

        else:

            self._select_sky_explorer_result_object(selected_object)

    def _sky_explorer_objects_match(self, first: SkyExplorerObject, second: SkyExplorerObject) -> bool:

        return (

            first.layer_key == second.layer_key

            and first.catalog == second.catalog

            and first.source_id == second.source_id

            and self._sky_explorer_is_mag_limit_measurement_object(first) == self._sky_explorer_is_mag_limit_measurement_object(second)

        )

    def _sky_explorer_result_group_info(self, sky_object: SkyExplorerObject) -> tuple[str, str, int]:

        if self._sky_explorer_is_mag_limit_measurement_object(sky_object):

            return self._sky_explorer_mag_limit_measurement_group_info()

        visible_object_types = set(self._selected_sky_explorer_object_type_keys())

        definition = self._sky_explorer_definition_for_object(sky_object, preferred_keys=visible_object_types)

        if definition is None:

            return "other", "Other / Unclassified", len(_SKY_EXPLORER_OBJECT_TYPE_GROUP_ORDER)

        return definition.group_key, definition.group_title, self._sky_explorer_object_type_group_sort_value(definition)

    def _sky_explorer_results_table_item(

        self,

        text: str,

        sort_value: float | int | str | None,

        *,

        group_order: int,

        row_rank: int,

    ) -> _SkyExplorerResultsTableItem:

        return _SkyExplorerResultsTableItem(text, sort_value, group_order=group_order, row_rank=row_rank)

    def _handle_sky_explorer_results_sort_requested(self, column_index: int) -> None:

        previous_selections = self._selected_sky_explorer_objects()

        previous_primary = self._selected_sky_explorer_object()

        if column_index == self._sky_explorer_results_sort_column:

            self._sky_explorer_results_sort_order = (

                Qt.SortOrder.DescendingOrder

                if self._sky_explorer_results_sort_order == Qt.SortOrder.AscendingOrder

                else Qt.SortOrder.AscendingOrder

            )

        else:

            self._sky_explorer_results_sort_column = column_index

            self._sky_explorer_results_sort_order = Qt.SortOrder.AscendingOrder

        self._sky_explorer_results_table.horizontalHeader().setSortIndicator(

            self._sky_explorer_results_sort_column,

            self._sky_explorer_results_sort_order,

        )

        self._populate_sky_explorer_results_table(self._current_sky_explorer_visible_objects)

        if previous_selections:

            self._select_sky_explorer_result_objects(previous_selections, current_object=previous_primary)

        elif previous_primary is not None:

            self._select_sky_explorer_result_object(previous_primary)

    def _sky_explorer_result_sort_key(self, sky_object: SkyExplorerObject, column_index: int) -> tuple[int, float | str]:

        if column_index == 1:

            return (0, self._sky_explorer_display_type_text_for_object(sky_object).casefold())

        if column_index == 2:

            return (1, 0.0) if sky_object.magnitude is None else (0, float(sky_object.magnitude))

        if column_index == 3:

            return (0, float(sky_object.ra_deg))

        if column_index == 4:

            return (0, float(sky_object.dec_deg))

        if column_index == 5:

            angular_size_arcmin = self._sky_explorer_angular_size_arcmin(sky_object)

            return (1, 0.0) if angular_size_arcmin is None else (0, float(angular_size_arcmin))

        return (0, str(sky_object.name or sky_object.source_id or "").casefold())

    def _sky_explorer_angular_size_arcmin(self, sky_object: SkyExplorerObject) -> float | None:

        metadata = sky_object.metadata if isinstance(sky_object.metadata, dict) else {}

        major_axis = self._sky_explorer_metadata_float(metadata, "catalog_major_axis_arcmin", "catalog_size_arcmin")

        if major_axis is None or major_axis <= 0.0:

            return None

        return float(major_axis)

    def _sky_explorer_display_type_text_for_object(self, sky_object: SkyExplorerObject) -> str:

        visible_object_types = set(self._selected_sky_explorer_object_type_keys())

        definition = self._sky_explorer_definition_for_object(sky_object, preferred_keys=visible_object_types)

        if definition is not None:

            return definition.title

        return str(sky_object.object_type or "-")

    def _format_sky_explorer_angular_size(self, sky_object: SkyExplorerObject) -> str:

        metadata = sky_object.metadata if isinstance(sky_object.metadata, dict) else {}

        major_axis = self._sky_explorer_metadata_float(metadata, "catalog_major_axis_arcmin", "catalog_size_arcmin")

        minor_axis = self._sky_explorer_metadata_float(metadata, "catalog_minor_axis_arcmin")

        if major_axis is None or major_axis <= 0.0:

            return "-"

        if minor_axis is not None and minor_axis > 0.0 and abs(float(minor_axis) - float(major_axis)) >= 0.01:

            return f"{float(major_axis):.2f} x {float(minor_axis):.2f}'"

        return f"{float(major_axis):.2f}'"

    def _style_sky_explorer_result_group_table_item(self, item: QTableWidgetItem) -> None:

        palette = self._sky_explorer_results_table.palette()

        background_color = QColor(palette.color(QPalette.ColorRole.AlternateBase)).lighter(112)

        foreground_color = QColor(palette.color(QPalette.ColorRole.Text))

        group_font = QFont(self.font())

        group_font.setBold(True)

        item.setBackground(QBrush(background_color))

        item.setForeground(QBrush(foreground_color))

        item.setFont(group_font)

    def _sky_explorer_result_group_label_text(self, group_title: str, member_count: int, *, collapsed: bool) -> str:

        count_text = f"{member_count} object" if member_count == 1 else f"{member_count} objects"

        label_text = f"{group_title} ({count_text})"

        if collapsed:

            return f"{label_text} [collapsed]"

        return label_text

    def _add_sky_explorer_result_group_row(

        self,

        row_index: int,

        *,

        group_key: str,

        group_title: str,

        group_order: int,

        member_count: int,

        collapsed: bool,

    ) -> None:

        label_text = self._sky_explorer_result_group_label_text(group_title, member_count, collapsed=collapsed)

        item = self._sky_explorer_results_table_item(label_text, group_title.casefold(), group_order=group_order, row_rank=0)

        item.setFlags(Qt.ItemFlag.ItemIsEnabled)

        item.setData(_SKY_EXPLORER_RESULT_GROUP_ROLE, group_key)

        item.setToolTip("Click to expand this group." if collapsed else "Click to collapse this group.")

        item.setTextAlignment(Qt.AlignmentFlag.AlignCenter)

        self._style_sky_explorer_result_group_table_item(item)

        self._sky_explorer_results_table.setItem(row_index, 0, item)

        self._sky_explorer_results_table.setSpan(row_index, 0, 1, self._sky_explorer_results_table.columnCount())

        self._sky_explorer_results_table.setVerticalHeaderItem(row_index, QTableWidgetItem(""))

    def _handle_sky_explorer_results_table_clicked(self, row_index: int, _column_index: int) -> None:

        item = self._sky_explorer_results_table.item(row_index, 0)

        if item is None:

            return

        sky_object = item.data(_SKY_EXPLORER_OBJECT_ROLE)

        if isinstance(sky_object, SkyExplorerObject):

            return

        group_key = item.data(_SKY_EXPLORER_RESULT_GROUP_ROLE)

        if not isinstance(group_key, str) or not group_key:

            return

        if group_key in self._sky_explorer_collapsed_result_groups:

            self._sky_explorer_collapsed_result_groups.discard(group_key)

        else:

            self._sky_explorer_collapsed_result_groups.add(group_key)

        self._populate_sky_explorer_results_table(self._current_sky_explorer_visible_objects)

        self._sky_explorer_results_table.clearSelection()

        result = self._current_sky_explorer_result

        self._sky_explorer_details_output.setPlainText(

            self._format_sky_explorer_result_summary(result) if isinstance(result, SkyExplorerResult) else ""

        )

        self._refresh_sky_explorer_image_view(reset_view=False, focus_selected=False)

        self._sync_sky_explorer_image_controls()

    def _populate_sky_explorer_results_table(self, objects: Sequence[SkyExplorerObject]) -> None:

        self._sky_explorer_results_table.blockSignals(True)

        grouped_objects: dict[str, tuple[str, int, list[SkyExplorerObject]]] = {}

        for sky_object in objects:

            group_key, group_title, group_order = self._sky_explorer_result_group_info(sky_object)

            if group_key not in grouped_objects:

                grouped_objects[group_key] = (group_title, group_order, [])

            grouped_objects[group_key][2].append(sky_object)

        ordered_groups = sorted(grouped_objects.items(), key=lambda item: (item[1][1], item[1][0].casefold()))

        visible_group_keys = {group_key for group_key, _group_data in ordered_groups}

        self._sky_explorer_collapsed_result_groups.intersection_update(visible_group_keys)

        visible_object_count = sum(

            0 if group_key in self._sky_explorer_collapsed_result_groups else len(group_objects)

            for group_key, (_group_title, _group_order, group_objects) in ordered_groups

        )

        self._sky_explorer_results_table.clearContents()

        self._sky_explorer_results_table.clearSpans()

        self._sky_explorer_results_table.setRowCount(len(ordered_groups) + visible_object_count)

        row_index = 0

        object_row_number = 1

        for group_key, (group_title, group_order, group_objects) in ordered_groups:

            collapsed = group_key in self._sky_explorer_collapsed_result_groups

            self._add_sky_explorer_result_group_row(

                row_index,

                group_key=group_key,

                group_title=group_title,

                group_order=group_order,

                member_count=len(group_objects),

                collapsed=collapsed,

            )

            row_index += 1

            if collapsed:

                continue

            sorted_group_objects = sorted(

                group_objects,

                key=lambda sky_object: self._sky_explorer_result_sort_key(sky_object, self._sky_explorer_results_sort_column),

                reverse=self._sky_explorer_results_sort_order == Qt.SortOrder.DescendingOrder,

            )

            for sky_object in sorted_group_objects:

                display_type_text = self._sky_explorer_display_type_text_for_object(sky_object)

                values: list[tuple[str, float | str | None]] = [

                    (sky_object.name, sky_object.name.lower()),

                    (display_type_text, display_type_text.casefold()),

                    ("-" if sky_object.magnitude is None else f"{sky_object.magnitude:.2f}", sky_object.magnitude),

                    (f"{sky_object.ra_deg:.6f}", sky_object.ra_deg),

                    (f"{sky_object.dec_deg:.6f}", sky_object.dec_deg),

                    (self._format_sky_explorer_angular_size(sky_object), self._sky_explorer_angular_size_arcmin(sky_object)),

                ]

                for column_index, (text, sort_value) in enumerate(values):

                    item = self._sky_explorer_results_table_item(text, sort_value, group_order=group_order, row_rank=1)

                    if column_index == 0:

                        item.setData(_SKY_EXPLORER_OBJECT_ROLE, sky_object)

                    if column_index == 1 and sky_object.object_type and sky_object.object_type != display_type_text:

                        item.setToolTip(f"SIMBAD type: {sky_object.object_type}")

                    item.setData(_SKY_EXPLORER_RESULT_GROUP_ROLE, group_key)

                    self._sky_explorer_results_table.setItem(row_index, column_index, item)


                self._sky_explorer_results_table.setVerticalHeaderItem(row_index, QTableWidgetItem(str(object_row_number)))

                object_row_number += 1

                row_index += 1


        self._sky_explorer_results_table.blockSignals(False)


        self._sky_explorer_results_table.resizeRowsToContents()

    def _selected_sky_explorer_object(self) -> SkyExplorerObject | None:

        current_item = self._sky_explorer_results_table.currentItem()

        if current_item is not None:

            item = self._sky_explorer_results_table.item(current_item.row(), 0)

            if item is not None:

                sky_object = item.data(_SKY_EXPLORER_OBJECT_ROLE)

                if isinstance(sky_object, SkyExplorerObject):

                    return sky_object

        selected_objects = self._selected_sky_explorer_objects()

        return selected_objects[0] if selected_objects else None

    def _selected_sky_explorer_objects(self) -> tuple[SkyExplorerObject, ...]:

        selected_rows = sorted({item.row() for item in self._sky_explorer_results_table.selectedItems()})

        selected_objects: list[SkyExplorerObject] = []

        for row_index in selected_rows:

            item = self._sky_explorer_results_table.item(row_index, 0)

            if item is None:

                continue

            sky_object = item.data(_SKY_EXPLORER_OBJECT_ROLE)

            if isinstance(sky_object, SkyExplorerObject):

                selected_objects.append(sky_object)

        return tuple(selected_objects)

    def _select_sky_explorer_result_object(self, sky_object: SkyExplorerObject) -> bool:

        return self._select_sky_explorer_result_objects((sky_object,), current_object=sky_object)

    def _select_sky_explorer_result_objects(

        self,

        sky_objects: Sequence[SkyExplorerObject],

        *,

        current_object: SkyExplorerObject | None = None,

    ) -> bool:

        if not sky_objects:

            return False

        groups_to_expand = {

            self._sky_explorer_result_group_info(sky_object)[0]

            for sky_object in sky_objects

        }

        expanded_any = False

        for group_key in groups_to_expand:

            if group_key in self._sky_explorer_collapsed_result_groups:

                self._sky_explorer_collapsed_result_groups.discard(group_key)

                expanded_any = True

        if expanded_any:

            self._populate_sky_explorer_results_table(self._current_sky_explorer_visible_objects)

        target_identities = {self._sky_explorer_object_identity(sky_object) for sky_object in sky_objects}

        current_identity = (

            self._sky_explorer_object_identity(current_object) if current_object is not None else None

        )

        self._sky_explorer_results_table.blockSignals(True)

        try:

            self._sky_explorer_results_table.clearSelection()

            first_item: QTableWidgetItem | None = None

            current_item: QTableWidgetItem | None = None

            column_count = max(1, self._sky_explorer_results_table.columnCount())

            for row_index in range(self._sky_explorer_results_table.rowCount()):

                item = self._sky_explorer_results_table.item(row_index, 0)

                if item is None:

                    continue

                row_object = item.data(_SKY_EXPLORER_OBJECT_ROLE)

                if not isinstance(row_object, SkyExplorerObject):

                    continue

                identity = self._sky_explorer_object_identity(row_object)

                if identity not in target_identities:

                    continue

                self._sky_explorer_results_table.setRangeSelected(

                    QTableWidgetSelectionRange(row_index, 0, row_index, column_count - 1),

                    True,

                )

                if first_item is None:

                    first_item = item

                if current_identity is not None and identity == current_identity:

                    current_item = item

            focus_item = current_item or first_item

            if focus_item is not None:

                self._sky_explorer_results_table.setCurrentItem(focus_item)

                self._sky_explorer_results_table.scrollToItem(focus_item)

        finally:

            self._sky_explorer_results_table.blockSignals(False)

        self._handle_sky_explorer_result_selection_changed()

        return first_item is not None

    def _handle_sky_explorer_image_overlay_clicked(self, overlay: object) -> None:

        if not isinstance(overlay, ImageOverlay):

            return

        manual_annotation_id = self._sky_explorer_manual_annotation_id_from_source_id(overlay.source_id)

        if manual_annotation_id is not None:

            self._selected_sky_explorer_manual_annotation_id = manual_annotation_id

            self._refresh_sky_explorer_image_view(reset_view=False, focus_selected=False)

            self.statusBar().showMessage("Selected manual Sky Explorer annotation.", 3000)

            return

        if str(overlay.source_id).startswith("mag-limit:"):

            for sky_object in self._sky_explorer_mag_limit_table_objects():

                if overlay.source_id == f"mag-limit:{self._sky_explorer_overlay_source_id(sky_object)}":

                    self._select_sky_explorer_result_object(sky_object)

                    return

        result = self._current_sky_explorer_result

        if result is None:

            return

        for sky_object in result.objects:

            if overlay.source_id == self._sky_explorer_overlay_source_id(sky_object):

                self._select_sky_explorer_result_object(sky_object)

                return

    def _handle_sky_explorer_result_item_double_clicked(self, item: QTableWidgetItem) -> None:

        row_item = self._sky_explorer_results_table.item(item.row(), 0)

        if row_item is None:

            return

        sky_object = row_item.data(_SKY_EXPLORER_OBJECT_ROLE)

        if isinstance(sky_object, SkyExplorerObject):

            self._open_sky_explorer_object_details(sky_object)

    def _handle_sky_explorer_result_selection_changed(self) -> None:

        sky_object = self._selected_sky_explorer_object()

        if sky_object is None:

            result = self._current_sky_explorer_result

            self._sky_explorer_details_output.setPlainText(

                self._format_sky_explorer_result_summary(result) if isinstance(result, SkyExplorerResult) else ""

            )

            self._refresh_sky_explorer_image_view(reset_view=False, focus_selected=False)

            self._sync_sky_explorer_image_controls()

            return

        self._sky_explorer_details_output.setPlainText(self._format_sky_explorer_object_details(sky_object))

        self._refresh_sky_explorer_image_view(

            reset_view=False,

            focus_selected=self._sky_explorer_center_object_button.isChecked(),

        )

        self._sync_sky_explorer_image_controls()

    def _format_sky_explorer_result_summary(self, result: SkyExplorerResult | None) -> str:

        if result is None:

            return ""

        footprint = result.footprint

        lines = [

            self._sky_explorer_status_summary_text(result),

            "",

            f"Center: RA {footprint.center_ra_deg:.6f} deg, Dec {footprint.center_dec_deg:.6f} deg",

            f"Radius: {footprint.radius_deg:.4f} deg",

        ]

        if footprint.width_deg is not None and footprint.height_deg is not None:

            lines.append(f"Estimated FOV: {footprint.width_deg:.4f} x {footprint.height_deg:.4f} deg")

        lines.append("")

        lines.append("Corners:")

        for corner in footprint.corners:

            lines.append(f"- {corner.label}: RA {corner.ra_deg:.6f}, Dec {corner.dec_deg:.6f}")

        layer_summaries = self._sky_explorer_display_layer_summaries(result)

        if layer_summaries:

            lines.append("")

            lines.append("Layer Counts:")

            for summary in layer_summaries:

                text = f"- {summary.title}: {summary.displayed_count} shown"

                if summary.returned_count != summary.displayed_count:

                    text += f" ({summary.returned_count} returned)"

                if summary.note:

                    text += f". {summary.note}"

                lines.append(text)

        return "\n".join(lines)

    def _sky_explorer_display_layer_summaries(self, result: SkyExplorerResult) -> tuple[SkyExplorerLayerSummary, ...]:

        if not self._sky_explorer_hide_unknown_magnitude_enabled():

            return result.layer_summaries

        displayed_counts: dict[str, int] = {}

        for sky_object in self._sky_explorer_result_objects_after_view_filters(result):

            displayed_counts[sky_object.layer_key] = displayed_counts.get(sky_object.layer_key, 0) + 1

        return tuple(

            SkyExplorerLayerSummary(

                layer_key=summary.layer_key,

                title=summary.title,

                returned_count=summary.returned_count,

                displayed_count=displayed_counts.get(summary.layer_key, 0),

                note=summary.note,

            )

            for summary in result.layer_summaries

        )

    def _format_sky_explorer_object_details(self, sky_object: SkyExplorerObject) -> str:

        lines = [

            f"Name: {sky_object.name}",

            f"Layer: {_SKY_EXPLORER_LAYER_TITLES.get(sky_object.layer_key, sky_object.layer_key.title())}",

            f"Catalog: {sky_object.catalog}",

            f"Type: {sky_object.object_type or '-'}",

            f"RA: {sky_object.ra_deg:.6f} deg",

            f"Dec: {sky_object.dec_deg:.6f} deg",

            f"Pixel: x={sky_object.pixel_x:.1f}, y={sky_object.pixel_y:.1f}",

            f"Angular Distance From Center: {sky_object.angular_distance_arcmin:.2f} arcmin",

        ]

        if sky_object.magnitude is not None:

            lines.append(f"Magnitude: {sky_object.magnitude:.2f}")

        angular_size_text = self._format_sky_explorer_angular_size(sky_object)

        if angular_size_text != "-":

            lines.append(f"Angular Size: {angular_size_text}")

        if sky_object.source_id and sky_object.source_id != sky_object.name:

            lines.append(f"Identifier: {sky_object.source_id}")

        if sky_object.metadata:

            lines.append("")

            lines.append("Metadata:")

            for key, value in sorted(sky_object.metadata.items()):

                if value is None or str(value).strip() == "":

                    continue

                label = key.replace("_", " ").strip().title()

                lines.append(f"- {label}: {value}")

        return "\n".join(lines)

    def _sync_sky_explorer_image_display_controls(self) -> None:

        stretch_mode = "stf"

        inverted = False

        settings = getattr(self, "_settings", None)

        if settings is not None:

            stretch_mode = str(settings.image_display_stretch_mode or "stf")

            inverted = bool(settings.image_display_inverted)

        self._sky_explorer_image_stretch_combo.blockSignals(True)

        self._sky_explorer_image_invert_checkbox.blockSignals(True)

        stretch_index = self._sky_explorer_image_stretch_combo.findData(stretch_mode)

        self._sky_explorer_image_stretch_combo.setCurrentIndex(
            stretch_index if stretch_index >= 0 else max(0, self._sky_explorer_image_stretch_combo.findData("stf"))
        )

        self._sky_explorer_image_invert_checkbox.setChecked(inverted)

        self._sky_explorer_image_stretch_combo.blockSignals(False)

        self._sky_explorer_image_invert_checkbox.blockSignals(False)

    def _sync_sky_explorer_image_controls(self) -> None:

        image_path = getattr(self, "_current_sky_explorer_source_image", None)

        has_image = image_path is not None and image_path.exists()

        has_selection = self._selected_sky_explorer_object() is not None

        has_survey = bool(self._sky_explorer_active_survey_key)

        self._sky_explorer_image_stretch_combo.setEnabled(has_image)

        self._sky_explorer_adjust_levels_button.setEnabled(has_image)

        self._sky_explorer_image_invert_checkbox.setEnabled(has_image)

        self._sky_explorer_image_reset_display_button.setEnabled(has_image)

        self._sky_explorer_mag_limit_button.setEnabled(has_image)

        self._sky_explorer_surveys_button.setEnabled(has_image)

        self._sky_explorer_survey_display_controls.setEnabled(has_image and has_survey)

        self._sky_explorer_center_object_button.setEnabled(has_image and has_selection)

        self._sky_explorer_show_auto_annotations_button.setEnabled(has_image)

        for tool_button in self._sky_explorer_annotation_tool_buttons.values():

            tool_button.setEnabled(has_image)

        self._sky_explorer_annotation_stroke_color_button.setEnabled(has_image)

        self._sky_explorer_annotation_fill_color_button.setEnabled(has_image)

        self._sky_explorer_annotation_line_width_label.setEnabled(has_image)

        self._sky_explorer_annotation_line_width_spin.setEnabled(has_image)

        self._sky_explorer_annotation_text_color_button.setEnabled(has_image)

        self._sky_explorer_annotation_opacity_label.setEnabled(has_image)

        self._sky_explorer_annotation_text_font_combo.setEnabled(has_image)

        self._sky_explorer_annotation_text_size_spin.setEnabled(has_image)

        self._sky_explorer_annotation_text_style_combo.setEnabled(has_image)

        self._sky_explorer_annotation_opacity_button.setEnabled(has_image)

        if not has_image:

            self._set_sky_explorer_annotation_tool("mouse", refresh=False)

            self._selected_sky_explorer_manual_annotation_id = None

            self._sky_explorer_manual_annotation_drag = None

        self._sky_explorer_export_image_button.setEnabled(has_image)

        if hasattr(self, "_sky_explorer_collage_button"):

            self._sky_explorer_collage_button.setEnabled(self._sky_explorer_can_export_collage())

        if hasattr(self, "_sky_explorer_export_animation_action"):

            self._sky_explorer_export_animation_action.setEnabled(
                self._sky_explorer_can_export_comparison_animation()
            )

    def _sync_sky_explorer_header_splitter_from_main(self) -> None:

        if getattr(self, "_sky_explorer_splitter_sync_in_progress", False):

            return

        self._sky_explorer_splitter_sync_in_progress = True

        try:

            self._sky_explorer_header_splitter.setSizes(self._sky_explorer_main_splitter.sizes())

        finally:

            self._sky_explorer_splitter_sync_in_progress = False

    def _schedule_sky_explorer_header_splitter_sync(self) -> None:

        QTimer.singleShot(0, self._sync_sky_explorer_header_splitter_from_main)

    def _current_sky_explorer_object_type_column_widths(self) -> list[int]:

        return [

            int(self._sky_explorer_object_type_table.columnWidth(column_index))

            for column_index in range(self._sky_explorer_object_type_table.columnCount())

        ]

    def _current_sky_explorer_results_column_widths(self) -> list[int]:

        return [

            int(self._sky_explorer_results_table.columnWidth(column_index))

            for column_index in range(self._sky_explorer_results_table.columnCount())

        ]

    def _apply_cached_sky_explorer_layout_state(self) -> None:

        if not hasattr(self, "_sky_explorer_main_splitter") or not hasattr(self, "_sky_explorer_results_splitter"):

            return

        self._sky_explorer_layout_settings_sync_enabled = False

        try:

            if self._settings is not None and self._settings.sky_explorer_left_splitter_sizes:

                self._sky_explorer_left_panel_splitter.setSizes(

                    self._normalized_splitter_sizes(

                        self._settings.sky_explorer_left_splitter_sizes,

                        fallback_sizes=[250, 360],

                        minimum_first=180,

                        minimum_second=160,

                    )

                )

            else:

                self._sky_explorer_left_panel_splitter.setSizes([250, 360])

            if self._settings is not None and self._settings.sky_explorer_results_splitter_sizes:

                self._sky_explorer_results_splitter.setSizes(

                    self._normalized_splitter_sizes(

                        self._settings.sky_explorer_results_splitter_sizes,

                        fallback_sizes=[460, 240],

                        minimum_first=220,

                        minimum_second=120,

                    )

                )

            else:

                self._sky_explorer_results_splitter.setSizes([460, 240])

            if self._settings is not None and self._settings.sky_explorer_main_splitter_sizes:

                self._sky_explorer_main_splitter.setSizes(

                    self._normalized_splitter_sizes(

                        self._settings.sky_explorer_main_splitter_sizes,

                        fallback_sizes=[720, 1000],

                        minimum_first=420,

                        minimum_second=520,

                    )

                )

            else:

                self._sky_explorer_main_splitter.setSizes([720, 1000])

            object_type_widths = self._settings.sky_explorer_object_type_column_widths if self._settings is not None else None

            if object_type_widths and len(object_type_widths) == self._sky_explorer_object_type_table.columnCount():

                for column_index, column_width in enumerate(object_type_widths):

                    self._sky_explorer_object_type_table.setColumnWidth(column_index, int(column_width))

            results_widths = self._settings.sky_explorer_results_column_widths if self._settings is not None else None

            if results_widths and len(results_widths) == self._sky_explorer_results_table.columnCount():

                for column_index, column_width in enumerate(results_widths):

                    self._sky_explorer_results_table.setColumnWidth(column_index, int(column_width))

            self._sync_sky_explorer_header_splitter_from_main()

            self._schedule_sky_explorer_header_splitter_sync()

        finally:

            self._sky_explorer_layout_settings_sync_enabled = True

    def _handle_sky_explorer_layout_state_changed(self, _position: int, _index: int) -> None:

        if not self._sky_explorer_layout_settings_sync_enabled:

            return

        settings = self._ensure_settings()

        left_sizes = [int(size) for size in self._sky_explorer_left_panel_splitter.sizes()]

        results_sizes = [int(size) for size in self._sky_explorer_results_splitter.sizes()]

        main_sizes = [int(size) for size in self._sky_explorer_main_splitter.sizes()]

        if len(left_sizes) != 2 or len(results_sizes) != 2 or len(main_sizes) != 2:

            return

        if any(size <= 0 for size in left_sizes + results_sizes + main_sizes):

            return

        settings.sky_explorer_left_splitter_sizes = left_sizes

        settings.sky_explorer_results_splitter_sizes = results_sizes

        settings.sky_explorer_main_splitter_sizes = main_sizes

        self._save_settings_snapshot()

    def _handle_sky_explorer_table_column_widths_changed(self, _logical_index: int, _old_size: int, _new_size: int) -> None:

        if not self._sky_explorer_layout_settings_sync_enabled:

            return

        settings = self._ensure_settings()

        object_type_widths = self._current_sky_explorer_object_type_column_widths()

        results_widths = self._current_sky_explorer_results_column_widths()

        if any(width <= 0 for width in object_type_widths + results_widths):

            return

        settings.sky_explorer_object_type_column_widths = object_type_widths

        settings.sky_explorer_results_column_widths = results_widths

        self._save_settings_snapshot()

    def _sync_sky_explorer_main_splitter_from_header(self) -> None:

        if getattr(self, "_sky_explorer_splitter_sync_in_progress", False):

            return

        self._sky_explorer_splitter_sync_in_progress = True

        try:

            self._sky_explorer_main_splitter.setSizes(self._sky_explorer_header_splitter.sizes())

        finally:

            self._sky_explorer_splitter_sync_in_progress = False

    def _sky_explorer_default_export_path(self) -> Path:

        image_path = getattr(self, "_current_sky_explorer_source_image", None)

        if image_path is None:

            return Path.cwd() / "sky_explorer_annotated.png"

        return image_path.with_name(f"{image_path.stem}_sky_explorer.png")

    def _sky_explorer_default_collage_export_path(self) -> Path:

        image_path = getattr(self, "_current_sky_explorer_source_image", None)

        if image_path is None:

            return Path.cwd() / "sky_explorer_collage.png"

        return image_path.with_name(f"{image_path.stem}_sky_explorer_collage.png")

    def _sky_explorer_can_export_collage(self) -> bool:

        image_path = getattr(self, "_current_sky_explorer_source_image", None)

        if image_path is None or not Path(image_path).exists():

            return False

        if self._current_sky_explorer_result is None:

            return False

        if self._sky_explorer_image_wcs() is None:

            return False

        selected_eligible, _selected_skipped = partition_sky_explorer_collage_objects(self._selected_sky_explorer_objects())

        visible_eligible, _visible_skipped = partition_sky_explorer_collage_objects(
            self._current_sky_explorer_visible_objects
        )

        return bool(selected_eligible or visible_eligible)

    def _export_sky_explorer_collage(self) -> None:

        image_path = getattr(self, "_current_sky_explorer_source_image", None)

        if image_path is None or not Path(image_path).exists():

            QMessageBox.information(self, "Nothing to export", "Open a Sky Explorer image before creating a collage.")

            return

        if self._current_sky_explorer_result is None:

            QMessageBox.information(self, "Nothing to export", "Explore the field before creating a collage.")

            return

        wcs = self._sky_explorer_image_wcs()

        if wcs is None:

            QMessageBox.information(

                self,

                "Collage unavailable",

                "Sky Explorer needs a valid WCS solution before catalog-size crops can be exported.",

            )

            return

        selected_objects = self._selected_sky_explorer_objects()

        visible_objects = tuple(self._current_sky_explorer_visible_objects)

        selected_eligible, selected_skipped = partition_sky_explorer_collage_objects(selected_objects)

        visible_eligible, visible_skipped = partition_sky_explorer_collage_objects(visible_objects)

        if not selected_eligible and not visible_eligible:

            QMessageBox.information(

                self,

                "No eligible objects",

                "Collage export needs objects with catalog size metadata "

                "(major/minor axis or catalog size). None of the selected or visible objects qualify.",

            )

            return

        options_dialog = SkyExplorerCollageDialog(

            selected_count=len(selected_objects),

            selected_eligible_count=len(selected_eligible),

            selected_skipped_count=len(selected_skipped),

            visible_count=len(visible_objects),

            visible_eligible_count=len(visible_eligible),

            visible_skipped_count=len(visible_skipped),

            initial_options=getattr(self, "_sky_explorer_collage_options", None),

            initial_scope="selected" if selected_eligible else "all_eligible_visible",

            parent=self,

        )

        if options_dialog.exec() != int(QDialog.DialogCode.Accepted):

            return

        collage_options = options_dialog.selected_options()

        self._sky_explorer_collage_options = collage_options

        scope = options_dialog.selected_scope()

        candidate_objects = selected_objects if scope == "selected" else visible_objects

        eligible_objects, skipped_objects = partition_sky_explorer_collage_objects(candidate_objects)

        if not eligible_objects:

            QMessageBox.information(

                self,

                "No eligible objects",

                "The chosen collage scope has no objects with usable catalog size metadata.",

            )

            return

        default_path = self._sky_explorer_default_collage_export_path()

        default_path.parent.mkdir(parents=True, exist_ok=True)

        selected_path, _selected_filter = QFileDialog.getSaveFileName(

            self,

            "Save Sky Explorer Collage",

            str(default_path),

            "PNG Files (*.png);;JPEG Files (*.jpg *.jpeg);;BMP Files (*.bmp);;All Files (*)",

            "PNG Files (*.png)",

        )

        if not selected_path:

            return

        output_path = Path(selected_path)

        if output_path.suffix.lower() not in {".png", ".jpg", ".jpeg", ".bmp"}:

            output_path = output_path.with_suffix(".png")

        try:

            collage_result = build_sky_explorer_collage(

                source_image_path=Path(image_path),

                objects=eligible_objects,

                wcs=wcs,

                render_settings=self._current_sky_explorer_image_render_settings(),

                options=collage_options,

            )

            save_sky_explorer_collage_image(collage_result.image_rgb, output_path)

        except Exception as exc:

            QMessageBox.warning(self, "Collage export failed", f"Could not create the Sky Explorer collage:\n{exc}")

            self._append_sky_explorer_workflow_note(f"Sky Explorer collage export failed: {exc}")

            return

        summary = format_sky_explorer_collage_summary(

            candidate_count=len(candidate_objects),

            eligible_count=len(eligible_objects),

            skipped_missing_size_count=len(skipped_objects),

            included_count=len(collage_result.included_objects),

            clipped_count=collage_result.clipped_count,

            padded_count=collage_result.padded_count,

            columns=collage_result.columns,

            rows=collage_result.rows,

            layout=collage_result.layout,

            margin_fraction=collage_result.margin_fraction,

            output_width=int(collage_result.image_rgb.shape[1]),

            output_height=int(collage_result.image_rgb.shape[0]),

        )

        status_message = (

            f"Saved Sky Explorer collage ({len(collage_result.included_objects)} object"

            f"{'' if len(collage_result.included_objects) == 1 else 's'}) to {output_path}."

        )

        self.statusBar().showMessage(status_message, 6000)

        self._append_sky_explorer_workflow_note(status_message)

        self._append_sky_explorer_workflow_note(summary.replace("\n", " | "))

        if skipped_objects or collage_result.skipped_objects:

            skipped_names = ", ".join(

                str(sky_object.short_label or sky_object.name or sky_object.source_id)

                for sky_object in skipped_objects[:8]

            )

            if len(skipped_objects) > 8:

                skipped_names = f"{skipped_names}, …"

            if skipped_names:

                self._append_sky_explorer_workflow_note(

                    f"Skipped for missing catalog size ({len(skipped_objects)}): {skipped_names}"

                )

    def _sky_explorer_default_comparison_animation_export_path(self) -> Path:

        image_path = getattr(self, "_current_sky_explorer_source_image", None)

        if image_path is None:

            return Path.cwd() / "sky_explorer_comparison.gif"

        return image_path.with_name(f"{image_path.stem}_sky_explorer_comparison.gif")

    def _sky_explorer_can_export_comparison_animation(self) -> bool:

        image_path = getattr(self, "_current_sky_explorer_source_image", None)

        if image_path is None or not image_path.exists():

            return False

        if not self._sky_explorer_active_survey_key:

            return False

        image_view = self._sky_explorer_image_view

        return bool(image_view._comparison_is_active() and image_view._comparison_has_survey_raster())

    def _export_sky_explorer_image_view(self) -> None:

        image_path = getattr(self, "_current_sky_explorer_source_image", None)

        if image_path is None or not image_path.exists():

            QMessageBox.information(self, "Nothing to export", "Open a Sky Explorer image before saving the annotated view.")

            return

        default_path = self._sky_explorer_default_export_path()

        default_path.parent.mkdir(parents=True, exist_ok=True)

        selected_path, _selected_filter = QFileDialog.getSaveFileName(

            self,

            "Save Sky Explorer Image",

            str(default_path),

            "PNG Files (*.png);;JPEG Files (*.jpg *.jpeg);;BMP Files (*.bmp);;All Files (*)",

            "PNG Files (*.png)",

        )

        if not selected_path:

            return

        output_path = Path(selected_path)

        if output_path.suffix.lower() not in {".png", ".jpg", ".jpeg", ".bmp"}:

            output_path = output_path.with_suffix(".png")

        self._refresh_sky_explorer_image_view(reset_view=False, focus_selected=False)

        image = self._sky_explorer_image_view.capture_view_image()

        if not image.save(str(output_path)):

            QMessageBox.warning(self, "Save failed", f"Could not save the Sky Explorer image to {output_path}.")

            return

        self.statusBar().showMessage(f"Saved Sky Explorer image to {output_path}.", 5000)

        self._append_sky_explorer_workflow_note(f"Saved Sky Explorer image to {output_path}.")

    def _export_sky_explorer_comparison_animation(self) -> None:

        if not self._sky_explorer_can_export_comparison_animation():

            QMessageBox.information(

                self,

                "Comparison animation unavailable",

                "Open a Sky Explorer image, choose a survey, and wait for the comparison view to finish loading "

                "before exporting an animation.",

            )

            return

        options_dialog = SkyExplorerComparisonAnimationExportDialog(parent=self)

        if options_dialog.exec() != int(QDialog.DialogCode.Accepted):

            return

        animation_options = options_dialog.selected_options()

        default_path = self._sky_explorer_default_comparison_animation_export_path()

        default_path.parent.mkdir(parents=True, exist_ok=True)

        selected_path, selected_filter = QFileDialog.getSaveFileName(

            self,

            "Save Sky Explorer Comparison Animation",

            str(default_path),

            "Animated GIF Files (*.gif);;MP4 Video Files (*.mp4)",

        )

        if not selected_path:

            return

        output_path, export_format = self._resolve_blink_export_target(selected_path, selected_filter)

        if export_format == "mp4":

            mp4_available, mp4_message = mp4_export_dependencies_available()

            if not mp4_available:

                QMessageBox.warning(

                    self,

                    "MP4 export unavailable",

                    mp4_export_unavailable_message(mp4_message),

                )

                return

        self._refresh_sky_explorer_image_view(reset_view=False, focus_selected=False)

        QApplication.processEvents()

        frame_count, _planned_frame_duration_ms = resolve_sky_explorer_comparison_animation_timing(
            animation_options.duration_seconds,
            fps=animation_options.frame_rate_fps,
            ping_pong=animation_options.ping_pong,
            divider_travel_pixels=self._sky_explorer_image_view.comparison_divider_travel_pixels(),
            smooth_motion=animation_options.smooth_motion,
            gif_mode=export_format == "gif",
        )

        split_fractions = sky_explorer_comparison_split_fractions(

            frame_count=frame_count,

            ping_pong=animation_options.ping_pong,

        )

        progress_dialog = QProgressDialog(

            "Capturing comparison frames...",

            "Cancel",

            0,

            len(split_fractions),

            self,

        )

        progress_dialog.setWindowTitle("Export Comparison Animation")

        progress_dialog.setMinimumDuration(0)

        progress_dialog.setAutoClose(False)

        progress_dialog.setAutoReset(False)

        progress_dialog.setWindowModality(Qt.WindowModality.ApplicationModal)

        progress_dialog.setValue(0)

        progress_dialog.show()

        try:

            self._append_sky_explorer_workflow_note(f"Exporting Sky Explorer comparison animation to {output_path}.")

            frames = self._capture_sky_explorer_comparison_animation_frames(

                split_fractions,

                progress_dialog=progress_dialog,

            )

            if progress_dialog.wasCanceled():

                raise _SkyExplorerComparisonExportCanceled()

            progress_dialog.setLabelText(

                "Encoding MP4 video..." if export_format == "mp4" else "Encoding animated GIF..."

            )

            QApplication.processEvents()

            if export_format == "mp4":

                export_qimages_to_mp4_for_total_duration(

                    frames,

                    output_path,

                    total_duration_seconds=animation_options.duration_seconds,

                    scale_percent=animation_options.output_scale_percent,

                )

            else:

                export_qimages_to_gif_for_total_duration(

                    frames,

                    output_path,

                    total_duration_seconds=animation_options.duration_seconds,

                    loop_count=0 if animation_options.loop_forever else None,

                    scale_percent=animation_options.output_scale_percent,

                )

        except _SkyExplorerComparisonExportCanceled:

            self._append_sky_explorer_workflow_note("Sky Explorer comparison animation export canceled.")

            self.statusBar().showMessage("Sky Explorer comparison animation export canceled.", 5000)

            return

        except Exception as exc:

            self._append_sky_explorer_workflow_note(

                f"Sky Explorer comparison animation export failed: {exc}"

            )

            QMessageBox.warning(self, "Comparison animation export failed", str(exc))

            return

        finally:

            progress_dialog.close()

            progress_dialog.deleteLater()

        self.statusBar().showMessage(

            f"Saved Sky Explorer comparison animation to {output_path.name}.",

            5000,

        )

        self._append_sky_explorer_workflow_note(

            f"Saved Sky Explorer comparison animation to {output_path}."

        )

    def _capture_sky_explorer_comparison_animation_frames(

        self,

        split_fractions: Sequence[float],

        *,

        progress_dialog: QProgressDialog,

    ) -> list[QImage]:

        image_view = self._sky_explorer_image_view

        original_fraction = image_view.comparison_split_fraction()

        was_loading = image_view._comparison_loading

        loading_message = image_view.comparison_loading_message()

        frames: list[QImage] = []

        try:

            image_view.set_comparison_loading(False)

            for index, fraction in enumerate(split_fractions):

                if progress_dialog.wasCanceled():

                    raise _SkyExplorerComparisonExportCanceled()

                frames.append(

                    image_view.capture_view_image_at_comparison_split(float(fraction))

                )

                progress_dialog.setValue(index + 1)

                QApplication.processEvents()

        finally:

            image_view.set_comparison_split_fraction(original_fraction)

            if was_loading:

                image_view.set_comparison_loading(True)

                image_view.set_comparison_loading_message(loading_message)

        return frames

    def _sky_explorer_definition_for_object(

        self,

        sky_object: SkyExplorerObject,

        *,

        preferred_keys: set[str] | None = None,

    ) -> SkyExplorerObjectTypeDefinition | None:

        object_keys = tuple(sky_explorer_object_type_keys_for_object(sky_object))

        object_key_set = set(object_keys)

        active_definitions = sky_explorer_object_type_definitions_for_mode(self._current_sky_explorer_object_type_mode())

        active_definitions_by_key = {definition.key: definition for definition in active_definitions}

        if preferred_keys:

            for object_key in object_keys:

                if object_key in preferred_keys and object_key in active_definitions_by_key:

                    return active_definitions_by_key[object_key]

        for object_key in object_keys:

            if object_key in active_definitions_by_key:

                return active_definitions_by_key[object_key]

        for definition in active_definitions:

            if definition.key in object_key_set:

                return definition

        for object_key in object_keys:

            definition = _SKY_EXPLORER_OBJECT_TYPE_DEFINITION_BY_KEY.get(object_key)

            if definition is not None:

                return definition

        return None

    def _current_sky_explorer_image_render_settings(self) -> AnnotatedImageRenderSettings:

        stretch_mode = self._sky_explorer_image_stretch_combo.currentData()

        black_point, midtone_point, white_point = self._sky_explorer_image_levels

        return AnnotatedImageRenderSettings(

            stretch_mode=str(stretch_mode) if isinstance(stretch_mode, str) and stretch_mode else "stf",

            black_point=black_point,

            midtone_point=midtone_point,

            white_point=white_point,

            curve_points=self._sky_explorer_image_curve_points,

            inverted=self._sky_explorer_image_invert_checkbox.isChecked(),

        )

    def _handle_sky_explorer_image_display_controls_changed(self) -> None:

        self._refresh_sky_explorer_image_view(reset_view=False, focus_selected=False)

    def _current_sky_explorer_survey_render_settings(self) -> AnnotatedImageRenderSettings:

        stretch_mode = self._sky_explorer_survey_stretch_combo.currentData()

        black_point, midtone_point, white_point = self._sky_explorer_survey_levels

        return AnnotatedImageRenderSettings(

            stretch_mode=str(stretch_mode) if isinstance(stretch_mode, str) and stretch_mode else "stf",

            black_point=black_point,

            midtone_point=midtone_point,

            white_point=white_point,

            curve_points=self._sky_explorer_survey_curve_points,

            inverted=self._sky_explorer_survey_invert_checkbox.isChecked(),

        )

    def _handle_sky_explorer_survey_display_controls_changed(self) -> None:

        self._apply_sky_explorer_survey_comparison()

    def _reset_sky_explorer_survey_display_controls(self) -> None:

        self._sky_explorer_survey_stretch_combo.blockSignals(True)

        self._sky_explorer_survey_invert_checkbox.blockSignals(True)

        self._sky_explorer_survey_stretch_combo.setCurrentIndex(

            max(0, self._sky_explorer_survey_stretch_combo.findData("stf"))

        )

        self._sky_explorer_survey_invert_checkbox.setChecked(False)

        self._sky_explorer_survey_stretch_combo.blockSignals(False)

        self._sky_explorer_survey_invert_checkbox.blockSignals(False)

        self._sky_explorer_survey_levels = (0.0, 0.5, 1.0)

        self._sky_explorer_survey_curve_points = ()

        self._apply_sky_explorer_survey_comparison()

    def _open_sky_explorer_survey_levels_dialog(self) -> None:

        display = self._sky_explorer_survey_display

        if display is None:

            QMessageBox.information(

                self,

                "Survey unavailable",

                "Choose a survey and wait for its image to load before adjusting curves.",

            )

            return

        dialog = CurvesDialog(

            display=display,

            initial_settings=self._current_sky_explorer_survey_render_settings(),

            parent=self,

        )

        if dialog.exec() != int(QDialog.DialogCode.Accepted):

            return

        selected_settings = dialog.selected_settings()

        self._sky_explorer_survey_levels = (

            float(selected_settings.black_point),

            float(selected_settings.midtone_point),

            float(selected_settings.white_point),

        )

        self._sky_explorer_survey_curve_points = selected_settings.curve_points

        self._apply_sky_explorer_survey_comparison()

    def _build_sky_explorer_survey_display(self, result: object) -> AnnotatedImageDisplay:

        image_data = np.asarray(getattr(result, "image_data"))

        color_data: np.ndarray | None = None

        if image_data.ndim == 3:

            if image_data.shape[-1] in {3, 4}:

                color_data = np.asarray(image_data[..., :3], dtype=float)

            elif image_data.shape[0] in {3, 4}:

                color_data = np.moveaxis(np.asarray(image_data[:3], dtype=float), 0, -1)

            else:

                raise ValueError("Survey image has an unsupported channel layout.")

            grayscale_data = np.asarray(np.mean(color_data, axis=-1), dtype=float)

        elif image_data.ndim == 2:

            grayscale_data = np.asarray(image_data, dtype=float)

        else:

            raise ValueError("Survey image is not a usable two-dimensional frame.")

        display_path = getattr(result, "cache_path", None)

        if not isinstance(display_path, Path):

            display_path = self._current_sky_explorer_source_image or Path.cwd() / "sky-explorer-survey.fits"

        return build_annotated_image_display_from_array(

            grayscale_data,

            image_path=display_path,

            color_data=color_data,

            recommended_stretch_mode="stf",

        )

    def _apply_sky_explorer_survey_comparison(self) -> None:

        if not self._sky_explorer_active_survey_key:

            self._sky_explorer_image_view.clear_comparison()

            return

        result = self._sky_explorer_survey_result

        display = self._sky_explorer_survey_display

        if result is None or display is None:

            self._sky_explorer_image_view.set_comparison_split_enabled(True)

            return

        target_rect_value = getattr(result, "target_rect", None)

        if isinstance(target_rect_value, QRectF):

            target_rect = QRectF(target_rect_value)

        else:

            try:

                target_x, target_y, target_width, target_height = target_rect_value

                target_rect = QRectF(

                    float(target_x),

                    float(target_y),

                    float(target_width),

                    float(target_height),

                )

            except (TypeError, ValueError):

                self._sky_explorer_image_view.clear_comparison_survey_content()

                self._sky_explorer_image_view.set_comparison_split_enabled(True)

                return

        self._sky_explorer_image_view.set_comparison_content(

            display,

            target_rect=target_rect,

            render_settings=self._current_sky_explorer_survey_render_settings(),

        )

        self._sky_explorer_image_view.set_comparison_loading(False)

        if hasattr(self, "_sky_explorer_export_animation_action"):

            self._sky_explorer_export_animation_action.setEnabled(
                self._sky_explorer_can_export_comparison_animation()
            )

    def _set_sky_explorer_survey_action_checked(self, survey_key: str | None) -> None:

        for action_key, action in self._sky_explorer_survey_actions.items():

            action.blockSignals(True)

            action.setChecked(action_key == survey_key)

            action.blockSignals(False)

    def _clear_sky_explorer_survey_comparison(self, *, reset_selection: bool) -> None:

        if hasattr(self, "_sky_explorer_survey_refresh_timer"):

            self._sky_explorer_survey_refresh_timer.stop()

        if hasattr(self, "_sky_explorer_survey_refine_timer"):

            self._sky_explorer_survey_refine_timer.stop()

        self._sky_explorer_survey_request_generation += 1

        self._pending_sky_explorer_survey_request = None

        self._sky_explorer_survey_result = None

        self._sky_explorer_survey_result_context = None

        self._sky_explorer_survey_last_error = None

        self._sky_explorer_survey_display = None

        self._sky_explorer_image_view.clear_comparison()

        if reset_selection:

            self._sky_explorer_active_survey_key = None

            if hasattr(self, "_sky_explorer_survey_actions"):

                self._set_sky_explorer_survey_action_checked(None)

            if hasattr(self, "_sky_explorer_surveys_button"):

                self._sky_explorer_surveys_button.setToolTip(

                    "Compare the current view with a WCS-aligned reference survey."

                )

        if hasattr(self, "_sky_explorer_survey_display_controls"):

            self._sky_explorer_survey_display_controls.setEnabled(

                bool(self._current_sky_explorer_source_image and self._sky_explorer_active_survey_key)

            )

    def _select_sky_explorer_survey(self, survey_key: str | None) -> None:

        normalized_key = None if survey_key is None else str(survey_key).strip().lower()

        valid_keys = {key for key, _title in _SKY_EXPLORER_SURVEY_OPTIONS}

        if normalized_key is not None and normalized_key not in valid_keys:

            return

        if normalized_key is None:

            had_survey = self._sky_explorer_active_survey_key is not None

            self._clear_sky_explorer_survey_comparison(reset_selection=True)

            self._sync_sky_explorer_image_controls()

            if had_survey:

                self.statusBar().showMessage("Survey comparison closed.", 3000)

            return

        source_path = self._current_sky_explorer_source_image

        if source_path is None or not source_path.exists():

            self._clear_sky_explorer_survey_comparison(reset_selection=True)

            self._sync_sky_explorer_image_controls()

            QMessageBox.information(self, "No source image", "Open a source image before choosing a survey.")

            return

        if self._sky_explorer_image_wcs() is None:

            self._clear_sky_explorer_survey_comparison(reset_selection=True)

            self._sync_sky_explorer_image_controls()

            QMessageBox.information(

                self,

                "Survey comparison unavailable",

                "The source image needs a usable celestial WCS before a survey can be aligned to it. "

                "Run Explore first if the image needs to be plate-solved.",

            )

            return

        self._clear_sky_explorer_survey_comparison(reset_selection=False)

        self._sky_explorer_active_survey_key = normalized_key

        self._set_sky_explorer_survey_action_checked(normalized_key)

        self._sync_sky_explorer_image_controls()

        title = dict(_SKY_EXPLORER_SURVEY_OPTIONS).get(normalized_key, normalized_key)

        self._sky_explorer_surveys_button.setToolTip(

            f"Comparing the source image with {title}. Drag the vertical divider to inspect either image."

        )

        self._append_sky_explorer_workflow_note(f"Requested {title} survey comparison for the current view.")

        self._sky_explorer_image_view.set_comparison_split_enabled(True)

        self._sky_explorer_image_view.set_comparison_loading(True)

        self._sky_explorer_survey_refresh_timer.start(0)

    def _handle_sky_explorer_survey_viewport_changed(self) -> None:

        if not self._sky_explorer_active_survey_key:

            return

        self._sky_explorer_survey_refresh_timer.start()

    @staticmethod

    def _sky_explorer_source_rect_contains(

        outer: tuple[float, float, float, float],

        inner: tuple[float, float, float, float],

        *,

        tolerance: float = 1.0,

    ) -> bool:

        outer_x, outer_y, outer_w, outer_h = outer

        inner_x, inner_y, inner_w, inner_h = inner

        return (

            inner_x >= outer_x - tolerance

            and inner_y >= outer_y - tolerance

            and inner_x + inner_w <= outer_x + outer_w + tolerance

            and inner_y + inner_h <= outer_y + outer_h + tolerance

        )

    def _sky_explorer_survey_cached_target_rect(

        self,

    ) -> tuple[float, float, float, float] | None:

        return self._sky_explorer_survey_result_target_rect(self._sky_explorer_survey_result)

    @staticmethod

    def _sky_explorer_survey_result_target_rect(

        result: object | None,

    ) -> tuple[float, float, float, float] | None:

        if result is None:

            return None

        target_rect_value = getattr(result, "target_rect", None)

        if isinstance(target_rect_value, QRectF):

            rect = QRectF(target_rect_value).normalized()

            return (rect.x(), rect.y(), rect.width(), rect.height())

        try:

            target_x, target_y, target_width, target_height = target_rect_value

        except (TypeError, ValueError):

            return None

        return (float(target_x), float(target_y), float(target_width), float(target_height))

    def _sky_explorer_survey_visible_bounds(self) -> tuple[float, float, float, float] | None:

        visible_rect = self._sky_explorer_image_view.visible_image_rect(margin_fraction=0.0)

        if visible_rect.isEmpty():

            return None

        return (

            float(visible_rect.left()),

            float(visible_rect.top()),

            float(visible_rect.width()),

            float(visible_rect.height()),

        )

    def _sky_explorer_survey_visible_in_cached_target(self) -> bool:

        cached_target = self._sky_explorer_survey_cached_target_rect()

        visible_bounds = self._sky_explorer_survey_visible_bounds()

        if cached_target is None or visible_bounds is None:

            return False

        return self._sky_explorer_source_rect_contains(cached_target, visible_bounds)

    @staticmethod

    def _sky_explorer_survey_signature_from_context(

        context: tuple[object, ...] | None,

    ) -> tuple[object, ...] | None:

        if context is None or len(context) < 4:

            return None

        if context[-1] in (_SKY_EXPLORER_SURVEY_DETAIL_PREVIEW, _SKY_EXPLORER_SURVEY_DETAIL_REFINE):

            return tuple(context[1:-1])

        return tuple(context[1:])

    @staticmethod

    def _sky_explorer_survey_fetch_bounds_from_signature(

        signature: tuple[object, ...],

    ) -> tuple[float, float, float, float] | None:

        if len(signature) < 10:

            return None

        try:

            x0 = int(signature[6])

            y0 = int(signature[7])

            x1 = int(signature[8])

            y1 = int(signature[9])

        except (TypeError, ValueError):

            return None

        if x1 <= x0 or y1 <= y0:

            return None

        return (float(x0), float(y0), float(x1 - x0), float(y1 - y0))

    def _sky_explorer_survey_context_covers_visible_viewport(

        self,

        context: tuple[object, ...] | None,

    ) -> bool:

        signature = self._sky_explorer_survey_signature_from_context(context)

        visible_bounds = self._sky_explorer_survey_visible_bounds()

        if signature is None or visible_bounds is None:

            return False

        fetch_bounds = self._sky_explorer_survey_fetch_bounds_from_signature(signature)

        if fetch_bounds is None:

            return False

        return self._sky_explorer_source_rect_contains(fetch_bounds, visible_bounds)

    def _sky_explorer_active_survey_title(self) -> str:

        return dict(_SKY_EXPLORER_SURVEY_OPTIONS).get(

            self._sky_explorer_active_survey_key or "",

            "Survey",

        )

    def _sky_explorer_survey_request_context(

        self,

        signature: tuple[object, ...],

        detail_tier: str,

    ) -> tuple[object, ...]:

        return (self._sky_explorer_survey_request_generation, *signature, detail_tier)

    @staticmethod

    def _sky_explorer_survey_detail_tier_from_context(context: tuple[object, ...] | None) -> str:

        if (

            context is not None

            and len(context) > 0

            and context[-1] in (_SKY_EXPLORER_SURVEY_DETAIL_PREVIEW, _SKY_EXPLORER_SURVEY_DETAIL_REFINE)

        ):

            return str(context[-1])

        return _SKY_EXPLORER_SURVEY_DETAIL_REFINE

    def _sky_explorer_survey_loading_message_for_detail(self, detail_tier: str) -> str:

        title = self._sky_explorer_active_survey_title()

        if detail_tier == _SKY_EXPLORER_SURVEY_DETAIL_PREVIEW:

            return f"Loading {title} preview…"

        if detail_tier == _SKY_EXPLORER_SURVEY_DETAIL_REFINE:

            return f"Refining {title} detail…"

        return f"Loading {title}…"

    def _sky_explorer_survey_set_loading_detail(self, detail_tier: str) -> None:

        self._sky_explorer_image_view.set_comparison_split_enabled(True)

        self._sky_explorer_image_view.set_comparison_loading(True)

        self._sky_explorer_image_view.set_comparison_loading_message(

            self._sky_explorer_survey_loading_message_for_detail(detail_tier)

        )

    @staticmethod

    def _sky_explorer_survey_specs_are_distinct(

        preview_spec: tuple[object, ...],

        refine_spec: tuple[object, ...],

    ) -> bool:

        _preview_wcs, preview_width, preview_height, _preview_target, preview_signature = preview_spec

        _refine_wcs, refine_width, refine_height, _refine_target, refine_signature = refine_spec

        return (

            int(preview_width),

            int(preview_height),

            int(preview_signature[10]),

        ) != (

            int(refine_width),

            int(refine_height),

            int(refine_signature[10]),

        )

    def _sky_explorer_survey_viewport_needs_refresh(

        self,

        signature: tuple[object, ...],

    ) -> bool:

        result = self._sky_explorer_survey_result

        cached_context = self._sky_explorer_survey_result_context

        if result is None or cached_context is None:

            return True

        refine_context = self._sky_explorer_survey_request_context(

            signature,

            _SKY_EXPLORER_SURVEY_DETAIL_REFINE,

        )

        if cached_context == refine_context:

            return False

        if len(signature) < 11 or len(cached_context) < 12:

            return True

        new_sampling_step = int(signature[10])

        cached_sampling_step = int(cached_context[11])

        if new_sampling_step < cached_sampling_step:

            return True

        if new_sampling_step == cached_sampling_step and self._sky_explorer_survey_visible_in_cached_target():

            return False

        return True

    def _sky_explorer_display_image_size(self) -> tuple[int, int] | None:

        qimage = getattr(self._sky_explorer_image_view, "_qimage", None)

        if qimage is None or qimage.isNull():

            return None

        return int(qimage.width()), int(qimage.height())

    def _sky_explorer_wcs_reference_size(self, wcs: WCS) -> tuple[int, int] | None:

        result = self._sky_explorer_overlay_reference_result()

        if result is not None:

            solved_field = result.solved_field

            if solved_field.width > 0 and solved_field.height > 0:

                return int(solved_field.width), int(solved_field.height)

        if wcs.array_shape is not None:

            height, width = wcs.array_shape

            if width and height:

                return int(width), int(height)

        if wcs.pixel_shape is not None:

            width, height = wcs.pixel_shape

            if width and height:

                return int(width), int(height)

        return None

    def _sky_explorer_wcs_for_display_coordinates(self, wcs: WCS) -> WCS:

        display_size = self._sky_explorer_display_image_size()

        reference_size = self._sky_explorer_wcs_reference_size(wcs)

        if display_size is None or reference_size is None:

            return wcs

        display_width, display_height = display_size

        reference_width, reference_height = reference_size

        scale_x = display_width / float(reference_width)

        scale_y = display_height / float(reference_height)

        if math.isclose(scale_x, 1.0, rel_tol=0.0, abs_tol=1.0e-9) and math.isclose(

            scale_y, 1.0, rel_tol=0.0, abs_tol=1.0e-9

        ):

            return wcs

        aligned = wcs.deepcopy()

        aligned.wcs.crpix = np.array(

            [float(aligned.wcs.crpix[0]) * scale_x, float(aligned.wcs.crpix[1]) * scale_y],

            dtype=float,

        )

        aligned.wcs.cdelt = np.array(

            [float(aligned.wcs.cdelt[0]) / scale_x, float(aligned.wcs.cdelt[1]) / scale_y],

            dtype=float,

        )

        try:

            aligned.array_shape = (display_height, display_width)

        except Exception:

            pass

        return aligned

    def _sky_explorer_survey_viewport_wcs(

        self,

        *,

        max_output_size: int | None = None,

    ) -> tuple[WCS, int, int, tuple[float, float, float, float], tuple[object, ...]] | None:

        source_wcs = self._sky_explorer_image_wcs()

        if source_wcs is None:

            return None

        source_wcs = self._sky_explorer_wcs_for_display_coordinates(source_wcs)

        visible_rect = self._sky_explorer_image_view.visible_image_rect(margin_fraction=0.0)

        if visible_rect.isEmpty():

            return None

        fetch_margin_fraction = max(0.0, float(_SKY_EXPLORER_SURVEY_FETCH_MARGIN_FRACTION))

        margin_x = visible_rect.width() * fetch_margin_fraction

        margin_y = visible_rect.height() * fetch_margin_fraction

        fetch_rect = visible_rect.adjusted(-margin_x, -margin_y, margin_x, margin_y)

        display_size = self._sky_explorer_display_image_size()

        image_width = display_size[0] if display_size is not None else None

        image_height = display_size[1] if display_size is not None else None

        x0 = max(0, int(math.floor(fetch_rect.left())))

        y0 = max(0, int(math.floor(fetch_rect.top())))

        x1 = max(x0 + 1, int(math.ceil(fetch_rect.right())))

        y1 = max(y0 + 1, int(math.ceil(fetch_rect.bottom())))

        if image_width is not None:

            x1 = min(x1, image_width)

        if image_height is not None:

            y1 = min(y1, image_height)

        if x1 <= x0 or y1 <= y0:

            return None

        source_width = x1 - x0

        source_height = y1 - y0

        target_width = max(256, min(2048, int(round(self._sky_explorer_image_view.width() * 1.25))))

        target_height = max(256, min(2048, int(round(self._sky_explorer_image_view.height() * 1.25))))

        if max_output_size is not None:

            preview_cap = max(128, int(max_output_size))

            target_width = min(target_width, preview_cap)

            target_height = min(target_height, preview_cap)

        sampling_step = max(

            1,

            int(math.ceil(source_width / max(1, target_width))),

            int(math.ceil(source_height / max(1, target_height))),

        )

        with warnings.catch_warnings():

            warnings.filterwarnings(

                "ignore",

                message="cdelt will be ignored since cd is present",

                category=RuntimeWarning,

            )

            viewport_wcs = scale_wcs_for_pixel_sampling(

                source_wcs.slice(

                    (

                        slice(y0, y1, sampling_step),

                        slice(x0, x1, sampling_step),

                    ),

                    numpy_order=True,

                ),

                sampling_step,

            )

            output_width = max(1, int(math.ceil(source_width / sampling_step)))

            output_height = max(1, int(math.ceil(source_height / sampling_step)))

            try:

                viewport_wcs.array_shape = (output_height, output_width)

            except Exception:

                pass

            target_rect = survey_target_rect_in_source_pixels(

                source_wcs,

                viewport_wcs,

                output_width=output_width,

                output_height=output_height,

            )

        signature = (

            str((self._current_sky_explorer_source_image or Path()).resolve()),

            self._sky_explorer_active_survey_key,

            round(float(visible_rect.left()), 3),

            round(float(visible_rect.top()), 3),

            round(float(visible_rect.width()), 3),

            round(float(visible_rect.height()), 3),

            x0,

            y0,

            x1,

            y1,

            sampling_step,

            output_width,

            output_height,

            round(target_rect[0], 4),

            round(target_rect[1], 4),

            round(target_rect[2], 4),

            round(target_rect[3], 4),

        )

        return viewport_wcs, output_width, output_height, target_rect, signature

    def _sky_explorer_survey_viewport_specs(

        self,

    ) -> tuple[

        tuple[WCS, int, int, tuple[float, float, float, float], tuple[object, ...]],

        tuple[WCS, int, int, tuple[float, float, float, float], tuple[object, ...]],

    ] | None:

        preview_spec = self._sky_explorer_survey_viewport_wcs(

            max_output_size=_SKY_EXPLORER_SURVEY_PREVIEW_MAX_OUTPUT,

        )

        refine_spec = self._sky_explorer_survey_viewport_wcs(max_output_size=None)

        if preview_spec is None or refine_spec is None:

            return None

        return preview_spec, refine_spec

    def _sky_explorer_survey_build_request(

        self,

        viewport_spec: tuple[WCS, int, int, tuple[float, float, float, float], tuple[object, ...]],

    ) -> SurveyImageRequest:

        viewport_wcs, width, height, target_rect, _signature = viewport_spec

        settings = self._ensure_settings()

        return SurveyImageRequest(

            survey_key=str(self._sky_explorer_active_survey_key),

            wcs=viewport_wcs,

            width=width,

            height=height,

            target_rect=target_rect,

            cache_dir=settings.cache_dir,

        )

    def _sky_explorer_survey_start_request(

        self,

        viewport_spec: tuple[WCS, int, int, tuple[float, float, float, float], tuple[object, ...]],

        *,

        detail_tier: str,

    ) -> None:

        if not self._sky_explorer_active_survey_key:

            return

        _viewport_wcs, _width, _height, _target_rect, signature = viewport_spec

        context = self._sky_explorer_survey_request_context(signature, detail_tier)

        request = self._sky_explorer_survey_build_request(viewport_spec)

        worker = self._sky_explorer_survey_worker

        if worker is not None and worker.isRunning():

            if context != self._sky_explorer_survey_worker_context:

                self._pending_sky_explorer_survey_request = (request, context)

            return

        self._pending_sky_explorer_survey_request = None

        self._start_sky_explorer_survey_request(request, context, detail_tier=detail_tier)

    def _request_current_sky_explorer_survey_viewport(

        self,

        *,

        force_detail: str | None = None,

    ) -> None:

        survey_key = self._sky_explorer_active_survey_key

        if not survey_key:

            return

        try:

            viewport_specs = self._sky_explorer_survey_viewport_specs()

        except Exception as exc:

            self._handle_sky_explorer_survey_result_error(

                f"Could not derive the current viewport WCS: {exc}"

            )

            return

        if viewport_specs is None:

            return

        preview_spec, refine_spec = viewport_specs

        _preview_wcs, _preview_width, _preview_height, _preview_target, preview_signature = preview_spec

        _refine_wcs, _refine_width, _refine_height, _refine_target, refine_signature = refine_spec

        if hasattr(self, "_sky_explorer_survey_refine_timer"):

            self._sky_explorer_survey_refine_timer.stop()

        refine_context = self._sky_explorer_survey_request_context(

            refine_signature,

            _SKY_EXPLORER_SURVEY_DETAIL_REFINE,

        )

        if refine_context == self._sky_explorer_survey_result_context:

            self._sky_explorer_image_view.set_comparison_loading(False)

            return

        if force_detail != _SKY_EXPLORER_SURVEY_DETAIL_REFINE and not self._sky_explorer_survey_viewport_needs_refresh(

            refine_signature

        ):

            self._sky_explorer_image_view.set_comparison_loading(False)

            return

        if force_detail != _SKY_EXPLORER_SURVEY_DETAIL_REFINE and not self._sky_explorer_survey_visible_in_cached_target():

            self._sky_explorer_image_view.clear_comparison_survey_content()

        preview_is_distinct = self._sky_explorer_survey_specs_are_distinct(preview_spec, refine_spec)

        if force_detail == _SKY_EXPLORER_SURVEY_DETAIL_REFINE:

            self._sky_explorer_survey_set_loading_detail(_SKY_EXPLORER_SURVEY_DETAIL_REFINE)

            self._sky_explorer_survey_start_request(refine_spec, detail_tier=_SKY_EXPLORER_SURVEY_DETAIL_REFINE)

            return

        if force_detail == _SKY_EXPLORER_SURVEY_DETAIL_PREVIEW:

            self._sky_explorer_survey_set_loading_detail(_SKY_EXPLORER_SURVEY_DETAIL_PREVIEW)

            self._sky_explorer_survey_start_request(preview_spec, detail_tier=_SKY_EXPLORER_SURVEY_DETAIL_PREVIEW)

            return

        if preview_is_distinct:

            self._sky_explorer_survey_set_loading_detail(_SKY_EXPLORER_SURVEY_DETAIL_PREVIEW)

            self._sky_explorer_survey_start_request(preview_spec, detail_tier=_SKY_EXPLORER_SURVEY_DETAIL_PREVIEW)

            return

        self._sky_explorer_survey_set_loading_detail(_SKY_EXPLORER_SURVEY_DETAIL_REFINE)

        self._sky_explorer_survey_start_request(refine_spec, detail_tier=_SKY_EXPLORER_SURVEY_DETAIL_REFINE)

    def _start_sky_explorer_survey_request(

        self,

        request: SurveyImageRequest,

        context: tuple[object, ...],

        *,

        detail_tier: str,

    ) -> None:

        if not self._sky_explorer_active_survey_key:

            return

        self._sky_explorer_survey_set_loading_detail(detail_tier)

        worker = SkyExplorerSurveyWorker(

            request=request,

            fetcher=fetch_survey_image,

            parent=self,

        )

        self._sky_explorer_survey_worker = worker

        self._sky_explorer_survey_worker_context = context

        worker.progress_updated.connect(self._handle_sky_explorer_survey_progress)

        worker.survey_completed.connect(self._handle_sky_explorer_survey_completed)

        worker.survey_failed.connect(self._handle_sky_explorer_survey_failed)

        worker.finished.connect(worker.deleteLater)

        worker.start()

    def _sky_explorer_survey_context_is_current(self, context: tuple[object, ...] | None) -> bool:

        return (

            context is not None

            and len(context) >= 3

            and context[0] == self._sky_explorer_survey_request_generation

            and context[2] == self._sky_explorer_active_survey_key

            and context[1] == str((self._current_sky_explorer_source_image or Path()).resolve())

        )

    def _handle_sky_explorer_survey_progress(self, message: str) -> None:

        if not self._sky_explorer_survey_context_is_current(self._sky_explorer_survey_worker_context):

            return

        progress_message = str(message).strip()

        if not progress_message:

            return

        worker_context = self._sky_explorer_survey_worker_context

        detail_tier = self._sky_explorer_survey_detail_tier_from_context(worker_context)

        title = self._sky_explorer_active_survey_title()

        if detail_tier == _SKY_EXPLORER_SURVEY_DETAIL_PREVIEW:

            status_message = f"{title} preview: {progress_message}"

        else:

            status_message = f"{title} detail: {progress_message}"

        self.statusBar().showMessage(status_message, 4000)

        self._sky_explorer_image_view.set_comparison_loading_message(status_message)

    def _handle_sky_explorer_survey_completed(self, result: object) -> None:

        context = self._sky_explorer_survey_worker_context

        detail_tier = self._sky_explorer_survey_detail_tier_from_context(context)

        self._sky_explorer_survey_worker = None

        self._sky_explorer_survey_worker_context = None

        if self._sky_explorer_survey_context_is_current(context):

            if not self._sky_explorer_survey_context_covers_visible_viewport(context):

                self._sky_explorer_survey_result = None

                self._sky_explorer_survey_result_context = None

                self._sky_explorer_survey_display = None

                self._sky_explorer_image_view.clear_comparison_survey_content()

                self._sky_explorer_survey_set_loading_detail(detail_tier)

                if self._pending_sky_explorer_survey_request is None:

                    self._sky_explorer_survey_refresh_timer.start(0)

            else:

                try:

                    display = self._build_sky_explorer_survey_display(result)

                except Exception as exc:

                    self._handle_sky_explorer_survey_result_error(str(exc))

                else:

                    self._sky_explorer_survey_result = result

                    self._sky_explorer_survey_result_context = context

                    self._sky_explorer_survey_display = display

                    self._sky_explorer_survey_last_error = None

                    self._apply_sky_explorer_survey_comparison()

                    title = self._sky_explorer_active_survey_title()

                    source_label = "cache" if bool(getattr(result, "from_cache", False)) else "CDS"

                    if detail_tier == _SKY_EXPLORER_SURVEY_DETAIL_PREVIEW:

                        try:

                            viewport_specs = self._sky_explorer_survey_viewport_specs()

                        except Exception:

                            viewport_specs = None

                        if viewport_specs is not None and self._sky_explorer_survey_specs_are_distinct(

                            *viewport_specs

                        ):

                            self.statusBar().showMessage(

                                f"{title} preview loaded from {source_label}. Refining detail…",

                                5000,

                            )

                            self._sky_explorer_image_view.set_comparison_loading_message(

                                self._sky_explorer_survey_loading_message_for_detail(

                                    _SKY_EXPLORER_SURVEY_DETAIL_REFINE

                                )

                            )

                            self._sky_explorer_survey_refine_timer.start()

                            self._start_pending_sky_explorer_survey_request()

                            return

                    self._sky_explorer_image_view.set_comparison_loading(False)

                    self.statusBar().showMessage(

                        f"{title} comparison updated from {source_label}. Drag the divider to compare images.",

                        5000,

                    )

        self._start_pending_sky_explorer_survey_request()

    def _handle_sky_explorer_survey_failed(self, message: str) -> None:

        context = self._sky_explorer_survey_worker_context

        detail_tier = self._sky_explorer_survey_detail_tier_from_context(context)

        self._sky_explorer_survey_worker = None

        self._sky_explorer_survey_worker_context = None

        if self._sky_explorer_survey_context_is_current(context):

            if detail_tier == _SKY_EXPLORER_SURVEY_DETAIL_PREVIEW:

                self.statusBar().showMessage(

                    f"{self._sky_explorer_active_survey_title()} preview unavailable; loading full detail…",

                    5000,

                )

                self._request_current_sky_explorer_survey_viewport(

                    force_detail=_SKY_EXPLORER_SURVEY_DETAIL_REFINE,

                )

            else:

                self._handle_sky_explorer_survey_result_error(message)

        self._start_pending_sky_explorer_survey_request()

    def _handle_sky_explorer_survey_result_error(self, message: str) -> None:

        title = dict(_SKY_EXPLORER_SURVEY_OPTIONS).get(

            self._sky_explorer_active_survey_key or "",

            "Survey",

        )

        summary = str(message).strip() or "The survey service did not return an image."

        self.statusBar().showMessage(f"{title} comparison could not be updated: {summary}", 8000)

        error_key = f"{title}: {summary}"

        if error_key != self._sky_explorer_survey_last_error:

            self._sky_explorer_survey_last_error = error_key

            self._append_sky_explorer_workflow_note(f"{title} survey comparison: {summary}")

        self._sky_explorer_image_view.set_comparison_loading(False)

        if self._sky_explorer_active_survey_key:

            self._sky_explorer_image_view.set_comparison_split_enabled(True)

    def _start_pending_sky_explorer_survey_request(self) -> None:

        pending = self._pending_sky_explorer_survey_request

        self._pending_sky_explorer_survey_request = None

        if pending is None:

            return

        request, context = pending

        if not self._sky_explorer_survey_context_is_current(context):

            return

        if context == self._sky_explorer_survey_result_context:

            return

        detail_tier = self._sky_explorer_survey_detail_tier_from_context(context)

        self._start_sky_explorer_survey_request(

            cast(SurveyImageRequest, request),

            context,

            detail_tier=detail_tier,

        )

    def _set_sky_explorer_annotation_tool(self, tool: str, *, refresh: bool = True) -> None:

        normalized_tool = str(tool or "mouse").strip().lower()

        if normalized_tool not in {"mouse", "circle", "ellipse", "text"}:

            normalized_tool = "mouse"

        self._sky_explorer_annotation_tool = normalized_tool

        self._sky_explorer_manual_annotation_drag = None

        self._pending_sky_explorer_text_annotation_position = None

        self._pending_sky_explorer_text_annotation_dragged = False

        self._sync_sky_explorer_annotation_tool_buttons()

        self._sync_sky_explorer_annotation_property_controls()

        if refresh:

            self._refresh_sky_explorer_image_view(reset_view=False, focus_selected=False)

            messages = {

                "mouse": "Mouse tool selected. Drag empty image space to pan; click manual annotations to select them.",

                "circle": "Circle tool selected. Drag on the image to draw a manual circle annotation.",

                "ellipse": "Ellipse tool selected. Drag on the image to draw a manual ellipse annotation.",

                "text": "Text tool selected. Click the image to place manual text.",

            }

            self.statusBar().showMessage(messages.get(normalized_tool, messages["mouse"]), 4000)

    def _sync_sky_explorer_annotation_tool_buttons(self) -> None:

        buttons = getattr(self, "_sky_explorer_annotation_tool_buttons", {})

        active_tool = getattr(self, "_sky_explorer_annotation_tool", "mouse")

        for tool_key, tool_button in buttons.items():

            tool_button.blockSignals(True)

            tool_button.setChecked(tool_key == active_tool)

            tool_button.blockSignals(False)

    def _sync_sky_explorer_annotation_tool_icons(self) -> None:

        buttons = getattr(self, "_sky_explorer_annotation_tool_buttons", {})

        if not buttons:

            return

        icon_color = self._current_custom_theme_colors().get("text", "#f8fafc")

        for tool_key, tool_button in buttons.items():

            tool_button.setIcon(self._create_sky_explorer_annotation_tool_icon(tool_key, color_hex=icon_color))

    def _create_sky_explorer_annotation_tool_icon(self, tool: str, *, color_hex: str) -> QIcon:

        pixmap = QPixmap(20, 20)

        pixmap.fill(Qt.GlobalColor.transparent)

        painter = QPainter(pixmap)

        painter.setRenderHint(QPainter.RenderHint.Antialiasing, True)

        color = QColor(color_hex)

        pen = QPen(color, 1.8)

        pen.setCosmetic(True)

        painter.setPen(pen)

        painter.setBrush(Qt.BrushStyle.NoBrush)

        normalized_tool = str(tool or "mouse").strip().lower()

        if normalized_tool == "mouse":

            path = QPainterPath()

            path.moveTo(4.0, 2.0)

            path.lineTo(4.0, 16.5)

            path.lineTo(8.2, 12.4)

            path.lineTo(10.8, 17.5)

            path.lineTo(12.9, 16.3)

            path.lineTo(10.1, 11.4)

            path.lineTo(15.8, 11.1)

            path.closeSubpath()

            painter.fillPath(path, color)

        elif normalized_tool == "circle":

            painter.drawEllipse(QRectF(3.5, 3.5, 13.0, 13.0))

        elif normalized_tool == "ellipse":

            painter.save()

            painter.translate(10.0, 10.0)

            painter.rotate(-28.0)

            painter.drawEllipse(QRectF(-6.5, -4.0, 13.0, 8.0))

            painter.restore()

        else:

            font = painter.font()

            font.setPointSizeF(11.5)

            font.setBold(True)

            painter.setFont(font)

            painter.drawText(QRectF(0.0, 0.0, 20.0, 20.0), int(Qt.AlignmentFlag.AlignCenter), "T")

        painter.end()

        return QIcon(pixmap)

    def _choose_sky_explorer_annotation_stroke_color(self) -> None:

        selected_color = QColorDialog.getColor(QColor(self._sky_explorer_annotation_stroke_color), self, "Choose Stroke Color")

        if not selected_color.isValid():

            return

        self._sky_explorer_annotation_stroke_color = selected_color.name().lower()

        self._sync_sky_explorer_annotation_stroke_color_button()

    def _choose_sky_explorer_annotation_fill_color(self) -> None:

        selected_color = QColorDialog.getColor(QColor(self._sky_explorer_annotation_fill_color), self, "Choose Fill Color")

        if not selected_color.isValid():

            return

        self._sky_explorer_annotation_fill_color = selected_color.name().lower()

        self._sync_sky_explorer_annotation_fill_color_button()

    def _choose_sky_explorer_annotation_text_color(self) -> None:

        selected_color = QColorDialog.getColor(QColor(self._sky_explorer_annotation_text_color), self, "Choose Text Color")

        if not selected_color.isValid():

            return

        self._sky_explorer_annotation_text_color = selected_color.name().lower()

        self._sync_sky_explorer_annotation_text_color_button()

    def _handle_sky_explorer_annotation_opacity_changed(self, value: int) -> None:

        self._sky_explorer_annotation_opacity = max(0.05, min(1.0, float(value) / 100.0))

        self._sync_sky_explorer_annotation_opacity_controls()

    def _handle_sky_explorer_annotation_opacity_label_dragged(self, delta_x: int) -> None:

        if delta_x == 0:

            return

        current_percent = int(round(max(0.05, min(1.0, float(self._sky_explorer_annotation_opacity))) * 100.0))

        self._handle_sky_explorer_annotation_opacity_changed(max(5, min(100, current_percent + delta_x)))

    def _handle_sky_explorer_annotation_line_width_changed(self, value: float) -> None:

        self._sky_explorer_annotation_line_width = max(0.5, min(12.0, float(value)))

    def _handle_sky_explorer_annotation_text_font_changed(self, font: QFont) -> None:

        self._sky_explorer_annotation_text_font_family = font.family().strip()

    def _handle_sky_explorer_annotation_text_style_changed(self, _index: int) -> None:

        style_value = self._sky_explorer_annotation_text_style_combo.currentData()

        self._sky_explorer_annotation_text_font_style = str(style_value or "regular")

    def _handle_sky_explorer_annotation_text_size_changed(self, value: int) -> None:

        self._sky_explorer_annotation_text_size = max(6.0, float(value))

    def _sync_sky_explorer_annotation_property_controls(self) -> None:

        properties_group = getattr(self, "_sky_explorer_annotation_properties_group", None)

        properties_stack = getattr(self, "_sky_explorer_annotation_properties_stack", None)

        if properties_group is None or properties_stack is None:

            return

        active_tool = getattr(self, "_sky_explorer_annotation_tool", "mouse")

        stack_index = {

            "mouse": 0,

            "circle": 1,

            "ellipse": 1,

            "text": 2,

        }.get(active_tool, 0)

        properties_stack.setCurrentIndex(stack_index)

        properties_group.setVisible(stack_index != 0)

    def _sync_sky_explorer_annotation_opacity_controls(self) -> None:

        opacity_percent = int(round(max(0.05, min(1.0, float(self._sky_explorer_annotation_opacity))) * 100.0))

        opacity_button = getattr(self, "_sky_explorer_annotation_opacity_button", None)

        if opacity_button is not None:

            opacity_button.setText(f"{opacity_percent}%")

        opacity_slider = getattr(self, "_sky_explorer_annotation_opacity_slider", None)

        if opacity_slider is not None:

            opacity_slider.blockSignals(True)

            opacity_slider.setValue(opacity_percent)

            opacity_slider.blockSignals(False)

    def _sync_sky_explorer_annotation_text_font_controls(self) -> None:

        font_combo = getattr(self, "_sky_explorer_annotation_text_font_combo", None)

        style_combo = getattr(self, "_sky_explorer_annotation_text_style_combo", None)

        size_spin = getattr(self, "_sky_explorer_annotation_text_size_spin", None)

        if font_combo is not None and self._sky_explorer_annotation_text_font_family:

            font_combo.blockSignals(True)

            font_combo.setCurrentFont(QFont(self._sky_explorer_annotation_text_font_family))

            font_combo.blockSignals(False)

        if style_combo is not None:

            target_index = style_combo.findData(self._sky_explorer_annotation_text_font_style)

            style_combo.blockSignals(True)

            style_combo.setCurrentIndex(target_index if target_index >= 0 else 0)

            style_combo.blockSignals(False)

        if size_spin is not None:

            size_spin.blockSignals(True)

            size_spin.setValue(int(round(max(6.0, float(self._sky_explorer_annotation_text_size)))))

            size_spin.blockSignals(False)

    def _sync_sky_explorer_annotation_stroke_color_button(self) -> None:

        color_button = getattr(self, "_sky_explorer_annotation_stroke_color_button", None)

        if color_button is None:

            return

        color_value = getattr(self, "_sky_explorer_annotation_stroke_color", "#38bdf8")

        color_button.setStyleSheet(

            f"background-color: {color_value}; border: 1px solid rgba(15, 23, 42, 0.45); border-radius: 6px; padding: 0;"

        )
        color_button.setText("")

    def _sync_sky_explorer_annotation_fill_color_button(self) -> None:

        color_button = getattr(self, "_sky_explorer_annotation_fill_color_button", None)

        if color_button is None:

            return

        color_value = getattr(self, "_sky_explorer_annotation_fill_color", "#38bdf8")

        color_button.setStyleSheet(

            f"background-color: {color_value}; border: 1px solid rgba(15, 23, 42, 0.45); border-radius: 6px; padding: 0;"

        )
        color_button.setText("")

    def _sync_sky_explorer_annotation_text_color_button(self) -> None:

        color_button = getattr(self, "_sky_explorer_annotation_text_color_button", None)

        if color_button is None:

            return

        color_value = getattr(self, "_sky_explorer_annotation_text_color", "#f8fafc")

        color_button.setStyleSheet(

            f"background-color: {color_value}; border: 1px solid rgba(15, 23, 42, 0.45); border-radius: 6px; padding: 0;"

        )
        color_button.setText("")

    def _handle_sky_explorer_show_auto_annotations_toggled(self, is_checked: bool) -> None:

        self._sky_explorer_show_auto_annotations = bool(is_checked)

        self._refresh_sky_explorer_image_view(reset_view=False, focus_selected=False)

        if is_checked:

            self.statusBar().showMessage("Automatic Sky Explorer annotations are visible.", 3000)

        else:

            self.statusBar().showMessage("Automatic Sky Explorer annotations are hidden; manual annotations remain visible.", 4000)

    def _handle_sky_explorer_mag_limit_toggled(self, is_checked: bool) -> None:

        if not is_checked:

            self._refresh_sky_explorer_filtered_view(preserve_selection=True, select_first_row=False)

            return

        source_objects = self._sky_explorer_mag_limit_source_objects()

        if source_objects:

            representative_stars = self._sky_explorer_mag_limit_representative_objects(source_objects)

            self._refresh_sky_explorer_filtered_view(

                preserve_selection=True,

                select_first_row=self._selected_sky_explorer_object() is None and self._current_sky_explorer_result is None,

            )

            if representative_stars:

                self.statusBar().showMessage(f"Mag Limit annotated {len(representative_stars)} representative Gaia stars.", 5000)

            else:

                self.statusBar().showMessage("Mag Limit did not find Gaia stars with usable magnitudes for this field.", 6000)

            return

        self._refresh_sky_explorer_image_view(reset_view=False, focus_selected=False)

        self._start_sky_explorer_mag_limit_query()

    def _set_sky_explorer_mag_limit_checked(self, is_checked: bool) -> None:

        self._sky_explorer_mag_limit_button.blockSignals(True)

        self._sky_explorer_mag_limit_button.setChecked(bool(is_checked))

        self._sky_explorer_mag_limit_button.blockSignals(False)

    def _reset_sky_explorer_image_display_controls(self) -> None:

        self._sync_sky_explorer_image_display_controls()

        self._sky_explorer_image_levels = (0.0, 0.5, 1.0)

        self._sky_explorer_image_curve_points = ()

        self._refresh_sky_explorer_image_view(reset_view=False, focus_selected=False)

        self.statusBar().showMessage("Reset Sky Explorer image display controls.", 3000)

    def _open_sky_explorer_levels_dialog(self) -> None:

        if self._current_sky_explorer_source_image is None or not self._current_sky_explorer_source_image.exists():

            return

        try:

            display = self._cached_annotated_image_display(self._current_sky_explorer_source_image)

        except Exception as exc:

            QMessageBox.warning(self, "Curves unavailable", f"Could not prepare the Sky Explorer preview for curve adjustment.\n\n{exc}")

            return

        dialog = CurvesDialog(

            display=display,

            initial_settings=self._current_sky_explorer_image_render_settings(),

            parent=self,

        )

        if dialog.exec() != int(QDialog.DialogCode.Accepted):

            return

        selected_settings = dialog.selected_settings()

        self._sky_explorer_image_levels = (

            float(selected_settings.black_point),

            float(selected_settings.midtone_point),

            float(selected_settings.white_point),

        )

        self._sky_explorer_image_curve_points = selected_settings.curve_points

        self._refresh_sky_explorer_image_view(reset_view=False, focus_selected=False)

        self.statusBar().showMessage("Applied Sky Explorer image curves.", 3000)

    def _refresh_sky_explorer_image_view(self, *, reset_view: bool, focus_selected: bool) -> None:

        if self._current_sky_explorer_source_image is None or not self._current_sky_explorer_source_image.exists():

            self._sky_explorer_image_view.set_hover_text_formatter(None)

            self._sky_explorer_manual_annotation_drag = None

            self._sky_explorer_image_view.set_message("Open a source image to explore the field.")

            return

        try:

            display = self._cached_annotated_image_display(self._current_sky_explorer_source_image)

        except Exception:

            self._sky_explorer_image_view.set_hover_text_formatter(None)

            self._sky_explorer_image_view.set_message("Could not render the selected Sky Explorer source image preview.")

            return

        self._sky_explorer_image_view.set_hover_text_formatter(self._sky_explorer_hover_coordinate_formatter())

        automatic_overlays, manual_overlays = self._current_sky_explorer_image_overlay_parts()

        self._sky_explorer_image_view.set_content(

            display,

            overlays=[*automatic_overlays, *manual_overlays],

            grid_overlays=[],

            editor_enabled=False,

            reset_view=reset_view,

            safe_margin_fraction=0.0,

            render_settings=self._current_sky_explorer_image_render_settings(),

            direct_edit_enabled=self._sky_explorer_annotation_tool != "mouse",

            direct_edit_draw_enabled=self._sky_explorer_annotation_tool in {"circle", "ellipse", "text"},

            static_overlay_count=len(automatic_overlays),

        )

        if focus_selected:

            sky_object = self._selected_sky_explorer_object()

            if sky_object is not None:

                self._sky_explorer_image_view.focus_on(float(sky_object.pixel_x), float(sky_object.pixel_y), minimum_zoom_scale=3.0)

    def _sky_explorer_current_manual_annotation_key(self) -> str | None:

        image_path = self._current_sky_explorer_source_image

        if image_path is None:

            return None

        try:

            return str(Path(image_path).resolve())

        except Exception:

            return str(image_path)

    def _sky_explorer_manual_annotations_for_current_image(self) -> list[_SkyExplorerManualAnnotation]:

        image_key = self._sky_explorer_current_manual_annotation_key()

        if image_key is None:

            return []

        return self._sky_explorer_manual_annotations_by_image.setdefault(image_key, [])

    def _next_sky_explorer_manual_annotation_id(self) -> str:

        self._sky_explorer_manual_annotation_counter += 1

        return f"annotation-{self._sky_explorer_manual_annotation_counter}"

    def _sky_explorer_manual_annotation_id_from_source_id(self, source_id: object) -> str | None:

        text = str(source_id or "")

        if not text.startswith(_SKY_EXPLORER_MANUAL_ANNOTATION_SOURCE_PREFIX):

            return None

        annotation_id = text[len(_SKY_EXPLORER_MANUAL_ANNOTATION_SOURCE_PREFIX) :].strip()

        return annotation_id or None

    def _sky_explorer_manual_annotation_at(self, image_x: float, image_y: float) -> _SkyExplorerManualAnnotation | None:

        best_annotation: _SkyExplorerManualAnnotation | None = None

        best_score: float | None = None

        for annotation in reversed(self._sky_explorer_manual_annotations_for_current_image()):

            score = self._sky_explorer_manual_annotation_hit_score(annotation, image_x, image_y)

            if score is None:

                continue

            if best_score is None or score < best_score:

                best_score = score

                best_annotation = annotation

        return best_annotation

    def _sky_explorer_manual_annotation_hit_score(self, annotation: _SkyExplorerManualAnnotation, image_x: float, image_y: float) -> float | None:

        dx = float(image_x) - float(annotation.x)

        dy = float(image_y) - float(annotation.y)

        if annotation.shape == "ellipse":

            major_radius = max(6.0, float(annotation.radius) + 4.0)

            minor_radius = max(6.0, float(annotation.minor_radius) + 4.0)

            rotation_radians = math.radians(float(annotation.rotation_degrees))

            cos_rotation = math.cos(rotation_radians)

            sin_rotation = math.sin(rotation_radians)

            ellipse_x = dx * cos_rotation + dy * sin_rotation

            ellipse_y = -dx * sin_rotation + dy * cos_rotation

            score = (ellipse_x * ellipse_x) / (major_radius * major_radius) + (ellipse_y * ellipse_y) / (minor_radius * minor_radius)

            return score if score <= 1.0 else None

        if annotation.shape == "text":

            anchor_point = self._sky_explorer_image_view.image_to_widget(float(annotation.x), float(annotation.y))

            hit_point = self._sky_explorer_image_view.image_to_widget(float(image_x), float(image_y))

            scale_probe = self._sky_explorer_image_view.image_to_widget(float(annotation.x) + 1.0, float(annotation.y))

            effective_scale = max(0.05, math.hypot(scale_probe.x() - anchor_point.x(), scale_probe.y() - anchor_point.y()))

            label = annotation.label.strip() or "Text"

            font = self._sky_explorer_manual_annotation_text_font(annotation)

            if font is None:

                font = QFont()

                font.setPointSizeF(max(6.0, float(annotation.text_size)))

            else:

                font = QFont(font)

            base_size = font.pointSizeF()

            if base_size <= 0.0:

                base_size = float(font.pointSize()) if font.pointSize() > 0 else max(6.0, float(annotation.text_size))

            font.setPointSizeF(max(1.0, base_size * effective_scale))

            metrics = QFontMetricsF(font)

            lines = label.splitlines() or [""]

            line_spacing = max(1.0, metrics.lineSpacing())

            text_bounds = QRectF()

            for line_index, line in enumerate(lines):

                line_bounds = QRectF(metrics.boundingRect(line))

                line_bounds.translate(0.0, float(line_index) * line_spacing)

                text_bounds = line_bounds if text_bounds.isNull() else text_bounds.united(line_bounds)

            text_bounds.translate(anchor_point)

            padding = max(1.0, float(annotation.text_size) * 0.18 * effective_scale)

            text_bounds = text_bounds.adjusted(-padding, -padding, padding, padding)

            if not text_bounds.contains(hit_point):

                return None

            half_width = max(1.0, text_bounds.width() * 0.5)

            half_height = max(1.0, text_bounds.height() * 0.5)

            normalized_dx = (hit_point.x() - text_bounds.center().x()) / half_width

            normalized_dy = (hit_point.y() - text_bounds.center().y()) / half_height

            return normalized_dx * normalized_dx + normalized_dy * normalized_dy

        hit_radius = max(10.0, float(annotation.radius) + 4.0)

        distance_squared = dx * dx + dy * dy

        if distance_squared > hit_radius * hit_radius:

            return None

        return distance_squared / max(1.0, hit_radius * hit_radius)

    def _sky_explorer_manual_annotation_by_id(self, annotation_id: str | None) -> _SkyExplorerManualAnnotation | None:

        if not annotation_id:

            return None

        for annotation in self._sky_explorer_manual_annotations_for_current_image():

            if annotation.annotation_id == annotation_id:

                return annotation

        return None

    def _replace_sky_explorer_manual_annotation(self, updated_annotation: _SkyExplorerManualAnnotation) -> None:

        annotations = self._sky_explorer_manual_annotations_for_current_image()

        for index, annotation in enumerate(annotations):

            if annotation.annotation_id == updated_annotation.annotation_id:

                annotations[index] = updated_annotation

                return

    def _remove_sky_explorer_manual_annotation_by_id(self, annotation_id: str) -> None:

        annotations = self._sky_explorer_manual_annotations_for_current_image()

        annotations[:] = [annotation for annotation in annotations if annotation.annotation_id != annotation_id]

        if self._selected_sky_explorer_manual_annotation_id == annotation_id:

            self._selected_sky_explorer_manual_annotation_id = None

    def _sky_explorer_manual_annotation_handle_at(self, annotation: _SkyExplorerManualAnnotation, image_x: float, image_y: float) -> str | None:

        if annotation.shape == "text":

            return None

        hit_radius = max(7.0, min(18.0, max(float(annotation.radius), float(annotation.minor_radius)) * 0.12))

        if annotation.shape == "ellipse":

            rotation_handle = self._sky_explorer_manual_annotation_rotation_handle_point(annotation)

            if rotation_handle is not None and math.hypot(float(image_x) - rotation_handle[0], float(image_y) - rotation_handle[1]) <= hit_radius + 2.0:

                return "rotate"

            rotation_radians = math.radians(float(annotation.rotation_degrees))

            cos_rotation = math.cos(rotation_radians)

            sin_rotation = math.sin(rotation_radians)

            handle_candidates = (

                ("resize_major", annotation.x + annotation.radius * cos_rotation, annotation.y + annotation.radius * sin_rotation),

                ("resize_major", annotation.x - annotation.radius * cos_rotation, annotation.y - annotation.radius * sin_rotation),

                ("resize_minor", annotation.x - annotation.minor_radius * sin_rotation, annotation.y + annotation.minor_radius * cos_rotation),

                ("resize_minor", annotation.x + annotation.minor_radius * sin_rotation, annotation.y - annotation.minor_radius * cos_rotation),

            )

            for operation, handle_x, handle_y in handle_candidates:

                if math.hypot(float(image_x) - float(handle_x), float(image_y) - float(handle_y)) <= hit_radius:

                    return operation

            return None

        handle_x = float(annotation.x) + float(annotation.radius)

        handle_y = float(annotation.y)

        if math.hypot(float(image_x) - handle_x, float(image_y) - handle_y) <= hit_radius:

            return "resize_radius"

        return None

    def _sky_explorer_manual_annotation_rotation_handle_point(self, annotation: _SkyExplorerManualAnnotation) -> tuple[float, float] | None:

        if annotation.shape != "ellipse":

            return None

        rotation_radians = math.radians(float(annotation.rotation_degrees))

        rotation_distance = max(1.0, float(annotation.radius)) + max(10.0, min(28.0, float(annotation.radius) * 0.35))

        return (

            float(annotation.x) + rotation_distance * math.cos(rotation_radians),

            float(annotation.y) + rotation_distance * math.sin(rotation_radians),

        )

    def _sky_explorer_manual_annotation_text_bounds(self, annotation: _SkyExplorerManualAnnotation) -> QRectF:

        label = annotation.label.strip() or "Text"

        font = self._sky_explorer_manual_annotation_text_font(annotation)

        if font is None:

            font = QFont()

            font.setPointSizeF(max(6.0, float(annotation.text_size)))

        metrics = QFontMetricsF(font)

        lines = label.splitlines() or [""]

        line_spacing = max(1.0, metrics.lineSpacing())

        bounds = QRectF()

        for line_index, line in enumerate(lines):

            line_bounds = QRectF(metrics.boundingRect(line))

            line_bounds.translate(0.0, float(line_index) * line_spacing)

            bounds = line_bounds if bounds.isNull() else bounds.united(line_bounds)

        bounds.translate(float(annotation.x), float(annotation.y))

        padding = max(4.0, float(annotation.text_size) * 0.18)

        return bounds.adjusted(-padding, -padding, padding, padding)

    def _open_sky_explorer_text_entry_dialog(self) -> str | None:

        image_view = getattr(self, "_sky_explorer_image_view", None)

        if image_view is not None:

            image_view.cancel_direct_edit_interaction()

        dialog = QDialog(self)

        dialog.setWindowTitle("Add Text")

        dialog.setModal(True)

        dialog.setMinimumWidth(360)

        theme_colors = self._current_custom_theme_colors()

        panel_background = theme_colors.get("secondary_background", "#111827")

        panel_border = theme_colors.get("secondary_border", "#334155")

        text_color = theme_colors.get("text", "#f8fafc")

        muted_color = QColor(text_color)

        muted_color.setAlphaF(0.72)

        accent_color = theme_colors.get("accent", "#3d8bfd")

        dialog.setStyleSheet(
            "QDialog {"
            f"background-color: {theme_colors.get('background', '#0f172a')};"
            "}"
            "QWidget#skyExplorerTextEntryCard {"
            f"background-color: {panel_background};"
            f"border: 1px solid {panel_border};"
            "border-radius: 12px;"
            "}"
            "QLabel#skyExplorerTextEntryTitle {"
            f"color: {text_color};"
            "font-size: 18px;"
            "font-weight: 700;"
            "border: none;"
            "background: transparent;"
            "}"
            "QLabel#skyExplorerTextEntrySubtitle, QLabel#skyExplorerTextEntryMeta {"
            f"color: {muted_color.name(QColor.NameFormat.HexArgb)};"
            "border: none;"
            "background: transparent;"
            "}"
            "QLineEdit#skyExplorerTextEntryInput {"
            f"background-color: {theme_colors.get('input_background', '#0b1220')};"
            f"color: {text_color};"
            f"border: 1px solid {panel_border};"
            "border-radius: 9px;"
            "padding: 10px 12px;"
            "selection-background-color: " + accent_color + ";"
            "}"
            "QLineEdit#skyExplorerTextEntryInput:focus {"
            f"border: 1px solid {accent_color};"
            "}"
        )

        layout = QVBoxLayout(dialog)

        layout.setContentsMargins(14, 14, 14, 14)

        layout.setSpacing(12)

        card = QWidget(dialog)

        card.setObjectName("skyExplorerTextEntryCard")

        card.setAttribute(Qt.WidgetAttribute.WA_StyledBackground, True)

        card_layout = QVBoxLayout(card)

        card_layout.setContentsMargins(16, 16, 16, 16)

        card_layout.setSpacing(10)

        title_label = QLabel("Add Text", card)

        title_label.setObjectName("skyExplorerTextEntryTitle")

        subtitle_label = QLabel("Place a label at the clicked position. You can drag it afterward to fine-tune the placement.", card)

        subtitle_label.setObjectName("skyExplorerTextEntrySubtitle")

        subtitle_label.setWordWrap(True)

        style_label = {
            "regular": "Regular",
            "bold": "Bold",
            "italic": "Italic",
            "bold-italic": "Bold Italic",
        }.get(self._normalize_sky_explorer_annotation_text_style(self._sky_explorer_annotation_text_font_style), "Regular")

        font_label = self._sky_explorer_annotation_text_font_family.strip() or "System"

        meta_label = QLabel(
            f"{font_label}  |  {style_label}  |  {int(round(max(6.0, float(self._sky_explorer_annotation_text_size))))} pt",
            card,
        )

        meta_label.setObjectName("skyExplorerTextEntryMeta")

        text_input = QLineEdit(card)

        text_input.setObjectName("skyExplorerTextEntryInput")

        text_input.setPlaceholderText("Enter label text")

        text_input.setText("Text")

        text_input.selectAll()

        card_layout.addWidget(title_label)

        card_layout.addWidget(subtitle_label)

        card_layout.addWidget(meta_label)

        card_layout.addWidget(text_input)

        layout.addWidget(card)

        buttons = QDialogButtonBox(QDialogButtonBox.StandardButton.Ok | QDialogButtonBox.StandardButton.Cancel, dialog)

        ok_button = buttons.button(QDialogButtonBox.StandardButton.Ok)

        if ok_button is not None:

            ok_button.setText("Add")

            ok_button.setDefault(True)

        buttons.accepted.connect(dialog.accept)

        buttons.rejected.connect(dialog.reject)

        text_input.returnPressed.connect(dialog.accept)

        layout.addWidget(buttons)

        text_input.setFocus(Qt.FocusReason.ActiveWindowFocusReason)

        if dialog.exec() != int(QDialog.DialogCode.Accepted):

            return None

        return text_input.text().strip() or "Text"

    def _start_sky_explorer_drawn_manual_annotation(self, shape: str, image_x: float, image_y: float) -> None:

        stroke_color = self._sky_explorer_annotation_stroke_color

        fill_color = self._sky_explorer_annotation_fill_color

        text_color = self._sky_explorer_annotation_text_color

        annotation_opacity = max(0.05, min(1.0, float(self._sky_explorer_annotation_opacity)))

        annotation = _SkyExplorerManualAnnotation(

            annotation_id=self._next_sky_explorer_manual_annotation_id(),

            shape=shape,

            label="",

            x=float(image_x),

            y=float(image_y),

            radius=2.0,

            minor_radius=2.0,


            stroke_color=stroke_color,

            fill_color=fill_color,

            text_color=text_color,

            line_width=max(0.5, float(self._sky_explorer_annotation_line_width)),

            opacity=annotation_opacity,

            show_label=False,

        )

        self._sky_explorer_manual_annotations_for_current_image().append(annotation)

        self._selected_sky_explorer_manual_annotation_id = annotation.annotation_id

        self._sky_explorer_manual_annotation_drag = _SkyExplorerManualAnnotationDrag(

            annotation_id=annotation.annotation_id,

            operation="draw_ellipse" if shape == "ellipse" else "draw_circle",

            origin_x=float(image_x),

            origin_y=float(image_y),

            initial_annotation=annotation,

            created_annotation=True,

        )

        self._refresh_sky_explorer_image_view(reset_view=False, focus_selected=False)

    def _add_sky_explorer_text_annotation_from_tool(self, image_x: float, image_y: float) -> None:

        label = self._open_sky_explorer_text_entry_dialog()

        if label is None:

            return

        stroke_color = self._sky_explorer_annotation_stroke_color

        fill_color = self._sky_explorer_annotation_fill_color

        text_color = self._sky_explorer_annotation_text_color

        font_family = self._sky_explorer_annotation_text_font_family.strip()

        font_style = self._normalize_sky_explorer_annotation_text_style(self._sky_explorer_annotation_text_font_style)

        text_size = max(6.0, float(self._sky_explorer_annotation_text_size))

        bounds_probe = self._sky_explorer_manual_annotation_text_bounds(
            _SkyExplorerManualAnnotation(
                annotation_id="preview",
                shape="text",
                label=label,
                x=float(image_x),
                y=float(image_y),
                text_size=text_size,
                text_font_family=font_family,
                text_font_style=font_style,
            )
        )

        annotation = _SkyExplorerManualAnnotation(

            annotation_id=self._next_sky_explorer_manual_annotation_id(),

            shape="text",

            label=label,

            x=float(image_x),

            y=float(image_y),

            radius=max(10.0, bounds_probe.width() * 0.5),

            minor_radius=max(10.0, bounds_probe.height() * 0.5),


            stroke_color=stroke_color,

            fill_color=fill_color,

            text_color=text_color,

            opacity=1.0,

            text_size=text_size,

            text_font_family=font_family,

            text_font_style=font_style,

            show_label=True,

            show_fill=False,

        )

        self._sky_explorer_manual_annotations_for_current_image().append(annotation)

        self._selected_sky_explorer_manual_annotation_id = annotation.annotation_id

        self._refresh_sky_explorer_image_view(reset_view=False, focus_selected=False)

        self.statusBar().showMessage("Added manual text annotation.", 3000)

    def _handle_sky_explorer_image_pressed(self, image_x: float, image_y: float, button: object, modifiers: object) -> None:

        if self._coerce_mouse_button(button) != Qt.MouseButton.LeftButton:

            return

        selected_annotation = self._sky_explorer_manual_annotation_by_id(self._selected_sky_explorer_manual_annotation_id)

        target_annotation = selected_annotation

        operation = self._sky_explorer_manual_annotation_handle_at(selected_annotation, image_x, image_y) if selected_annotation is not None else None

        if operation is None:

            target_annotation = self._sky_explorer_manual_annotation_at(image_x, image_y)

            if target_annotation is not None:

                operation = self._sky_explorer_manual_annotation_handle_at(target_annotation, image_x, image_y) or "move"

        if target_annotation is not None and operation is not None:

            self._selected_sky_explorer_manual_annotation_id = target_annotation.annotation_id

            self._sky_explorer_manual_annotation_drag = _SkyExplorerManualAnnotationDrag(

                annotation_id=target_annotation.annotation_id,

                operation=operation,

                origin_x=float(image_x),

                origin_y=float(image_y),

                initial_annotation=target_annotation,

            )

            self._refresh_sky_explorer_image_view(reset_view=False, focus_selected=False)

            return

        active_tool = str(getattr(self, "_sky_explorer_annotation_tool", "mouse"))

        if active_tool == "mouse":

            return

        if active_tool == "text":

            self._pending_sky_explorer_text_annotation_position = (float(image_x), float(image_y))

            self._pending_sky_explorer_text_annotation_dragged = False

            return

        shape = "ellipse" if active_tool == "ellipse" else "circle"

        self._start_sky_explorer_drawn_manual_annotation(shape, image_x, image_y)

    def _handle_sky_explorer_image_moved(self, image_x: float, image_y: float, buttons: object, _modifiers: object) -> None:

        if not bool(self._coerce_mouse_buttons(buttons) & Qt.MouseButton.LeftButton):

            return

        drag = self._sky_explorer_manual_annotation_drag

        if drag is None:

            pending_text_position = self._pending_sky_explorer_text_annotation_position

            if pending_text_position is not None and math.hypot(float(image_x) - pending_text_position[0], float(image_y) - pending_text_position[1]) > 2.0:

                self._pending_sky_explorer_text_annotation_dragged = True

            return

        drag.drag_started = True

        initial_annotation = drag.initial_annotation

        delta_x = float(image_x) - float(drag.origin_x)

        delta_y = float(image_y) - float(drag.origin_y)

        operation = drag.operation

        if operation == "move":

            updated_annotation = replace(

                initial_annotation,

                x=float(initial_annotation.x) + delta_x,

                y=float(initial_annotation.y) + delta_y,

            )

        elif operation in {"draw_circle", "resize_radius"}:

            radius = max(2.0, math.hypot(float(image_x) - float(initial_annotation.x), float(image_y) - float(initial_annotation.y)))

            updated_annotation = replace(initial_annotation, radius=radius, minor_radius=radius)

        elif operation == "draw_ellipse":

            updated_annotation = replace(

                initial_annotation,

                radius=max(2.0, abs(float(image_x) - float(initial_annotation.x))),

                minor_radius=max(2.0, abs(float(image_y) - float(initial_annotation.y))),

            )

        elif operation in {"resize_major", "resize_minor"}:

            rotation_radians = math.radians(float(initial_annotation.rotation_degrees))

            cos_rotation = math.cos(rotation_radians)

            sin_rotation = math.sin(rotation_radians)

            center_delta_x = float(image_x) - float(initial_annotation.x)

            center_delta_y = float(image_y) - float(initial_annotation.y)

            major_distance = abs(center_delta_x * cos_rotation + center_delta_y * sin_rotation)

            minor_distance = abs(-center_delta_x * sin_rotation + center_delta_y * cos_rotation)

            if operation == "resize_major":

                updated_annotation = replace(initial_annotation, radius=max(2.0, major_distance))

            else:

                updated_annotation = replace(initial_annotation, minor_radius=max(2.0, minor_distance))

        elif operation == "rotate":

            rotation_degrees = math.degrees(math.atan2(float(image_y) - float(initial_annotation.y), float(image_x) - float(initial_annotation.x)))

            updated_annotation = replace(initial_annotation, rotation_degrees=rotation_degrees)

        else:

            return

        self._replace_sky_explorer_manual_annotation(updated_annotation)

        drag.initial_annotation = updated_annotation

        drag.origin_x = float(image_x)

        drag.origin_y = float(image_y)

        self._refresh_sky_explorer_image_view(reset_view=False, focus_selected=False)

    def _handle_sky_explorer_image_released(self, button: object, _modifiers: object) -> None:

        if self._coerce_mouse_button(button) != Qt.MouseButton.LeftButton:

            return

        drag = self._sky_explorer_manual_annotation_drag

        if drag is None:

            pending_text_position = self._pending_sky_explorer_text_annotation_position

            pending_text_dragged = self._pending_sky_explorer_text_annotation_dragged

            self._pending_sky_explorer_text_annotation_position = None

            self._pending_sky_explorer_text_annotation_dragged = False

            if pending_text_position is not None and not pending_text_dragged:

                QTimer.singleShot(
                    0,
                    lambda image_x=pending_text_position[0], image_y=pending_text_position[1]: self._add_sky_explorer_text_annotation_from_tool(image_x, image_y),
                )

            return

        self._sky_explorer_manual_annotation_drag = None

        if drag.created_annotation and not drag.drag_started:

            self._remove_sky_explorer_manual_annotation_by_id(drag.annotation_id)

            self._refresh_sky_explorer_image_view(reset_view=False, focus_selected=False)

            return

        if drag.created_annotation:

            self.statusBar().showMessage("Added manual Sky Explorer annotation. Drag selected handles to resize it.", 3500)

    def _sky_explorer_manual_annotation_to_overlay(self, annotation: _SkyExplorerManualAnnotation) -> ImageOverlay:

        is_selected = annotation.annotation_id == self._selected_sky_explorer_manual_annotation_id

        accent_color = self._current_custom_theme_colors().get("accent", "#3d8bfd") if is_selected else None

        shape = str(annotation.shape or "circle")

        marker_style = "ellipse" if shape == "ellipse" else ("text" if shape == "text" else "circle")

        show_label = True if shape == "text" else bool(annotation.show_label and annotation.label.strip())

        show_marker = True

        annotation_opacity = max(0.0, min(1.0, float(annotation.opacity)))

        stroke_opacity = annotation_opacity

        fill_color = annotation.fill_color if annotation.show_fill and shape != "text" else None

        overlay_font = self._sky_explorer_manual_annotation_text_font(annotation)

        return ImageOverlay(

            source_id=f"{_SKY_EXPLORER_MANUAL_ANNOTATION_SOURCE_PREFIX}{annotation.annotation_id}",

            name=annotation.label.strip() or ("Text" if shape == "text" else "Annotation"),

            x=float(annotation.x),

            y=float(annotation.y),

            aperture_radius=max(1.0, float(annotation.radius)),

            annulus_inner_radius=max(1.0, float(annotation.radius)),

            annulus_outer_radius=max(1.0, float(annotation.radius)),

            color=annotation.stroke_color,

            show_annulus=False,

            show_handles=is_selected and self._sky_explorer_annotation_tool != "mouse",

            marker_style=marker_style,

            show_marker=show_marker,

            show_label=show_label,

            pen_width=max(0.0, float(annotation.line_width)),

            text_color=annotation.text_color,

            fill_color=fill_color,

            fill_opacity=annotation_opacity,

            stroke_opacity=stroke_opacity,

            text_size=max(6.0, float(annotation.text_size)),

            text_opacity=annotation_opacity,

            text_font=overlay_font,

            accent_color=accent_color,

            show_center_dot=shape != "text",

            outline_color="#111827" if shape != "text" else None,

            outline_width=1.0 if shape != "text" else 0.0,

            ellipse_minor_radius=max(1.0, float(annotation.minor_radius)) if shape == "ellipse" else None,

            rotation_degrees=float(annotation.rotation_degrees),

        )

    def _normalize_sky_explorer_annotation_text_style(self, style: str | None) -> str:

        normalized_style = str(style or "regular").strip().lower()

        if normalized_style not in {"regular", "bold", "italic", "bold-italic"}:

            return "regular"

        return normalized_style

    def _sky_explorer_manual_annotation_text_font(self, annotation: _SkyExplorerManualAnnotation) -> QFont | None:

        font_family = str(annotation.text_font_family or "").strip()

        text_style = self._normalize_sky_explorer_annotation_text_style(annotation.text_font_style)

        if not font_family and text_style == "regular":

            return None

        font = QFont(font_family) if font_family else QFont()

        font.setBold(text_style in {"bold", "bold-italic"})

        font.setItalic(text_style in {"italic", "bold-italic"})

        font.setPointSizeF(max(6.0, float(annotation.text_size)))

        return font

    def _sky_explorer_manual_annotation_overlays(self) -> list[ImageOverlay]:

        return [

            self._sky_explorer_manual_annotation_to_overlay(annotation)

            for annotation in self._sky_explorer_manual_annotations_for_current_image()

        ]

    def _add_sky_explorer_manual_annotation(self, shape: str, image_x: float, image_y: float) -> None:

        annotation = self._open_sky_explorer_manual_annotation_dialog(

            None,

            default_shape=shape,

            image_x=image_x,

            image_y=image_y,

        )

        if annotation is None:

            return

        self._sky_explorer_manual_annotations_for_current_image().append(annotation)

        self._selected_sky_explorer_manual_annotation_id = annotation.annotation_id

        self._refresh_sky_explorer_image_view(reset_view=False, focus_selected=False)

        self.statusBar().showMessage("Added manual Sky Explorer annotation.", 3000)

    def _edit_sky_explorer_manual_annotation(self, annotation: _SkyExplorerManualAnnotation) -> None:

        updated_annotation = self._open_sky_explorer_manual_annotation_dialog(

            annotation,

            default_shape=annotation.shape,

            image_x=annotation.x,

            image_y=annotation.y,

        )

        if updated_annotation is None:

            return

        annotations = self._sky_explorer_manual_annotations_for_current_image()

        for index, existing_annotation in enumerate(annotations):

            if existing_annotation.annotation_id == annotation.annotation_id:

                annotations[index] = updated_annotation

                break

        self._selected_sky_explorer_manual_annotation_id = updated_annotation.annotation_id

        self._refresh_sky_explorer_image_view(reset_view=False, focus_selected=False)

        self.statusBar().showMessage("Updated manual Sky Explorer annotation.", 3000)

    def _delete_sky_explorer_manual_annotation(self, annotation: _SkyExplorerManualAnnotation) -> None:

        annotations = self._sky_explorer_manual_annotations_for_current_image()

        annotations[:] = [existing_annotation for existing_annotation in annotations if existing_annotation.annotation_id != annotation.annotation_id]

        if self._selected_sky_explorer_manual_annotation_id == annotation.annotation_id:

            self._selected_sky_explorer_manual_annotation_id = None

        self._refresh_sky_explorer_image_view(reset_view=False, focus_selected=False)

        self.statusBar().showMessage("Deleted manual Sky Explorer annotation.", 3000)

    def _clear_sky_explorer_manual_annotations(self) -> None:

        annotations = self._sky_explorer_manual_annotations_for_current_image()

        if not annotations:

            return

        annotations.clear()

        self._selected_sky_explorer_manual_annotation_id = None

        self._refresh_sky_explorer_image_view(reset_view=False, focus_selected=False)

        self.statusBar().showMessage("Cleared manual Sky Explorer annotations for this image.", 3000)

    def _open_sky_explorer_manual_annotation_dialog(

        self,

        annotation: _SkyExplorerManualAnnotation | None,

        *,

        default_shape: str,

        image_x: float,

        image_y: float,

    ) -> _SkyExplorerManualAnnotation | None:

        dialog = QDialog(self)

        dialog.setWindowTitle("Manual Annotation")

        dialog.setModal(True)

        layout = QVBoxLayout(dialog)

        layout.setContentsMargins(12, 12, 12, 12)

        layout.setSpacing(10)

        form_layout = QFormLayout()

        form_layout.setContentsMargins(0, 0, 0, 0)

        form_layout.setSpacing(8)


        shape_combo = QComboBox(dialog)

        shape_combo.addItem("Text", "text")

        shape_combo.addItem("Circle", "circle")

        shape_combo.addItem("Ellipse", "ellipse")

        resolved_shape = str(annotation.shape if annotation is not None else default_shape or "circle").strip().lower()

        shape_index = shape_combo.findData(resolved_shape)

        shape_combo.setCurrentIndex(shape_index if shape_index >= 0 else shape_combo.findData("circle"))


        label_input = QLineEdit(dialog)

        label_input.setText(annotation.label if annotation is not None else ("Text" if resolved_shape == "text" else ""))


        def make_double_spin(value: float, minimum: float, maximum: float, decimals: int = 2) -> QDoubleSpinBox:

            spin = QDoubleSpinBox(dialog)

            spin.setRange(minimum, maximum)

            spin.setDecimals(decimals)

            spin.setSingleStep(1.0)

            spin.setValue(float(value))

            return spin


        x_spin = make_double_spin(annotation.x if annotation is not None else image_x, -100000.0, 100000.0)

        y_spin = make_double_spin(annotation.y if annotation is not None else image_y, -100000.0, 100000.0)

        radius_spin = make_double_spin(annotation.radius if annotation is not None else 28.0, 1.0, 10000.0)

        minor_radius_spin = make_double_spin(annotation.minor_radius if annotation is not None else 18.0, 1.0, 10000.0)

        rotation_spin = make_double_spin(annotation.rotation_degrees if annotation is not None else 0.0, -360.0, 360.0, decimals=1)

        line_width_spin = make_double_spin(annotation.line_width if annotation is not None else self._sky_explorer_annotation_line_width, 0.0, 12.0, decimals=2)

        line_width_spin.setSingleStep(0.25)

        text_size_spin = make_double_spin(annotation.text_size if annotation is not None else 12.0, 6.0, 96.0, decimals=1)

        text_size_spin.setSingleStep(1.0)

        opacity_spin = QSpinBox(dialog)

        opacity_spin.setRange(5, 100)

        opacity_spin.setSingleStep(5)

        opacity_spin.setSuffix("%")

        opacity_spin.setValue(int(round(max(0.05, min(1.0, annotation.opacity if annotation is not None else self._sky_explorer_annotation_opacity)) * 100.0)))


        show_label_checkbox = QCheckBox("Show text", dialog)

        show_label_checkbox.setChecked(True if annotation is None else annotation.show_label)

        show_fill_checkbox = QCheckBox("Fill shape", dialog)

        show_fill_checkbox.setChecked(True if annotation is None else annotation.show_fill)


        font_family_combo = QFontComboBox(dialog)

        initial_font_family = str(annotation.text_font_family if annotation is not None else self._sky_explorer_annotation_text_font_family).strip()

        if initial_font_family:

            font_family_combo.setCurrentFont(QFont(initial_font_family))

        text_style_combo = QComboBox(dialog)

        text_style_combo.addItem("Regular", "regular")

        text_style_combo.addItem("Bold", "bold")

        text_style_combo.addItem("Italic", "italic")

        text_style_combo.addItem("Bold Italic", "bold-italic")

        initial_text_style = self._normalize_sky_explorer_annotation_text_style(annotation.text_font_style if annotation is not None else self._sky_explorer_annotation_text_font_style)

        initial_text_style_index = text_style_combo.findData(initial_text_style)

        text_style_combo.setCurrentIndex(initial_text_style_index if initial_text_style_index >= 0 else 0)


        color_values = {

            "stroke": annotation.stroke_color if annotation is not None else self._sky_explorer_annotation_stroke_color,

            "fill": annotation.fill_color if annotation is not None else self._sky_explorer_annotation_fill_color,

            "text": annotation.text_color if annotation is not None else self._sky_explorer_annotation_text_color,

        }


        def sync_color_button(button: QPushButton, key: str) -> None:

            color_value = color_values[key]

            button.setText(color_value)

            text_color = self._contrast_text_color(color_value)

            button.setStyleSheet(f"background-color: {color_value}; color: {text_color}; padding: 4px 8px;")


        def make_color_button(key: str) -> QPushButton:

            button = QPushButton(dialog)

            sync_color_button(button, key)


            def choose_color() -> None:

                selected_color = QColorDialog.getColor(QColor(color_values[key]), dialog, "Choose Color")

                if not selected_color.isValid():

                    return

                color_values[key] = selected_color.name().lower()

                sync_color_button(button, key)


            button.clicked.connect(choose_color)

            return button


        stroke_button = make_color_button("stroke")

        fill_button = make_color_button("fill")

        text_button = make_color_button("text")


        def sync_shape_controls() -> None:

            shape = str(shape_combo.currentData() or "circle")

            is_text = shape == "text"

            is_ellipse = shape == "ellipse"

            radius_spin.setEnabled(not is_text)

            minor_radius_spin.setEnabled(is_ellipse)

            rotation_spin.setEnabled(is_ellipse)

            line_width_spin.setEnabled(not is_text)

            opacity_spin.setEnabled(not is_text)

            stroke_button.setEnabled(not is_text)

            fill_button.setEnabled(not is_text)

            font_family_combo.setEnabled(is_text)

            text_style_combo.setEnabled(is_text)

            show_fill_checkbox.setEnabled(not is_text)

            show_label_checkbox.setEnabled(not is_text)

            if is_text:

                show_label_checkbox.setChecked(True)


        shape_combo.currentIndexChanged.connect(lambda _index: sync_shape_controls())

        sync_shape_controls()


        form_layout.addRow("Type", shape_combo)

        form_layout.addRow("Text", label_input)

        form_layout.addRow("X", x_spin)

        form_layout.addRow("Y", y_spin)

        form_layout.addRow("Radius", radius_spin)

        form_layout.addRow("Minor Radius", minor_radius_spin)

        form_layout.addRow("Rotation", rotation_spin)

        form_layout.addRow("Line Width", line_width_spin)

        form_layout.addRow("Text Size", text_size_spin)

        form_layout.addRow("Font", font_family_combo)

        form_layout.addRow("Type", text_style_combo)

        form_layout.addRow("Opacity", opacity_spin)

        form_layout.addRow("Stroke", stroke_button)

        form_layout.addRow("Fill", fill_button)

        form_layout.addRow("Text Color", text_button)

        form_layout.addRow("Label", show_label_checkbox)

        form_layout.addRow("Fill", show_fill_checkbox)

        layout.addLayout(form_layout)

        buttons = QDialogButtonBox(QDialogButtonBox.StandardButton.Ok | QDialogButtonBox.StandardButton.Cancel, dialog)

        buttons.accepted.connect(dialog.accept)

        buttons.rejected.connect(dialog.reject)

        layout.addWidget(buttons)

        if dialog.exec() != int(QDialog.DialogCode.Accepted):

            return None

        shape = str(shape_combo.currentData() or "circle")

        label = label_input.text().strip()

        if shape == "text" and not label:

            label = "Text"

        annotation_id = annotation.annotation_id if annotation is not None else self._next_sky_explorer_manual_annotation_id()

        resolved_text_size = max(6.0, float(text_size_spin.value()))

        resolved_text_font_family = font_family_combo.currentFont().family().strip()

        resolved_text_font_style = self._normalize_sky_explorer_annotation_text_style(str(text_style_combo.currentData() or "regular"))

        resolved_radius = float(radius_spin.value())

        resolved_minor_radius = float(minor_radius_spin.value())

        if shape == "text":

            text_bounds = self._sky_explorer_manual_annotation_text_bounds(
                _SkyExplorerManualAnnotation(
                    annotation_id=annotation_id,
                    shape="text",
                    label=label,
                    x=float(x_spin.value()),
                    y=float(y_spin.value()),
                    text_size=resolved_text_size,
                    text_font_family=resolved_text_font_family,
                    text_font_style=resolved_text_font_style,
                )
            )

            resolved_radius = max(10.0, text_bounds.width() * 0.5)

            resolved_minor_radius = max(10.0, text_bounds.height() * 0.5)

        return _SkyExplorerManualAnnotation(

            annotation_id=annotation_id,

            shape=shape,

            label=label,

            x=float(x_spin.value()),

            y=float(y_spin.value()),

            radius=resolved_radius,

            minor_radius=resolved_minor_radius,

            rotation_degrees=float(rotation_spin.value()),

            stroke_color=color_values["stroke"],

            fill_color=color_values["fill"],

            text_color=color_values["text"],

            line_width=float(line_width_spin.value()),

            text_size=resolved_text_size,

            opacity=1.0 if shape == "text" else max(0.05, min(1.0, float(opacity_spin.value()) / 100.0)),

            text_font_family=resolved_text_font_family,

            text_font_style=resolved_text_font_style,

            show_label=True if shape == "text" else bool(show_label_checkbox.isChecked()),

            show_fill=False if shape == "text" else bool(show_fill_checkbox.isChecked()),

        )

    def _sky_explorer_hover_coordinate_formatter(self) -> Callable[[float, float], str | None] | None:

        wcs = self._sky_explorer_image_wcs()

        if wcs is None:

            return None

        def formatter(image_x: float, image_y: float) -> str | None:

            coordinates = self._sky_explorer_world_coordinates_from_wcs(wcs, image_x, image_y)

            if coordinates is None:

                return None

            ra_value, dec_value = coordinates

            ra_text = Angle(ra_value * u.deg).to_string(unit=u.hour, sep=":", precision=2, pad=True)

            dec_text = Angle(dec_value * u.deg).to_string(unit=u.deg, sep=":", precision=1, alwayssign=True, pad=True)

            return f"RA {ra_text}  Dec {dec_text}"

        return formatter

    def _sky_explorer_image_wcs(self) -> WCS | None:

        overlay_wcs = self._sky_explorer_overlay_projection_wcs()

        if overlay_wcs is not None:

            return overlay_wcs

        source_path = self._current_sky_explorer_source_image

        if source_path is None or not source_path.exists():

            return None

        try:

            wcs = celestial_wcs(read_header(source_path))

        except Exception:

            return None

        if not getattr(wcs, "has_celestial", False):

            return None

        return wcs

    def _sky_explorer_world_coordinates_for_image_point(self, image_x: float, image_y: float) -> tuple[float, float] | None:

        wcs = self._sky_explorer_image_wcs()

        if wcs is None:

            return None

        return self._sky_explorer_world_coordinates_from_wcs(wcs, image_x, image_y)

    def _sky_explorer_world_coordinates_from_wcs(self, wcs: WCS, image_x: float, image_y: float) -> tuple[float, float] | None:

        try:

            ra_deg, dec_deg = wcs.pixel_to_world_values(float(image_x), float(image_y))

            ra_value = float(ra_deg)

            dec_value = float(dec_deg)

        except Exception:

            return None

        if not math.isfinite(ra_value) or not math.isfinite(dec_value):

            return None

        return ra_value, dec_value

    def _handle_sky_explorer_image_context_requested(self, image_x: float, image_y: float, global_position: QPoint, _modifiers: object) -> None:

        menu = QMenu(self)

        world_coordinates = self._sky_explorer_world_coordinates_for_image_point(image_x, image_y)

        search_action = menu.addAction("Search")

        search_action.setEnabled(world_coordinates is not None)

        detect_action = menu.addAction("Detect")

        detect_action.setEnabled(world_coordinates is not None)

        edit_annotation_action = None

        delete_annotation_action = None

        clear_annotations_action = None

        clear_detections_action = None

        target_annotation = self._sky_explorer_manual_annotation_at(image_x, image_y)

        if target_annotation is not None or self._sky_explorer_manual_annotations_for_current_image():

            menu.addSeparator()

            if target_annotation is not None:

                edit_annotation_action = menu.addAction("Edit Annotation")

                delete_annotation_action = menu.addAction("Delete Annotation")

            if self._sky_explorer_manual_annotations_for_current_image():

                menu.addSeparator()

                clear_annotations_action = menu.addAction("Clear Manual Annotations")

        if self._sky_explorer_detected_objects_for_current_image() or self._sky_explorer_detected_object_identities_for_current_image():

            menu.addSeparator()

            clear_detections_action = menu.addAction("Clear Detections")

        selected_action = menu.exec(global_position)

        if selected_action is search_action:

            self._open_simbad_coordinate_search_for_sky_explorer_image_point(image_x, image_y)

        elif selected_action is detect_action:

            self._detect_sky_explorer_targets_at_image_point(image_x, image_y)

        elif selected_action is edit_annotation_action and target_annotation is not None:

            self._edit_sky_explorer_manual_annotation(target_annotation)

        elif selected_action is delete_annotation_action and target_annotation is not None:

            self._delete_sky_explorer_manual_annotation(target_annotation)

        elif selected_action is clear_annotations_action:

            self._clear_sky_explorer_manual_annotations()

        elif selected_action is clear_detections_action:

            self._clear_sky_explorer_detected_targets()

    def _handle_image_context_requested(self, image_x: float, image_y: float, global_position: QPoint, _modifiers: object) -> None:

        menu = QMenu(self)

        search_action = menu.addAction("Search")

        search_action.setEnabled(self._image_world_coordinates_for_current_image_point(image_x, image_y) is not None)

        selected_action = menu.exec(global_position)

        if selected_action is search_action:

            self._open_simbad_coordinate_search_for_image_point(image_x, image_y)

    def _open_simbad_coordinate_search_for_sky_explorer_image_point(self, image_x: float, image_y: float) -> None:

        coordinates = self._sky_explorer_world_coordinates_for_image_point(image_x, image_y)

        if coordinates is None:

            QMessageBox.information(self, "No sky coordinates", "This image does not have usable WCS coordinates at the clicked position.")

            return

        ra_deg, dec_deg = coordinates

        coord_text = f"{ra_deg:.6f} {dec_deg:.6f}"

        search_radius_arcsec = self._sky_explorer_manual_search_radius_arcsec()

        url = (

            "https://simbad.cds.unistra.fr/simbad/sim-coo?Coord="

            f"{quote_plus(coord_text)}&CooFrame=FK5&CooEpoch=2000&CooEqui=2000&Radius={search_radius_arcsec:g}&Radius.unit=arcsec"

        )

        self._open_external_target_url(url, f"Opened SIMBAD coordinate search at {coord_text}.")

    def _open_simbad_coordinate_search_for_image_point(self, image_x: float, image_y: float) -> None:

        coordinates = self._image_world_coordinates_for_current_image_point(image_x, image_y)

        if coordinates is None:

            QMessageBox.information(self, "No sky coordinates", "This image does not have usable WCS coordinates at the clicked position.")

            return

        ra_deg, dec_deg = coordinates

        coord_text = f"{ra_deg:.6f} {dec_deg:.6f}"

        search_radius_arcsec = self._sky_explorer_manual_search_radius_arcsec()

        url = (

            "https://simbad.cds.unistra.fr/simbad/sim-coo?Coord="

            f"{quote_plus(coord_text)}&CooFrame=FK5&CooEpoch=2000&CooEqui=2000&Radius={search_radius_arcsec:g}&Radius.unit=arcsec"

        )

        self._open_external_target_url(url, f"Opened SIMBAD coordinate search at {coord_text}.")

    def _sky_explorer_detected_objects_for_current_image(self) -> list[SkyExplorerObject]:

        image_key = self._sky_explorer_current_manual_annotation_key()

        if image_key is None:

            return []

        return self._sky_explorer_detected_objects_by_image.setdefault(image_key, [])

    def _sky_explorer_detected_object_identities_for_current_image(self) -> set[tuple[str, str, str]]:

        image_key = self._sky_explorer_current_manual_annotation_key()

        if image_key is None:

            return set()

        return self._sky_explorer_detected_object_identities_by_image.setdefault(image_key, set())

    def _sky_explorer_detected_table_objects(self) -> tuple[SkyExplorerObject, ...]:

        return tuple(self._sky_explorer_detected_objects_for_current_image())

    def _sky_explorer_is_detected_object(self, sky_object: SkyExplorerObject) -> bool:

        return self._sky_explorer_object_identity(sky_object) in self._sky_explorer_detected_object_identities_for_current_image()

    def _sky_explorer_layer_key_for_object_type_key(self, type_key: str) -> str:

        definition = _SKY_EXPLORER_OBJECT_TYPE_DEFINITION_BY_KEY.get(type_key)

        if definition is None:

            for mode in ("scientific", "advanced", "simple"):

                for candidate in sky_explorer_object_type_definitions_for_mode(mode):

                    if candidate.key == type_key:

                        definition = candidate

                        break

                if definition is not None:

                    break

        if definition is not None and definition.query_layers:

            return definition.query_layers[0]

        if type_key == "variable_star":

            return "variable_stars"

        if type_key == "exoplanet_host":

            return "exoplanets"

        if type_key == "asteroid_comet":

            return "solar_system"

        if type_key == "star":

            return "gaia_stars"

        if type_key == "general_object":

            return "general_objects"

        return "deep_sky"

    def _sky_explorer_pixel_coordinates_for_world(self, ra_deg: float, dec_deg: float) -> tuple[float, float] | None:

        wcs = self._sky_explorer_image_wcs()

        if wcs is None:

            return None

        try:

            pixel_x, pixel_y = wcs.world_to_pixel_values(float(ra_deg), float(dec_deg))

            x_value = float(pixel_x)

            y_value = float(pixel_y)

        except Exception:

            return None

        if not math.isfinite(x_value) or not math.isfinite(y_value):

            return None

        return x_value, y_value

    def _sky_explorer_sky_object_from_catalog_target(

        self,

        target: CatalogTargetAtCoordinate,

        *,

        click_ra_deg: float,

        click_dec_deg: float,

    ) -> SkyExplorerObject | None:

        pixel_position = self._sky_explorer_pixel_coordinates_for_world(target.ra_deg, target.dec_deg)

        if pixel_position is None:

            return None

        pixel_x, pixel_y = pixel_position

        object_type = str(target.object_type or "Object").strip() or "Object"

        type_key = sky_explorer_object_type_key_for_catalog_type(object_type)

        layer_key = self._sky_explorer_layer_key_for_object_type_key(type_key)

        main_id = str(target.main_id or object_type).strip() or "Object"

        click_coord = SkyCoord(float(click_ra_deg) * u.deg, float(click_dec_deg) * u.deg, frame="icrs")

        object_coord = SkyCoord(float(target.ra_deg) * u.deg, float(target.dec_deg) * u.deg, frame="icrs")

        angular_distance_arcmin = float(click_coord.separation(object_coord).arcmin)

        preferred_name = main_id

        return SkyExplorerObject(

            layer_key=layer_key,

            catalog="simbad",

            source_id=f"detect:{preferred_name}",

            name=preferred_name,

            object_type=object_type,

            ra_deg=float(target.ra_deg),

            dec_deg=float(target.dec_deg),

            pixel_x=float(pixel_x),

            pixel_y=float(pixel_y),

            magnitude=target.visual_magnitude,

            angular_distance_arcmin=angular_distance_arcmin,

            short_label=_short_label_for_name(preferred_name, fallback=preferred_name),

            metadata={

                "main_id": main_id,

                "catalog_type": object_type,

                "object_type": object_type,

                "sky_explorer_detected": True,

            },

        )

    def _sky_explorer_local_detected_objects_near_coordinate(

        self,

        ra_deg: float,

        dec_deg: float,

        *,

        radius_arcsec: float,

    ) -> list[SkyExplorerObject]:

        result = self._current_sky_explorer_result

        if result is None:

            return []

        click_coord = SkyCoord(float(ra_deg) * u.deg, float(dec_deg) * u.deg, frame="icrs")

        targets: list[SkyExplorerObject] = []

        for sky_object in result.objects:

            object_coord = SkyCoord(float(sky_object.ra_deg) * u.deg, float(sky_object.dec_deg) * u.deg, frame="icrs")

            separation_arcsec = float(click_coord.separation(object_coord).arcsec)

            if separation_arcsec > float(radius_arcsec):

                continue

            metadata = dict(sky_object.metadata if isinstance(sky_object.metadata, dict) else {})

            metadata["sky_explorer_detected"] = True

            targets.append(replace(sky_object, metadata=metadata))

        targets.sort(key=lambda item: item.angular_distance_arcmin if math.isfinite(float(item.angular_distance_arcmin)) else float("inf"))

        return targets

    def _sky_explorer_detected_object_dedup_key(self, sky_object: SkyExplorerObject) -> str:

        label = str(sky_object.short_label or sky_object.name or sky_object.source_id).casefold()

        return f"{label}:{sky_object.ra_deg:.6f}:{sky_object.dec_deg:.6f}"

    def _merge_sky_explorer_detected_objects(

        self,

        *object_groups: Sequence[SkyExplorerObject],

    ) -> list[SkyExplorerObject]:

        merged: dict[str, SkyExplorerObject] = {}

        for objects in object_groups:

            for sky_object in objects:

                dedup_key = self._sky_explorer_detected_object_dedup_key(sky_object)

                existing = merged.get(dedup_key)

                if existing is None:

                    merged[dedup_key] = sky_object

                    continue

                existing_distance = float(existing.angular_distance_arcmin) if math.isfinite(float(existing.angular_distance_arcmin)) else float("inf")

                candidate_distance = float(sky_object.angular_distance_arcmin) if math.isfinite(float(sky_object.angular_distance_arcmin)) else float("inf")

                if candidate_distance < existing_distance:

                    merged[dedup_key] = sky_object

        return sorted(

            merged.values(),

            key=lambda item: item.angular_distance_arcmin if math.isfinite(float(item.angular_distance_arcmin)) else float("inf"),

        )

    def _register_sky_explorer_detected_objects(self, objects: Sequence[SkyExplorerObject]) -> None:

        if not objects:

            return

        image_key = self._sky_explorer_current_manual_annotation_key()

        if image_key is None:

            return

        stored_objects = self._sky_explorer_detected_objects_for_current_image()

        explore_identities = {

            self._sky_explorer_object_identity(sky_object)

            for sky_object in (self._current_sky_explorer_result.objects if self._current_sky_explorer_result is not None else ())

        }

        new_table_objects: list[SkyExplorerObject] = []

        detected_identities = self._sky_explorer_detected_object_identities_for_current_image()

        for sky_object in objects:

            identity = self._sky_explorer_object_identity(sky_object)

            detected_identities.add(identity)

            if identity in explore_identities:

                continue

            new_table_objects.append(sky_object)

        self._sky_explorer_detected_object_identities_by_image[image_key] = detected_identities

        self._sky_explorer_detected_objects_by_image[image_key] = self._merge_sky_explorer_detected_objects(

            stored_objects,

            new_table_objects,

        )

    def _detect_sky_explorer_targets_at_image_point(self, image_x: float, image_y: float) -> None:

        coordinates = self._sky_explorer_world_coordinates_for_image_point(image_x, image_y)

        if coordinates is None:

            QMessageBox.information(self, "No sky coordinates", "This image does not have usable WCS coordinates at the clicked position.")

            return

        image_key = self._sky_explorer_current_manual_annotation_key()

        if image_key is None:

            return

        ra_deg, dec_deg = coordinates

        radius_arcsec = self._sky_explorer_manual_search_radius_arcsec()

        local_objects = self._sky_explorer_local_detected_objects_near_coordinate(

            ra_deg,

            dec_deg,

            radius_arcsec=radius_arcsec,

        )

        if local_objects:

            self._register_sky_explorer_detected_objects(local_objects)

            self._refresh_sky_explorer_filtered_view(preserve_selection=True, select_first_row=False)

        worker = self._sky_explorer_detect_worker

        if worker is not None and worker.isRunning():

            self.statusBar().showMessage("Sky Explorer detection already in progress.", 4000)

            return

        self.statusBar().showMessage("Detecting objects at the clicked position...", 0)

        self._append_sky_explorer_workflow_note(

            f"Detecting Sky Explorer objects near RA {ra_deg:.6f}, Dec {dec_deg:.6f} within {radius_arcsec:g} arcsec."

        )

        self._sky_explorer_detect_worker = SkyExplorerDetectWorker(

            image_key,

            ra_deg,

            dec_deg,

            radius_arcsec=radius_arcsec,

            parent=self,

        )

        self._sky_explorer_detect_worker.detect_completed.connect(self._handle_sky_explorer_detect_completed)

        self._sky_explorer_detect_worker.detect_failed.connect(self._handle_sky_explorer_detect_failed)

        self._sky_explorer_detect_worker.finished.connect(self._clear_sky_explorer_detect_worker)

        self._sky_explorer_detect_worker.start()

    def _clear_sky_explorer_detect_worker(self) -> None:

        sender = self.sender()

        if sender is self._sky_explorer_detect_worker:

            self._sky_explorer_detect_worker = None

    def _handle_sky_explorer_detect_completed(self, result: SkyExplorerDetectResult) -> None:

        if str(result.image_key) != str(self._sky_explorer_current_manual_annotation_key() or ""):

            return

        catalog_objects = [

            converted_object

            for target in result.targets

            if (

                converted_object := self._sky_explorer_sky_object_from_catalog_target(

                    target,

                    click_ra_deg=result.click_ra_deg,

                    click_dec_deg=result.click_dec_deg,

                )

            )

            is not None

        ]

        self._register_sky_explorer_detected_objects(catalog_objects)

        self._refresh_sky_explorer_filtered_view(preserve_selection=True, select_first_row=False)

        detected_count = len(self._sky_explorer_detected_object_identities_for_current_image())

        if detected_count:

            labels = ", ".join(

                sky_object.short_label or sky_object.name

                for sky_object in self._sky_explorer_detected_table_objects()[:3]

            )

            if not labels:

                labels = ", ".join(

                    sky_object.short_label or sky_object.name

                    for sky_object in catalog_objects[:3]

                )

            extra_count = max(0, detected_count - 3)

            if extra_count:

                labels = f"{labels} (+{extra_count} more)" if labels else f"{detected_count} object(s)"

            message = f"Detected {detected_count} object(s): {labels}." if labels else f"Detected {detected_count} object(s)."

        else:

            message = "No catalog objects were found near the clicked position."

        self.statusBar().showMessage(message, 7000)

        self._append_sky_explorer_workflow_note(message)

    def _handle_sky_explorer_detect_failed(self, image_key: str, message: str) -> None:

        if str(image_key) != str(self._sky_explorer_current_manual_annotation_key() or ""):

            return

        self.statusBar().showMessage(f"Sky Explorer detection failed: {message}", 7000)

        self._append_sky_explorer_workflow_note(f"Sky Explorer detection failed: {message}")

        QMessageBox.warning(self, "Detection failed", message)

    def _clear_sky_explorer_detected_targets(self) -> None:

        image_key = self._sky_explorer_current_manual_annotation_key()

        if image_key is None:

            return

        self._sky_explorer_detected_objects_by_image[image_key] = []

        self._sky_explorer_detected_object_identities_by_image[image_key] = set()

        self._refresh_sky_explorer_filtered_view(preserve_selection=True, select_first_row=False)

        self.statusBar().showMessage("Cleared Sky Explorer detections for the current image.", 4000)

    def _open_sky_explorer_object_details(self, sky_object: SkyExplorerObject) -> None:

        url, status_message = self._sky_explorer_object_details_url(sky_object)

        self._open_external_target_url(url, status_message)

    def _sky_explorer_object_details_url(self, sky_object: SkyExplorerObject) -> tuple[str, str]:

        catalog = str(sky_object.catalog or "").strip().lower()

        source_id = str(sky_object.source_id or "").strip()

        name = str(sky_object.name or "").strip()

        identifier = name or source_id

        if catalog == "gaia-dr3":

            gaia_identifier = f"Gaia DR3 {source_id or name}".strip()

            return (

                f"https://vizier.cds.unistra.fr/viz-bin/VizieR-S?{quote_plus(gaia_identifier)}",

                f"Opened Gaia DR3 details for {gaia_identifier} in CDS/VizieR.",

            )

        if catalog == "vsx":

            target_name = identifier or f"{sky_object.ra_deg:.6f} {sky_object.dec_deg:.6f}"

            return (

                f"https://www.aavso.org/vsx/index.php?view=results.submit1&targetcenter={quote_plus(target_name)}&format=d",

                f"Opened VSX details for {target_name}.",

            )

        if catalog == "nasa-exoplanet-archive":

            target_name = identifier or f"{sky_object.ra_deg:.6f} {sky_object.dec_deg:.6f}"

            return (

                f"https://exoplanetarchive.ipac.caltech.edu/overview/{quote_plus(target_name)}",

                f"Opened NASA Exoplanet Archive details for {target_name}.",

            )

        if catalog == "skybot":

            target_name = identifier or f"{sky_object.ra_deg:.6f} {sky_object.dec_deg:.6f}"

            return (

                f"https://ssd.jpl.nasa.gov/tools/sbdb_lookup.html#/?sstr={quote_plus(target_name)}",

                f"Opened JPL Small-Body Database lookup for {target_name}.",

            )

        if catalog == "hyperleda":

            target_name = identifier or f"{sky_object.ra_deg:.6f} {sky_object.dec_deg:.6f}"

            return (

                f"https://leda.univ-lyon1.fr/ledacat.cgi?o={quote_plus(target_name)}",

                f"Opened HyperLEDA details for {target_name}.",

            )

        if catalog == "ngc2000" and identifier:

            return (

                f"https://vizier.cds.unistra.fr/viz-bin/VizieR-S?{quote_plus(identifier)}",

                f"Opened NGC2000/VizieR details for {identifier}.",

            )

        if identifier:

            return (

                f"https://simbad.cds.unistra.fr/simbad/sim-id?Ident={quote_plus(identifier)}",

                f"Opened SIMBAD details for {identifier}.",

            )

        coord_text = f"{sky_object.ra_deg:.6f} {sky_object.dec_deg:.6f}"

        url = (

            "https://simbad.cds.unistra.fr/simbad/sim-coo?Coord="

            f"{quote_plus(coord_text)}&CooFrame=FK5&CooEpoch=2000&CooEqui=2000&Radius=2&Radius.unit=arcsec"

        )

        return url, f"Opened SIMBAD coordinate search at {coord_text}."

    def _sky_explorer_overlay_source_id(self, sky_object: SkyExplorerObject) -> str:

        return f"sky-explorer:{sky_object.layer_key}:{sky_object.catalog}:{sky_object.source_id}"

    def _sky_explorer_overlay_fill_opacity(self) -> float:

        settings = self._ensure_settings()

        return max(0.0, min(1.0, float(getattr(settings, "sky_explorer_fill_opacity", 0.25))))

    def _sky_explorer_overlay_stroke_opacity(self) -> float:

        settings = self._ensure_settings()

        return max(0.0, min(1.0, float(getattr(settings, "sky_explorer_stroke_opacity", 1.0))))

    def _current_sky_explorer_image_overlays(self) -> list[ImageOverlay]:

        automatic_overlays, manual_overlays = self._current_sky_explorer_image_overlay_parts()

        return [*automatic_overlays, *manual_overlays]

    def _current_sky_explorer_image_overlay_parts(self) -> tuple[list[ImageOverlay], list[ImageOverlay]]:

        if not self._sky_explorer_show_auto_annotations:

            return [], self._sky_explorer_manual_annotation_overlays()

        overlays = self._sky_explorer_automatic_image_overlays()

        return overlays, self._sky_explorer_manual_annotation_overlays()

    def _sky_explorer_automatic_image_overlays(self) -> list[ImageOverlay]:

        signature = self._sky_explorer_automatic_overlay_cache_key()

        if signature == self._sky_explorer_automatic_overlay_cache_signature:

            return list(self._sky_explorer_automatic_overlay_cache)

        overlays = self._build_sky_explorer_automatic_image_overlays()

        self._sky_explorer_automatic_overlay_cache_signature = signature

        self._sky_explorer_automatic_overlay_cache = list(overlays)

        return overlays

    def _sky_explorer_automatic_overlay_cache_key(self) -> tuple[object, ...]:

        result = self._current_sky_explorer_result

        mag_limit_result = self._sky_explorer_mag_limit_result

        selected_object = self._selected_sky_explorer_object()

        selected_identity = self._sky_explorer_object_identity(selected_object) if selected_object is not None else None

        settings = self._ensure_settings()

        source_image = self._current_sky_explorer_source_image

        source_key = str(source_image.resolve()) if source_image is not None else ""

        font_signature = tuple(

            sorted((key, font.toString()) for key, font in self._sky_explorer_object_type_font_overrides.items())

        )

        return (

            source_key,

            id(result),

            len(result.objects) if result is not None else 0,

            id(mag_limit_result),

            len(mag_limit_result.objects) if mag_limit_result is not None else 0,

            tuple(sorted(self._selected_sky_explorer_object_type_keys())),

            selected_identity,

            bool(self._sky_explorer_mag_limit_button.isChecked()),

            self._current_sky_explorer_gaia_query_signature(),

            round(float(getattr(settings, "sky_explorer_fill_opacity", 0.25)), 4),

            round(float(getattr(settings, "sky_explorer_stroke_opacity", 1.0)), 4),

            bool(getattr(settings, "sky_explorer_scale_overlay_strokes", True)),

            bool(getattr(settings, "sky_explorer_scale_extended_nebulae", True)),

            bool(getattr(settings, "sky_explorer_annotated_galaxy_require_shape_metadata", False)),

            bool(getattr(settings, "sky_explorer_annotated_galaxy_max_magnitude_enabled", False)),

            round(float(getattr(settings, "sky_explorer_annotated_galaxy_max_magnitude", 17.0)), 4),

            int(getattr(settings, "sky_explorer_mag_limit_examples_per_bin", 1)),

            str(settings.sky_explorer_mag_limit_marker_color).strip().lower(),

            str(settings.sky_explorer_mag_limit_marker_stroke_color).strip().lower(),

            round(float(settings.sky_explorer_mag_limit_marker_stroke_width), 3),

            round(float(settings.sky_explorer_mag_limit_target_size), 3),

            str(settings.sky_explorer_mag_limit_text_color).strip().lower(),

            str(settings.sky_explorer_mag_limit_text_stroke_color).strip().lower(),

            round(float(settings.sky_explorer_mag_limit_text_stroke_width), 3),

            round(float(settings.sky_explorer_mag_limit_text_size), 3),

            tuple(sorted(self._sky_explorer_object_type_color_overrides.items())),

            tuple(sorted(self._sky_explorer_object_group_color_overrides.items())),

            tuple(sorted(self._sky_explorer_object_type_text_color_overrides.items())),

            font_signature,

            self._current_custom_theme_colors().get("accent", "#3d8bfd"),

            tuple(sorted(self._sky_explorer_detected_object_identities_for_current_image())),

            len(self._sky_explorer_detected_table_objects()),

        )

    def _build_sky_explorer_automatic_image_overlays(self) -> list[ImageOverlay]:

        result = self._current_sky_explorer_result

        visible_object_types = set(self._selected_sky_explorer_object_type_keys())

        selected_object = self._selected_sky_explorer_object()

        visible_objects: list[SkyExplorerObject] = []

        if result is not None:

            visible_objects = [
                sky_object
                for sky_object in result.objects
                if visible_object_types.intersection(sky_explorer_object_type_keys_for_object(sky_object))
            ]

            visible_objects = [
                sky_object for sky_object in visible_objects if self._should_annotate_sky_explorer_object(sky_object)
            ]

        detected_objects = self._sky_explorer_detected_table_objects()

        detected_identities = self._sky_explorer_detected_object_identities_for_current_image()

        annotate_objects = list(visible_objects)

        seen_identities = {self._sky_explorer_object_identity(sky_object) for sky_object in annotate_objects}

        for sky_object in detected_objects:

            identity = self._sky_explorer_object_identity(sky_object)

            if identity in seen_identities:

                continue

            annotate_objects.append(sky_object)

            seen_identities.add(identity)

        if result is not None:

            for sky_object in result.objects:

                identity = self._sky_explorer_object_identity(sky_object)

                if identity not in detected_identities or identity in seen_identities:

                    continue

                annotate_objects.append(sky_object)

                seen_identities.add(identity)

        if not annotate_objects:

            return self._sky_explorer_mag_limit_image_overlays(self._sky_explorer_mag_limit_source_objects())

        label_object_keys = self._sky_explorer_overlay_labeled_object_keys(annotate_objects)

        selected_accent_color = self._current_custom_theme_colors().get("accent", "#3d8bfd")

        fill_opacity = self._sky_explorer_overlay_fill_opacity()

        stroke_opacity = self._sky_explorer_overlay_stroke_opacity()

        overlay_wcs = self._sky_explorer_overlay_projection_wcs()

        overlays: list[ImageOverlay] = []

        for sky_object in annotate_objects:

            definition = self._sky_explorer_definition_for_object(sky_object, preferred_keys=visible_object_types)

            if definition is not None:

                stroke_color, fill_color = self._sky_explorer_object_type_colors_for_key(definition.key, definition=definition)

                text_color = self._sky_explorer_object_type_text_color_for_key(definition.key, stroke_color=stroke_color, fill_color=fill_color)

                text_font = self._sky_explorer_object_type_font_for_key(definition.key)

            else:

                stroke_color = "#f8fafc"

                fill_color = _SKY_EXPLORER_LAYER_COLORS.get(sky_object.layer_key, "#f8fafc")

                text_color = stroke_color

                text_font = None

            is_selected = selected_object is not None and selected_object.source_id == sky_object.source_id and selected_object.layer_key == sky_object.layer_key

            marker_style, aperture_radius, ellipse_minor_radius, rotation_degrees = self._sky_explorer_overlay_geometry_for_object(
                sky_object,
                wcs=overlay_wcs,
            )
            overlay_text_size = self._sky_explorer_overlay_text_size_for_radius(
                aperture_radius,
                base_size=self._sky_explorer_overlay_base_text_size(text_font),
            )
            overlay_text_font = self._sky_explorer_overlay_font_with_size(
                text_font,
                point_size=overlay_text_size,
            )
            overlay_pen_width = self._sky_explorer_overlay_pen_width_for_radius(
                aperture_radius,
                is_selected=is_selected,
            )

            overlays.append(

                ImageOverlay(

                    source_id=self._sky_explorer_overlay_source_id(sky_object),

                    name=sky_object.short_label,

                    x=float(sky_object.pixel_x),

                    y=float(sky_object.pixel_y),

                    aperture_radius=aperture_radius,

                    annulus_inner_radius=aperture_radius,

                    annulus_outer_radius=aperture_radius,

                    color=stroke_color,

                    show_annulus=False,

                    marker_style=marker_style,

                    show_label=(
                        self._sky_explorer_is_detected_object(sky_object)
                        or is_selected
                        or self._sky_explorer_object_identity(sky_object) in label_object_keys
                    ),

                    pen_width=overlay_pen_width,

                    text_color=text_color,

                    text_font=overlay_text_font,

                    text_size=None if overlay_text_font is not None else overlay_text_size,

                    fill_color=fill_color,

                    fill_opacity=fill_opacity,

                    stroke_opacity=stroke_opacity,

                    accent_color=selected_accent_color if is_selected else None,

                    outline_color="#111827",

                    outline_width=self._sky_explorer_overlay_outline_width_for_pen_width(overlay_pen_width),

                    ellipse_minor_radius=ellipse_minor_radius,

                    rotation_degrees=rotation_degrees,

                )

            )

        overlays.extend(self._sky_explorer_mag_limit_image_overlays(self._sky_explorer_mag_limit_source_objects()))

        return overlays

    def _sky_explorer_mag_limit_source_objects(self) -> tuple[SkyExplorerObject, ...]:

        current_signature = self._current_sky_explorer_gaia_query_signature()

        current_result = self._current_sky_explorer_result

        if (
            self._sky_explorer_result_matches_current_source(current_result)
            and self._sky_explorer_has_mag_limit_gaia_objects(current_result.objects)
            and self._sky_explorer_result_has_full_mag_limit_gaia_coverage(current_result)
            and self._sky_explorer_gaia_query_signature_matches(self._sky_explorer_result_gaia_query_signature, current_signature)
        ):

            return tuple(current_result.objects)

        mag_limit_result = self._sky_explorer_mag_limit_result

        current_mag_limit_signature = self._current_sky_explorer_mag_limit_query_signature()

        if (
            self._sky_explorer_result_matches_current_source(mag_limit_result)
            and self._sky_explorer_has_mag_limit_gaia_objects(mag_limit_result.objects)
            and self._sky_explorer_result_has_full_mag_limit_gaia_coverage(mag_limit_result)
            and self._sky_explorer_gaia_query_signature_matches(self._sky_explorer_mag_limit_query_signature, current_mag_limit_signature)
        ):

            return tuple(mag_limit_result.objects)

        return ()

    def _current_sky_explorer_mag_limit_query_signature(self) -> tuple[float,]:

        settings = self._ensure_settings()

        return (round(float(getattr(settings, "sky_explorer_gaia_max_magnitude", 17.0)), 6),)

    def _current_sky_explorer_gaia_query_signature(self) -> tuple[float, bool, int | None]:

        settings = self._ensure_settings()

        hard_cap_enabled = bool(getattr(settings, "sky_explorer_gaia_hard_cap_enabled", False))

        hard_cap_rows = max(1, int(getattr(settings, "sky_explorer_gaia_hard_cap_rows", 1000))) if hard_cap_enabled else None

        return (round(float(getattr(settings, "sky_explorer_gaia_max_magnitude", 17.0)), 6), hard_cap_enabled, hard_cap_rows)

    def _sky_explorer_gaia_query_signature_matches(

        self,

        cached_signature: tuple[float, bool, int | None] | None,

        current_signature: tuple[float, bool, int | None],

    ) -> bool:

        if cached_signature is None:

            return True

        return cached_signature == current_signature

    def _sky_explorer_result_matches_current_source(self, result: SkyExplorerResult | None) -> bool:

        source_path = self._current_sky_explorer_source_image

        return result is not None and source_path is not None and Path(result.source_path) == Path(source_path)

    def _sky_explorer_is_mag_limit_measurement_object(self, sky_object: SkyExplorerObject) -> bool:

        metadata = sky_object.metadata if isinstance(sky_object.metadata, dict) else {}

        return bool(metadata.get("sky_explorer_mag_limit_measurement"))

    def _sky_explorer_mag_limit_measurement_group_info(self) -> tuple[str, str, int]:

        return ("magnitude_limit_measurement", "Magnitude Limit Measurement", len(_SKY_EXPLORER_OBJECT_TYPE_GROUP_ORDER) + 1)

    def _sky_explorer_mag_limit_table_objects(self) -> tuple[SkyExplorerObject, ...]:

        if not self._sky_explorer_mag_limit_button.isChecked():

            return ()

        source_objects = self._sky_explorer_mag_limit_source_objects()

        if not source_objects:

            return ()

        measurement_objects: list[SkyExplorerObject] = []

        for sky_object in self._sky_explorer_mag_limit_representative_objects(source_objects):

            metadata = dict(sky_object.metadata or {})

            metadata["sky_explorer_mag_limit_measurement"] = True

            measurement_name = self._sky_explorer_mag_limit_label_name(sky_object)

            measurement_objects.append(

                replace(

                    sky_object,

                    name=measurement_name,

                    short_label=measurement_name,

                    metadata=metadata,

                )

            )

        return tuple(measurement_objects)

    def _sky_explorer_result_has_full_mag_limit_gaia_coverage(self, result: SkyExplorerResult | None) -> bool:

        if result is None:

            return False

        for summary in result.layer_summaries:

            if summary.layer_key != "gaia_stars":

                continue

            summary_note = str(getattr(summary, "note", "") or "").casefold()

            return not summary_note.startswith("showing the brightest")

        return False

    def _sky_explorer_has_mag_limit_gaia_objects(self, objects: Sequence[SkyExplorerObject]) -> bool:

        for sky_object in objects:

            if sky_object.layer_key != "gaia_stars":

                continue

            magnitude = _sky_explorer_numeric_magnitude(sky_object)

            if magnitude is not None and math.isfinite(float(magnitude)):

                return True

        return False

    def _sky_explorer_mag_limit_label_name(self, sky_object: SkyExplorerObject) -> str:

        metadata = sky_object.metadata if isinstance(sky_object.metadata, dict) else {}

        preferred_display_name = metadata.get("preferred_display_name")

        if isinstance(preferred_display_name, str) and preferred_display_name.strip():

            return preferred_display_name.strip()

        return str(sky_object.short_label or sky_object.name or sky_object.source_id).strip()

    def _sky_explorer_mag_limit_style_key(self) -> str:

        for key in ("star", "open_cluster", "globular_cluster", "association"):

            if key in _SKY_EXPLORER_OBJECT_TYPE_DEFINITION_BY_KEY:

                return key

        return "star"

    def _sky_explorer_mag_limit_overlay_style(self) -> tuple[float, float, str, str, float, str, str, float]:

        settings = self._ensure_settings()

        target_size = float(settings.sky_explorer_mag_limit_target_size)

        text_size = float(settings.sky_explorer_mag_limit_text_size)

        fill_color = str(settings.sky_explorer_mag_limit_marker_color).strip().lower() or "#3d8bfd"

        stroke_color = str(settings.sky_explorer_mag_limit_marker_stroke_color).strip().lower() or "#111827"

        stroke_width = float(settings.sky_explorer_mag_limit_marker_stroke_width)

        text_color = str(settings.sky_explorer_mag_limit_text_color).strip().lower() or "#111827"

        text_stroke_color = str(settings.sky_explorer_mag_limit_text_stroke_color).strip().lower() or "#ffffff"

        text_stroke_width = float(settings.sky_explorer_mag_limit_text_stroke_width)

        return target_size, text_size, fill_color, stroke_color, stroke_width, text_color, text_stroke_color, text_stroke_width

    def _sky_explorer_mag_limit_image_overlays(self, objects: Sequence[SkyExplorerObject]) -> list[ImageOverlay]:

        if not self._sky_explorer_mag_limit_button.isChecked():

            return []

        selected_stars = self._sky_explorer_mag_limit_representative_objects(objects)

        if not selected_stars:

            return []

        style_key = self._sky_explorer_mag_limit_style_key()

        (
            target_size,
            text_size,
            fill_color,
            stroke_color,
            stroke_width,
            text_color,
            text_stroke_color,
            text_stroke_width,
        ) = self._sky_explorer_mag_limit_overlay_style()

        text_font = self._sky_explorer_object_type_font_for_key(style_key)

        fill_opacity = self._sky_explorer_overlay_fill_opacity()

        stroke_opacity = self._sky_explorer_overlay_stroke_opacity()

        selected_object = self._selected_sky_explorer_object()

        selected_accent_color = self._current_custom_theme_colors().get("accent", "#3d8bfd")

        overlays: list[ImageOverlay] = []

        for sky_object in selected_stars:

            magnitude = _sky_explorer_numeric_magnitude(sky_object)

            if magnitude is None:

                continue

            is_selected = (

                selected_object is not None

                and selected_object.layer_key == sky_object.layer_key

                and selected_object.catalog == sky_object.catalog

                and selected_object.source_id == sky_object.source_id

            )

            marker_style = "circle"

            aperture_radius = max(2.0, float(target_size))

            ellipse_minor_radius = None

            rotation_degrees = 0.0

            overlay_text_size = max(7.0, float(text_size))

            overlay_text_font = self._sky_explorer_overlay_font_with_size(

                text_font,

                point_size=overlay_text_size,

            )

            overlay_pen_width = max(0.0, float(stroke_width))

            overlays.append(

                ImageOverlay(

                    source_id=f"mag-limit:{self._sky_explorer_overlay_source_id(sky_object)}",

                    name=f"{self._sky_explorer_mag_limit_label_name(sky_object)}\nG {float(magnitude):.1f}",

                    x=float(sky_object.pixel_x),

                    y=float(sky_object.pixel_y),

                    aperture_radius=aperture_radius,

                    annulus_inner_radius=aperture_radius,

                    annulus_outer_radius=aperture_radius,

                    color=stroke_color,

                    show_annulus=False,

                    marker_style=marker_style,

                    show_label=True,

                    pen_width=overlay_pen_width,

                    text_color=text_color,

                    text_font=overlay_text_font,

                    text_size=None if overlay_text_font is not None else overlay_text_size,

                    text_outline_color=text_stroke_color if text_stroke_width > 0.0 else None,

                    text_outline_width=text_stroke_width if text_stroke_width > 0.0 else 0.0,

                    fill_color=fill_color,

                    fill_opacity=fill_opacity,

                    stroke_opacity=stroke_opacity,

                    accent_color=selected_accent_color if is_selected else None,

                    outline_color=None,

                    outline_width=0.0,

                    ellipse_minor_radius=ellipse_minor_radius,

                    rotation_degrees=rotation_degrees,

                )

            )

        return overlays

    def _sky_explorer_mag_limit_representative_objects(self, objects: Sequence[SkyExplorerObject]) -> tuple[SkyExplorerObject, ...]:

        settings = self._ensure_settings()

        examples_per_bin = max(1, min(10, int(getattr(settings, "sky_explorer_mag_limit_examples_per_bin", 1))))

        objects_by_bin: dict[float, list[tuple[SkyExplorerObject, float]]] = {}

        for sky_object in objects:

            if sky_object.layer_key != "gaia_stars":

                continue

            magnitude = _sky_explorer_numeric_magnitude(sky_object)

            if magnitude is None or not math.isfinite(float(magnitude)):

                continue

            magnitude_value = float(magnitude)

            bin_start = math.floor(magnitude_value * 2.0) / 2.0

            objects_by_bin.setdefault(bin_start, []).append((sky_object, magnitude_value))

        selected_objects: list[SkyExplorerObject] = []

        for bin_start in sorted(objects_by_bin):

            bin_center = bin_start + 0.25

            ranked_objects = sorted(

                objects_by_bin[bin_start],

                key=lambda item: (

                    abs(item[1] - bin_center),

                    item[1],

                    item[0].angular_distance_arcmin if math.isfinite(float(item[0].angular_distance_arcmin)) else 1.0e9,

                    str(item[0].short_label or item[0].name or item[0].source_id).casefold(),

                ),

            )

            selected_objects.extend(sky_object for sky_object, _magnitude in ranked_objects[:examples_per_bin])

        return tuple(selected_objects)

    def _should_annotate_sky_explorer_object(self, sky_object: SkyExplorerObject) -> bool:

        object_type_keys = set(sky_explorer_object_type_keys_for_object(sky_object))

        if "galaxy" not in object_type_keys:

            return True

        settings = self._ensure_settings()

        if bool(getattr(settings, "sky_explorer_annotated_galaxy_require_shape_metadata", False)) and not self._sky_explorer_galaxy_has_shape_metadata(sky_object):

            return False

        if bool(getattr(settings, "sky_explorer_annotated_galaxy_max_magnitude_enabled", False)):

            numeric_magnitude = _sky_explorer_numeric_magnitude(sky_object)

            if numeric_magnitude is None:

                return False

            max_magnitude = float(getattr(settings, "sky_explorer_annotated_galaxy_max_magnitude", 17.0))

            if numeric_magnitude > max_magnitude:

                return False

        return True

    def _sky_explorer_galaxy_has_shape_metadata(self, sky_object: SkyExplorerObject) -> bool:

        metadata = sky_object.metadata if isinstance(sky_object.metadata, dict) else {}

        major_axis_arcmin = self._sky_explorer_metadata_float(metadata, "catalog_major_axis_arcmin", "catalog_size_arcmin")

        minor_axis_arcmin = self._sky_explorer_metadata_float(metadata, "catalog_minor_axis_arcmin")

        position_angle_deg = self._sky_explorer_metadata_float(metadata, "catalog_position_angle_deg")

        return bool(

            major_axis_arcmin is not None and major_axis_arcmin > 0.0

            and minor_axis_arcmin is not None and minor_axis_arcmin > 0.0

            and position_angle_deg is not None

        )

    def _sky_explorer_overlay_base_text_size(self, text_font: QFont | None) -> float:

        candidate_font = QFont(text_font) if text_font is not None else QFont(self.font())

        point_size = candidate_font.pointSizeF()

        if point_size > 0.0:

            return float(point_size)

        fallback_font = self.font()

        fallback_point_size = fallback_font.pointSizeF()

        if fallback_point_size > 0.0:

            return float(fallback_point_size)

        return 9.0

    def _sky_explorer_overlay_text_size_for_radius(self, radius: float, *, base_size: float) -> float:

        resolved_base_size = max(7.0, float(base_size))

        resolved_radius = max(0.0, float(radius))

        scaled_size = resolved_base_size

        scaled_size += max(0.0, min(resolved_radius, 40.0) - 10.0) * 0.18

        scaled_size += max(0.0, resolved_radius - 40.0) * 0.035

        return min(24.0, max(resolved_base_size, scaled_size))

    def _sky_explorer_overlay_font_with_size(self, text_font: QFont | None, *, point_size: float) -> QFont | None:

        if text_font is None:

            return None

        scaled_font = QFont(text_font)

        scaled_font.setPointSizeF(max(6.0, float(point_size)))

        return scaled_font

    def _sky_explorer_overlay_pen_width_for_radius(self, radius: float, *, is_selected: bool) -> float:

        base_width = 3.0 if is_selected else 2.0

        if not bool(getattr(self._ensure_settings(), "sky_explorer_scale_overlay_strokes", True)):

            return base_width

        resolved_radius = max(0.0, float(radius))

        scaled_width = base_width

        scaled_width += max(0.0, min(resolved_radius, 220.0) - 10.0) * 0.012

        scaled_width += max(0.0, resolved_radius - 220.0) * 0.0015

        return min(8.0, max(base_width, scaled_width))

    def _sky_explorer_overlay_outline_width_for_pen_width(self, pen_width: float) -> float:

        if not bool(getattr(self._ensure_settings(), "sky_explorer_scale_overlay_strokes", True)):

            return 1.2

        return max(1.2, min(3.5, float(pen_width) * 0.45))

    def _sky_explorer_overlay_labeled_object_keys(self, objects: Sequence[SkyExplorerObject]) -> set[tuple[str, str, str]]:

        labeled_keys: set[tuple[str, str, str]] = set()

        objects_by_layer: dict[str, list[SkyExplorerObject]] = {}

        for sky_object in objects:

            objects_by_layer.setdefault(sky_object.layer_key, []).append(sky_object)

        for layer_key, layer_objects in objects_by_layer.items():

            label_limit = int(_SKY_EXPLORER_OVERLAY_LABEL_LIMITS.get(layer_key, 0))

            if label_limit <= 0:

                continue

            ranked_objects = sorted(layer_objects, key=self._sky_explorer_overlay_label_sort_key)

            for sky_object in ranked_objects[:label_limit]:

                labeled_keys.add(self._sky_explorer_object_identity(sky_object))

        return labeled_keys

    def _sky_explorer_overlay_label_sort_key(self, sky_object: SkyExplorerObject) -> tuple[bool, float, float, float, str]:

        magnitude = sky_object.magnitude

        angular_distance = sky_object.angular_distance_arcmin

        angular_size = self._sky_explorer_angular_size_arcmin(sky_object) or 0.0

        return (

            magnitude is None,

            float(magnitude) if magnitude is not None else 99.0,

            -float(angular_size),

            float(angular_distance) if math.isfinite(float(angular_distance)) else 1.0e9,

            str(sky_object.short_label or sky_object.name or sky_object.source_id).lower(),

        )

    def _sky_explorer_object_identity(self, sky_object: SkyExplorerObject) -> tuple[str, str, str]:

        return (

            str(sky_object.layer_key),

            str(sky_object.catalog),

            str(sky_object.source_id),

        )

    def _sky_explorer_overlay_radius_for_object(self, sky_object: SkyExplorerObject) -> float:

        default_radius = 10.0 if sky_object.layer_key != "gaia_stars" else 6.0

        size_arcmin = sky_object.metadata.get("catalog_size_arcmin") if isinstance(sky_object.metadata, dict) else None

        if not isinstance(size_arcmin, (int, float, str)):

            return default_radius

        try:

            size_arcmin_value = float(size_arcmin)

        except (TypeError, ValueError):

            return default_radius

        if size_arcmin_value <= 0.0:

            return default_radius

        if self._sky_explorer_should_scale_extended_nebula(sky_object):

            size_arcmin_value *= 2.5

        result = self._current_sky_explorer_result

        if result is None:

            return default_radius

        pixels_per_arcmin_candidates: list[float] = []

        if result.footprint.width_deg and result.solved_field.width > 0:

            pixels_per_arcmin_candidates.append(float(result.solved_field.width) / (float(result.footprint.width_deg) * 60.0))

        if result.footprint.height_deg and result.solved_field.height > 0:

            pixels_per_arcmin_candidates.append(float(result.solved_field.height) / (float(result.footprint.height_deg) * 60.0))

        if not pixels_per_arcmin_candidates:

            return default_radius

        pixels_per_arcmin = sum(pixels_per_arcmin_candidates) / len(pixels_per_arcmin_candidates)

        radius = (size_arcmin_value * pixels_per_arcmin) * 0.5

        radius_cap = self._sky_explorer_overlay_radius_cap_for_object(sky_object)

        return max(default_radius, min(radius_cap, float(radius)))

    def _sky_explorer_overlay_radius_cap_for_object(self, sky_object: SkyExplorerObject) -> float:

        if not self._sky_explorer_should_scale_extended_nebula(sky_object):

            return 220.0

        result = self._current_sky_explorer_result

        if result is None:

            return 220.0

        frame_min_dimension = min(max(0.0, float(result.solved_field.width)), max(0.0, float(result.solved_field.height)))

        if frame_min_dimension <= 0.0:

            return 220.0

        return min(2400.0, max(220.0, frame_min_dimension * 0.6))

    def _sky_explorer_should_scale_extended_nebula(self, sky_object: SkyExplorerObject) -> bool:

        settings = self._ensure_settings()

        if not bool(getattr(settings, "sky_explorer_scale_extended_nebulae", True)):

            return False

        object_type_keys = set(sky_explorer_object_type_keys_for_object(sky_object))

        return bool(object_type_keys.intersection({"emission_nebula", "reflection_nebula", "dark_nebula", "hii_region", "nebula"}))

    def _sky_explorer_overlay_projection_wcs(self) -> WCS | None:

        result = self._sky_explorer_overlay_reference_result()

        if result is None:

            self._sky_explorer_overlay_wcs_path = None

            self._sky_explorer_overlay_wcs = None

            return None

        cached_path = getattr(self, "_sky_explorer_overlay_wcs_path", None)

        cached_wcs = getattr(self, "_sky_explorer_overlay_wcs", None)

        if cached_path == result.solved_field.wcs_path and isinstance(cached_wcs, WCS):

            return cached_wcs

        try:

            overlay_wcs = celestial_wcs(read_header(result.solved_field.wcs_path))

        except Exception:

            overlay_wcs = None

        self._sky_explorer_overlay_wcs_path = result.solved_field.wcs_path

        self._sky_explorer_overlay_wcs = overlay_wcs

        return overlay_wcs

    def _sky_explorer_overlay_reference_result(self) -> SkyExplorerResult | None:

        current_result = self._current_sky_explorer_result

        if self._sky_explorer_result_matches_current_source(current_result):

            return current_result

        mag_limit_result = self._sky_explorer_mag_limit_result

        if self._sky_explorer_result_matches_current_source(mag_limit_result):

            return mag_limit_result

        return current_result or mag_limit_result

    def _sky_explorer_overlay_geometry_for_object(

        self,

        sky_object: SkyExplorerObject,

        *,

        wcs: WCS | None,

    ) -> tuple[str, float, float | None, float]:

        if sky_object.layer_key == "solar_system":

            radius = self._sky_explorer_overlay_radius_for_object(sky_object)

            return "cross", radius, None, 0.0

        aperture_radius = self._sky_explorer_overlay_radius_for_object(sky_object)

        metadata = sky_object.metadata if isinstance(sky_object.metadata, dict) else {}

        major_axis_arcmin = self._sky_explorer_metadata_float(metadata, "catalog_major_axis_arcmin", "catalog_size_arcmin")

        minor_axis_arcmin = self._sky_explorer_metadata_float(metadata, "catalog_minor_axis_arcmin")

        position_angle_deg = self._sky_explorer_metadata_float(metadata, "catalog_position_angle_deg")

        if major_axis_arcmin is None or minor_axis_arcmin is None or position_angle_deg is None:

            return "circle", aperture_radius, None, 0.0

        ellipse_geometry = self._project_sky_explorer_ellipse_geometry(

            sky_object,

            major_axis_arcmin=major_axis_arcmin,

            minor_axis_arcmin=minor_axis_arcmin,

            position_angle_deg=position_angle_deg,

            wcs=wcs,

        )

        if ellipse_geometry is not None:

            major_radius, minor_radius, rotation_degrees = ellipse_geometry

            return "ellipse", max(aperture_radius, major_radius), minor_radius, rotation_degrees

        minor_radius = self._sky_explorer_scaled_overlay_radius(minor_axis_arcmin, default_radius=max(5.0, aperture_radius * 0.45))

        return "ellipse", aperture_radius, min(aperture_radius, minor_radius), 0.0

    def _project_sky_explorer_ellipse_geometry(

        self,

        sky_object: SkyExplorerObject,

        *,

        major_axis_arcmin: float,

        minor_axis_arcmin: float,

        position_angle_deg: float,

        wcs: WCS | None,

    ) -> tuple[float, float, float] | None:

        if wcs is None or major_axis_arcmin <= 0.0 or minor_axis_arcmin <= 0.0:

            return None

        center = SkyCoord(float(sky_object.ra_deg) * u.deg, float(sky_object.dec_deg) * u.deg)

        major_endpoint = cast(SkyCoord, center.directional_offset_by(float(position_angle_deg) * u.deg, float(major_axis_arcmin * 0.5) * u.arcmin))

        minor_endpoint = cast(SkyCoord, center.directional_offset_by(float(position_angle_deg + 90.0) * u.deg, float(minor_axis_arcmin * 0.5) * u.arcmin))

        try:

            major_x, major_y = wcs.world_to_pixel_values(float(major_endpoint.ra.deg), float(major_endpoint.dec.deg))

            minor_x, minor_y = wcs.world_to_pixel_values(float(minor_endpoint.ra.deg), float(minor_endpoint.dec.deg))

        except Exception:

            return None

        if not all(math.isfinite(float(value)) for value in (major_x, major_y, minor_x, minor_y)):

            return None

        major_radius = math.hypot(float(major_x) - float(sky_object.pixel_x), float(major_y) - float(sky_object.pixel_y))

        minor_radius = math.hypot(float(minor_x) - float(sky_object.pixel_x), float(minor_y) - float(sky_object.pixel_y))

        if major_radius <= 0.0 or minor_radius <= 0.0:

            return None

        rotation_degrees = math.degrees(math.atan2(float(major_y) - float(sky_object.pixel_y), float(major_x) - float(sky_object.pixel_x)))

        return max(major_radius, minor_radius), min(major_radius, minor_radius), rotation_degrees

    def _sky_explorer_scaled_overlay_radius(self, size_arcmin: float, *, default_radius: float) -> float:

        result = self._current_sky_explorer_result

        if result is None or size_arcmin <= 0.0:

            return default_radius

        pixels_per_arcmin_candidates: list[float] = []

        if result.footprint.width_deg and result.solved_field.width > 0:

            pixels_per_arcmin_candidates.append(float(result.solved_field.width) / (float(result.footprint.width_deg) * 60.0))

        if result.footprint.height_deg and result.solved_field.height > 0:

            pixels_per_arcmin_candidates.append(float(result.solved_field.height) / (float(result.footprint.height_deg) * 60.0))

        if not pixels_per_arcmin_candidates:

            return default_radius

        pixels_per_arcmin = sum(pixels_per_arcmin_candidates) / len(pixels_per_arcmin_candidates)

        radius = (float(size_arcmin) * pixels_per_arcmin) * 0.5

        return max(default_radius, min(220.0, float(radius)))

    def _sky_explorer_metadata_float(self, metadata: dict[str, object], *keys: str) -> float | None:

        for key in keys:

            raw_value = metadata.get(key)

            if not isinstance(raw_value, (int, float, str)):

                continue

            try:

                numeric_value = float(raw_value)

            except (TypeError, ValueError):

                continue

            if math.isfinite(numeric_value) and numeric_value > 0.0:

                return numeric_value

        return None

    def _center_selected_sky_explorer_object(self) -> None:

        sky_object = self._selected_sky_explorer_object()

        if sky_object is None:

            return

        self._sky_explorer_image_view.focus_on(float(sky_object.pixel_x), float(sky_object.pixel_y), minimum_zoom_scale=3.0)

    def _handle_sky_explorer_object_type_mode_changed(self) -> None:

        self._set_sky_explorer_object_type_mode(self._current_sky_explorer_object_type_mode(), preserve_selection=True)

        self._refresh_sky_explorer_filtered_view(preserve_selection=True, select_first_row=False)

    def _handle_sky_explorer_object_type_selection_changed(self, item: QTableWidgetItem) -> None:

        if item.column() != _SKY_EXPLORER_OBJECT_TYPE_COLUMN:

            return

        item_key = item.data(_SKY_EXPLORER_QUERY_OBJECT_TYPE_ROLE)

        group_key = item.data(_SKY_EXPLORER_QUERY_GROUP_ROLE)

        if not isinstance(item_key, str) or not item_key:

            if isinstance(group_key, str) and group_key:

                self._set_sky_explorer_group_checked(group_key, item.checkState())

            return

        self._sync_sky_explorer_select_all_button()

        self._refresh_sky_explorer_filtered_view(preserve_selection=True, select_first_row=False)

    def _handle_sky_explorer_center_object_toggled(self, is_checked: bool) -> None:

        if is_checked:

            self._center_selected_sky_explorer_object()

    def _open_calibration_pipeline(self) -> None:

        if self._calibration_worker is not None and self._calibration_worker.isRunning():

            self.statusBar().showMessage("Image calibration is already running.", 5000)

            return

        root_path = Path(self._root_path_input.text()).expanduser()

        default_root = root_path if root_path.exists() else Path.cwd()

        settings = self._ensure_settings()

        dialog = CalibrationPipelineDialog(default_root=default_root, settings=settings, parent=self)

        if dialog.exec() != int(QDialog.DialogCode.Accepted):

            return

        request = dialog.request()
        settings.calibration_bias_path = "" if request.bias_path is None else str(request.bias_path)
        settings.calibration_dark_path = "" if request.dark_path is None else str(request.dark_path)
        settings.calibration_flat_path = "" if request.flat_path is None else str(request.flat_path)
        settings_root = root_path if root_path.exists() else default_root
        settings.save(settings_root)
        self._start_calibration_pipeline(replace(request, max_parallel_workers=resolve_shared_parallel_workers(settings)))

    def _start_calibration_pipeline(self, request: CalibrationPipelineRequest) -> None:

        workflow_calibration_active = self._differential_workflow_active and self._differential_workflow_current_step == "calibration"

        if workflow_calibration_active:

            self._close_calibration_progress_dialog()

        else:

            self._calibration_progress_dialog = QProgressDialog("Starting calibration pipeline...", "", 0, 0, self)

            self._calibration_progress_dialog.setWindowTitle("Calibrate Images")

            self._calibration_progress_dialog.setCancelButton(None)

            self._calibration_progress_dialog.setMinimumDuration(0)

            self._calibration_progress_dialog.setAutoClose(False)

            self._calibration_progress_dialog.setAutoReset(False)

            self._calibration_progress_dialog.setWindowModality(Qt.WindowModality.ApplicationModal)

            self._calibration_progress_dialog.show()

        self._calibrate_action.setEnabled(False)

        self.statusBar().showMessage("Image calibration started.", 5000)

        worker = CalibrationWorker(request, parent=self)

        worker.progress_updated.connect(self._handle_calibration_progress)

        worker.calibration_completed.connect(self._handle_calibration_completed)

        worker.calibration_failed.connect(self._handle_calibration_failed)

        self._calibration_worker = worker

        worker.start()

    def _handle_calibration_progress(self, message: str) -> None:

        progress_dialog = self._calibration_progress_dialog

        if progress_dialog is not None and qt_object_is_valid(progress_dialog):

            progress_dialog.setLabelText(message)

        if self._differential_workflow_active and self._differential_workflow_current_step == "calibration":

            self._set_differential_workflow_stage("calibrating images", message)

        self.statusBar().showMessage(message, 5000)

    def _handle_calibration_completed(self, result: object) -> None:

        self._calibration_worker = None

        self._calibrate_action.setEnabled(True)

        self._close_calibration_progress_dialog()

        if not isinstance(result, CalibrationPipelineResult):

            self._handle_calibration_failed("Calibration returned an unexpected result.")

            return

        lines = [result.summary_text, f"Output: {result.output_directory}", f"Calibrated frames: {len(result.calibrated_frames)}"]

        if result.aligned_directory is not None:

            lines.append(f"Aligned frames: {len(result.aligned_frames)}")

        workflow_calibration_active = self._differential_workflow_active and self._differential_workflow_current_step == "calibration"

        if workflow_calibration_active:

            use_aligned_output = self._differential_workflow_should_assume_aligned_images()

            next_root = result.aligned_directory if use_aligned_output and result.aligned_directory is not None else result.calibrated_directory

            if self._differential_workflow_uses_virtual_alignment():

                self._append_work_log(
                    "Workflow Star Alignment skipped writing a separate aligned copy folder because Differential photometry measures directly from each calibrated frame's WCS."
                )

            self._append_work_log(f"Workflow calibration step complete: continuing from {next_root}.")

            self._root_path_input.setText(str(next_root))

            self._load_settings_for_root(next_root, preserve_app_mode=True)

            self._apply_differential_workflow_alignment_setting(next_root, use_aligned_output)

            self._differential_workflow_scan_requested = True

            self._differential_workflow_auto_generate_after_scan = True

            self._differential_workflow_current_step = "calibration-scan"

            if self._differential_workflow_dialog is not None and qt_object_is_valid(self._differential_workflow_dialog):

                self._differential_workflow_dialog.set_scanning(next_root)

            self._start_scan()

            return

        self.statusBar().showMessage("Image calibration complete.", 5000)

        QMessageBox.information(self, "Calibration Complete", "\n".join(lines))

    def _handle_calibration_failed(self, message: str) -> None:

        self._calibration_worker = None

        self._calibrate_action.setEnabled(True)

        self._close_calibration_progress_dialog()

        self.statusBar().showMessage("Image calibration failed.", 5000)

        if self._differential_workflow_active and self._differential_workflow_current_step == "calibration":

            self._fail_differential_workflow(f"Calibration failed: {message}")

        QMessageBox.warning(self, "Calibration Failed", message)

    def _close_calibration_progress_dialog(self) -> None:

        progress_dialog = self._calibration_progress_dialog

        self._calibration_progress_dialog = None

        if progress_dialog is not None and qt_object_is_valid(progress_dialog):

            progress_dialog.close()

            progress_dialog.deleteLater()

