    def _ensure_settings(self) -> AppSettings:

        if self._settings is None:

            root_path = Path(self._root_path_input.text()).expanduser()

            settings_root = root_path if root_path.exists() else Path.cwd()

            self._settings = AppSettings.from_root(settings_root)

            if hasattr(self, "_sky_explorer_object_type_color_overrides"):

                self._load_sky_explorer_style_settings_from_settings()

        return self._settings

    def _sync_hr_settings_menu_controls(self) -> None:

        settings = getattr(self, "_settings", None)

        require_parallax = True if settings is None else bool(settings.hr_plot_require_parallax)

        color_saturation = 1.0 if settings is None else min(2.0, max(0.0, float(settings.hr_plot_color_saturation)))

        point_opacity = 0.8 if settings is None else min(1.0, max(0.05, float(settings.hr_plot_point_opacity)))

        selection_circle_opacity = 0.85 if settings is None else min(1.0, max(0.0, float(settings.hr_selection_circle_opacity)))

        selection_circle_size_factor = 1.35 if settings is None else min(4.0, max(1.0, float(settings.hr_selection_circle_size_factor)))

        marker_size_mode = "scaled" if settings is None else str(settings.hr_plot_marker_size_mode or "scaled").strip().lower()

        if marker_size_mode not in {"scaled", "fixed"}:

            marker_size_mode = "scaled"

        fixed_marker_size = 8.0 if settings is None else min(24.0, max(2.0, float(settings.hr_plot_fixed_marker_size)))

        motion_color_by_angle = False if settings is None else bool(settings.hr_motion_vector_color_by_angle)

        motion_saturation_by_magnitude = False if settings is None else bool(getattr(settings, "hr_motion_vector_saturation_by_magnitude", False))

        search_catalog_names = True if settings is None else bool(getattr(settings, "hr_search_catalog_names", True))

        search_catalog_names_magnitude_threshold = 9.0 if settings is None else min(30.0, max(-5.0, float(getattr(settings, "hr_search_catalog_names_magnitude_threshold", 9.0))))

        motion_width = 1.5 if settings is None else min(8.0, max(0.5, float(settings.hr_motion_vector_width)))



        self._hr_settings_require_parallax_checkbox.blockSignals(True)

        self._hr_settings_color_saturation_spin.blockSignals(True)

        self._hr_settings_point_opacity_spin.blockSignals(True)

        self._hr_settings_selection_circle_opacity_spin.blockSignals(True)

        self._hr_settings_selection_circle_size_factor_spin.blockSignals(True)

        self._hr_settings_marker_size_mode_combo.blockSignals(True)

        self._hr_settings_fixed_marker_size_spin.blockSignals(True)

        self._hr_settings_motion_color_by_angle_checkbox.blockSignals(True)

        self._hr_settings_motion_saturation_by_magnitude_checkbox.blockSignals(True)

        self._hr_settings_search_catalog_names_checkbox.blockSignals(True)

        self._hr_settings_search_catalog_names_magnitude_threshold_spin.blockSignals(True)

        self._hr_settings_motion_width_spin.blockSignals(True)

        self._hr_settings_require_parallax_checkbox.setChecked(require_parallax)

        self._hr_settings_color_saturation_spin.setValue(color_saturation)

        self._hr_settings_point_opacity_spin.setValue(point_opacity)

        self._hr_settings_selection_circle_opacity_spin.setValue(selection_circle_opacity)

        self._hr_settings_selection_circle_size_factor_spin.setValue(selection_circle_size_factor)

        marker_index = self._hr_settings_marker_size_mode_combo.findData(marker_size_mode)

        self._hr_settings_marker_size_mode_combo.setCurrentIndex(0 if marker_index < 0 else marker_index)

        self._hr_settings_fixed_marker_size_spin.setValue(fixed_marker_size)

        self._hr_settings_motion_color_by_angle_checkbox.setChecked(motion_color_by_angle)

        self._hr_settings_motion_saturation_by_magnitude_checkbox.setChecked(motion_saturation_by_magnitude)

        self._hr_settings_search_catalog_names_checkbox.setChecked(search_catalog_names)

        self._hr_settings_search_catalog_names_magnitude_threshold_spin.setValue(search_catalog_names_magnitude_threshold)

        self._hr_settings_motion_width_spin.setValue(motion_width)

        self._hr_settings_require_parallax_checkbox.blockSignals(False)

        self._hr_settings_color_saturation_spin.blockSignals(False)

        self._hr_settings_point_opacity_spin.blockSignals(False)

        self._hr_settings_selection_circle_opacity_spin.blockSignals(False)

        self._hr_settings_selection_circle_size_factor_spin.blockSignals(False)

        self._hr_settings_marker_size_mode_combo.blockSignals(False)

        self._hr_settings_fixed_marker_size_spin.blockSignals(False)

        self._hr_settings_motion_color_by_angle_checkbox.blockSignals(False)

        self._hr_settings_motion_saturation_by_magnitude_checkbox.blockSignals(False)

        self._hr_settings_search_catalog_names_checkbox.blockSignals(False)

        self._hr_settings_search_catalog_names_magnitude_threshold_spin.blockSignals(False)

        self._hr_settings_motion_width_spin.blockSignals(False)



        self._sync_hr_motion_overlay_settings()

        self._update_hr_settings_fixed_size_input()

        self._update_hr_roi_drag_color_button()

        self._update_hr_roi_color_button()

        self._update_hr_selection_circle_color_button()

        self._update_hr_motion_vector_color_button()

        self._update_hr_motion_group_button_tooltips()

    def _sync_hr_plot_filter_controls(self) -> None:

        settings = getattr(self, "_settings", None)

        hide_flagged = False if settings is None else bool(settings.hr_plot_hide_flagged)

        hide_saturated = True if settings is None else bool(settings.hr_plot_hide_saturated)

        apparent_magnitude_min = -5.0 if settings is None else min(30.0, max(-5.0, float(settings.hr_plot_apparent_magnitude_min)))

        apparent_magnitude_max = 30.0 if settings is None else min(30.0, max(-5.0, float(settings.hr_plot_apparent_magnitude_max)))

        self._hr_plot_hide_flagged_checkbox.blockSignals(True)

        self._hr_plot_hide_saturated_checkbox.blockSignals(True)

        self._hr_plot_apparent_mag_min_spin.blockSignals(True)

        self._hr_plot_apparent_mag_max_spin.blockSignals(True)

        self._hr_plot_hide_flagged_checkbox.setChecked(hide_flagged)

        self._hr_plot_hide_saturated_checkbox.setChecked(hide_saturated)

        self._hr_plot_apparent_mag_min_spin.setValue(apparent_magnitude_min)

        self._hr_plot_apparent_mag_max_spin.setValue(apparent_magnitude_max)

        self._hr_plot_hide_flagged_checkbox.blockSignals(False)

        self._hr_plot_hide_saturated_checkbox.blockSignals(False)

        self._hr_plot_apparent_mag_min_spin.blockSignals(False)

        self._hr_plot_apparent_mag_max_spin.blockSignals(False)

    def _sync_asteroid_settings_menu_controls(self) -> None:

        if not hasattr(self, "_asteroid_show_markers_action"):

            return

        settings = getattr(self, "_settings", None)

        markers_enabled = True if settings is None else bool(settings.asteroid_visual_show_object_markers)

        labels_enabled = True if settings is None else bool(settings.asteroid_visual_label_all_objects)

        target_marker_enabled = False if settings is None else bool(settings.asteroid_visual_show_target_marker)

        target_marker_line_width = 4.0 if settings is None else min(8.0, max(0.5, float(settings.asteroid_target_marker_line_width)))

        self._asteroid_show_markers_action.blockSignals(True)

        self._asteroid_show_labels_action.blockSignals(True)

        has_target_marker_toolbar_button = hasattr(self, "_asteroid_target_marker_button")

        if has_target_marker_toolbar_button:

            self._asteroid_target_marker_button.blockSignals(True)

        self._asteroid_target_marker_line_width_spin.blockSignals(True)

        self._asteroid_show_markers_action.setChecked(markers_enabled)

        self._asteroid_show_labels_action.setChecked(labels_enabled)

        if has_target_marker_toolbar_button:

            self._asteroid_target_marker_button.setChecked(target_marker_enabled)

        self._asteroid_target_marker_line_width_spin.setValue(target_marker_line_width)

        self._asteroid_show_markers_action.blockSignals(False)

        self._asteroid_show_labels_action.blockSignals(False)

        if has_target_marker_toolbar_button:

            self._asteroid_target_marker_button.blockSignals(False)

        self._asteroid_target_marker_line_width_spin.blockSignals(False)

        self._update_asteroid_target_marker_line_color_button()

        self._update_asteroid_target_marker_accent_color_button()

        self._update_asteroid_target_marker_text_color_button()

        self._update_asteroid_target_marker_outline_color_button()

    def _update_hr_settings_fixed_size_input(self) -> None:

        marker_mode = self._hr_settings_marker_size_mode_combo.currentData()

        self._hr_settings_fixed_marker_size_spin.setEnabled(marker_mode == "fixed")

