    def _choose_asteroid_target_marker_line_color(self) -> None:

        settings = self._ensure_settings()

        selected_color = QColorDialog.getColor(
            QColor(str(settings.asteroid_target_marker_line_color or "#ef4444")),
            self,
            "Select Asteroid/Comet Target Marker Line Color",
        )

        if not selected_color.isValid():

            return

        settings.asteroid_target_marker_line_color = selected_color.name(QColor.NameFormat.HexRgb).lower()

        self._update_asteroid_target_marker_line_color_button()

        self._save_settings_snapshot()

        if self._current_asteroid_source_image is not None:

            self._refresh_asteroid_image_view(reset_view=False)

