    def _handle_hr_settings_menu_changed(self) -> None:

        sender = self.sender()

        settings = self._ensure_settings()

        settings.hr_plot_require_parallax = self._hr_settings_require_parallax_checkbox.isChecked()

        settings.hr_plot_color_saturation = float(self._hr_settings_color_saturation_spin.value())

        settings.hr_plot_point_opacity = float(self._hr_settings_point_opacity_spin.value())

        settings.hr_selection_circle_opacity = float(self._hr_settings_selection_circle_opacity_spin.value())

        settings.hr_selection_circle_size_factor = float(self._hr_settings_selection_circle_size_factor_spin.value())

        marker_size_mode = self._hr_settings_marker_size_mode_combo.currentData()

        settings.hr_plot_marker_size_mode = str(marker_size_mode) if isinstance(marker_size_mode, str) and marker_size_mode else "scaled"

        settings.hr_plot_fixed_marker_size = float(self._hr_settings_fixed_marker_size_spin.value())

        settings.hr_motion_vector_color_by_angle = self._hr_settings_motion_color_by_angle_checkbox.isChecked()

        settings.hr_motion_vector_saturation_by_magnitude = self._hr_settings_motion_saturation_by_magnitude_checkbox.isChecked()

        settings.hr_search_catalog_names = self._hr_settings_search_catalog_names_checkbox.isChecked()

        settings.hr_search_catalog_names_magnitude_threshold = float(self._hr_settings_search_catalog_names_magnitude_threshold_spin.value())

        settings.hr_motion_vector_width = float(self._hr_settings_motion_width_spin.value())

        self._sync_hr_motion_overlay_settings()

        self._update_hr_settings_fixed_size_input()

        self._save_settings_snapshot()

        if self._current_hr_source_image is not None:

            self._refresh_hr_image_view(reset_view=False)

        self._refresh_hr_plot()

        if sender in {

            self._hr_settings_search_catalog_names_checkbox,

            self._hr_settings_search_catalog_names_magnitude_threshold_spin,

        }:

            self._sync_hr_background_name_lookup(force_restart=True)

