    def _normalized_splitter_sizes(

        self,

        sizes: Sequence[int],

        *,

        fallback_sizes: Sequence[int],


        minimum_first: int,

        minimum_second: int,

    ) -> list[int]:

        candidate_sizes = [max(0, int(size)) for size in sizes]

        if len(candidate_sizes) != 2 or sum(candidate_sizes) <= 0:

            return [int(fallback_sizes[0]), int(fallback_sizes[1])]

        total = sum(candidate_sizes)

        if total < (minimum_first + minimum_second):

            return candidate_sizes

        first = min(max(candidate_sizes[0], minimum_first), total - minimum_second)

        second = total - first

        return [first, second]

    def _handle_hr_splitter_sizes_changed(self, _position: int, _index: int) -> None:

        if not self._hr_splitter_settings_sync_enabled:

            return

        settings = self._ensure_settings()

        left_sizes = [int(size) for size in self._hr_left_splitter.sizes()]

        main_sizes = [int(size) for size in self._hr_main_splitter.sizes()]

        updated = False

        if len(left_sizes) == 2 and all(size > 0 for size in left_sizes):

            settings.hr_left_splitter_sizes = left_sizes

            updated = True

        if len(main_sizes) == 2 and all(size > 0 for size in main_sizes):

            settings.hr_main_splitter_sizes = main_sizes

            updated = True

        self._sync_hr_footer_splitter_sizes()

        if updated:

            self._save_settings_snapshot()

    def _handle_differential_splitter_sizes_changed(self, _position: int, _index: int) -> None:

        if not self._differential_splitter_settings_sync_enabled:

            return

        settings = self._ensure_settings()

        analysis_sizes = [int(size) for size in self._differential_analysis_splitter.sizes()]

        results_sizes = [int(size) for size in self._differential_results_splitter.sizes()]

        main_sizes = [int(size) for size in self._differential_main_splitter.sizes()]

        updated = False

        if len(analysis_sizes) == 2 and all(size > 0 for size in analysis_sizes):

            settings.differential_analysis_splitter_sizes = analysis_sizes

            updated = True

        if len(results_sizes) == 2 and all(size > 0 for size in results_sizes):

            settings.differential_results_splitter_sizes = results_sizes

            updated = True

        if len(main_sizes) == 2 and all(size > 0 for size in main_sizes):

            settings.differential_main_splitter_sizes = main_sizes

            updated = True

        if updated:

            self._save_settings_snapshot()

