    def _browse_for_transient_folder(self) -> None:
        start_path = (
            str(self._current_transient_root_path)
            if self._current_transient_root_path is not None and self._current_transient_root_path.exists()
            else (self._root_path_input.text() or str(Path.cwd()))
        )
        selected = QFileDialog.getExistingDirectory(self, "Select transient image folder", start_path)
        if not selected:
            return
        self._set_transient_folder_path(Path(selected).expanduser())

    def _handle_transient_primary_action(self) -> None:
        root_path = self._current_transient_root_path
        if root_path is None or not root_path.exists():
            self._browse_for_transient_folder()
            return
        self._start_transient_search()

    def _set_transient_folder_path(self, root_path: Path) -> None:
        self._current_transient_root_path = root_path
        self._root_path_input.setText(str(root_path))
        if root_path.exists():
            self._load_settings_for_root(root_path, preserve_app_mode=True)
        self._current_transient_search_result = None
        self._transient_results_table.setSortingEnabled(False)
        self._transient_results_table.setRowCount(0)
        self._transient_results_table.setSortingEnabled(True)
        self._transient_details_output.clear()
        self._transient_steps_output.clear()
        self._append_transient_workflow_note(f"Opened transient image folder: {root_path}")
        first_image = self._first_supported_transient_image_path(root_path)
        self._set_current_transient_image_path(first_image, reset_view=True, focus_candidate=False)
        self._transient_status_label.setText(f"Selected transient image folder: {root_path}.")
        self.statusBar().showMessage("Transient image folder opened.", 3000)
        self._sync_transient_primary_button()

    def _start_transient_search(self) -> None:
        root_path = self._current_transient_root_path
        if root_path is None:
            QMessageBox.warning(self, "Invalid path", "Open a transient image folder before starting a search.")
            return
        if not root_path.exists():
            QMessageBox.warning(self, "Invalid path", "The selected transient image folder does not exist.")
            return
        if self._transient_search_worker is not None and self._transient_search_worker.isRunning():
            self.statusBar().showMessage("Transient Finder is already searching.", 5000)
            return
        self._root_path_input.setText(str(root_path))
        self._load_settings_for_root(root_path, preserve_app_mode=True)
        settings = self._ensure_settings()
        self._current_transient_search_result = None
        self._transient_training_predictions.clear()
        self._transient_results_table.setSortingEnabled(False)
        self._transient_results_table.setRowCount(0)
        self._transient_results_table.setSortingEnabled(True)
        if hasattr(self, "_transient_quick_label_button"):
            self._transient_quick_label_button.setEnabled(False)
        self._transient_steps_output.clear()
        self._transient_details_output.clear()
        self._append_transient_workflow_note(
            f"Started transient search for {root_path} with minimum {self._transient_min_frames_spin.value()} frame(s), threshold {self._transient_detection_sigma_spin.value():.1f} sigma, and ROI border {self._transient_roi_margin_spin.value()}%."
        )
        self._transient_status_label.setText("Checking image WCS, solving missing astrometry when possible, and searching for variable point sources.")
        self.statusBar().showMessage("Transient Finder search started.", 5000)
        self._set_transient_search_busy(True)
        self._transient_search_worker = TransientSearchWorker(
            root_path=root_path,
            settings=settings,
            min_frame_count=self._transient_min_frames_spin.value(),
            detection_sigma=self._transient_detection_sigma_spin.value(),
            edge_margin_fraction=self._transient_roi_margin_fraction(),
            parent=self,
        )
        self._transient_search_worker.progress_updated.connect(self._handle_transient_search_progress)
        self._transient_search_worker.search_completed.connect(self._handle_transient_search_completed)
        self._transient_search_worker.search_failed.connect(self._handle_transient_search_failed)
        self._transient_search_worker.search_cancelled.connect(self._handle_transient_search_cancelled)
        self._transient_search_worker.start()

    def _set_transient_search_busy(self, is_busy: bool) -> None:
        self._transient_search_button.setEnabled(not is_busy)
        self._transient_min_frames_spin.setEnabled(not is_busy)
        self._transient_detection_sigma_spin.setEnabled(not is_busy)
        self._transient_roi_margin_spin.setEnabled(not is_busy)
        if is_busy:
            self._transient_search_button.setText("Searching...")
            self._set_transient_primary_button_attention(False)
            self._transient_progress_bar.setRange(0, 0)
        else:
            self._transient_progress_bar.setRange(0, 1)
            self._transient_progress_bar.setValue(0)
            self._sync_transient_primary_button()

    def _handle_transient_search_progress(self, message: str) -> None:
        self._transient_status_label.setText(message)
        self.statusBar().showMessage(message, 5000)
        self._append_transient_workflow_note(message)

    def _handle_transient_search_completed(self, result: object) -> None:
        if not isinstance(result, TransientSearchResult):
            self._handle_transient_search_failed("Transient Finder returned an unexpected result.")
            return
        self._current_transient_search_result = result
        self._transient_search_worker = None
        self._set_transient_search_busy(False)
        self._populate_transient_results_table(result.candidates)
        self._append_transient_workflow_note(result.report_text)
        self._transient_status_label.setText(
            f"Transient Finder found {len(result.candidates)} candidate(s) from {result.solved_frame_count}/{result.total_files} solved frame(s)."
        )
        self.statusBar().showMessage(self._transient_status_label.text(), 5000)
        self._start_transient_image_preload(
            [frame_result.source_path for frame_result in result.frame_results if frame_result.solved_field is not None]
        )
        if result.candidates:
            self._transient_results_table.setCurrentCell(0, 0)
            self._transient_results_table.selectRow(0)

    def _handle_transient_search_failed(self, message: str) -> None:
        self._transient_search_worker = None
        self._set_transient_search_busy(False)
        self._transient_status_label.setText(f"Transient Finder failed: {message}")
        self._append_transient_workflow_note(f"Transient Finder failed: {message}")
        QMessageBox.warning(self, "Transient Finder failed", message)

    def _handle_transient_search_cancelled(self, message: str) -> None:
        self._transient_search_worker = None
        self._set_transient_search_busy(False)
        self._transient_status_label.setText(message)
        self._append_transient_workflow_note(message)
        self.statusBar().showMessage(message, 5000)

    def _append_transient_workflow_note(self, message: str) -> None:
        if message:
            timestamp = datetime.now().strftime("%H:%M:%S")
            lines = str(message).splitlines() or [str(message)]
            self._transient_steps_output.appendPlainText("\n".join(f"[{timestamp}] {line}" for line in lines))

    def _populate_transient_results_table(self, candidates: tuple[TransientCandidate, ...]) -> None:
        sorting_enabled = self._transient_results_table.isSortingEnabled()
        self._transient_results_table.setSortingEnabled(False)
        self._transient_results_table.setRowCount(len(candidates))
        self._transient_training_predictions.clear()
        for row_index, candidate in enumerate(candidates):
            nearest_text = "-"
            nearest_sort = float("inf")
            if candidate.nearest_catalog_separation_arcsec is not None:
                nearest_name = candidate.nearest_catalog_name or "Gaia source"
                nearest_text = f"{nearest_name} ({candidate.nearest_catalog_separation_arcsec:.2f}\")"
                nearest_sort = candidate.nearest_catalog_separation_arcsec
            values: list[tuple[str, float | int | str | None]] = [
                (candidate.candidate_id, candidate.candidate_id),
                (f"{candidate.ra_deg:.6f}", candidate.ra_deg),
                (f"{candidate.dec_deg:.6f}", candidate.dec_deg),
                (str(candidate.frame_count), candidate.frame_count),
                (f"{candidate.median_snr:.1f}", candidate.median_snr),
                (nearest_text, nearest_sort),
                (self._format_transient_observation_time(candidate.first_observation), candidate.first_observation.timestamp() if candidate.first_observation is not None else None),
                (self._format_transient_observation_time(candidate.last_observation), candidate.last_observation.timestamp() if candidate.last_observation is not None else None),
                self._transient_training_label_cell(candidate),
                self._transient_training_prediction_cell(candidate),
            ]
            for column_index, (text, sort_value) in enumerate(values):
                item = _SourceResultsTableItem(text, sort_value)
                if column_index == 0:
                    item.setData(_TRANSIENT_CANDIDATE_ROLE, candidate)
                self._transient_results_table.setItem(row_index, column_index, item)
        self._transient_results_table.setSortingEnabled(sorting_enabled)
        self._transient_results_table.resizeRowsToContents()
        if hasattr(self, "_transient_quick_label_button"):
            self._transient_quick_label_button.setEnabled(bool(candidates))
        self._refresh_transient_training_summary()

    def _handle_transient_result_selection_changed(self) -> None:
        candidate = self._selected_transient_candidate()
        if candidate is None:
            self._transient_details_output.clear()
            self._sync_transient_image_controls()
            self._sync_transient_training_controls(None)
            return
        focus_candidate = self._transient_center_candidate_button.isChecked()
        self._start_transient_image_preload(self._transient_candidate_frame_paths(candidate))
        self._transient_details_output.setPlainText(self._format_transient_candidate_details(candidate))
        if candidate.detections:
            current_paths = {detection.source_path.resolve() for detection in candidate.detections if detection.source_path.exists()}
            if self._current_transient_source_image is None or self._current_transient_source_image.resolve() not in current_paths:
                self._set_current_transient_image_path(candidate.detections[0].source_path, reset_view=False, focus_candidate=focus_candidate)
            else:
                self._refresh_transient_image_view(reset_view=False, focus_candidate=focus_candidate)
        self._sync_transient_image_controls()
        self._sync_transient_training_controls(candidate)

    def _selected_transient_candidate(self) -> TransientCandidate | None:
        selected_candidates = self._selected_transient_candidates()
        return selected_candidates[0] if selected_candidates else None

    def _selected_transient_candidates(self) -> list[TransientCandidate]:
        selection_model = self._transient_results_table.selectionModel()
        if selection_model is None:
            return []
        selected_rows = {index.row() for index in selection_model.selectedRows()}
        if not selected_rows:
            return []
        ordered_rows: list[int] = []
        current_row = self._transient_results_table.currentRow()
        if current_row in selected_rows:
            ordered_rows.append(current_row)
        ordered_rows.extend(sorted(row for row in selected_rows if row != current_row))
        candidates: list[TransientCandidate] = []
        seen_candidate_ids: set[str] = set()
        for row_index in ordered_rows:
            item = self._transient_results_table.item(row_index, 0)
            candidate = item.data(_TRANSIENT_CANDIDATE_ROLE) if item is not None else None
            if not isinstance(candidate, TransientCandidate):
                continue
            if candidate.candidate_id in seen_candidate_ids:
                continue
            seen_candidate_ids.add(candidate.candidate_id)
            candidates.append(candidate)
        return candidates

    def _format_transient_candidate_details(self, candidate: TransientCandidate) -> str:
        lines = [
            candidate.summary_text,
            "",
            f"Detections: {candidate.detection_count}",
            f"Max SNR: {candidate.max_snr:.1f}",
            f"Variability SNR: {candidate.variability_snr:.1f}",
            f"Flux ratio: {candidate.flux_ratio:.1f}",
        ]
        label_record = self._transient_training_label_record(candidate)
        if label_record is not None:
            lines.append(f"Training label: {self._format_transient_training_label(label_record.label)}")
        prediction = self._transient_training_prediction(candidate)
        if prediction is not None:
            lines.append(f"ML score: {self._format_transient_training_label(prediction.label)} ({prediction.confidence:.0%})")
        if candidate.nearest_catalog_separation_arcsec is not None:
            lines.append(
                f"Nearest Gaia: {candidate.nearest_catalog_name or 'Gaia source'} at {candidate.nearest_catalog_separation_arcsec:.2f} arcsec"
            )
        lines.append("")
        lines.append("Per-frame detections:")
        for detection in candidate.detections:
            time_text = self._format_transient_observation_time(detection.observation_time)
            lines.append(
                f"- {detection.source_path.name}: {time_text}, x={detection.x:.1f}, y={detection.y:.1f}, "
                f"RA={detection.ra_deg:.6f}, Dec={detection.dec_deg:.6f}, SNR={detection.snr:.1f}"
            )
        return "\n".join(lines)

    def _format_transient_observation_time(self, value: datetime | None) -> str:
        if value is None:
            return "-"
        timestamp = value if value.tzinfo is not None else value.replace(tzinfo=UTC)
        return timestamp.astimezone(UTC).strftime("%Y-%m-%d %H:%M:%S")

    def _transient_training_key(self, candidate: TransientCandidate) -> str:
        root_path = self._current_transient_search_result.root_path if self._current_transient_search_result is not None else self._current_transient_root_path
        return transient_candidate_training_key(root_path or Path.cwd(), candidate)

    def _transient_training_label_record(self, candidate: TransientCandidate):
        return self._candidate_training_store.label_for_key(TRAINING_MODE_TRANSIENT, self._transient_training_key(candidate))

    def _transient_training_label_cell(self, candidate: TransientCandidate) -> tuple[str, str]:
        label_record = self._transient_training_label_record(candidate)
        if label_record is None:
            return "-", ""
        return self._format_transient_training_label(label_record.label), label_record.label

    def _transient_training_prediction(self, candidate: TransientCandidate) -> CandidatePrediction | None:
        key = self._transient_training_key(candidate)
        prediction = self._transient_training_predictions.get(key)
        if prediction is not None:
            return prediction
        prediction = self._candidate_training_store.predict(TRAINING_MODE_TRANSIENT, transient_candidate_training_features(candidate))
        if prediction is not None:
            self._transient_training_predictions[key] = prediction
        return prediction

    def _transient_training_prediction_cell(self, candidate: TransientCandidate) -> tuple[str, float]:
        prediction = self._transient_training_prediction(candidate)
        if prediction is None:
            return "-", -1.0
        return f"{self._format_transient_training_label(prediction.label)} {prediction.confidence:.0%}", prediction.confidence

    def _format_transient_training_label(self, label: str) -> str:
        return str(label or "").replace("_", " ").title()

    def _sync_transient_training_controls(self, candidate: TransientCandidate | None) -> None:
        if not hasattr(self, "_transient_training_label_combo"):
            return
        has_candidate = candidate is not None
        self._transient_training_label_combo.setEnabled(has_candidate)
        self._transient_save_label_button.setEnabled(has_candidate)
        selected_label = ""
        if candidate is not None:
            label_record = self._transient_training_label_record(candidate)
            selected_label = "" if label_record is None else label_record.label
        label_index = self._transient_training_label_combo.findData(selected_label)
        self._transient_training_label_combo.setCurrentIndex(0 if label_index < 0 else label_index)
        self._refresh_transient_training_summary()

    def _refresh_transient_training_summary(self) -> None:
        if hasattr(self, "_transient_training_status_label"):
            self._transient_training_status_label.setText(self._candidate_training_store.training_summary(TRAINING_MODE_TRANSIENT))

    def _save_transient_training_label(self) -> None:
        candidate = self._selected_transient_candidate()
        if candidate is None:
            self.statusBar().showMessage("Select a transient candidate before saving a training label.", 5000)
            return
        label = str(self._transient_training_label_combo.currentData() or "")
        if not label:
            self.statusBar().showMessage("Choose a training label before saving.", 5000)
            return
        self._record_transient_training_label(candidate, label, announce=True)

    def _record_transient_training_label(self, candidate: TransientCandidate, label: str, *, announce: bool = False) -> None:
        root_path = self._current_transient_search_result.root_path if self._current_transient_search_result is not None else self._current_transient_root_path
        root_path = root_path or Path.cwd()
        self._candidate_training_store.record_label(
            mode=TRAINING_MODE_TRANSIENT,
            candidate_key=self._transient_training_key(candidate),
            features=transient_candidate_training_features(candidate),
            payload=transient_candidate_training_payload(root_path, candidate),
            label=label,
        )
        self._update_transient_training_cells_for_candidate(candidate)
        self._refresh_transient_training_summary()
        selected_candidate = self._selected_transient_candidate()
        if selected_candidate is not None and selected_candidate.candidate_id == candidate.candidate_id:
            self._sync_transient_training_controls(candidate)
            self._transient_details_output.setPlainText(self._format_transient_candidate_details(candidate))
        message = f"Saved transient training label {self._format_transient_training_label(label)} for {candidate.candidate_id}."
        if announce:
            self._append_transient_workflow_note(message)
            self.statusBar().showMessage(message, 5000)

    def _open_transient_quick_label_dialog(self) -> None:
        result = self._current_transient_search_result
        if result is None or not result.candidates:
            QMessageBox.information(self, "No candidates", "Run Transient Finder before opening the fast labeling window.")
            return
        dialog = TransientQuickLabelDialog(
            candidates=result.candidates,
            frame_results=result.frame_results,
            label_lookup=lambda candidate: (record.label if (record := self._transient_training_label_record(candidate)) is not None else None),
            save_label=lambda candidate, label: self._record_transient_training_label(candidate, label, announce=False),
            parent=self,
        )
        dialog.exec()
        if dialog.saved_count:
            self._append_transient_workflow_note(f"Fast labeling saved {dialog.saved_count} transient training label(s).")
            self.statusBar().showMessage(f"Saved {dialog.saved_count} transient training label(s).", 5000)
            selected_candidate = self._selected_transient_candidate()
            if selected_candidate is not None:
                self._transient_details_output.setPlainText(self._format_transient_candidate_details(selected_candidate))
        self._refresh_transient_training_summary()

    def _train_transient_candidate_model(self) -> None:
        result = self._candidate_training_store.train_model(TRAINING_MODE_TRANSIENT)
        self._append_transient_workflow_note(result.message)
        self.statusBar().showMessage(result.message, 7000)
        self._transient_training_predictions.clear()
        if self._current_transient_search_result is not None:
            selected_candidate = self._selected_transient_candidate()
            self._populate_transient_results_table(self._current_transient_search_result.candidates)
            if selected_candidate is not None:
                self._select_transient_candidate_by_id(selected_candidate.candidate_id)
                self._transient_details_output.setPlainText(self._format_transient_candidate_details(selected_candidate))
        self._refresh_transient_training_summary()

    def _update_transient_training_cells_for_candidate(self, candidate: TransientCandidate) -> None:
        row_index = self._transient_row_index_for_candidate_id(candidate.candidate_id)
        if row_index is None:
            return
        label_text, label_sort = self._transient_training_label_cell(candidate)
        score_text, score_sort = self._transient_training_prediction_cell(candidate)
        self._transient_results_table.setItem(row_index, _TRANSIENT_LABEL_COLUMN, _SourceResultsTableItem(label_text, label_sort))
        self._transient_results_table.setItem(row_index, _TRANSIENT_SCORE_COLUMN, _SourceResultsTableItem(score_text, score_sort))

    def _selected_transient_row_index(self) -> int | None:
        current_row = self._transient_results_table.currentRow()
        if current_row >= 0:
            current_item = self._transient_results_table.item(current_row, 0)
            if current_item is not None and current_item.isSelected():
                return current_row
        selection_model = self._transient_results_table.selectionModel()
        if selection_model is None:
            return None
        selected_rows = selection_model.selectedRows()
        if not selected_rows:
            return None
        return selected_rows[0].row()

    def _transient_row_index_for_candidate_id(self, candidate_id: str) -> int | None:
        for row_index in range(self._transient_results_table.rowCount()):
            item = self._transient_results_table.item(row_index, 0)
            candidate = item.data(_TRANSIENT_CANDIDATE_ROLE) if item is not None else None
            if isinstance(candidate, TransientCandidate) and candidate.candidate_id == candidate_id:
                return row_index
        return None

    def _select_transient_candidate_by_id(self, candidate_id: str) -> None:
        row_index = self._transient_row_index_for_candidate_id(candidate_id)
        if row_index is not None:
            self._transient_results_table.setCurrentCell(row_index, 0)
            self._transient_results_table.selectRow(row_index)

    def _transient_folder_ready(self) -> bool:
        return self._current_transient_root_path is not None and self._current_transient_root_path.exists()

    def _sync_transient_primary_button(self) -> None:
        if not hasattr(self, "_transient_search_button"):
            return
        if self._transient_search_worker is not None and self._transient_search_worker.isRunning():
            self._transient_search_button.setText("Searching...")
            self._sync_transient_primary_button_width()
            self._set_transient_primary_button_attention(False)
            return
        if self._transient_folder_ready():
            self._transient_search_button.setText("Search")
        else:
            self._transient_search_button.setText("Open")
        self._sync_transient_primary_button_width()
        self._set_transient_primary_button_attention(True)

    def _sync_transient_primary_button_width(self) -> None:
        label_candidates = ["Open", "Search", "Searching..."]
        metrics = self._transient_search_button.fontMetrics()
        widest_text = max(label_candidates, key=metrics.horizontalAdvance)
        minimum_width = max(
            self._transient_search_button.minimumWidth(),
            self._transient_search_button.minimumSizeHint().width(),
            metrics.horizontalAdvance(widest_text) + 36,
        )
        self._transient_search_button.setMinimumWidth(minimum_width)

    def _set_transient_primary_button_attention(self, enabled: bool) -> None:
        self._transient_primary_button_needs_attention = enabled
        self._apply_generate_button_attention_style()

    def _transient_primary_button_default_tooltip(self) -> str:
        if self._transient_search_worker is not None and self._transient_search_worker.isRunning():
            return "Transient Finder is searching the selected folder."
        if self._transient_folder_ready():
            return "Search the opened transient folder for repeated uncataloged point-source candidates."
        return "Open a folder containing repeated sky images for Transient Finder."

    def _first_supported_transient_image_path(self, root_path: Path) -> Path | None:
        if not root_path.exists():
            return None
        candidates: list[Path] = []
        if root_path.is_file() and is_supported_image_path(root_path):
            candidates.append(root_path)
        elif root_path.is_dir():
            for path in root_path.rglob("*"):
                if path.is_file() and is_supported_image_path(path):
                    candidates.append(path)
        return sorted(candidates, key=lambda path: str(path).lower())[0] if candidates else None

    def _set_current_transient_image_path(self, image_path: Path | None, *, reset_view: bool, focus_candidate: bool) -> None:
        self._current_transient_source_image = image_path
        self._update_transient_frame_display(image_path)
        self._refresh_transient_image_view(reset_view=reset_view, focus_candidate=focus_candidate)
        self._sync_transient_image_controls()

    def _update_transient_frame_display(self, image_path: Path | None) -> None:
        if not hasattr(self, "_transient_frame_input"):
            return
        if image_path is None:
            self._transient_frame_input.clear()
            self._transient_frame_input.setToolTip("Shows the currently displayed source frame for the selected transient candidate.")
            return
        label = image_path.name
        observation_text = self._transient_frame_observation_label(image_path)
        if observation_text:
            label = f"{label} | {observation_text}"
        self._transient_frame_input.setText(label)
        self._transient_frame_input.setToolTip(str(image_path))

    def _transient_frame_observation_label(self, image_path: Path) -> str:
        result = self._current_transient_search_result
        if result is None:
            return ""
        try:
            image_resolved = image_path.resolve()
        except Exception:
            return ""
        for frame_result in result.frame_results:
            try:
                if frame_result.source_path.resolve() != image_resolved:
                    continue
            except Exception:
                continue
            if frame_result.metadata.date_obs is None:
                return ""
            return _coerce_utc_datetime(frame_result.metadata.date_obs).strftime("%Y-%m-%d %H:%M:%S UTC")
        return ""

    def _sync_transient_image_display_controls(self) -> None:
        if not hasattr(self, "_transient_image_stretch_combo"):
            return
        stretch_mode = "stf"
        inverted = False
        settings = getattr(self, "_settings", None)
        if settings is not None:
            stretch_mode = str(settings.image_display_stretch_mode or "stf")
            inverted = bool(settings.image_display_inverted)
        self._transient_image_stretch_combo.blockSignals(True)
        self._transient_image_invert_checkbox.blockSignals(True)
        stretch_index = self._transient_image_stretch_combo.findData(stretch_mode)
        self._transient_image_stretch_combo.setCurrentIndex(
            stretch_index if stretch_index >= 0 else max(0, self._transient_image_stretch_combo.findData("stf"))
        )
        self._transient_image_invert_checkbox.setChecked(inverted)
        self._transient_image_stretch_combo.blockSignals(False)
        self._transient_image_invert_checkbox.blockSignals(False)

    def _sync_transient_image_controls(self) -> None:
        if not hasattr(self, "_transient_image_view"):
            return
        current_image = getattr(self, "_current_transient_source_image", None)
        has_image = current_image is not None and current_image.exists()
        candidate = self._selected_transient_candidate()
        frame_count = len(self._transient_candidate_frame_paths(candidate)) if candidate is not None else 0
        self._transient_image_stretch_combo.setEnabled(has_image)
        self._transient_display_section_label.setEnabled(has_image)
        self._transient_adjust_levels_button.setEnabled(has_image)
        self._transient_image_invert_checkbox.setEnabled(has_image)
        self._transient_image_reset_display_button.setEnabled(has_image)
        self._transient_info_panel_toggle_button.setEnabled(has_image)
        self._transient_center_candidate_button.setEnabled(candidate is not None and has_image)
        self._transient_blink_button.setEnabled(candidate is not None and frame_count > 1)
        self._transient_blink_interval_combo.setEnabled(candidate is not None and frame_count > 1)
        self._transient_export_blink_button.setEnabled(candidate is not None and frame_count > 1)
        if frame_count <= 1 and self._transient_blink_button.isChecked():
            self._transient_blink_button.blockSignals(True)
            self._transient_blink_button.setChecked(False)
            self._transient_blink_button.blockSignals(False)
            self._transient_blink_timer.stop()

    def _transient_roi_margin_fraction(self) -> float:
        if not hasattr(self, "_transient_roi_margin_spin"):
            return 0.0
        return max(0.0, min(0.45, float(self._transient_roi_margin_spin.value()) / 100.0))

    def _handle_transient_roi_margin_changed(self, _value: int) -> None:
        self._refresh_transient_image_view(reset_view=False, focus_candidate=False)

    def _current_transient_image_render_settings(self) -> AnnotatedImageRenderSettings:
        stretch_mode = self._transient_image_stretch_combo.currentData()
        black_point, midtone_point, white_point = self._transient_image_levels
        return AnnotatedImageRenderSettings(
            stretch_mode=str(stretch_mode) if isinstance(stretch_mode, str) and stretch_mode else "stf",
            black_point=black_point,
            midtone_point=midtone_point,
            white_point=white_point,
            curve_points=self._transient_image_curve_points,
            inverted=self._transient_image_invert_checkbox.isChecked(),
        )

    def _handle_transient_image_display_controls_changed(self) -> None:
        self._refresh_transient_image_view(reset_view=False, focus_candidate=False)

    def _reset_transient_image_display_controls(self) -> None:
        self._sync_transient_image_display_controls()
        self._transient_image_levels = (0.0, 0.5, 1.0)
        self._transient_image_curve_points = ()
        self._refresh_transient_image_view(reset_view=False, focus_candidate=False)
        self.statusBar().showMessage("Reset transient image display controls.", 3000)

    def _open_transient_levels_dialog(self) -> None:
        if self._current_transient_source_image is None or not self._current_transient_source_image.exists():
            return
        try:
            display = self._cached_annotated_image_display(self._current_transient_source_image)
        except Exception as exc:
            QMessageBox.warning(self, "Curves unavailable", f"Could not prepare the transient preview for curve adjustment.\n\n{exc}")
            return
        dialog = CurvesDialog(
            display=display,
            initial_settings=self._current_transient_image_render_settings(),
            parent=self,
        )
        if dialog.exec() != int(QDialog.DialogCode.Accepted):
            return
        selected_settings = dialog.selected_settings()
        self._transient_image_levels = (
            float(selected_settings.black_point),
            float(selected_settings.midtone_point),
            float(selected_settings.white_point),
        )
        self._transient_image_curve_points = selected_settings.curve_points
        self._refresh_transient_image_view(reset_view=False, focus_candidate=False)
        self.statusBar().showMessage("Applied transient image curves.", 3000)

    def _refresh_transient_image_view(self, *, reset_view: bool, focus_candidate: bool) -> None:
        if self._current_transient_source_image is None or not self._current_transient_source_image.exists():
            self._transient_image_view.set_message("Open a transient folder to preview candidate source frames.")
            return
        try:
            display = self._cached_annotated_image_display(self._current_transient_source_image)
        except Exception:
            self._transient_image_view.set_message("Could not render the selected transient source image preview.")
            return
        self._transient_image_view.set_content(
            display,
            overlays=self._current_transient_image_overlays(),
            grid_overlays=[],
            editor_enabled=False,
            reset_view=reset_view,
            safe_margin_fraction=self._transient_roi_margin_fraction(),
            render_settings=self._current_transient_image_render_settings(),
            info_panel=(
                self._current_transient_image_info_panel()
                if getattr(self, "_transient_info_panel_visible", True)
                else None
            ),
        )
        if focus_candidate:
            focus_coordinates = self._selected_transient_focus_coordinates()
            if focus_coordinates is not None:
                self._transient_image_view.focus_on(*focus_coordinates)

    def _current_transient_image_info_panel(self) -> ImageInfoPanel | None:

        image_path = self._current_transient_source_image

        if image_path is None:

            return None

        candidate = self._selected_transient_candidate()

        status_text = (

            self._format_transient_candidate_details(candidate)

            if candidate is not None

            else f"Reviewing {image_path.name}"

        )

        return self._build_image_info_panel(image_path, None, [], status_text)

    def _toggle_transient_info_panel(self) -> None:

        self._transient_info_panel_visible = not self._transient_info_panel_visible

        self._update_transient_info_panel_toggle_button()

        if self._current_transient_source_image is not None:

            self._refresh_transient_image_view(

                reset_view=False,

                focus_candidate=self._transient_center_candidate_button.isChecked(),

            )

    def _update_transient_info_panel_toggle_button(self) -> None:

        if not hasattr(self, "_transient_info_panel_toggle_button"):

            return

        self._transient_info_panel_toggle_button.setText(

            "Hide Info" if getattr(self, "_transient_info_panel_visible", True) else "Show Info"

        )

    def _current_transient_image_overlays(self) -> list[ImageOverlay]:
        selected_candidates = self._selected_transient_candidates()
        image_path = self._current_transient_source_image
        if not selected_candidates or image_path is None:
            return []
        primary_candidate_id = selected_candidates[0].candidate_id
        primary_marker_color = self._asteroid_overlay_display_color("#f59e0b") if hasattr(self, "_asteroid_overlay_display_color") else "#f59e0b"
        primary_accent_color = self._asteroid_overlay_display_color("#fde68a") if hasattr(self, "_asteroid_overlay_display_color") else "#fde68a"
        secondary_marker_color = self._asteroid_overlay_display_color("#38bdf8") if hasattr(self, "_asteroid_overlay_display_color") else "#38bdf8"
        secondary_accent_color = self._asteroid_overlay_display_color("#bae6fd") if hasattr(self, "_asteroid_overlay_display_color") else "#bae6fd"
        overlays: list[ImageOverlay] = []
        for candidate in selected_candidates:
            overlay_position = self._transient_overlay_position_for_image(candidate, image_path)
            if overlay_position is None:
                continue
            x_value, y_value = overlay_position
            is_primary = candidate.candidate_id == primary_candidate_id
            marker_color = primary_marker_color if is_primary else secondary_marker_color
            accent_color = primary_accent_color if is_primary else secondary_accent_color
            overlays.append(
                ImageOverlay(
                    source_id=f"transient:{candidate.candidate_id}",
                    name=candidate.candidate_id,
                    x=x_value,
                    y=y_value,
                    aperture_radius=10.0,
                    annulus_inner_radius=10.0,
                    annulus_outer_radius=10.0,
                    color=marker_color,
                    show_annulus=False,
                    marker_style="cross",
                    pen_width=3.0 if is_primary else 2.5,
                    text_color=accent_color,
                    accent_color=accent_color,
                    outline_color="#111827",
                    outline_width=1.5,
                )
            )
        return overlays

    def _selected_transient_focus_coordinates(self) -> tuple[float, float] | None:
        detection = self._selected_transient_detection_for_current_image()
        if detection is not None:
            return float(detection.x), float(detection.y)
        candidate = self._selected_transient_candidate()
        if candidate is None or not candidate.detections:
            return None
        detection = candidate.detections[0]
        return float(detection.x), float(detection.y)

    def _selected_transient_detection_for_current_image(self) -> TransientSourceDetection | None:
        candidate = self._selected_transient_candidate()
        image_path = self._current_transient_source_image
        if candidate is None or image_path is None:
            return None
        return self._transient_detection_for_image(candidate, image_path)

    def _transient_detection_for_image(
        self,
        candidate: TransientCandidate,
        image_path: Path,
    ) -> TransientSourceDetection | None:
        for detection in candidate.detections:
            if detection.source_path.exists() and detection.source_path.resolve() == image_path.resolve():
                return detection
        return None

    def _transient_overlay_position_for_image(
        self,
        candidate: TransientCandidate,
        image_path: Path,
    ) -> tuple[float, float] | None:
        detection = self._transient_detection_for_image(candidate, image_path)
        if detection is not None:
            return float(detection.x), float(detection.y)
        frame_result = self._transient_frame_result_for_image(image_path)
        if frame_result is None or frame_result.wcs_path is None:
            return None
        try:
            wcs = WCS(read_header(frame_result.wcs_path))
            x_value, y_value = wcs.world_to_pixel_values(float(candidate.ra_deg), float(candidate.dec_deg))
        except Exception:
            return None
        if not (np.isfinite(x_value) and np.isfinite(y_value)):
            return None
        width = frame_result.solved_field.width if frame_result.solved_field is not None else frame_result.metadata.width
        height = frame_result.solved_field.height if frame_result.solved_field is not None else frame_result.metadata.height
        if width is not None and height is not None:
            if float(x_value) < 0.0 or float(y_value) < 0.0 or float(x_value) > float(width - 1) or float(y_value) > float(height - 1):
                return None
        return float(x_value), float(y_value)

    def _transient_frame_result_for_image(self, image_path: Path) -> TransientFrameResult | None:
        result = self._current_transient_search_result
        if result is None:
            return None
        try:
            image_resolved = image_path.resolve()
        except Exception:
            return None
        for frame_result in result.frame_results:
            try:
                if frame_result.source_path.resolve() == image_resolved:
                    return frame_result
            except Exception:
                continue
        return None

    def _center_selected_transient_candidate(self) -> None:
        focus_coordinates = self._selected_transient_focus_coordinates()
        if focus_coordinates is None:
            return
        self._transient_image_view.focus_on(*focus_coordinates)
        self.statusBar().showMessage("Centered the selected transient candidate in the image view.", 3000)

    def _handle_transient_center_candidate_toggled(self, checked: bool) -> None:
        if checked:
            focus_coordinates = self._selected_transient_focus_coordinates()
            if focus_coordinates is not None:
                self._transient_image_view.focus_on(*focus_coordinates)

    def _transient_candidate_frame_paths(self, candidate: TransientCandidate | None) -> list[Path]:
        if candidate is None:
            return []
        paths: list[Path] = []
        seen: set[Path] = set()
        candidate_paths = candidate.blink_paths or tuple(detection.source_path for detection in candidate.detections)
        for path in candidate_paths:
            if not path.exists():
                continue
            resolved = path.resolve()
            if resolved in seen:
                continue
            seen.add(resolved)
            paths.append(path)
        return paths

    def _start_transient_image_preload(self, frame_paths: list[Path]) -> None:
        unique_paths: list[Path] = []
        seen: set[Path] = set()
        for frame_path in frame_paths:
            if not frame_path.exists():
                continue
            resolved = frame_path.resolve()
            if resolved in seen:
                continue
            seen.add(resolved)
            cache_key = self._image_display_cache_key(frame_path)
            if cache_key in self._image_display_cache:
                continue
            unique_paths.append(frame_path)
        if not unique_paths:
            return
        if self._transient_preload_worker is not None and self._transient_preload_worker.isRunning():
            return
        worker = ImageDisplayPreloadWorker(
            frame_paths=unique_paths,
            max_parallel_workers=resolve_shared_parallel_workers(self._ensure_settings()),
            parent=self,
        )
        worker.preload_completed.connect(self._handle_transient_image_preload_completed)
        worker.preload_failed.connect(self._handle_transient_image_preload_failed)
        self._transient_preload_worker = worker
        worker.start()

    def _handle_transient_image_preload_completed(self, result: object) -> None:
        self._transient_preload_worker = None
        if not isinstance(result, ImageDisplayPreloadResult):
            return
        for cache_key, display in result.image_displays.items():
            self._store_cached_annotated_image_display(cache_key, display)

    def _handle_transient_image_preload_failed(self, message: str) -> None:
        self._transient_preload_worker = None
        if message:
            self._append_transient_workflow_note(f"Frame preload warning: {message}")

    def _handle_transient_blink_toggled(self, checked: bool) -> None:
        if checked:
            self._prepare_transient_blink_playback()
            return
        self._transient_blink_timer.stop()
        self._transient_blink_frame_advance_in_progress = False
        if self._selected_transient_candidate() is not None:
            self._append_transient_workflow_note("Blink playback stopped.")

    def _handle_transient_blink_interval_changed(self, _index: int) -> None:
        interval_ms = self._transient_blink_interval_combo.currentData()
        if not isinstance(interval_ms, int):
            interval_ms = _TRANSIENT_BLINK_INTERVAL_MS
        self._transient_blink_timer.setInterval(max(50, int(interval_ms)))

    def _prepare_transient_blink_playback(self) -> None:
        candidate = self._selected_transient_candidate()
        paths = self._transient_candidate_frame_paths(candidate)
        if candidate is None or len(paths) <= 1:
            self._transient_blink_button.blockSignals(True)
            self._transient_blink_button.setChecked(False)
            self._transient_blink_button.blockSignals(False)
            self.statusBar().showMessage("Select a transient candidate with at least two frames before blinking.", 5000)
            return
        progress_dialog = QProgressDialog("Preparing blink playback...", "", 0, max(1, len(paths)), self)
        progress_dialog.setWindowTitle("Preparing Blink")
        progress_dialog.setMinimumDuration(0)
        progress_dialog.setAutoClose(False)
        progress_dialog.setAutoReset(False)
        progress_dialog.setWindowModality(Qt.WindowModality.ApplicationModal)
        progress_dialog.setValue(0)
        progress_dialog.show()
        QApplication.processEvents()
        try:
            self._append_transient_workflow_note(f"Preparing blink playback for {candidate.candidate_id}.")
            for frame_index, image_path in enumerate(paths, start=1):
                progress_dialog.setLabelText(f"Loading {frame_index}/{len(paths)}: {image_path.name}")
                progress_dialog.setValue(frame_index - 1)
                QApplication.processEvents()
                self._cached_annotated_image_display(image_path)
                progress_dialog.setValue(frame_index)
                QApplication.processEvents()
        except Exception as exc:
            self._transient_blink_button.blockSignals(True)
            self._transient_blink_button.setChecked(False)
            self._transient_blink_button.blockSignals(False)
            self._append_transient_workflow_note(f"Blink preload failed: {exc}")
            QMessageBox.warning(self, "Blink preload failed", str(exc))
            return
        finally:
            progress_dialog.close()
            progress_dialog.deleteLater()
        if self._transient_blink_button.isChecked():
            self._append_transient_workflow_note(f"Blink frames ready: loaded {len(paths)} frame preview(s).")
            self._start_transient_blink_playback()

    def _start_transient_blink_playback(self) -> None:
        candidate = self._selected_transient_candidate()
        paths = self._transient_candidate_frame_paths(candidate)
        if candidate is None or len(paths) <= 1:
            self._transient_blink_button.blockSignals(True)
            self._transient_blink_button.setChecked(False)
            self._transient_blink_button.blockSignals(False)
            self.statusBar().showMessage("Select a transient candidate with at least two detections before blinking.", 5000)
            return
        if self._current_transient_source_image is None or self._current_transient_source_image.resolve() not in {path.resolve() for path in paths}:
            self._set_current_transient_image_path(paths[0], reset_view=False, focus_candidate=True)
        self._transient_blink_timer.start()
        self.statusBar().showMessage(f"Blinking {candidate.candidate_id} across {len(paths)} frame(s).", 3000)
        self._append_transient_workflow_note(
            f"Blink playback started for {candidate.candidate_id} at {self._transient_blink_timer.interval() / 1000.0:.2f} s."
        )

    def _advance_transient_blink_frame(self) -> None:
        if self._transient_blink_frame_advance_in_progress:
            return
        candidate = self._selected_transient_candidate()
        paths = self._transient_candidate_frame_paths(candidate)
        if candidate is None or len(paths) <= 1:
            self._transient_blink_timer.stop()
            self._transient_blink_button.blockSignals(True)
            self._transient_blink_button.setChecked(False)
            self._transient_blink_button.blockSignals(False)
            return
        current_index = -1
        if self._current_transient_source_image is not None:
            current_resolved = self._current_transient_source_image.resolve()
            for path_index, path in enumerate(paths):
                if path.resolve() == current_resolved:
                    current_index = path_index
                    break
        next_path = paths[(current_index + 1) % len(paths)]
        restart_timer = self._transient_blink_timer.isActive()
        if restart_timer:
            self._transient_blink_timer.stop()
        self._transient_blink_frame_advance_in_progress = True
        try:
            self._set_current_transient_image_path(next_path, reset_view=False, focus_candidate=True)
        finally:
            self._transient_blink_frame_advance_in_progress = False
            if restart_timer and self._transient_blink_button.isChecked() and len(paths) > 1:
                self._transient_blink_timer.start()

    def _default_transient_blink_export_path(self, candidate: TransientCandidate) -> Path:
        root_path = self._current_transient_root_path
        if root_path is not None and root_path.exists() and root_path.is_dir():
            return root_path / f"{candidate.candidate_id}_transient_blink.gif"
        if candidate.detections:
            source_path = candidate.detections[0].source_path
            return source_path.with_name(f"{candidate.candidate_id}_transient_blink.gif")
        return Path.cwd() / f"{candidate.candidate_id}_transient_blink.gif"

    def _capture_transient_blink_frames(self, candidate: TransientCandidate, progress_dialog: QProgressDialog | None = None) -> list[QImage]:
        paths = self._transient_candidate_frame_paths(candidate)
        if len(paths) <= 1:
            raise ValueError("Select a transient candidate with at least two detections before exporting blink playback.")
        exported_frames: list[QImage] = []
        original_path = self._current_transient_source_image
        try:
            for frame_index, image_path in enumerate(paths):
                if progress_dialog is not None and progress_dialog.wasCanceled():
                    raise _TransientBlinkExportCanceled()
                self._set_current_transient_image_path(image_path, reset_view=False, focus_candidate=True)
                QApplication.processEvents()
                if progress_dialog is not None and progress_dialog.wasCanceled():
                    raise _TransientBlinkExportCanceled()
                exported_frames.append(self._transient_image_view.capture_view_image())
                if progress_dialog is not None:
                    progress_dialog.setValue(frame_index + 1)
                    progress_dialog.setLabelText(f"Captured {frame_index + 1}/{len(paths)} blink frame(s)...")
                QApplication.processEvents()
        finally:
            self._set_current_transient_image_path(original_path, reset_view=False, focus_candidate=False)
            QApplication.processEvents()
        return exported_frames

    def _export_transient_blink_animation(self) -> None:
        candidate = self._selected_transient_candidate()
        if candidate is None or len(self._transient_candidate_frame_paths(candidate)) <= 1:
            QMessageBox.information(
                self,
                "Blink export unavailable",
                "Select a transient candidate with at least two detections before exporting blink playback.",
            )
            return
        selected_path, _selected_filter = QFileDialog.getSaveFileName(
            self,
            "Export Transient Blink Animation",
            str(self._default_transient_blink_export_path(candidate)), 
            "Animated GIF Files (*.gif);;MP4 Video Files (*.mp4)",
        )
        if not selected_path:
            return
        output_path, export_format = self._resolve_blink_export_target(selected_path, _selected_filter)
        was_blinking = self._transient_blink_timer.isActive()
        was_checked = self._transient_blink_button.isChecked()
        self._transient_blink_timer.stop()
        self._transient_blink_button.blockSignals(True)
        self._transient_blink_button.setChecked(False)
        self._transient_blink_button.blockSignals(False)
        progress_dialog = QProgressDialog(
            "Capturing transient blink frames...",
            "Cancel",
            0,
            max(1, len(self._transient_candidate_frame_paths(candidate))),
            self,
        )
        progress_dialog.setWindowTitle("Export Blink")
        progress_dialog.setMinimumDuration(0)
        progress_dialog.setAutoClose(False)
        progress_dialog.setAutoReset(False)
        progress_dialog.setWindowModality(Qt.WindowModality.ApplicationModal)
        progress_dialog.setValue(0)
        progress_dialog.show()
        try:
            self._append_transient_workflow_note(f"Exporting transient blink animation to {output_path}.")
            frames = self._capture_transient_blink_frames(candidate, progress_dialog)
            if progress_dialog.wasCanceled():
                raise _TransientBlinkExportCanceled()
            progress_dialog.setLabelText("Encoding MP4 video..." if export_format == "mp4" else "Encoding animated GIF...")
            QApplication.processEvents()
            if export_format == "mp4":
                export_qimages_to_mp4(
                    frames,
                    output_path,
                    frame_duration_ms=max(50, self._transient_blink_timer.interval()),
                    scale_percent=100,
                )
            else:
                export_qimages_to_gif(
                    frames,
                    output_path,
                    frame_duration_ms=max(50, self._transient_blink_timer.interval()),
                    loop_count=0,
                    scale_percent=100,
                )
        except _TransientBlinkExportCanceled:
            self._append_transient_workflow_note("Transient blink export canceled.")
            self.statusBar().showMessage("Transient blink export canceled.", 5000)
            return
        except Exception as exc:
            self._append_transient_workflow_note(f"Transient blink export failed: {exc}")
            QMessageBox.warning(self, "Blink export failed", str(exc))
            return
        finally:
            progress_dialog.close()
            progress_dialog.deleteLater()
            self._transient_blink_button.blockSignals(True)
            self._transient_blink_button.setChecked(was_checked)
            self._transient_blink_button.blockSignals(False)
            if was_blinking:
                self._start_transient_blink_playback()
        self._append_transient_workflow_note(f"Transient blink animation exported to {output_path}.")
        self.statusBar().showMessage(f"Exported transient blink animation to {output_path.name}.", 5000)

    def _browse_for_root(self) -> None:

        selected = QFileDialog.getExistingDirectory(self, "Select data folder", self._root_path_input.text())

        if selected:

            self._root_path_input.setText(selected)

            if not self._hr_working_directory_input.text().strip():

                self._hr_working_directory_input.setText(selected)

            root_path = Path(selected).expanduser()

            if root_path.exists():

                self._load_settings_for_root(root_path, preserve_app_mode=True)

                self._start_scan()

    def _handle_differential_primary_button_clicked(self) -> None:

        if getattr(self, "_differential_scan_in_progress", False):

            return

        self._open_differential_workflow_dialog()

    def _open_differential_workflow_dialog(self) -> None:

        dialog = self._differential_workflow_dialog

        if dialog is not None and qt_object_is_valid(dialog):

            dialog.show()

            dialog.raise_()

            dialog.activateWindow()

            return

        dialog = _DifferentialWorkflowDialog(

            self,

            choose_folder_callback=self._choose_differential_workflow_folder,

            generate_callback=self._start_differential_workflow_generate,

        )

        dialog.destroyed.connect(lambda _obj=None: setattr(self, "_differential_workflow_dialog", None))

        self._differential_workflow_dialog = dialog

        root_text = self._root_path_input.text().strip()

        if root_text:

            root_path = Path(root_text).expanduser()

        else:

            root_path = None

        if root_path is not None and root_path.exists():

            dialog.set_filter_defaults(AppSettings.from_root(root_path))

            dialog.set_folder_path(root_path)

        selected_object = self._selected_object_name()

        if selected_object is not None and self._current_report is not None:

            summary = next((item for item in self._current_report.object_summaries if item.object_name == selected_object), None)

            if summary is not None:

                dialog.set_ready(selected_object, len(summary.files))

        dialog.show()

        dialog.raise_()

        dialog.activateWindow()

    def _choose_differential_workflow_folder(self) -> None:

        selected = QFileDialog.getExistingDirectory(self, "Select image folder", self._root_path_input.text())

        if not selected:

            return

        self._root_path_input.setText(selected)

        if not self._hr_working_directory_input.text().strip():

            self._hr_working_directory_input.setText(selected)

        root_path = Path(selected).expanduser()

        if not root_path.exists():

            QMessageBox.warning(self, "Invalid path", "The selected data folder does not exist.")

            return

        self._differential_workflow_scan_requested = True

        if self._differential_workflow_dialog is not None and qt_object_is_valid(self._differential_workflow_dialog):

            self._differential_workflow_dialog.set_scanning(root_path)

        self._load_settings_for_root(root_path, preserve_app_mode=True)

        if self._differential_workflow_dialog is not None and qt_object_is_valid(self._differential_workflow_dialog) and self._settings is not None:

            self._differential_workflow_dialog.set_filter_defaults(self._settings)

        self._start_scan()

    def _prompt_differential_workflow_calibration_request(self, *, align_output: bool) -> CalibrationPipelineRequest | None:

        if self._calibration_worker is not None and self._calibration_worker.isRunning():

            self.statusBar().showMessage("Image calibration is already running.", 5000)

            return None

        root_path = Path(self._root_path_input.text()).expanduser()

        default_root = root_path if root_path.exists() else Path.cwd()

        settings = self._ensure_settings()

        dialog = WorkflowCalibrationPipelineDialog(
            default_root=default_root,
            settings=settings,
            align_output=align_output,
            parent=self,
        )

        if dialog.exec() != int(QDialog.DialogCode.Accepted):

            return None

        request = dialog.request()

        settings.calibration_bias_path = "" if request.bias_path is None else str(request.bias_path)

        settings.calibration_dark_path = "" if request.dark_path is None else str(request.dark_path)

        settings.calibration_flat_path = "" if request.flat_path is None else str(request.flat_path)

        settings_root = root_path if root_path.exists() else default_root

        settings.save(settings_root)

        return replace(request, max_parallel_workers=resolve_shared_parallel_workers(settings))

    def _apply_differential_workflow_alignment_setting(self, root_path: Path, checked: bool) -> None:

        settings = self._settings if self._settings is not None else AppSettings.from_root(root_path)

        settings.assume_aligned_images = checked

        settings.save(root_path)

        root_text = self._root_path_input.text().strip()

        current_root = Path(root_text).expanduser() if root_text else None

        if current_root == root_path:

            self._settings = settings

            self._sync_alignment_control()

    def _differential_workflow_uses_virtual_alignment(self, options: _DifferentialWorkflowOptions | None = None) -> bool:

        current_options = options if options is not None else self._differential_workflow_options

        if current_options is None:

            return False

        return current_options.calibrate_images and current_options.align_star_images

    def _differential_workflow_should_assume_aligned_images(self, options: _DifferentialWorkflowOptions | None = None) -> bool:

        current_options = options if options is not None else self._differential_workflow_options

        if current_options is None:

            return False

        return current_options.align_star_images and not self._differential_workflow_uses_virtual_alignment(current_options)

    def _workflow_supported_image_count(self, root_path: Path) -> int:

        if not root_path.exists():

            return 0

        return sum(1 for candidate in root_path.rglob("*") if candidate.is_file() and is_supported_image_path(candidate))

    def _resolve_differential_workflow_cached_root(
        self,
        root_path: Path,
        options: _DifferentialWorkflowOptions,
    ) -> tuple[Path, bool, list[str]] | None:

        if not options.calibrate_images:

            return None

        output_root = root_path / "calibration_output"

        calibrated_root = output_root / "calibrated"

        aligned_root = output_root / "aligned"

        calibrated_count = self._workflow_supported_image_count(calibrated_root)

        aligned_count = self._workflow_supported_image_count(aligned_root)

        if options.align_star_images and aligned_count > 0:

            return (
                aligned_root,
                True,
                [
                    f"Found {aligned_count:,} cached aligned frame(s) in {aligned_root}.",
                    "Workflow skipped calibration and star alignment and continued from the cached aligned stack.",
                ],
            )

        if calibrated_count <= 0:

            return None

        if options.align_star_images:

            return (
                calibrated_root,
                False,
                [
                    f"Found {calibrated_count:,} cached calibrated frame(s) in {calibrated_root}.",
                    "Workflow skipped calibration and continued from the cached calibrated stack; Differential photometry will use the calibrated frames directly for star-aligned processing.",
                ],
            )

        return (
            calibrated_root,
            False,
            [
                f"Found {calibrated_count:,} cached calibrated frame(s) in {calibrated_root}.",
                "Workflow skipped calibration and continued from the cached calibrated stack.",
            ],
        )

    def _differential_workflow_processing_settings(
        self,
        root_path: Path,
        object_name: str,
        options: _DifferentialWorkflowOptions,
    ) -> AppSettings:

        settings = AppSettings.from_root(root_path)

        selected_sources = dict(settings.selected_catalog_source_ids or {})

        selected_sources.pop(object_name, None)

        manual_configs = dict(settings.manual_photometry_configs or {})

        manual_config = manual_configs.get(object_name)

        if manual_config is not None and manual_config.mode != ObjectPhotometryMode.AUTO:

            manual_configs[object_name] = replace(manual_config, mode=ObjectPhotometryMode.AUTO)

        designation_filters = (
            list(settings.variable_star_designation_filters)
            if options.use_designation_filters
            else list(VariableStarDesignationFamily)
        )

        return replace(
            settings,
            assume_aligned_images=self._differential_workflow_should_assume_aligned_images(options),
            variable_star_limit_mode=VariableStarLimitMode.PERCENT,
            variable_star_limit_value=max(1, min(100, int(options.brightest_variable_percent))),
            variable_star_designation_filters=designation_filters,
            selected_catalog_source_ids=selected_sources,
            manual_photometry_configs=manual_configs,
        )

    def _differential_workflow_filter_summary(self, options: _DifferentialWorkflowOptions) -> str:

        designation_text = "Settings-General designations" if options.use_designation_filters else "all designation families"

        target_text = "Analyze Best ADU range" if options.analyze_best_targets else f"top {max(1, min(100, int(options.brightest_variable_percent)))}% brightest variables"

        return f"Filter Targets={designation_text}, {target_text}"

    def _begin_differential_workflow_processing_from_selection(self) -> bool:

        if not self._current_report or not self._current_report.object_summaries:

            return False

        selected_row = self._object_table.currentRow()

        if selected_row < 0:

            selected_row = 0

            self._object_table.selectRow(0)

        if selected_row < 0 or selected_row >= len(self._current_report.object_summaries):

            return False

        object_summary = self._current_report.object_summaries[selected_row]

        object_name = object_summary.object_name

        root_path = Path(self._root_path_input.text()).expanduser()

        processing_settings = self._differential_workflow_processing_settings(
            root_path,
            object_name,
            self._differential_workflow_options,
        )

        self._pending_processing_settings_override = processing_settings

        self._pending_processing_analyze_best_targets = bool(self._differential_workflow_options.analyze_best_targets)

        self._apply_differential_workflow_alignment_setting(
            root_path,
            self._differential_workflow_should_assume_aligned_images(),
        )

        self._set_differential_workflow_stage(
            "loading cached results",
            "Checking saved light-curve results before Generate continues.",
        )

        self._cached_processing_report_context = (root_path, object_name)

        self._cached_processing_report_worker = CachedProcessingReportWorker(
            root_path=root_path,
            object_name=object_name,
            summary_files=object_summary.files,
            settings_override=processing_settings,
            analyze_best_targets=bool(self._differential_workflow_options.analyze_best_targets),
            parent=self,
        )

        self._cached_processing_report_worker.cache_loaded.connect(self._handle_cached_processing_report_loaded)

        self._cached_processing_report_worker.cache_failed.connect(self._handle_cached_processing_report_failed)

        self._cached_processing_report_worker.start()

        return True

    def _handle_cached_processing_report_loaded(self, payload: object) -> None:

        self._cached_processing_report_worker = None

        context = self._cached_processing_report_context

        self._cached_processing_report_context = None

        if context is None:

            return

        root_path, object_name = context

        cached_report: ProcessingReport | None = None

        cache_note: str | None = None

        if isinstance(payload, tuple) and len(payload) == 2:

            maybe_report, maybe_note = payload

            if isinstance(maybe_report, ProcessingReport):

                cached_report = maybe_report

            if isinstance(maybe_note, str):

                cache_note = maybe_note

        if cache_note:

            self._append_work_log(cache_note)

        if cached_report is None:

            self._differential_workflow_cache_summary_lines = []

            self._set_differential_workflow_stage("generating light curves", "Reading files, measuring stars, and building light curves.")

            self._begin_processing(root_path, object_name)

            return

        self._pending_processing_settings_override = None

        self._pending_processing_analyze_best_targets = False

        cache_summary_lines = [

            *self._differential_workflow_cache_summary_lines,

            (

                f"Reused cached light-curve results for {object_name}: "

                f"{len(cached_report.light_curves)} light curve(s), "

                f"{len(cached_report.measurements)} measurement row(s), "

                f"{cached_report.solved_files} solved file(s)."

            ),

        ]

        self._differential_workflow_cache_summary_lines = []

        self._append_work_log(f"Workflow reused cached processing results for {object_name}.")

        QMessageBox.information(self, "Workflow Reused Cached Results", "\n".join(cache_summary_lines))

        self._set_differential_workflow_stage(

            "restoring cached results",

            "Updating Source Results, file rows, notes, and light curves before the selected follow-up steps.",

        )

        QTimer.singleShot(0, lambda report=cached_report: self._restore_cached_processing_report_after_prompt(report))

    def _handle_cached_processing_report_failed(self, message: str) -> None:

        self._cached_processing_report_worker = None

        context = self._cached_processing_report_context

        self._cached_processing_report_context = None

        if context is None:

            return

        root_path, object_name = context

        self._append_work_log(f"Ignored cached light-curve load failure: {message}")

        self._differential_workflow_cache_summary_lines = []

        self._set_differential_workflow_stage("generating light curves", "Reading files, measuring stars, and building light curves.")

        self._begin_processing(root_path, object_name)

    def _restore_cached_processing_report_after_prompt(self, report: ProcessingReport) -> None:

        self._yield_differential_workflow_ui()

        self._handle_processing_completed(report, save_cache=False)

    def _start_differential_workflow_generate(self, options: _DifferentialWorkflowOptions) -> None:

        if not self._current_report or not self._current_report.object_summaries:

            QMessageBox.information(self, "No folder loaded", "Choose a folder before generating results.")

            return

        selected_row = self._object_table.currentRow()

        if selected_row < 0:

            selected_row = 0

            self._object_table.selectRow(0)

        if selected_row < 0 or selected_row >= len(self._current_report.object_summaries):

            QMessageBox.information(self, "No object available", "No usable object was found in the selected folder.")

            return

        self._differential_workflow_options = options

        self._differential_workflow_pending_steps = []

        self._differential_workflow_current_step = None

        self._differential_workflow_cache_summary_lines = []

        self._differential_workflow_auto_generate_after_scan = False

        if options.pull_periods:

            self._differential_workflow_pending_steps.append("pull-periods")

        if options.calculate_periods:

            self._differential_workflow_pending_steps.append("calculate-periods")

        if options.create_measurements_table:

            self._differential_workflow_pending_steps.append("measurements-table")

        self._differential_workflow_active = True

        self._append_work_log(

            "Workflow Pipeline started: "

            f"Calibration={'on' if options.calibrate_images else 'off'}, "

            f"Star Alignment={'on' if options.align_star_images else 'off'}, "

            "Plate-solving=on, "

            f"{self._differential_workflow_filter_summary(options)}, "

            "Light Curves=on; "

            f"Pull Periods={'on' if options.pull_periods else 'off'}, "

            f"Calculate Periods={'on' if options.calculate_periods else 'off'}, "

            f"Measurements Table={'on' if options.create_measurements_table else 'off'}."

        )

        if self._differential_workflow_uses_virtual_alignment(options):

            self._append_work_log(
                "Workflow Star Alignment will continue from calibrated frames without writing a separate aligned copy folder."
            )

        root_path = Path(self._root_path_input.text()).expanduser()

        cached_root_info = self._resolve_differential_workflow_cached_root(root_path, options)

        if cached_root_info is not None:

            cached_root, assume_aligned_images, summary_lines = cached_root_info

            self._differential_workflow_cache_summary_lines = list(summary_lines)

            for line in summary_lines:

                self._append_work_log(line)

            self._differential_workflow_current_step = "cached-scan"

            self._set_differential_workflow_stage("checking cached preparation", summary_lines[-1])

            self._root_path_input.setText(str(cached_root))

            self._load_settings_for_root(cached_root, preserve_app_mode=True)

            self._apply_differential_workflow_alignment_setting(cached_root, assume_aligned_images)

            self._differential_workflow_scan_requested = True

            self._differential_workflow_auto_generate_after_scan = True

            if self._differential_workflow_dialog is not None and qt_object_is_valid(self._differential_workflow_dialog):

                self._differential_workflow_dialog.set_scanning(cached_root)

            self._start_scan()

            return

        if options.calibrate_images:

            request = self._prompt_differential_workflow_calibration_request(
                align_output=self._differential_workflow_should_assume_aligned_images(options)
            )

            if request is None:

                self._differential_workflow_active = False

                self._differential_workflow_pending_steps = []

                self._differential_workflow_current_step = None

                return

            self._differential_workflow_current_step = "calibration"

            calibration_message = "Applying calibration masters before Differential processing starts."

            if self._differential_workflow_uses_virtual_alignment(options):

                calibration_message = (
                    "Applying calibration masters before Differential processing starts; the workflow will continue from the calibrated frames without creating a separate aligned copy folder."
                )

            self._set_differential_workflow_stage("calibrating images", calibration_message)

            self._append_work_log(

                "Workflow calibration step started"

                + (
                    " with materialized aligned output enabled."
                    if request.align_output
                    else " using calibrated-frame workflow processing."
                    if self._differential_workflow_uses_virtual_alignment(options)
                    else "."
                )

            )

            self._start_calibration_pipeline(request)

            return

        if not self._begin_differential_workflow_processing_from_selection():

            self._fail_differential_workflow("No usable object was found in the selected folder.")

    def _create_differential_section_menu_button(self, title: str) -> QPushButton:

        button = QPushButton(title)

        button.setToolTip(f"Open the {title} controls.")

        button.setSizePolicy(QSizePolicy.Policy.Maximum, QSizePolicy.Policy.Fixed)

        button.setFixedWidth(self.fontMetrics().horizontalAdvance(title) + 40)

        return button

    def _create_differential_gear_icon(self, *, color_hex: str = "#f8fafc") -> QIcon:

        icon_extent = 24

        pixmap = QPixmap(icon_extent, icon_extent)

        pixmap.fill(Qt.GlobalColor.transparent)

        painter = QPainter(pixmap)

        painter.setRenderHint(QPainter.RenderHint.Antialiasing, True)

        color = QColor(color_hex)

        painter.setPen(QPen(color, 1.5))

        painter.setBrush(color)

        gear_path = QPainterPath()

        center = icon_extent / 2.0

        tooth_count = 8

        outer_radius = 6.8

        inner_radius = 5.4

        for point_index in range(tooth_count * 4):

            angle = (-math.pi / 2.0) + (point_index * math.pi / (tooth_count * 2.0))

            phase = point_index % 4

            radius = outer_radius if phase in {0, 1} else inner_radius

            point = QPointF(
                center + math.cos(angle) * radius,
                center + math.sin(angle) * radius,
            )

            if point_index == 0:

                gear_path.moveTo(point)

            else:

                gear_path.lineTo(point)

        gear_path.closeSubpath()

        painter.drawPath(gear_path)

        painter.setCompositionMode(QPainter.CompositionMode.CompositionMode_Clear)

        painter.setPen(Qt.PenStyle.NoPen)

        painter.setBrush(Qt.GlobalColor.transparent)

        hole_diameter = 5.8

        hole_offset = center - (hole_diameter / 2.0)

        painter.drawEllipse(QRectF(hole_offset, hole_offset, hole_diameter, hole_diameter))

        painter.end()

        return QIcon(pixmap)

    def _create_display_menu_content(

        self,

        stretch_combo: QComboBox,

        curves_button: QPushButton,

        invert_checkbox: QCheckBox | None = None,

        *,

        trailing_widgets: Sequence[QWidget] = (),

    ) -> QWidget:

        content = QWidget()

        content_layout = QVBoxLayout()

        content_layout.setContentsMargins(6, 6, 6, 6)

        content_layout.setSpacing(10)

        stretch_row = QHBoxLayout()

        stretch_row.setContentsMargins(0, 0, 0, 0)

        stretch_row.setSpacing(10)

        stretch_label = QLabel("Stretch:")

        stretch_label.setMinimumWidth(self.fontMetrics().horizontalAdvance("Stretch:") + 8)

        stretch_combo.setMinimumWidth(max(156, stretch_combo.minimumSizeHint().width()))

        stretch_combo.setSizePolicy(QSizePolicy.Policy.Expanding, QSizePolicy.Policy.Fixed)

        stretch_row.addWidget(stretch_label)

        stretch_row.addWidget(stretch_combo, 1)

        content_layout.addLayout(stretch_row)

        action_row = QHBoxLayout()

        action_row.setContentsMargins(0, 0, 0, 0)

        action_row.setSpacing(10)

        action_row.addWidget(curves_button)

        if invert_checkbox is not None:

            action_row.addWidget(invert_checkbox)

        action_row.addStretch(1)

        for widget in trailing_widgets:

            action_row.addWidget(widget)

        content_layout.addLayout(action_row)

        content.setLayout(content_layout)

        return content

    def _create_differential_section_menu(self, button: QPushButton, content: QWidget) -> QMenu:

        menu = QMenu(button)

        widget_action = QWidgetAction(menu)

        widget_action.setDefaultWidget(content)

        menu.addAction(widget_action)

        menu.setMinimumWidth(max(button.sizeHint().width(), content.sizeHint().width() + 20))

        button.setMenu(menu)

        return menu

    def _sync_differential_primary_button(self) -> None:

        if not hasattr(self, "_process_button"):

            return

        scan_in_progress = bool(getattr(self, "_differential_scan_in_progress", False))

        has_opened_workspace = getattr(self, "_current_report", None) is not None

        current_mode = getattr(getattr(self, "_settings", None), "app_mode", AppMode.DIFFERENTIAL_PHOTOMETRY)

        if scan_in_progress:

            self._process_button.setText("Scanning...")

            self._process_button.setEnabled(False)

            self._process_button.setToolTip("Scanning the selected Differential Photometry folder.")

        elif has_opened_workspace:

            self._process_button.setText("Open")

            self._process_button.setEnabled(current_mode == AppMode.DIFFERENTIAL_PHOTOMETRY)

            self._process_button.setToolTip("Open the guided Differential Photometry workflow.")

        else:

            self._process_button.setText("Open")

            self._process_button.setEnabled(current_mode == AppMode.DIFFERENTIAL_PHOTOMETRY)

            self._process_button.setToolTip("Open the guided Differential Photometry workflow.")

        if hasattr(self, "_open_workspace_menu_button"):

            self._open_workspace_menu_button.setVisible(False)

        if hasattr(self, "_rescan_workspace_menu_action"):

            root_path = Path(self._root_path_input.text()).expanduser()

            self._rescan_workspace_menu_action.setEnabled(root_path.exists())

