        discovery_detector_mode = str(discovery_settings.asteroid_discovery_detector_mode or "hybrid").strip().lower()

        discovery_streak_min_area_px = max(2, int(discovery_settings.asteroid_discovery_streak_min_area_px))

        discovery_streak_min_elongation = max(1.0, float(discovery_settings.asteroid_discovery_streak_min_elongation))

        reference_path = self._current_asteroid_source_image or frame_paths[0]

        assume_aligned = bool(discovery_run_options.assume_aligned)

