    def _apply_hr_motion_group_settings(self, motion_group_settings: HrMotionGroupSettings, *, save: bool = True) -> HrMotionGroupSettings:

        normalized_settings = motion_group_settings.normalized()

        settings = self._ensure_settings()

        settings.hr_motion_group_preset = normalized_settings.preset

        settings.hr_motion_group_method = normalized_settings.method

        settings.hr_motion_group_strictness = normalized_settings.strictness

