    def _resolve_hr_source_field(self, source_image: Path, progress_callback: Callable[[str], None] | None = None):

        header, width, height = read_header_and_shape(source_image)

        valid_wcs, reasons = validate_wcs(header, source_image)

        if valid_wcs:

            solved_field = extract_solved_field(header, width, height, source_image)

            if solved_field is None:

                raise ValueError("Could not derive an image footprint from the selected source image.")

            return solved_field



        if progress_callback is not None:

            progress_callback("Embedded WCS was unusable; attempting astrometry.net fallback for the HR source image.")

        solved_field = self._resolve_hr_source_field_via_astrometry(source_image, header, width, height, reasons, progress_callback)

        if solved_field is not None:

            return solved_field



        reason_text = " ".join(reason.strip() for reason in reasons if reason.strip()) or "The selected image does not contain a usable celestial WCS."

        raise ValueError(f"Selected source image does not contain a usable celestial WCS. {reason_text}")

    def _resolve_hr_source_field_via_astrometry(

        self,

        source_image: Path,

        header,

        width: int | None,

        height: int | None,

        reasons: list[str],

        progress_callback: Callable[[str], None] | None = None,

    ) -> object | None:

        root_path = Path(self._root_path_input.text()).expanduser()

        if self._settings is None and root_path.exists():

            self._settings = AppSettings.from_root(root_path)

        if self._settings is None or not self._settings.astrometry_api_key:

            return None



        hints = infer_astrometry_solve_hints(header, width, height, source_image)

        try:

            if progress_callback is not None:

                progress_callback("Submitting the HR source image to astrometry.net fallback.")

            result = AstrometryNetClient(self._settings.astrometry_api_key).solve_file(

                source_image,

                self._settings.cache_dir / "hr-wcs",

                hints=hints,

            )

        except Exception as exc:

            reasons.append(f"Astrometry fallback failed: {exc}")

            return None



        if result.solved_field is None:

            reasons.extend(result.reasons)

            return None

        if progress_callback is not None:

            progress_callback("Recovered a usable HR WCS via astrometry.net fallback.")

        return result.solved_field

    def _query_hr_field_catalog(self, solved_field, progress_callback: Callable[[str], None] | None = None):

        catalog_service = CatalogService(self._hr_catalog_cache_dir())

        return catalog_service.query_field_catalog(solved_field, progress_callback=progress_callback)

    def _build_hr_working_table(

        self,

        source_image: Path,

        field_catalog,

        progress_callback: Callable[[str], None] | None = None,

    ):

        root_path = Path(self._root_path_input.text()).expanduser()

        if self._settings is None:

            settings_root = root_path if root_path.exists() else Path.cwd()

            self._settings = AppSettings.from_root(settings_root)

        self._settings.hr_max_sources = max(0, int(self._hr_max_sources_spin.value()))

        return measure_hr_sources(source_image, field_catalog.gaia_stars, self._settings, progress_callback=progress_callback)

    def _hr_catalog_cache_dir(self) -> Path:

        root_path = Path(self._root_path_input.text()).expanduser()

        if self._settings is None:

            settings_root = root_path if root_path.exists() else Path.cwd()

            self._settings = AppSettings.from_root(settings_root)

        return self._settings.cache_dir / "catalogs"

    def _write_hr_field_catalog_file(self, working_directory: Path, source_image: Path, solved_field, field_catalog) -> Path:

        working_directory.mkdir(parents=True, exist_ok=True)

        output_path = working_directory / _HR_FIELD_CATALOG_FILE_NAME

        payload = {

            "source_image": str(source_image),

            "field": {

                "center_ra_deg": solved_field.center_ra_deg,

                "center_dec_deg": solved_field.center_dec_deg,

                "radius_deg": solved_field.radius_deg,

                "width": solved_field.width,

                "height": solved_field.height,

                "wcs_path": str(solved_field.wcs_path),

            },

            "catalog_counts": {

                "gaia_stars": len(field_catalog.gaia_stars),

                "variable_stars": len(field_catalog.variable_stars),

                "exoplanets": len(field_catalog.exoplanets),

            },

            "gaia_stars": [self._catalog_star_payload(star) for star in field_catalog.gaia_stars],

            "variable_stars": [self._catalog_star_payload(star) for star in field_catalog.variable_stars],

            "exoplanets": [self._catalog_star_payload(star) for star in field_catalog.exoplanets],

        }

        output_path.write_text(json.dumps(payload, indent=2), encoding="utf-8")

        return output_path

    def _write_hr_working_table_files(self, working_directory: Path, source_image: Path, solved_field, hr_working_table) -> tuple[Path, Path]:

        working_directory.mkdir(parents=True, exist_ok=True)

        json_path = working_directory / _HR_WORKING_TABLE_JSON_FILE_NAME

        csv_path = working_directory / _HR_WORKING_TABLE_CSV_FILE_NAME

        json_payload = {

            "source_image": str(source_image),

            "field": {

                "center_ra_deg": solved_field.center_ra_deg,

                "center_dec_deg": solved_field.center_dec_deg,

                "radius_deg": solved_field.radius_deg,

                "width": solved_field.width,

                "height": solved_field.height,

                "wcs_path": str(solved_field.wcs_path),

            },

            "working_table": hr_working_table_payload(hr_working_table),

        }

        json_path.write_text(json.dumps(json_payload, indent=2), encoding="utf-8")



        self._write_hr_rows_csv(

            csv_path,

            hr_working_table.rows,

            plane_labels=hr_working_table.plane_labels,

            zero_point_offset_mag=hr_working_table.zero_point_offset_mag,

        )



        return json_path, csv_path

    def _write_hr_rows_csv(

        self,

        csv_path: Path,

        rows: list[HrMeasurementRow],

        *,

        plane_labels: list[str] | None = None,

        zero_point_offset_mag: float | None = None,

    ) -> None:

        serialized_rows = hr_working_table_payload(

            HrWorkingTable(

                rows=list(rows),

                plane_labels=list(plane_labels) if plane_labels else ["red", "green", "blue", "luminance"],

                measured_count=len(rows),

                usable_count=sum(

                    1

                    for row in rows

                    if row.flux_luminance is not None or row.flux_red is not None or row.flux_green is not None or row.flux_blue is not None

                ),

                zero_point_offset_mag=zero_point_offset_mag,

                zero_point_source_count=sum(1 for row in rows if row.used_for_zero_point),

            )

        )["rows"]

        fieldnames = [

            "source_id",

            "source_name",

            "catalog",

            "ra_deg",

            "dec_deg",

            "gaia_g_mag",

            "gaia_bp_rp",

            "parallax_mas",

            "parallax_error_mas",

            "pm_ra_mas_per_year",

            "pm_dec_mas_per_year",

            "x",

            "y",

            "aperture_radius",

            "annulus_inner_radius",

            "annulus_outer_radius",

            "flux_red",

            "flux_green",

            "flux_blue",

            "flux_luminance",

            "flux_error_red",

            "flux_error_green",

            "flux_error_blue",

            "flux_error_luminance",

            "instrumental_mag_red",

            "instrumental_mag_green",

            "instrumental_mag_blue",

            "instrumental_mag_luminance",

            "instrumental_blue_minus_red",

            "calibrated_mag_luminance",

            "absolute_magnitude_proxy",

            "gaia_absolute_magnitude",

            "plot_color_index",

            "display_color_hex",

            "snr_red",

            "snr_green",

            "snr_blue",

            "snr_luminance",

            "background_red",

            "background_green",

            "background_blue",

            "background_luminance",

            "is_saturated",

            "used_for_zero_point",

            "flags",

        ]

        with csv_path.open("w", encoding="utf-8", newline="") as handle:

            writer = csv.DictWriter(handle, fieldnames=fieldnames)

            writer.writeheader()

            for row in serialized_rows:

                csv_row = dict(row)

                csv_row["flags"] = " | ".join(csv_row.get("flags") or [])

                writer.writerow(csv_row)

    def _catalog_star_payload(self, star) -> dict[str, object]:

        return {

            "catalog": star.catalog,

            "source_id": star.source_id,

            "name": star.name,

            "ra_deg": star.ra_deg,

            "dec_deg": star.dec_deg,

            "magnitude": star.magnitude,

            "is_variable": star.is_variable,

            "object_type": star.object_type,

            "metadata": dict(star.metadata),

        }

    def _sync_alignment_control(self) -> None:

        aligned = self._settings.assume_aligned_images if self._settings is not None else False

        self._aligned_action.blockSignals(True)

        self._non_aligned_action.blockSignals(True)

        self._aligned_action.setChecked(aligned)

        self._non_aligned_action.setChecked(not aligned)

        self._aligned_action.blockSignals(False)

        self._non_aligned_action.blockSignals(False)

    def _sync_theme_control(self) -> None:

        theme = self._current_theme_name()

        self._theme_normal_action.blockSignals(True)

        self._theme_dark_action.blockSignals(True)

        self._theme_dracula_action.blockSignals(True)

        self._theme_nord_action.blockSignals(True)

        self._theme_tokyo_night_action.blockSignals(True)

        self._theme_gruvbox_action.blockSignals(True)

        self._theme_catppuccin_action.blockSignals(True)

        self._theme_solarized_dark_action.blockSignals(True)

        self._theme_one_dark_action.blockSignals(True)

        self._theme_custom_action.blockSignals(True)

        self._theme_normal_action.setChecked(theme == _THEME_NORMAL)

        self._theme_dark_action.setChecked(theme == _THEME_DARK)

        self._theme_dracula_action.setChecked(theme == _THEME_DRACULA)

        self._theme_nord_action.setChecked(theme == _THEME_NORD)

        self._theme_tokyo_night_action.setChecked(theme == _THEME_TOKYO_NIGHT)

        self._theme_gruvbox_action.setChecked(theme == _THEME_GRUVBOX)

        self._theme_catppuccin_action.setChecked(theme == _THEME_CATPPUCCIN)

        self._theme_solarized_dark_action.setChecked(theme == _THEME_SOLARIZED_DARK)

        self._theme_one_dark_action.setChecked(theme == _THEME_ONE_DARK)

        self._theme_custom_action.setChecked(theme == _THEME_CUSTOM)

        self._theme_normal_action.blockSignals(False)

        self._theme_dark_action.blockSignals(False)

        self._theme_dracula_action.blockSignals(False)

        self._theme_nord_action.blockSignals(False)

        self._theme_tokyo_night_action.blockSignals(False)

        self._theme_gruvbox_action.blockSignals(False)

        self._theme_catppuccin_action.blockSignals(False)

        self._theme_solarized_dark_action.blockSignals(False)

        self._theme_one_dark_action.blockSignals(False)

        self._theme_custom_action.blockSignals(False)

    def _apply_startup_theme(self) -> None:

        root_path = Path(self._root_path_input.text()).expanduser()

        if root_path.exists():

            self._settings = AppSettings.from_root(root_path)

        self._sync_alignment_control()

        self._sync_theme_control()

        self._apply_current_theme()

    def _current_theme_name(self) -> str:

        theme = self._settings.theme if self._settings is not None else _THEME_DEFAULT

        return theme if theme in _VALID_THEME_NAMES else _THEME_DEFAULT

    def _apply_current_theme(self) -> None:

        theme = self._current_theme_name()

        self._refresh_theme_action_icons()

        self._apply_theme(theme)

    def _apply_theme(self, theme: str) -> None:

        app = QApplication.instance()

        if app is None:

            return

        custom_colors = self._current_custom_theme_colors()

        if theme in _BUILTIN_THEME_STYLES:

            colors = _BUILTIN_THEME_STYLES[theme]

            palette = QPalette()

            palette.setColor(QPalette.ColorRole.Window, QColor(colors["window"]))

            palette.setColor(QPalette.ColorRole.WindowText, QColor(colors["window_text"]))

            palette.setColor(QPalette.ColorRole.Base, QColor(colors["base"]))

            palette.setColor(QPalette.ColorRole.AlternateBase, QColor(colors["alternate_base"]))

            palette.setColor(QPalette.ColorRole.ToolTipBase, QColor(colors["tooltip_base"]))

            palette.setColor(QPalette.ColorRole.ToolTipText, QColor(colors["tooltip_text"]))

            palette.setColor(QPalette.ColorRole.Text, QColor(colors["window_text"]))

            palette.setColor(QPalette.ColorRole.Button, QColor(colors["button"]))

            palette.setColor(QPalette.ColorRole.ButtonText, QColor(colors["button_text"]))

            palette.setColor(QPalette.ColorRole.BrightText, QColor(colors["bright_text"]))

            palette.setColor(QPalette.ColorRole.Highlight, QColor(colors["highlight"]))

            palette.setColor(QPalette.ColorRole.HighlightedText, QColor(colors["highlight_text"]))

            palette.setColor(QPalette.ColorRole.PlaceholderText, QColor(colors["placeholder"]))

            _apply_disabled_palette_group(palette, colors)

            app.setPalette(palette)

            app.setStyleSheet(

                f"QToolTip {{ color: {colors['tooltip_text']}; background-color: {colors['tooltip_base']}; border: 1px solid {colors['gridline']}; }}"

                f"QMenuBar {{ background-color: {colors['menu_bg']}; color: {colors['menu_text']}; }}"

                f"QMenuBar::item {{ background-color: transparent; color: {colors['menu_text']}; padding: 4px 8px; }}"

                f"QTableWidget {{ gridline-color: {colors['gridline']}; }}"

                f"QHeaderView::section {{ background-color: {colors['header_bg']}; color: {colors['header_text']}; border: 1px solid {colors['gridline']}; padding: 4px; }}"

                f"QMenu {{ background-color: {colors['menu_bg']}; color: {colors['menu_text']}; border: 1px solid {colors['gridline']}; }}"

                f"QMenu::item {{ background-color: transparent; color: {colors['menu_text']}; padding: 4px 24px 4px 20px; }}"

                f"QMenuBar::item:selected, QMenu::item:selected {{ background-color: {colors['highlight']}; color: {colors['highlight_text']}; }}"

                f"{_application_widget_chrome_stylesheet(colors)}"

            )

        elif theme == _THEME_CUSTOM:

            palette = QPalette()

            palette.setColor(QPalette.ColorRole.Window, QColor(custom_colors["window_bg"]))

            palette.setColor(QPalette.ColorRole.WindowText, QColor(custom_colors["text"]))

            palette.setColor(QPalette.ColorRole.Base, QColor(custom_colors["panel_bg"]))

            palette.setColor(QPalette.ColorRole.AlternateBase, QColor(custom_colors["panel_bg"]))

            palette.setColor(QPalette.ColorRole.ToolTipBase, QColor(custom_colors["menu_bg"]))

            palette.setColor(QPalette.ColorRole.ToolTipText, QColor(custom_colors["menu_text"]))

            palette.setColor(QPalette.ColorRole.Text, QColor(custom_colors["text"]))

            palette.setColor(QPalette.ColorRole.Button, QColor(custom_colors["panel_bg"]))

            palette.setColor(QPalette.ColorRole.ButtonText, QColor(custom_colors["text"]))

            palette.setColor(QPalette.ColorRole.BrightText, QColor(self._contrast_text_color(custom_colors["accent"])))

            palette.setColor(QPalette.ColorRole.Highlight, QColor(custom_colors["accent"]))

            palette.setColor(QPalette.ColorRole.HighlightedText, QColor(self._contrast_text_color(custom_colors["accent"])))

            palette.setColor(QPalette.ColorRole.PlaceholderText, QColor(custom_colors["text"]))

            border_color = QColor(custom_colors["menu_bg"]).lighter(140).name().lower()

            chrome_colors = {
                "base": custom_colors["panel_bg"],
                "button": custom_colors["panel_bg"],
                "gridline": border_color,
                "placeholder": QColor(custom_colors["text"]).lighter(150).name().lower(),
                "highlight": custom_colors["accent"],
            }

            _apply_disabled_palette_group(palette, chrome_colors)

            app.setPalette(palette)

            app.setStyleSheet(

                f"QToolTip {{ color: {custom_colors['menu_text']}; background-color: {custom_colors['menu_bg']}; border: 1px solid {border_color}; }}"

                f"QMenuBar {{ background-color: {custom_colors['menu_bg']}; color: {custom_colors['menu_text']}; }}"

                f"QMenuBar::item {{ background-color: transparent; color: {custom_colors['menu_text']}; padding: 4px 8px; }}"

                f"QTableWidget {{ gridline-color: {border_color}; }}"

                f"QHeaderView::section {{ background-color: {custom_colors['menu_bg']}; color: {custom_colors['menu_text']}; border: 1px solid {border_color}; padding: 4px; }}"

                f"QMenu {{ background-color: {custom_colors['menu_bg']}; color: {custom_colors['menu_text']}; border: 1px solid {border_color}; }}"

                f"QMenu::item {{ background-color: transparent; color: {custom_colors['menu_text']}; padding: 4px 24px 4px 20px; }}"

                f"QMenuBar::item:selected, QMenu::item:selected {{ background-color: {custom_colors['accent']}; color: {self._contrast_text_color(custom_colors['accent'])}; }}"

                f"{_application_widget_chrome_stylesheet(chrome_colors)}"

            )

        else:

            palette = app.style().standardPalette()

            normal_chrome_colors = {
                "base": "#f0f0f0",
                "button": "#e6e6e6",
                "gridline": "#c8c8c8",
                "placeholder": "#6b6b6b",
                "highlight": "#3d8bfd",
            }

            _apply_disabled_palette_group(palette, normal_chrome_colors)

            app.setPalette(palette)

            app.setStyleSheet(

                "QToolTip { color: #1f1f1f; background-color: #f5f1e8; border: 1px solid #b8b0a2; }"

                "QMenuBar { background-color: #d9d2c7; color: #1f1f1f; }"

                "QMenuBar::item { background-color: transparent; color: #1f1f1f; padding: 4px 8px; }"

                "QMenu { background-color: #1f1f1f; color: #f5f1e8; border: 1px solid #4b4b4b; }"

                "QMenu::item { background-color: transparent; color: #f5f1e8; padding: 4px 24px 4px 20px; }"

                "QMenuBar::item:selected, QMenu::item:selected { background-color: #3d8bfd; color: #ffffff; }"

                f"{_application_widget_chrome_stylesheet(normal_chrome_colors)}"

            )

        themed_custom_colors = custom_colors if theme == _THEME_CUSTOM else None

        self._light_curve_widget.set_theme(theme, themed_custom_colors)

        self._hr_diagram_widget.set_theme(theme, themed_custom_colors)

        self._apply_generate_button_attention_style()

        self._sync_hr_plot_toolbar_buttons()

        self._apply_inline_progress_bar_style()

        self._sync_mode_launcher_accent()

    def _handle_theme_changed(self, theme: str) -> None:

        root_path = Path(self._root_path_input.text()).expanduser()

        if self._settings is None and root_path.exists():

            self._settings = AppSettings.from_root(root_path)

        if self._settings is None:

            return

        self._settings.theme = theme if theme in _VALID_THEME_NAMES else _THEME_DEFAULT

        if self._settings.custom_theme_colors is None:

            self._settings.custom_theme_colors = default_custom_theme_colors()

        self._sync_theme_control()

        self._apply_current_theme()

        save_last_theme(self._settings.theme)

        self._save_settings_snapshot()

        self.statusBar().showMessage(f"Theme set to {_THEME_LABELS.get(self._settings.theme, self._settings.theme.title())}.", 5000)

    def closeEvent(self, event: QCloseEvent) -> None:

        if hasattr(self, "_transient_blink_timer"):

            self._transient_blink_timer.stop()

        if hasattr(self, "_sky_explorer_survey_refresh_timer"):

            self._sky_explorer_survey_refresh_timer.stop()

        if hasattr(self, "_sky_explorer_survey_refine_timer"):

            self._sky_explorer_survey_refine_timer.stop()

        if self._update_check_worker is not None:

            self._update_check_worker.wait(4500)

        if self._update_download_worker is not None:

            self._update_download_worker.request_cancel()

            self._update_download_worker.wait(4500)

        self._close_update_download_progress_dialog()

        if self._sky_explorer_survey_worker is not None:

            self._sky_explorer_survey_worker.wait(4500)

        if self._calculate_period_worker is not None:

            self._calculate_period_worker.request_cancel()

        if self._fit_period_worker is not None:

            self._fit_period_worker.request_cancel()

            self._fit_period_worker.wait(4500)

        if self._literature_period_worker is not None:

            self._literature_period_worker.request_cancel()

        if self._increase_snr_worker is not None:

            self._increase_snr_worker.request_cancel()

        if self._comparison_fit_worker is not None:

            self._comparison_fit_worker.request_cancel()

        if self._report_export_worker is not None:

            self._report_export_worker.request_cancel()

        if self._light_curve_gif_export_worker is not None:

            self._light_curve_gif_export_worker.request_cancel()

            self._light_curve_gif_export_worker.wait(4500)

        if self._calibration_worker is not None:

            self._calibration_worker.wait(4500)

        if self._transient_search_worker is not None:

            self._transient_search_worker.request_cancel()

            self._transient_search_worker.wait(4500)

        if self._asteroid_detection_worker is not None:

            self._asteroid_detection_worker.wait(4500)

        if self._asteroid_synthetic_tracking_worker is not None:

            self._asteroid_synthetic_tracking_worker.wait(4500)

        if self._asteroid_recovery_worker is not None:

            self._asteroid_recovery_worker.request_cancel()

            self._asteroid_recovery_worker.wait(4500)

        if self._asteroid_discovery_worker is not None:

            self._asteroid_discovery_worker.request_cancel()

            self._asteroid_discovery_worker.wait(4500)

        if self._asteroid_discovery_test_worker is not None:

            self._asteroid_discovery_test_worker.request_cancel()

            self._asteroid_discovery_test_worker.wait(4500)

        if self._asteroid_preload_worker is not None:

            self._asteroid_preload_worker.wait(4500)

        self._close_asteroid_blink_progress_dialog()

        self._close_asteroid_synthetic_tracking_progress_dialog()

        self._close_asteroid_recovery_progress_dialog()

        self._close_asteroid_discovery_test_progress_dialog()

        self._close_asteroid_discovery_progress_dialog()

        for worker in tuple(self._hr_star_details_workers.values()):

            worker.wait(4500)

        save_last_theme(self._current_theme_name())

        self._save_settings_snapshot()

        super().closeEvent(event)

    def _open_theme_customizer(self) -> None:

        root_path = Path(self._root_path_input.text()).expanduser()

        if self._settings is None and root_path.exists():

            self._settings = AppSettings.from_root(root_path)

        if self._settings is None:

            return

        dialog = ThemeCustomizeDialog(colors=self._resolved_theme_editor_colors(), parent=self)

        if dialog.exec() != dialog.DialogCode.Accepted:

            return

        self._settings.custom_theme_colors = dialog.selected_colors()

        self._settings.theme = _THEME_CUSTOM

        self._sync_theme_control()

        self._refresh_theme_action_icons()

        self._apply_current_theme()

        self._save_settings_snapshot()

        self.statusBar().showMessage("Custom theme updated.", 5000)

    def _import_theme(self) -> None:

        root_path = Path(self._root_path_input.text()).expanduser()

        if self._settings is None and root_path.exists():

            self._settings = AppSettings.from_root(root_path)

        if self._settings is None:

            return

        selected_path, _selected_filter = QFileDialog.getOpenFileName(

            self,

            "Import Theme",

            str(root_path if root_path.exists() else Path.cwd()),

            "JSON Files (*.json)",

        )

        if not selected_path:

            return

        try:

            payload = json.loads(Path(selected_path).read_text(encoding="utf-8"))

        except (OSError, json.JSONDecodeError) as exc:

            QMessageBox.warning(self, "Import Theme", f"Could not read theme file: {exc}")

            return

        imported_colors = payload.get("custom_theme_colors") if isinstance(payload, dict) else None

        if imported_colors is None and isinstance(payload, dict):

            imported_colors = payload.get("colors")

        normalized_colors = self._normalize_custom_theme_colors(imported_colors)

        self._settings.custom_theme_colors = normalized_colors

        self._settings.theme = _THEME_CUSTOM

        self._sync_theme_control()

        self._refresh_theme_action_icons()

        self._apply_current_theme()

        self._save_settings_snapshot()

        self.statusBar().showMessage(f"Imported custom theme from {selected_path}.", 5000)

    def _export_theme(self) -> None:

        root_path = Path(self._root_path_input.text()).expanduser()

        if self._settings is None and root_path.exists():

            self._settings = AppSettings.from_root(root_path)

        theme_colors = self._current_custom_theme_colors()

        default_name = "photometry-theme.json"

        default_path = (root_path / default_name) if root_path.exists() else Path.cwd() / default_name

        selected_path, _selected_filter = QFileDialog.getSaveFileName(

            self,

            "Export Theme",

            str(default_path),

            "JSON Files (*.json)",

        )

        if not selected_path:

            return

        payload = {

            "theme": _THEME_CUSTOM,

            "custom_theme_colors": theme_colors,

        }

        try:

            Path(selected_path).write_text(json.dumps(payload, indent=2), encoding="utf-8")

        except OSError as exc:

            QMessageBox.warning(self, "Export Theme", f"Could not write theme file: {exc}")

            return

        self.statusBar().showMessage(f"Exported custom theme to {selected_path}.", 5000)

    def _current_custom_theme_colors(self) -> dict[str, str]:

        settings = getattr(self, "_settings", None)

        if settings is None or settings.custom_theme_colors is None:

            return default_custom_theme_colors()

        return self._normalize_custom_theme_colors(settings.custom_theme_colors)

    def _resolved_theme_editor_colors(self) -> dict[str, str]:

        theme = self._current_theme_name()

        plot_colors = resolve_light_curve_theme_colors(theme, self._current_custom_theme_colors())

        if theme == _THEME_CUSTOM:

            return self._current_custom_theme_colors()

        if theme in _BUILTIN_THEME_STYLES:

            colors = _BUILTIN_THEME_STYLES[theme]

            resolved = default_custom_theme_colors()

            resolved.update(

                {

                    "window_bg": colors["window"],

                    "panel_bg": colors["base"],

                    "text": colors["window_text"],

                    "menu_bg": colors["window"],

                    "menu_text": colors["menu_text"],

                    "accent": colors["highlight"],

                    "plot_bg": plot_colors["background_color"],

                    "plot_axis": plot_colors["axis_color"],

                    "plot_points": plot_colors["point_brush"],

                    "plot_fit": plot_colors["fit_curve_color"],

                    "asteroid_overlay_circle_color": plot_colors["point_brush"],

                    "asteroid_overlay_line_color": colors["highlight"],

                    "asteroid_overlay_text_color": colors["window_text"],

                }

            )

            return resolved

        resolved = default_custom_theme_colors()

        resolved.update(

            {

                "window_bg": "#f5f1e8",

                "panel_bg": "#ffffff",

                "text": "#1f1f1f",

                "menu_bg": "#d9d2c7",

                "menu_text": "#1f1f1f",

                "accent": "#3d8bfd",

                "plot_bg": plot_colors["background_color"],

                "plot_axis": plot_colors["axis_color"],

                "plot_points": plot_colors["point_brush"],

                "plot_fit": plot_colors["fit_curve_color"],

                "asteroid_overlay_circle_color": plot_colors["point_brush"],

                "asteroid_overlay_line_color": "#3d8bfd",

                "asteroid_overlay_text_color": "#1f1f1f",

            }

        )

        return resolved

    def _refresh_theme_action_icons(self) -> None:

        self._theme_normal_action.setIcon(self._theme_preview_icon(_THEME_NORMAL))

        self._theme_dark_action.setIcon(self._theme_preview_icon(_THEME_DARK))

        self._theme_dracula_action.setIcon(self._theme_preview_icon(_THEME_DRACULA))

        self._theme_nord_action.setIcon(self._theme_preview_icon(_THEME_NORD))

        self._theme_tokyo_night_action.setIcon(self._theme_preview_icon(_THEME_TOKYO_NIGHT))

        self._theme_gruvbox_action.setIcon(self._theme_preview_icon(_THEME_GRUVBOX))

        self._theme_catppuccin_action.setIcon(self._theme_preview_icon(_THEME_CATPPUCCIN))

        self._theme_solarized_dark_action.setIcon(self._theme_preview_icon(_THEME_SOLARIZED_DARK))

        self._theme_one_dark_action.setIcon(self._theme_preview_icon(_THEME_ONE_DARK))

        self._theme_custom_action.setIcon(self._theme_preview_icon(_THEME_CUSTOM))

    def _theme_preview_icon(self, theme: str) -> QIcon:

        background, accent, point, border = self._theme_preview_colors(theme)

        pixmap = QPixmap(18, 18)

        pixmap.fill(Qt.GlobalColor.transparent)

        painter = QPainter(pixmap)

        painter.fillRect(1, 1, 16, 16, QColor(background))

        painter.fillRect(2, 11, 6, 4, QColor(accent))

        painter.fillRect(10, 11, 6, 4, QColor(point))

        painter.setPen(QColor(border))

        painter.drawRect(1, 1, 16, 16)

        painter.end()

        return QIcon(pixmap)

    def _theme_preview_colors(self, theme: str) -> tuple[str, str, str, str]:

        if theme == _THEME_CUSTOM:

            colors = self._current_custom_theme_colors()

            return (

                colors["menu_bg"],

                colors["accent"],

                colors["plot_points"],

                colors["plot_axis"],

            )

        return _THEME_PREVIEW_SWATCHES.get(theme, _THEME_PREVIEW_SWATCHES[_THEME_NORMAL])

    def _normalize_custom_theme_colors(self, value: object) -> dict[str, str]:

        colors = default_custom_theme_colors()

        if not isinstance(value, dict):

            return colors

        numeric_ranges = {

            "asteroid_overlay_line_width": (0.5, 8.0),

            "asteroid_overlay_text_size": (7.0, 24.0),

        }

        for key in colors:

            item = value.get(key)

            if isinstance(item, str):

                normalized = item.strip().lower()

                if key in numeric_ranges:

                    try:

                        numeric = float(normalized)

                    except ValueError:

                        continue

                    minimum, maximum = numeric_ranges[key]

                    colors[key] = f"{min(maximum, max(minimum, numeric)):g}"

                    continue

                if len(normalized) == 7 and normalized.startswith("#") and all(character in "0123456789abcdef" for character in normalized[1:]):

                    colors[key] = normalized

        return colors

    def _current_asteroid_overlay_theme(self) -> dict[str, object] | None:

        if self._current_theme_name() != _THEME_CUSTOM:

            return None

        colors = self._current_custom_theme_colors()

        try:

            line_width = float(colors.get("asteroid_overlay_line_width", "1.5"))

        except (TypeError, ValueError):

            line_width = 1.5

        try:

            text_size = float(colors.get("asteroid_overlay_text_size", "10.0"))

        except (TypeError, ValueError):

            text_size = 10.0

        return {

            "circle_color": self._asteroid_overlay_display_color(colors.get("asteroid_overlay_circle_color", "#38bdf8")),

            "line_color": self._asteroid_overlay_display_color(colors.get("asteroid_overlay_line_color", "#8b5cf6")),

            "text_color": self._asteroid_overlay_display_color(colors.get("asteroid_overlay_text_color", colors.get("text", "#f8fafc"))),

            "line_width": min(8.0, max(0.5, line_width)),

            "text_size": min(24.0, max(7.0, text_size)),

        }

    def _current_asteroid_other_overlay_theme(self) -> dict[str, object] | None:

        if self._current_theme_name() != _THEME_CUSTOM:

            return None

        colors = self._current_custom_theme_colors()

        try:

            line_width = float(colors.get("asteroid_other_overlay_line_width", "1.75"))

        except (TypeError, ValueError):

            line_width = 1.75

        try:

            text_size = float(colors.get("asteroid_other_overlay_text_size", "10.0"))

        except (TypeError, ValueError):

            text_size = 10.0

        return {

            "circle_color": self._asteroid_overlay_display_color(colors.get("asteroid_other_overlay_circle_color", "#fbbf24")),

            "line_color": self._asteroid_overlay_display_color(colors.get("asteroid_other_overlay_line_color", "#f8fafc")),

            "text_color": self._asteroid_overlay_display_color(colors.get("asteroid_other_overlay_text_color", colors.get("text", "#f8fafc"))),

            "line_width": min(8.0, max(0.5, line_width)),

            "text_size": min(24.0, max(7.0, text_size)),

        }

    def _asteroid_annotations_follow_invert(self) -> bool:

        settings = self._ensure_settings()

        return bool(

            settings.asteroid_visual_invert_annotation_colors

            and hasattr(self, "_asteroid_image_invert_checkbox")

            and self._asteroid_image_invert_checkbox.isChecked()

        )

    def _invert_hex_color(self, color_value: str) -> str:

        color = QColor(color_value)

        if not color.isValid():

            return color_value

        return QColor(255 - color.red(), 255 - color.green(), 255 - color.blue(), color.alpha()).name().lower()

    def _asteroid_overlay_display_color(self, color_value: str) -> str:

        normalized = str(color_value).strip() or "#ffffff"

        if not self._asteroid_annotations_follow_invert():

            return normalized

        return self._invert_hex_color(normalized)

    def _asteroid_overlay_outline_color(self, color_value: str) -> str:

        color = QColor(color_value)

        if not color.isValid():

            return "#000000"

        return "#000000" if color.lightness() >= 128 else "#ffffff"

    def _contrast_text_color(self, color_value: str) -> str:

        color = QColor(color_value)

        return "#ffffff" if color.lightness() < 128 else "#1f1f1f"

    def _apply_inline_progress_bar_style(self) -> None:

        colors = self._resolved_theme_editor_colors()

        accent_color = colors.get("accent", "#3d8bfd")

        panel_color = colors.get("panel_bg", "#202020")

        border_color = QColor(panel_color).lighter(135).name().lower()

        chunk_color = QColor(accent_color).name().lower()

        progress_style = (

            "QProgressBar {"

            f"background-color: {panel_color};"

            f"border: 1px solid {border_color};"

            "border-radius: 2px;"

            f"min-height: {_ASTEROID_PROGRESS_BAR_HEIGHT_PX}px;"

            f"max-height: {_ASTEROID_PROGRESS_BAR_HEIGHT_PX}px;"

            "padding: 0px;"

            "}"

            "QProgressBar::chunk {"

            f"background-color: {chunk_color};"

            "border-radius: 2px;"

            "}"

        )

        if hasattr(self, "_hr_progress_bar"):

            self._hr_progress_bar.setStyleSheet(progress_style)

        if hasattr(self, "_transient_progress_bar"):

            self._transient_progress_bar.setStyleSheet(progress_style)

        if hasattr(self, "_processing_progress_bar"):

            self._processing_progress_bar.setStyleSheet(progress_style)

    def _handle_aligned_option_changed(self, checked: bool) -> None:

        root_path = Path(self._root_path_input.text()).expanduser()

        if self._settings is None and root_path.exists():

            self._settings = AppSettings.from_root(root_path)

        if self._settings is None:

            return

        self._settings.assume_aligned_images = checked

        self._save_settings_snapshot()

        message = "Aligned stack reuse enabled: one representative frame will be plate solved per object." if checked else "Aligned stack reuse disabled: each unsolved geometry group may be solved independently."

        self.statusBar().showMessage(message, 5000)

