    def _current_image_render_settings(self) -> AnnotatedImageRenderSettings:

        stretch_mode = self._image_stretch_combo.currentData()

        black_point, midtone_point, white_point = self._image_levels

        return AnnotatedImageRenderSettings(

            stretch_mode=str(stretch_mode) if isinstance(stretch_mode, str) and stretch_mode else "stf",

            black_point=black_point,

            midtone_point=midtone_point,

            white_point=white_point,

            curve_points=self._image_curve_points,

            inverted=self._image_invert_checkbox.isChecked(),

        )

    def _reset_image_display_controls(self) -> None:

        root_path = Path(self._root_path_input.text()).expanduser()

        defaults = AppSettings.defaults(root_path if root_path.exists() else Path.cwd())

        self._image_stretch_combo.blockSignals(True)

        self._image_invert_checkbox.blockSignals(True)

        stretch_index = self._image_stretch_combo.findData(defaults.image_display_stretch_mode)

        self._image_stretch_combo.setCurrentIndex(
            stretch_index if stretch_index >= 0 else max(0, self._image_stretch_combo.findData("stf"))
        )

        self._image_levels = (

            float(defaults.image_display_black_point),

            float(defaults.image_display_midtone_point),

            float(defaults.image_display_white_point),

        )

        self._image_curve_points = defaults.image_display_curve_points

        self._image_invert_checkbox.setChecked(defaults.image_display_inverted)

        self._image_stretch_combo.blockSignals(False)

        self._image_invert_checkbox.blockSignals(False)

        self._handle_image_display_controls_changed()

        self.statusBar().showMessage("Reset annotated image display controls.", 3000)

    def _open_image_levels_dialog(self) -> None:

        image_path, _measurement, _comparison_measurements, _status_text = self._image_context()

        if image_path is None or not image_path.exists():

            return

        try:

            display = self._cached_annotated_image_display(image_path)

        except Exception as exc:

            QMessageBox.warning(self, "Curves unavailable", f"Could not prepare the annotated-image preview for curve adjustment.\n\n{exc}")

            return

        dialog = CurvesDialog(

            display=display,

            initial_settings=self._current_image_render_settings(),

            parent=self,

        )

        if dialog.exec() != int(QDialog.DialogCode.Accepted):

            return

        selected_settings = dialog.selected_settings()

        self._image_levels = (

            float(selected_settings.black_point),

            float(selected_settings.midtone_point),

            float(selected_settings.white_point),

        )

        self._image_curve_points = selected_settings.curve_points

        self._handle_image_display_controls_changed()

        self.statusBar().showMessage("Applied annotated image curves.", 3000)

    def _current_equatorial_grid_colors(self) -> tuple[str, str]:

        settings = self._active_settings()

        inverted = bool(settings is not None and settings.image_display_inverted)

        if inverted:

            return "#5f6975", "#7b8794"

        return "#8f98a3", "#b4bbc3"

    def _selected_object_name(self) -> str | None:

        if self._current_report is None:

            return self._current_processing_report.object_name if self._current_processing_report is not None else None

        selected_row = self._object_table.currentRow()

        if 0 <= selected_row < len(self._current_report.object_summaries):

            return self._current_report.object_summaries[selected_row].object_name

        return self._current_processing_report.object_name if self._current_processing_report is not None else None

    def _selected_object_summary(self) -> ObjectScanSummary | None:

        if self._current_report is None:

            return None

        selected_row = self._object_table.currentRow()

        if 0 <= selected_row < len(self._current_report.object_summaries):

            return self._current_report.object_summaries[selected_row]

        return None

    def _clear_selected_dataset_cache(self) -> None:

        mode = self._visible_app_mode()

        cleared = self._clear_selected_dataset_cache_for_mode(mode)

        if cleared is None:

            QMessageBox.warning(self, "No dataset selected", "Open or select a dataset first before clearing its cache.")

            return

        dataset_label, removed = cleared

        item_label = "item" if removed == 1 else "items"

        if removed == 0:

            message = f"No cached items were found for {dataset_label}."

        else:

            message = f"Cleared {removed} cached {item_label} for {dataset_label}."

        self.statusBar().showMessage(message, 5000)

        if mode == AppMode.DIFFERENTIAL_PHOTOMETRY:

            self._detail_output.setPlainText(message)

            return

        if mode == AppMode.ASTEROID_COMET_DETECTION:

            self._append_asteroid_workflow_note(message)

            return

        if mode == AppMode.HR_DIAGRAM:

            self._append_hr_workflow_note(message)

            return

        if mode == AppMode.TRANSIENT_FINDER:

            self._append_transient_workflow_note(message)

            return

        if mode == AppMode.SKY_EXPLORER:

            self._append_sky_explorer_workflow_note(message)

    def _clear_selected_dataset_cache_for_mode(self, mode: AppMode) -> tuple[str, int] | None:

        if mode == AppMode.DIFFERENTIAL_PHOTOMETRY:

            return self._clear_selected_differential_dataset_cache()

        if mode == AppMode.ASTEROID_COMET_DETECTION:

            return self._clear_selected_asteroid_dataset_cache()

        if mode == AppMode.HR_DIAGRAM:

            return self._clear_selected_hr_dataset_cache()

        if mode == AppMode.TRANSIENT_FINDER:

            return self._clear_selected_transient_dataset_cache()

        if mode == AppMode.SKY_EXPLORER:

            return self._clear_selected_sky_explorer_dataset_cache()

        return None

    def _clear_selected_differential_dataset_cache(self) -> tuple[str, int] | None:

        root_path = Path(self._root_path_input.text()).expanduser()

        summary = self._selected_object_summary()

        if not root_path.exists() or summary is None:

            return None

        settings = AppSettings.from_root(root_path)

        removed = 0

        removed += self._remove_cache_path(settings.cache_dir / "processed" / f"{summary.object_name}.json")

        removed += self._remove_cache_path(settings.cache_dir / "measurements" / summary.object_name)

        removed += self._remove_cache_path(settings.cache_dir / "runs" / f"{summary.object_name}.jsonl")

        removed += self._remove_source_astrometry_cache_entries(

            settings.cache_dir / "astrometry",

            [file_result.path for file_result in summary.files],

        )

        try:

            removed += self._pipeline.clear_object_catalog_cache(root_path, summary.object_name)

        except ValueError:

            pass

        return summary.object_name, removed

    def _clear_selected_asteroid_dataset_cache(self) -> tuple[str, int] | None:

        source_label = self._asteroid_sequence_source_label

        source_paths = list(self._asteroid_all_frame_paths)

        if not source_paths and self._current_asteroid_source_image is not None:

            source_paths = [self._current_asteroid_source_image]

        if not source_paths:

            return None

        settings_root = source_label if source_label is not None else source_paths[0]

        settings = AppSettings.from_root(settings_root)

        removed = self._remove_source_astrometry_cache_entries(settings.cache_dir / "solar-system-wcs", source_paths)

        current_result = self._current_asteroid_detection_result

        current_source = self._current_asteroid_source_image

        if current_result is not None and current_source is not None:

            try:

                if current_result.source_path.resolve() == current_source.resolve():

                    removed += CatalogService(settings.cache_dir / "catalogs").clear_field_cache(current_result.solved_field)

            except OSError:

                pass

        current_estimate = self._current_asteroid_visible_limit_estimate()

        if current_estimate is not None:

            removed += CatalogService(settings.cache_dir / "catalogs").clear_field_cache(current_estimate.solved_field)

        self._asteroid_source_wcs_cache.clear()

        self._asteroid_frame_measurement_cache.clear()

        self._asteroid_preloaded_sequence_signature = None

        self._asteroid_preloaded_measurement_generation = None

        dataset_label = source_label.name if source_label is not None else source_paths[0].name

        return dataset_label, removed

    def _clear_selected_hr_dataset_cache(self) -> tuple[str, int] | None:

        source_image = self._current_hr_source_image

        if source_image is None:

            return None

        settings = AppSettings.from_root(source_image)

        removed = self._remove_source_astrometry_cache_entries(settings.cache_dir / "hr-wcs", [source_image])

        return source_image.name, removed

    def _clear_selected_transient_dataset_cache(self) -> tuple[str, int] | None:

        root_path = self._current_transient_root_path

        if root_path is None:

            return None

        source_paths: list[Path]

        if self._current_transient_search_result is not None:

            source_paths = [frame_result.source_path for frame_result in self._current_transient_search_result.frame_results]

        elif self._current_transient_source_image is not None:

            source_paths = [self._current_transient_source_image]

        else:

            source_paths = []

        if not source_paths:

            return None

        settings = AppSettings.from_root(root_path)

        removed = self._remove_source_astrometry_cache_entries(settings.cache_dir / "transient-wcs", source_paths)

        return root_path.name or str(root_path), removed

    def _clear_selected_sky_explorer_dataset_cache(self) -> tuple[str, int] | None:

        source_image = self._current_sky_explorer_source_image

        if source_image is None:

            return None

        settings = AppSettings.from_root(source_image)

        removed = self._remove_source_astrometry_cache_entries(settings.cache_dir / "sky-explorer-wcs", [source_image])

        current_result = self._current_sky_explorer_result

        if current_result is not None:

            try:

                if current_result.source_path.resolve() == source_image.resolve():

                    removed += CatalogService(settings.cache_dir / "sky-explorer-catalogs").clear_field_cache(current_result.solved_field)

            except OSError:

                pass

        return source_image.name, removed

    def _remove_source_astrometry_cache_entries(self, cache_dir: Path, source_paths: Sequence[Path]) -> int:

        removed = 0

        seen_keys: set[str] = set()

        for source_path in source_paths:

            try:

                cache_key = hashlib.sha256(str(source_path.resolve()).encode("utf-8")).hexdigest()

            except OSError:

                continue

            if cache_key in seen_keys:

                continue

            seen_keys.add(cache_key)

            removed += self._remove_cache_path(cache_dir / f"{cache_key}.json")

            removed += self._remove_cache_path(cache_dir / f"{cache_key}_solved.fits")

        return removed

    def _remove_cache_path(self, path: Path) -> int:

        if not path.exists():

            return 0

        if path.is_dir():

            shutil.rmtree(path)

            return 1

        path.unlink(missing_ok=True)

        return 1

    def _snr_binning_settings(self) -> SnrBinningSettings:

        settings = self._active_settings()

        if settings is None:

            return SnrBinningSettings()

        return SnrBinningSettings(

            max_period_fraction=settings.snr_binning_max_period_fraction,

            max_absolute_bin_duration_seconds=settings.snr_binning_max_absolute_duration_seconds,

            target_snr=settings.snr_binning_target_snr,

            max_frames_per_bin=settings.snr_binning_max_frames_per_bin,

            min_frames_per_bin=settings.snr_binning_min_frames_per_bin,

            variability_type_aware_thresholds=settings.snr_binning_type_aware_thresholds,

            sharp_period_fraction_override=settings.snr_binning_sharp_period_fraction,

            smooth_period_fraction_override=settings.snr_binning_smooth_period_fraction,

            weighted_flux_binning=settings.snr_binning_weighted_flux_binning,

            allow_direct_magnitude_averaging_fallback=settings.snr_binning_allow_magnitude_fallback,

            minimum_valid_points_per_bin=settings.snr_binning_minimum_valid_points_per_bin,

            outlier_rejection_enabled=settings.snr_binning_outlier_rejection_enabled,

            sigma_clip_threshold=settings.snr_binning_sigma_clip_threshold,

            dataset_mode=settings.snr_binning_dataset_mode,

            apply_to_selected_measurements_only=settings.snr_binning_apply_to_selected_measurements_only,

            allow_periodless_fallback=settings.snr_binning_allow_periodless_fallback,

        ).normalized()

    def _snr_series_key(self, catalog: str, source_id: str, filter_name: str | None) -> tuple[str, str, str]:

        return catalog, source_id, (filter_name or "unknown")

    def _snr_source_key(self, catalog: str, source_id: str) -> str:

        return f"{catalog}:{source_id}"

    def _snr_period_key(self, source_id: str, filter_name: str | None) -> tuple[str, str]:

        return source_id, (filter_name or "unknown")

    def _snr_series_key_for_light_curve(self, series: LightCurveSeries) -> tuple[str, str, str] | None:

        report = self._current_processing_report

        if report is None:

            return None

        filter_name = series.filter_name or "unknown"

        for measurement in report.measurements:

            if (

                not measurement.is_reference

                and measurement.source_id == series.source_id

                and (measurement.filter_name or "unknown") == filter_name

            ):

                return self._snr_series_key(measurement.catalog, measurement.source_id, measurement.filter_name)

        return None

    def _snr_series_has_derived_measurements(self, series: LightCurveSeries) -> bool:

        series_key = self._snr_series_key_for_light_curve(series)

        return series_key is not None and series_key in self._snr_binning_original_measurements

    def _replace_light_curves_for_snr_series(

        self,

        report: ProcessingReport,

        replacement_series: dict[tuple[str, str], LightCurveSeries],

    ) -> None:

        if not replacement_series:

            return

        updated_series: list[LightCurveSeries] = []

        inserted_keys: set[tuple[str, str]] = set()

        for series in report.light_curves:

            series_identity = self._series_identity(series)

            replacement = replacement_series.get(series_identity)

            if replacement is not None:

                if series_identity not in inserted_keys:

                    updated_series.append(replacement)

                    inserted_keys.add(series_identity)

                continue

            updated_series.append(series)

        for series_identity, replacement in replacement_series.items():

            if series_identity not in inserted_keys:

                updated_series.append(replacement)

        report.light_curves = updated_series

    def _clear_active_fit_curve_for_series_keys(self, series_keys: set[tuple[str, str]]) -> None:

        if not series_keys:

            return

        current_series = self._series_selector.currentData()

        if not isinstance(current_series, LightCurveSeries):

            return

        if self._series_identity(current_series) not in series_keys:

            return

        if not self._fit_curve_checkbox.isChecked():

            return

        self._fit_curve_checkbox.blockSignals(True)

        self._fit_curve_checkbox.setChecked(False)

        self._fit_curve_checkbox.blockSignals(False)

        self._sync_fit_period_button_state()

    def _selected_source_increase_snr_tasks(self) -> list[SnrBinningTask]:

        report = self._current_processing_report

        if report is None:

            return []

        settings = self._snr_binning_settings()

        selected_targets = self._selected_source_targets()

        if not selected_targets:

            selected_target = self._selected_source_target()

            if selected_target is not None:

                selected_targets = [selected_target]

        if not selected_targets:

            return []



        filtered_rows = self._filtered_measurements() if settings.apply_to_selected_measurements_only else None

        tasks: list[SnrBinningTask] = []

        seen_sources: set[str] = set()

        for source_name, catalog_name in selected_targets:

            entry = self._source_entry(report, source_name, catalog_name)

            if entry is None:

                continue

            source_key = self._snr_source_key(entry.catalog, entry.source_id)

            if source_key in seen_sources:

                continue

            seen_sources.add(source_key)

            measurements_by_filter: dict[str, list[PhotometryMeasurement]] = {}

            if settings.apply_to_selected_measurements_only and filtered_rows is not None:

                candidate_rows = [

                    measurement

                    for measurement in filtered_rows

                    if isinstance(measurement, PhotometryMeasurement)

                    and not measurement.is_reference

                    and measurement.catalog == entry.catalog

                    and measurement.source_id == entry.source_id

                ]

                for measurement in candidate_rows:

                    measurements_by_filter.setdefault(measurement.filter_name or "unknown", []).append(measurement)

            else:

                current_rows = [

                    measurement

                    for measurement in report.measurements

                    if not measurement.is_reference and measurement.catalog == entry.catalog and measurement.source_id == entry.source_id

                ]

                current_by_filter: dict[str, list[PhotometryMeasurement]] = {}

                for measurement in current_rows:

                    current_by_filter.setdefault(measurement.filter_name or "unknown", []).append(measurement)

                for filter_name, active_rows in current_by_filter.items():

                    series_key = self._snr_series_key(entry.catalog, entry.source_id, filter_name)

                    if settings.dataset_mode == "derived" and series_key in self._snr_binning_original_measurements:

                        measurements_by_filter[filter_name] = list(self._snr_binning_original_measurements[series_key])

                    else:

                        measurements_by_filter[filter_name] = list(active_rows)

            if not measurements_by_filter:

                continue

            tasks.append(

                SnrBinningTask(

                    source_id=entry.source_id,

                    source_name=entry.name,

                    catalog=entry.catalog,

                    variability_type=str(entry.metadata.get("type") or ""),

                    object_type=entry.object_type,

                    period_days=self._selected_source_actual_period_days(entry),

                    measurements_by_filter=measurements_by_filter,

                )

            )

        return tasks

    def _update_workspace_active_object_label(self) -> None:

        if not hasattr(self, "_process_button"):

            return

        self._sync_differential_primary_button()

        if self._current_report is None or getattr(self, "_differential_scan_in_progress", False):

            return

        object_name = self._selected_object_name()

        selected_filter = self._measurement_filter_combo.currentText().strip() if hasattr(self, "_measurement_filter_combo") else "All"

        filter_enabled = bool(object_name) and self._measurement_filter_combo.count() > 0

        if hasattr(self, "_measurement_filter_combo"):

            self._measurement_filter_combo.setEnabled(filter_enabled)

            if not object_name:

                self._measurement_filter_combo.setToolTip("Scan a workspace and choose an object before narrowing the filter.")

            elif selected_filter and selected_filter != "All":

                self._measurement_filter_combo.setToolTip(f"Generate is currently scoped to {selected_filter} for {object_name}.")

            else:

                self._measurement_filter_combo.setToolTip(f"Generate will include all available filters for {object_name}.")

        if hasattr(self, "_workspace_filter_label"):

            self._workspace_filter_label.setEnabled(filter_enabled)

        if not object_name:

            self._process_button.setToolTip("Select an object and optional filter before generating results.")

            return

        if selected_filter and selected_filter != "All":

            self._process_button.setToolTip(f"Generate will use {object_name} with filter {selected_filter}.")

        else:

            self._process_button.setToolTip(f"Generate will use all available filters for {object_name}.")

    def _set_generate_button_attention(self, enabled: bool) -> None:

        self._generate_button_needs_attention = enabled

        self._apply_generate_button_attention_style()

    def _set_hr_generate_button_attention(self, enabled: bool) -> None:

        self._hr_generate_button_needs_attention = enabled

        self._apply_generate_button_attention_style()

    def _set_asteroid_generate_button_attention(self, enabled: bool) -> None:

        self._asteroid_generate_button_needs_attention = enabled

        self._apply_generate_button_attention_style()

    def _apply_attention_button_style(

        self,

        button: QPushButton,

        enabled: bool,

        *,

        default_tooltip: str,

        active_tooltip: str,

    ) -> None:

        if not enabled:

            button.setStyleSheet("")

            button.setToolTip(default_tooltip)

            return

        accent_color = QColor(self._resolved_theme_editor_colors().get("accent", "#3d8bfd"))

        hover_color = accent_color.lighter(110).name().lower()

        pressed_color = accent_color.darker(110).name().lower()

        border_color = accent_color.darker(122).name().lower()

        text_color = self._contrast_text_color(accent_color.name().lower())

        button.setStyleSheet(

            "QPushButton {"

            f"background-color: {accent_color.name().lower()};"

            f"color: {text_color};"

            f"border: 1px solid {border_color};"

            "border-radius: 4px;"

            "font-weight: 600;"

            "padding: 4px 10px;"

            "}"

            f"QPushButton:hover {{ background-color: {hover_color}; }}"

            f"QPushButton:pressed {{ background-color: {pressed_color}; }}"

        )

        button.setToolTip(active_tooltip)

        button.setFixedHeight(_MODE_TOOLBAR_BUTTON_HEIGHT)

    def _apply_generate_button_attention_style(self) -> None:

        if hasattr(self, "_process_button"):

            self._apply_attention_button_style(

                self._process_button,

                getattr(self, "_generate_button_needs_attention", False),

                default_tooltip="Generate results for the active object.",

                active_tooltip="Loaded results are ready. Generate the active object.",

            )

            self._sync_differential_primary_button()

        if hasattr(self, "_hr_prepare_button"):

            self._apply_attention_button_style(

                self._hr_prepare_button,

                getattr(self, "_hr_generate_button_needs_attention", False),

                default_tooltip="Open a solved RGB source image for HR Diagram mode.",

                active_tooltip="Open a solved RGB source image for HR Diagram mode.",

            )

        if hasattr(self, "_asteroid_detect_button"):

            apply_pending = getattr(self, "_asteroid_apply_estimate_pending", False)

            has_loaded_source = self._current_asteroid_source_image is not None

            if apply_pending:

                button_text = "Apply"

            elif has_loaded_source:

                button_text = "Generate"

            else:

                button_text = "Open"

            self._asteroid_detect_button.setText(button_text)

            self._apply_attention_button_style(

                self._asteroid_detect_button,

                getattr(self, "_asteroid_generate_button_needs_attention", False),

                default_tooltip=(

                    "Apply the estimated magnitude limit to regenerate asteroid/comet predictions for the current source image."

                    if apply_pending

                    else (

                        "Generate known asteroid/comet predictions for the current source image."

                        if has_loaded_source

                        else "Open an asteroid/comet subframe folder and start detection automatically."

                    )

                ),

                active_tooltip=(

                    "Asteroid/comet source frames are ready. Apply the estimated magnitude limit to the current sequence."

                    if apply_pending

                    else (

                        "Asteroid/comet source frames are ready. Generate predictions for the current sequence."

                        if has_loaded_source

                        else "Open an asteroid/comet subframe folder and start detection automatically."

                    )

                ),

            )

        if hasattr(self, "_transient_search_button"):

            transient_tooltip = self._transient_primary_button_default_tooltip()

            self._apply_attention_button_style(

                self._transient_search_button,

                getattr(self, "_transient_primary_button_needs_attention", False),

                default_tooltip=transient_tooltip,

                active_tooltip=transient_tooltip,

            )

        self._sync_hr_plot_toolbar_buttons()

        self._apply_hr_mode_chrome()

        self._apply_differential_mode_chrome()

        self._apply_asteroid_mode_chrome()

        self._apply_transient_mode_chrome()

        self._apply_astrostack_mode_chrome()

        self._apply_distance_map_mode_chrome()

    def _apply_distance_map_mode_chrome(self) -> None:
        panel = getattr(self, "_distance_map_panel_widget", None)
