    def _sync_hr_plot_toolbar_buttons(self) -> None:

        if not hasattr(self, "_hr_plot_reset_button") or not hasattr(self, "_hr_export_button"):

            return

        button_width = max(self._hr_plot_reset_button.sizeHint().width(), self._hr_export_button.sizeHint().width())

        button_height = max(self._hr_plot_reset_button.sizeHint().height(), self._hr_export_button.sizeHint().height())

        self._hr_plot_reset_button.setMinimumWidth(button_width)

        self._hr_plot_reset_button.setMinimumHeight(button_height)

        self._hr_export_button.setMinimumWidth(button_width)

        self._hr_export_button.setMinimumHeight(button_height)

