    def _handle_scan_completed(self, report: ScanReport) -> None:

        self._differential_scan_in_progress = False

        workflow_scan_requested = self._differential_workflow_scan_requested

        workflow_auto_generate_after_scan = self._differential_workflow_auto_generate_after_scan

        self._differential_workflow_scan_requested = False

        self._differential_workflow_auto_generate_after_scan = False

        self._current_report = report

        self._scan_file_result_lookup = {

            str(result.path.resolve()): result

            for summary in report.object_summaries

            for result in summary.files

        }

        self._image_display_cache = {}

        self._populate_object_table(report.object_summaries)

        self._sync_manual_controls()

        self._update_target_browser_buttons()

        self.statusBar().showMessage(f"Scanned {report.total_files} FITS files.")

        self._append_work_log(f"Scan completed: found {report.total_files} FITS file(s) across {len(report.object_summaries)} object folder(s).")



        if report.object_summaries:

            object_count = len(report.object_summaries)

            if workflow_scan_requested:

                self._summary_label.setText(

                    f"Found {report.total_files} FITS files across {object_count} object folder(s). Ready for guided Generate."

                )

            else:

                self._summary_label.setText(

                    f"Found {report.total_files} FITS files across {object_count} object folders. "

                    "Review the loaded-results summary to choose the active object for Generate and scan-file inspection."

                )

            self._object_table.selectRow(0)

            self._set_generate_button_attention(not workflow_scan_requested)

            if workflow_scan_requested:

                selected_object = self._selected_object_name()

                summary = report.object_summaries[0]

                if workflow_auto_generate_after_scan:

                    self._append_work_log("Workflow calibration scan complete: continuing into light-curve generation.")

                    if not self._begin_differential_workflow_processing_from_selection():

                        self._fail_differential_workflow("No usable object was found after workflow calibration completed.")

                    return

                if self._differential_workflow_dialog is not None and qt_object_is_valid(self._differential_workflow_dialog):

                    self._differential_workflow_dialog.set_ready(selected_object or summary.object_name, len(summary.files))

                self._append_work_log("Workflow folder step complete: one object folder is assumed for guided Generate.")

            else:

                self._show_scan_results_summary_dialog(report)

        else:

            self._summary_label.setText(

                "No FITS files were found under Files/<ObjectName>. Add data and rescan."

            )

            self._append_work_log("Scan completed: no supported FITS files were found in the selected location.")

            self._set_generate_button_attention(False)

            if workflow_scan_requested and self._differential_workflow_dialog is not None and qt_object_is_valid(self._differential_workflow_dialog):

                self._differential_workflow_dialog.set_failed("No supported FITS files were found in the selected folder.", can_generate=False)

        self._populate_workspace_filter_options_for_selected_object()

        self._update_workspace_active_object_label()

        self._sync_differential_primary_button()

    def _handle_scan_failed(self, message: str) -> None:

        self._differential_scan_in_progress = False

        workflow_scan_requested = self._differential_workflow_scan_requested

        self._differential_workflow_scan_requested = False

        self._differential_workflow_auto_generate_after_scan = False

        self.statusBar().showMessage("Scan failed.")

        self._append_work_log(f"Scan failed: {message}")

        self._set_generate_button_attention(False)

        self._update_workspace_active_object_label()

        self._sync_differential_primary_button()

        if workflow_scan_requested and self._differential_workflow_dialog is not None and qt_object_is_valid(self._differential_workflow_dialog):

            self._differential_workflow_dialog.set_failed(f"Folder scan failed: {message}", can_generate=False)

        QMessageBox.critical(self, "Scan failed", message)

    def _handle_preview_completed(self, preview: VariableSelectionPreview) -> None:

        self._current_preview = None

        self._current_processing_report = None

        self._pending_object_name = None

        self._process_button.setText("Generate")

        self._update_target_browser_buttons()

        exoplanet_count = sum(1 for entry in preview.candidate_sources if entry.object_type == "exoplanet")

        self._append_work_log(

            f"Preview complete for {preview.object_name}: found {preview.total_variable_stars_found} variable star(s) and {exoplanet_count} exoplanet entry/entries."

        )



        dialog = PreviewSelectionDialog(preview, self)

        if dialog.exec() != dialog.DialogCode.Accepted:

            self.statusBar().showMessage("Processing canceled.")

            self._summary_label.setText(f"Processing canceled for {preview.object_name}.")

            self._append_work_log(f"Processing canceled after preview for {preview.object_name}.")

            return



        selected_source_keys = dialog.selected_source_keys()

        if self._settings is None:

            root_path = Path(self._root_path_input.text()).expanduser()

            if root_path.exists():

                self._settings = AppSettings.from_root(root_path)

        if self._settings is not None:

            self._settings.variable_star_limit_mode = dialog.variable_star_limit_mode()

            self._settings.variable_star_limit_value = dialog.variable_star_limit_value()

            self._settings.variable_star_designation_filters = dialog.variable_star_designation_filters()

            selected_sources = self._settings.selected_catalog_source_ids or {}

            selected_sources[preview.object_name] = selected_source_keys

            self._settings.selected_catalog_source_ids = selected_sources

            self._save_settings_snapshot()



        self._begin_processing(Path(self._root_path_input.text()).expanduser(), preview.object_name)

    def _handle_preview_failed(self, message: str) -> None:

        object_name = self._pending_object_name or "selected object"

        user_message = summarize_catalog_service_error(message)

        self._current_preview = None

        self._pending_object_name = None

        self._process_button.setText("Generate")

        self._update_target_browser_buttons()

        self.statusBar().showMessage("Preview failed.")

        self._summary_label.setText(f"Preview for {object_name} could not be prepared. {user_message}")

        self._append_work_log(f"Preview failed for {object_name}: {user_message}")

        QMessageBox.warning(self, "Preview unavailable", user_message)

    def _handle_process_progress(self, message: str) -> None:

        display_message = self._format_processing_progress_message(message)

        self.statusBar().showMessage(display_message)

        if self._processing_started_monotonic is not None:

            self._summary_label.setText(display_message)

            self._sync_processing_progress_bar()

        elif "Submitting " in message and " photometry file(s) with " in message:

            self._summary_label.setText(message)

        self._append_work_log(message)

        if self._differential_workflow_active:

            self._set_differential_workflow_stage("generating light curves", display_message)

    def _handle_processing_completed(self, report: ProcessingReport, *, save_cache: bool = True) -> None:

        self._clear_processing_progress_state()

        manual_recompute_targets = self._pending_manual_recompute_selection

        manual_recompute_base_report = self._pending_manual_recompute_base_report

        self._pending_manual_recompute_selection = None

        self._pending_manual_recompute_base_report = None

        if manual_recompute_base_report is not None and report.manual_config is not None:

            report = self._merge_manual_recompute_report(manual_recompute_base_report, report)

        if report.photometry_mode != ObjectPhotometryMode.MANUAL and report.manual_config is not None and report.manual_config.mode != ObjectPhotometryMode.AUTO:

            report.manual_config = replace(report.manual_config, mode=ObjectPhotometryMode.AUTO)

        self._current_processing_report = report

        self._yield_differential_workflow_ui()

        settings_override = self._active_processing_settings_override

        analyze_best_targets = self._active_processing_analyze_best_targets

        self._active_processing_settings_override = None

        self._active_processing_analyze_best_targets = False

        if save_cache:

            try:

                self._pipeline.save_cached_processing_report(
                    Path(self._root_path_input.text()).expanduser(),
                    report,
                    summary_files=self._current_processed_object_files(),
                    settings_override=settings_override,
                    analyze_best_targets=analyze_best_targets,
                )

            except Exception as exc:

                self._append_work_log(f"Ignored cached light-curve save failure: {exc}")

        self._snr_binning_original_measurements = {}

        self._snr_binning_original_light_curves = {}

        self._snr_binning_original_period_states = {}

        self._snr_binning_summaries = {}

        self._set_generate_button_attention(False)

        self._calculated_period_results = {}

        self._literature_period_results = {}

        self._restore_period_result_cache(report)

        self._yield_differential_workflow_ui()

        self._image_display_cache.clear()

        if self._settings is not None and report.manual_config is not None:

            manual_configs = self._settings.manual_photometry_configs or {}

            settings_changed = manual_configs.get(report.object_name) != report.manual_config

            manual_configs[report.object_name] = report.manual_config

            self._settings.manual_photometry_configs = manual_configs

            if settings_changed:

                self._save_settings_snapshot()

        self.statusBar().showMessage(

            f"Processed {report.object_name}: {len(report.light_curves)} light curves from {report.solved_files} solved files."

        )

        self._append_work_log(

            f"Processing completed for {report.object_name}: {len(report.measurements)} measurement row(s), {len(report.light_curves)} light curve(s)."

        )

        self._summary_label.setText(

            f"Processed {report.object_name}. Generated {len(report.light_curves)} per-filter variable-star light curves."

        )

        self._populate_processing_file_table(report)

        self._yield_differential_workflow_ui()

        self._populate_source_table(report)

        if manual_recompute_targets:

            self._restore_source_target_selection(manual_recompute_targets)

            self._ensure_manual_light_curve_axis_visible(report)

        self._yield_differential_workflow_ui()

        self._populate_measurement_filter_options(report)

        self._mark_measurement_table_pending()

        self._populate_history_table(self._pipeline.load_run_history(Path(self._root_path_input.text()).expanduser(), report.object_name))

        self._render_notes(report)

        self._yield_differential_workflow_ui()

        self._refresh_processing_views()

        if manual_recompute_targets:

            self._sync_series_selection_for_source_target(*manual_recompute_targets[0])

            self._plot_selected_series()

            self._render_image_panel()

        self._yield_differential_workflow_ui()

        self._sync_manual_controls()

        self._update_target_browser_buttons()

        self._update_workspace_active_object_label()

        self._update_source_period_button_state()

        pending_targets = self._pending_comparison_fit_targets_after_processing

        self._pending_comparison_fit_targets_after_processing = None

        if pending_targets:

            self._restore_source_target_selection(pending_targets)

            self._append_work_log("Resuming Find Better Fit after manual-aperture reprocessing.")

            self._optimize_selected_source_comparison_fit()

        if self._differential_workflow_active:

            self._append_work_log("Workflow light-curve step complete.")

            self._yield_differential_workflow_ui()

            self._run_next_differential_workflow_step()

    def _merge_manual_recompute_report(self, base_report: ProcessingReport, manual_report: ProcessingReport) -> ProcessingReport:

        if base_report.object_name != manual_report.object_name or manual_report.manual_config is None:

            return manual_report

        manual_variable_entries = list(manual_report.field_catalog.variable_stars) if manual_report.field_catalog is not None else []

        if base_report.field_catalog is None:

            base_report.field_catalog = manual_report.field_catalog

        else:

            base_report.field_catalog = FieldCatalog(

                center_ra_deg=base_report.field_catalog.center_ra_deg,

                center_dec_deg=base_report.field_catalog.center_dec_deg,

                radius_deg=base_report.field_catalog.radius_deg,

                gaia_stars=list(base_report.field_catalog.gaia_stars),

                variable_stars=[

                    entry for entry in base_report.field_catalog.variable_stars if entry.catalog != "manual"

                ]

                + manual_variable_entries,

                exoplanets=list(base_report.field_catalog.exoplanets),

            )

        manual_reference_entries = list(manual_report.reference_stars)

        base_report.reference_stars = [entry for entry in base_report.reference_stars if entry.catalog != "manual"] + manual_reference_entries

        base_report.measurements = [measurement for measurement in base_report.measurements if measurement.catalog != "manual"] + list(manual_report.measurements)

        base_report.light_curves = build_light_curve_series(base_report.measurements)

        base_report.files_processed = max(base_report.files_processed, manual_report.files_processed)

        base_report.solved_files = max(base_report.solved_files, manual_report.solved_files)

        persisted_manual_config = self._manual_config_for_object(base_report.object_name)

        if persisted_manual_config is not None:

            persisted_manual_config = replace(

                persisted_manual_config,

                mode=ObjectPhotometryMode.AUTO,

                reference_frame_name=manual_report.manual_config.reference_frame_name,

                keep_comparison_stars=manual_report.manual_config.keep_comparison_stars,

                recenter_mode=manual_report.manual_config.recenter_mode,

                max_recenter_radius_pixels=manual_report.manual_config.max_recenter_radius_pixels,

                fallback_to_wcs_on_centroid_failure=manual_report.manual_config.fallback_to_wcs_on_centroid_failure,

                sources=list(manual_report.manual_config.sources),

            )

        else:

            persisted_manual_config = replace(manual_report.manual_config, mode=ObjectPhotometryMode.AUTO)

        base_report.manual_config = persisted_manual_config

        base_report.photometry_mode = ObjectPhotometryMode.AUTO

        base_notes = [

            note

            for note in base_report.notes

            if not note.startswith("Manual mode measured ") and not note.startswith("Manual aperture update ")

        ]

        manual_notes = [note for note in manual_report.notes if note.startswith("Manual mode measured ")]

        manual_note = (

            f"Manual aperture update added {len(manual_report.measurements)} measurement row(s) for "

            f"{len(base_report.manual_config.measured_sources)} manual source(s) while preserving existing Source Results."

        )

        base_report.notes = self._deduplicated_text_items([*base_notes, *manual_notes, manual_note])

        merged_file_notes = {key: list(value) for key, value in base_report.file_notes.items()}

        for file_name, notes in manual_report.file_notes.items():

            merged_file_notes[file_name] = self._deduplicated_text_items([*merged_file_notes.get(file_name, []), *notes])

        base_report.file_notes = merged_file_notes

        return base_report

    def _ensure_manual_light_curve_axis_visible(self, report: ProcessingReport) -> None:

        manual_config = report.manual_config

        if manual_config is None:

            return

        current_axis = self._current_light_curve_y_axis_mode()

        manual_source_ids = {source.source_id for source in manual_config.measured_sources}

        for series in report.light_curves:

            if series.source_id not in manual_source_ids:

                continue

            if self._series_has_valid_light_curve_values(series, current_axis):

                return

            if any(point.differential_magnitude is not None for point in series.points):

                axis_index = self._light_curve_y_axis_selector.findData("differential_magnitude")

                if axis_index >= 0 and self._light_curve_y_axis_selector.currentIndex() != axis_index:

                    self._light_curve_y_axis_selector.blockSignals(True)

                    self._light_curve_y_axis_selector.setCurrentIndex(axis_index)

                    self._light_curve_y_axis_selector.blockSignals(False)

                return

    def _deduplicated_text_items(self, values: list[str]) -> list[str]:

        deduplicated: list[str] = []

        for value in values:

            if value and value not in deduplicated:

                deduplicated.append(value)

        return deduplicated

    def _handle_processing_failed(self, message: str) -> None:

        self._clear_processing_progress_state()

        self._pending_comparison_fit_targets_after_processing = None

        self._pending_manual_recompute_base_report = None

        self._pending_manual_recompute_selection = None

        self._pending_processing_settings_override = None

        self._pending_processing_analyze_best_targets = False

        self._active_processing_settings_override = None

        self._active_processing_analyze_best_targets = False

        self._set_generate_button_attention(False)

        self.statusBar().showMessage("Processing failed.")

        self._append_work_log(f"Processing failed: {message}")

        if self._differential_workflow_active:

            self._fail_differential_workflow(f"Light-curve generation failed: {message}")

        QMessageBox.critical(self, "Processing failed", message)

    def _set_differential_workflow_stage(self, title: str, detail: str) -> None:

        self._set_processing_progress_bar_active(True)

        if self._differential_workflow_dialog is not None and qt_object_is_valid(self._differential_workflow_dialog):

            self._differential_workflow_dialog.set_busy(title, detail)

    def _yield_differential_workflow_ui(self) -> None:

        if not self._differential_workflow_active:

            return

        QApplication.processEvents(QEventLoop.ProcessEventsFlag.ExcludeUserInputEvents)

    def _finish_differential_workflow(self, detail: str) -> None:

        self._differential_workflow_active = False

        self._differential_workflow_pending_steps = []

        self._differential_workflow_current_step = None

        self._differential_workflow_cache_summary_lines = []

        self._differential_workflow_auto_generate_after_scan = False

        self._pending_processing_settings_override = None

        self._pending_processing_analyze_best_targets = False

        self._active_processing_settings_override = None

        self._active_processing_analyze_best_targets = False

        self._set_processing_progress_bar_active(False)

        if self._differential_workflow_dialog is not None and qt_object_is_valid(self._differential_workflow_dialog):

            self._differential_workflow_dialog.set_finished(detail)

        self._append_work_log(f"Workflow complete: {detail}")

    def _fail_differential_workflow(self, detail: str) -> None:

        self._differential_workflow_active = False

        self._differential_workflow_pending_steps = []

        self._differential_workflow_current_step = None

        self._differential_workflow_cache_summary_lines = []

        self._differential_workflow_auto_generate_after_scan = False

        self._pending_processing_settings_override = None

        self._pending_processing_analyze_best_targets = False

        self._active_processing_settings_override = None

        self._active_processing_analyze_best_targets = False

        self._set_processing_progress_bar_active(False)

        if self._differential_workflow_dialog is not None and qt_object_is_valid(self._differential_workflow_dialog):

            self._differential_workflow_dialog.set_failed(detail)

        self._append_work_log(f"Workflow stopped: {detail}")

    def _complete_differential_workflow_step(self, detail: str) -> None:

        if not self._differential_workflow_active:

            return

        self._append_work_log(detail)

        self._differential_workflow_current_step = None

        self._run_next_differential_workflow_step()

    def _run_next_differential_workflow_step(self) -> None:

        if not self._differential_workflow_active:

            return

        report = self._current_processing_report

        if report is None:

            self._fail_differential_workflow("No processed report is available for the follow-up workflow steps.")

            return

        while self._differential_workflow_pending_steps:

            step = self._differential_workflow_pending_steps.pop(0)

            self._differential_workflow_current_step = step

            if step == "pull-periods":

                self._set_differential_workflow_stage("pulling periods", "Checking literature period values for supported source rows.")

                literature_entries = self._current_literature_period_entries()

                if literature_entries and self._current_literature_period_entries_are_cached(literature_entries):

                    self._append_work_log(
                        f"Workflow skipped Pull Periods: reused cached literature period values for {len(literature_entries)} displayed source row(s)."
                    )

                    self._differential_workflow_current_step = None

                    continue

                self._pull_literature_period_data()

                if self._literature_period_worker is not None:

                    return

                self._append_work_log("Workflow skipped Pull Periods: no supported literature period rows were available.")

                self._differential_workflow_current_step = None

                continue

            if step == "calculate-periods":

                self._set_differential_workflow_stage("calculating periods", "Estimating periods from the displayed light-curve series.")

                target_series = self._current_calculate_period_series()

                if target_series and self._current_calculate_period_series_are_cached(target_series):

                    self._append_work_log(
                        f"Workflow skipped Calculate Periods: reused cached period fits for {len(target_series)} displayed light-curve series."
                    )

                    self._differential_workflow_current_step = None

                    continue

                self._calculate_period_data()

                if self._calculate_period_worker is not None:

                    return

                self._append_work_log("Workflow skipped Calculate Periods: no variable-star light curves were available.")

                self._differential_workflow_current_step = None

                continue

            if step == "measurements-table":

                self._set_differential_workflow_stage("creating Measurements table", "Loading detailed measurement rows into the Measurements tab.")

                pending_rows = self._pending_measurement_row_count()

                if pending_rows > 0:

                    self._populate_measurement_table(report)

                    self._render_selected_details()

                    self.statusBar().showMessage(f"Loaded {pending_rows:,} measurement row(s) into the Measurements table.", 5000)

                    self._append_work_log(f"Workflow loaded {pending_rows} measurement row(s) into the Measurements table.")

                else:

                    self._measurement_table_refresh_pending = False

                    self._clear_measurement_table_view()

                    self._update_measure_button_state()

                    self._render_selected_details()

                    self._append_work_log("Workflow skipped Measurements table: no rows matched the current filters.")

                self._differential_workflow_current_step = None

                continue

        self._finish_differential_workflow("Results are ready. Review Source Results, Light Curve, Measurements, and Work Log for details.")

    def _reset_processing_progress_state(self, object_name: str) -> None:

        self._active_processing_object_name = object_name

        self._processing_started_monotonic = monotonic()

        self._processing_total_files = None

        self._processing_wcs_completed = 0

        self._processing_wcs_total = None

        self._processing_wcs_active_index = None

        self._processing_photometry_completed = 0

        self._processing_photometry_total = None

        self._processing_photometry_active_index = None

        self._processing_stage = "starting"

        self._sync_processing_progress_bar()

    def _clear_processing_progress_state(self) -> None:

        self._active_processing_object_name = None

        self._processing_started_monotonic = None

        self._processing_total_files = None

        self._processing_wcs_completed = 0

        self._processing_wcs_total = None

        self._processing_wcs_active_index = None

        self._processing_photometry_completed = 0

        self._processing_photometry_total = None

        self._processing_photometry_active_index = None

        self._processing_stage = None

        self._sync_processing_progress_bar()

    def _format_processing_progress_message(self, message: str) -> str:

        self._update_processing_progress_state(message)

        progress_fraction = self._estimated_processing_fraction()

        if progress_fraction is None or progress_fraction <= 0 or self._processing_started_monotonic is None:

            return message

        elapsed_seconds = max(0.0, monotonic() - self._processing_started_monotonic)

        eta_seconds = max(0.0, (elapsed_seconds * (1.0 - progress_fraction) / progress_fraction)) if progress_fraction < 1.0 else 0.0

        percent = max(1, min(100, int(round(progress_fraction * 100.0))))

        return f"{message} ({percent}% | ETA {self._format_duration_seconds(eta_seconds)})"

    def _set_processing_progress_bar_active(self, active: bool) -> None:

        if active:

            self._processing_progress_bar.setRange(0, 0)

            return

        self._processing_progress_bar.setRange(0, 1)

        self._processing_progress_bar.setValue(0)

    def _update_processing_progress_state(self, message: str) -> None:

        if self._processing_started_monotonic is None:

            return

        normalized_message = message.lower()

        total_match = re.search(r"Found\s+(\d+)\s+file\(s\) queued for analysis\.", message)

        if total_match is not None:

            self._processing_total_files = int(total_match.group(1))



        wcs_match = _PROCESS_WCS_PROGRESS_RE.search(message)

        if wcs_match is not None:

            self._processing_stage = "wcs"

            wcs_index = int(wcs_match.group(1))

            self._processing_wcs_total = int(wcs_match.group(2))

            if "inspecting" in normalized_message:

                self._processing_wcs_active_index = wcs_index

                self._processing_wcs_completed = max(self._processing_wcs_completed, wcs_index - 1)

            elif "solved field ready" in normalized_message or "skipped" in normalized_message or "reused solved wcs" in normalized_message:

                self._processing_wcs_completed = max(self._processing_wcs_completed, wcs_index)

                self._processing_wcs_active_index = None



        photometry_match = _PROCESS_PHOTOMETRY_PROGRESS_RE.search(message)

        if photometry_match is not None:

            self._processing_stage = "photometry"

        if photometry_match is not None:

            photometry_index = int(photometry_match.group(1))

            self._processing_photometry_total = int(photometry_match.group(2))

            if "preparing" in normalized_message:

                self._processing_photometry_active_index = photometry_index

                self._processing_photometry_completed = max(self._processing_photometry_completed, photometry_index - 1)

            elif "reused cached measurements" in normalized_message or "measured " in normalized_message:

                self._processing_photometry_completed = max(self._processing_photometry_completed, photometry_index)

                self._processing_photometry_active_index = None



        if "querying gaia dr3 and vsx catalogs" in normalized_message or "catalog lookup complete" in normalized_message:

            self._processing_stage = "catalog"

        elif "applying differential photometry" in normalized_message:

            self._processing_stage = "differential"

        elif "scoring measurement quality" in normalized_message:

            self._processing_stage = "quality"

        elif "building per-filter light curves" in normalized_message:

            self._processing_stage = "light-curves"

        elif "completed processing" in normalized_message:

            self._processing_stage = "completed"

    def _estimated_processing_fraction(self) -> float | None:

        if self._processing_started_monotonic is None:

            return None

        if self._processing_stage == "completed":

            return 1.0

        if self._processing_stage == "light-curves":

            return 0.98

        if self._processing_stage == "quality":

            return 0.94

        if self._processing_stage == "differential":

            return 0.88

        if self._processing_stage == "catalog":

            return 0.22

        if self._processing_photometry_total and self._processing_photometry_total > 0:

            photometry_units = float(self._processing_photometry_completed)

            if self._processing_photometry_active_index is not None and self._processing_photometry_active_index > self._processing_photometry_completed:

                photometry_units += 0.15

            photometry_fraction = min(1.0, photometry_units / self._processing_photometry_total)

            return min(0.86, 0.24 + (0.62 * photometry_fraction))

        if self._processing_wcs_total and self._processing_wcs_total > 0:

            wcs_units = float(self._processing_wcs_completed)

            if self._processing_wcs_active_index is not None and self._processing_wcs_active_index > self._processing_wcs_completed:

                wcs_units += 0.1

            wcs_fraction = min(1.0, wcs_units / self._processing_wcs_total)

            return min(0.20, 0.02 + (0.18 * wcs_fraction))

        if self._processing_total_files:

            return 0.01

        return None

    def _format_duration_seconds(self, total_seconds: float) -> str:

        rounded_seconds = max(0, int(round(total_seconds)))

        minutes, seconds = divmod(rounded_seconds, 60)

        hours, minutes = divmod(minutes, 60)

        if hours > 0:

            return f"{hours}h {minutes}m"

        if minutes > 0:

            return f"{minutes}m {seconds}s"

        return f"{seconds}s"

    def _sync_processing_progress_bar(self) -> None:

        self._set_processing_progress_bar_active(self._processing_started_monotonic is not None)

    def _populate_object_table(self, summaries: list[ObjectScanSummary]) -> None:

        self._object_table.setRowCount(len(summaries))



        for row_index, summary in enumerate(summaries):

            self._object_table.setItem(row_index, 0, QTableWidgetItem(summary.object_name))

            self._object_table.setItem(row_index, 1, QTableWidgetItem(str(len(summary.files))))

            self._object_table.setItem(row_index, 2, QTableWidgetItem(str(summary.solved_count)))

            self._object_table.setItem(row_index, 3, QTableWidgetItem(str(summary.unsolved_count)))

    def _handle_object_selection_changed(self) -> None:

        self._image_context_source = "scan"

        selected_object = self._selected_object_name()

        if self._current_preview is not None and self._current_preview.object_name != selected_object:

            self._current_preview = None

            self._process_button.setText("Generate")

        self._populate_workspace_filter_options_for_selected_object()

        self._update_workspace_active_object_label()

        self._populate_file_table()

        self._populate_selected_object_history()

        self._sync_manual_controls()

        self._update_target_browser_buttons()

        self._render_image_panel()

        if self._image_auto_center_object_enabled:

            self._center_image_view_on_selected_source(show_status_message=False)

    def _populate_file_table(self) -> None:

        if not self._current_report:

            return



        selected_row = self._object_table.currentRow()

        if selected_row < 0 or selected_row >= len(self._current_report.object_summaries):

            return



        files = self._current_report.object_summaries[selected_row].files

        self._file_table.setRowCount(len(files))

        for row_index, result in enumerate(files):

            self._set_file_row(row_index, result)

    def _set_file_row(self, row_index: int, result: FileScanResult) -> None:

        metadata = result.metadata

        dimensions = "-"

        if metadata.width and metadata.height:

            dimensions = f"{metadata.width} x {metadata.height}"



        values = [

            result.path.name,

            (_coerce_utc_datetime(metadata.date_obs).isoformat(sep=" ") if _coerce_utc_datetime(metadata.date_obs) else "-"),

            metadata.filter_name or "-",

            f"{metadata.exposure_seconds:.2f}" if metadata.exposure_seconds is not None else "-",

            dimensions,

            result.wcs_status.value,

            "; ".join(result.reasons) if result.reasons else "-",

        ]



        for column_index, value in enumerate(values):

            item = QTableWidgetItem(value)

            if column_index in (1, 2, 4, 5, 6):

                item.setFlags(item.flags() ^ Qt.ItemFlag.ItemIsEditable)

            self._file_table.setItem(row_index, column_index, item)

    def _populate_series_selector(self, light_curves: list[LightCurveSeries]) -> None:

        current_series = self._series_selector.currentData()

        current_key = None

        if isinstance(current_series, LightCurveSeries):

            current_key = (current_series.source_id, current_series.filter_name)

        self._series_selector.clear()

        displayed_series = self._visible_light_curve_series(light_curves)

        for series in displayed_series:

            label = f"{series.source_name} [{series.filter_name}] ({len(series.points)} points)"

            self._series_selector.addItem(label, series)

        if current_key is not None:

            for index in range(self._series_selector.count()):

                series = self._series_selector.itemData(index)

                if not isinstance(series, LightCurveSeries):

                    continue

                if (series.source_id, series.filter_name) == current_key:

                    self._series_selector.setCurrentIndex(index)

                    break

        if self._series_selector.count() > 0 and self._series_selector.currentIndex() < 0:

            self._series_selector.setCurrentIndex(0)

        self._update_series_navigation_buttons()

        self._update_fit_control_visibility()

    def _handle_light_curve_series_filter_changed(self, _value: object | None = None) -> None:

        if self._current_processing_report is None:

            return

        self._populate_series_selector(self._filtered_light_curves())

        self._populate_image_frame_selector()

        self._plot_selected_series()

        self._render_image_panel()

    def _handle_series_selection_changed(self) -> None:

        self._image_context_source = "series"

        self._update_series_navigation_buttons()

        self._update_fit_control_visibility()

        self._update_target_browser_buttons()

        self._populate_image_frame_selector()

        self._plot_selected_series()

        self._render_image_panel()

    def _handle_fit_control_changed(self, _value: object | None = None) -> None:

        self._sync_fold_button_state()

        self._update_fit_control_visibility()

        self._update_fit_period_summary_label()

        self._plot_selected_series()

    def _handle_fit_curve_enabled_changed(self, _state: int) -> None:

        self._sync_fit_period_button_state()

        self._handle_fit_control_changed(_state)

    def _update_fit_control_visibility(self) -> None:

        mode = str(self._fit_mode_selector.currentData() or "polynomial")

        phase_mode = self._current_light_curve_x_axis_mode() == "phase"

        show_polynomial_controls = mode == "polynomial"

        show_spline_controls = mode == "spline"

        show_auto_controls = mode == "auto"

        show_period_controls = (not show_polynomial_controls) or phase_mode

        self._phase_anchor_label.setVisible(phase_mode)

        self._phase_anchor_selector.setVisible(phase_mode)

        self._fit_degree_label.setVisible(show_polynomial_controls)

        self._fit_degree_spin.setVisible(show_polynomial_controls)

        if show_auto_controls:

            self._fit_degree_label.setVisible(True)

            self._fit_degree_spin.setVisible(True)

        self._fit_period_label.setVisible(False)

        self._fit_period_spin.setVisible(False)

        self._fit_period_summary_label.setVisible(False)

        self._period_search_method_label.setVisible(show_period_controls)

        self._period_search_method_selector.setVisible(show_period_controls)

        self._period_convention_label.setVisible(show_period_controls)

        self._period_convention_selector.setVisible(show_period_controls)

        self._fit_guess_period_button.setVisible(show_period_controls)

        self._fit_harmonics_label.setVisible(mode == "periodic" or show_auto_controls)

        self._fit_harmonics_spin.setVisible(mode == "periodic" or show_auto_controls)

        self._fit_smoothing_label.setVisible(show_spline_controls or show_auto_controls)

        self._fit_smoothing_spin.setVisible(show_spline_controls or show_auto_controls)

        filters_available = getattr(self, "_current_processing_report", None) is not None

        self._light_curve_filter_button.setEnabled(filters_available)

        self._fit_guess_period_button.setEnabled(self._series_selector.count() > 0 and self._fit_period_worker is None)

        self._fold_plot_button.setEnabled(self._series_selector.count() > 0)

        self._export_light_curve_button.setEnabled(self._series_selector.count() > 0)

        self._sync_fit_period_button_state()

        self._sync_light_curve_filter_button_state()

    def _sync_fit_period_button_state(self) -> None:

        checked = self._fit_curve_checkbox.isChecked()

        self._fit_guess_period_button.blockSignals(True)

        self._fit_guess_period_button.setChecked(checked)

        self._fit_guess_period_button.blockSignals(False)

    def _sync_light_curve_filter_button_state(self) -> None:

        checked = self._light_curve_filtering_active()

        self._light_curve_filter_button.blockSignals(True)

        self._light_curve_filter_button.setChecked(checked)

        self._light_curve_filter_button.blockSignals(False)

    def _update_series_navigation_buttons(self) -> None:

        current_index = self._series_selector.currentIndex()

        count = self._series_selector.count()

        has_previous = count > 1 and current_index > 0

        has_next = count > 1 and current_index >= 0 and current_index < count - 1

        self._previous_series_button.setEnabled(has_previous)

        self._next_series_button.setEnabled(has_next)

    def _select_previous_series(self) -> None:

        current_index = self._series_selector.currentIndex()

        if current_index > 0:

            self._series_selector.setCurrentIndex(current_index - 1)

    def _select_next_series(self) -> None:

        current_index = self._series_selector.currentIndex()

        if 0 <= current_index < self._series_selector.count() - 1:

            self._series_selector.setCurrentIndex(current_index + 1)

    def _handle_previous_series_shortcut(self) -> None:

        if self._can_use_series_navigation_shortcuts():

            self._select_previous_source_result()

    def _handle_next_series_shortcut(self) -> None:

        if self._can_use_series_navigation_shortcuts():

            self._select_next_source_result()

    def keyPressEvent(self, event: object) -> None:

        if event.modifiers() == Qt.KeyboardModifier.NoModifier and self._series_selector.count() > 0:

            if self._can_use_series_navigation_shortcuts():

                if event.key() == Qt.Key.Key_Up:

                    self._select_previous_source_result()

                    event.accept()

                    return

                if event.key() == Qt.Key.Key_Down:

                    self._select_next_source_result()

                    event.accept()

                    return

        super().keyPressEvent(event)

    def _can_use_series_navigation_shortcuts(self) -> bool:

        focus_widget = self.focusWidget()

        return not isinstance(

            focus_widget,

            (QLineEdit, QPlainTextEdit, QSpinBox, QDoubleSpinBox, QTableWidget),

        )

    def _reset_light_curve_view(self) -> None:

        had_segment_selection = bool(self._active_light_curve_segment_keys)

        if had_segment_selection:

            self._clear_light_curve_segment_selection(replot=True)

        self._light_curve_widget.reset_view()

        series = self._series_selector.currentData()

        if isinstance(series, LightCurveSeries):

            if had_segment_selection:

                self.statusBar().showMessage(f"Reset light-curve view for {series.source_name} [{series.filter_name}] and restored the full dataset.")

            else:

                self.statusBar().showMessage(f"Reset light-curve view for {series.source_name} [{series.filter_name}].")

        else:

            self.statusBar().showMessage("Reset light-curve view.")

    def _current_fit_config(self) -> LightCurveFitConfig | None:

        if not self._fit_curve_checkbox.isChecked():

            return None

        return LightCurveFitConfig(

            mode=str(self._fit_mode_selector.currentData() or "polynomial"),

            polynomial_degree=self._fit_degree_spin.value(),

            periodic_period_hours=self._fit_period_spin.value() / _MINUTES_PER_HOUR,

            periodic_harmonics=self._fit_harmonics_spin.value(),

            spline_smoothing=self._fit_smoothing_spin.value(),

        )

    def _handle_fit_period_button_clicked(self) -> None:

        if self._fit_period_worker is not None:

            self.statusBar().showMessage("Fit Period is already running for the selected series.")

            return

        fit_active = self._fit_curve_checkbox.isChecked()

        self._sync_fit_period_button_state()

        if fit_active:

            self._fit_curve_checkbox.setChecked(False)

            series = self._series_selector.currentData()

            if isinstance(series, LightCurveSeries):

                self.statusBar().showMessage(f"Removed fitted curve for {series.source_name} [{series.filter_name}].")

            else:

                self.statusBar().showMessage("Removed fitted curve.")

            return

        self._start_fit_selected_period_job()

    def _fit_selected_period(self) -> None:

        request = self._build_fit_period_request()

        if request is None:

            return

        if bool(request["use_cached_best_fit"]):

            cached_result = request["cached_result"]

            if isinstance(cached_result, FitPeriodInferenceResult):

                self._apply_fit_period_result(request, cached_result)

            else:

                self.statusBar().showMessage("Unable to fit a period for the selected series.")

            return

        fit_result = infer_fit_period_result(

            request["series"],

            fit_config=self._current_fit_config(),

            y_axis_mode=self._current_light_curve_y_axis_mode(),

            method=self._current_period_search_method(),

            period_convention=self._current_period_convention(),

        )

        if fit_result is None:

            self.statusBar().showMessage("Unable to fit a period for the selected series.")

            return

        self._apply_fit_period_result(request, fit_result)

    def _build_fit_period_request(self) -> dict[str, object] | None:

        selected_series = self._series_selector.currentData()

        if selected_series is None:

            self.statusBar().showMessage("Select a light-curve series before fitting a period.")

            return None

        series = self._active_series_for_plotting(selected_series)

        if series is None or len(series.points) < 2:

            self.statusBar().showMessage("Select at least two points in the active light-curve segment before fitting a period.")

            return None

        series_key = (selected_series.source_id, selected_series.filter_name)

        cached_result = self._calculated_period_results.get(series_key)

        snr_derived_series = self._snr_series_has_derived_measurements(selected_series)

        has_segment_override = self._series_has_active_segment(selected_series)

        restored_origin = self._restored_cached_period_origin(series_key)

        has_remembered_override = (

            series_key in self._comparison_fit_cached_series_keys

            or series_key in self._manual_period_override_series_keys

        )

        use_cached_best_fit = not snr_derived_series and cached_result is not None and not has_segment_override and (

            has_remembered_override or restored_origin == "legacy_cached"

        )

        current_period_summary = self._format_period_summary(period_minutes=float(self._fit_period_spin.value()))

        self._append_work_log(

            f"Fit Period started for {series.source_name} [{series.filter_name}]. Current displayed value: {current_period_summary}."

        )

        report = self._current_processing_report

        return {

            "report_token": 0 if report is None else id(report),

            "selected_series": selected_series,

            "series": series,

            "series_key": series_key,

            "cached_result": cached_result,

            "snr_derived_series": snr_derived_series,

            "has_segment_override": has_segment_override,

            "restored_origin": restored_origin,

            "has_remembered_override": has_remembered_override,

            "use_cached_best_fit": use_cached_best_fit,

        }

    def _set_fit_period_button_busy_state(self, busy: bool) -> None:

        self._fit_guess_period_button.setText("Fitting..." if busy else "Fit Period")

        if busy:

            self._fit_guess_period_button.setEnabled(False)

            return

        self._fit_guess_period_button.setEnabled(self._series_selector.count() > 0)

    def _start_fit_selected_period_job(self) -> None:

        if self._period_job_active():

            self.statusBar().showMessage("Another period job is already running.")

            return

        request = self._build_fit_period_request()

        if request is None:

            return

        if bool(request["use_cached_best_fit"]):

            cached_result = request["cached_result"]

            if isinstance(cached_result, FitPeriodInferenceResult):

                self._apply_fit_period_result(request, cached_result)

            else:

                self.statusBar().showMessage("Unable to fit a period for the selected series.")

            return

        fit_config = self._current_fit_config()

        y_axis_mode = self._current_light_curve_y_axis_mode()

        period_method = self._current_period_search_method()

        period_convention = self._current_period_convention()

        series_key = request["series_key"]

        series = request["series"]

        self._pending_fit_period_request = request

        self._fit_period_worker = CalculatePeriodWorker(

            report_token=int(request["report_token"]),

            series_items=[(series_key, series)],

            fit_config=fit_config,

            y_axis_mode=y_axis_mode,

            period_method=period_method,

            period_convention=period_convention,

            max_parallel_workers=1,

            include_bls_duration=False,

            parent=self,

        )

        self._fit_period_worker.progress_updated.connect(self._handle_fit_period_worker_progress)

        self._fit_period_worker.calculation_completed.connect(self._handle_fit_period_worker_completed)

        self._fit_period_worker.calculation_failed.connect(self._handle_fit_period_worker_failed)

        self._set_fit_period_button_busy_state(True)

        self.statusBar().showMessage("Fitting period for the selected series in the background.")

        self._fit_period_worker.start()

    def _handle_fit_period_worker_progress(self, message: str) -> None:

        self.statusBar().showMessage(message)

    def _handle_fit_period_worker_completed(self, result: object) -> None:

        self._fit_period_worker = None

        self._set_fit_period_button_busy_state(False)

        request = self._pending_fit_period_request

        self._pending_fit_period_request = None

        if request is None:

            return

        report = self._current_processing_report

        if report is None or not hasattr(result, "report_token") or result.report_token != int(request["report_token"]):

            self._append_work_log("Fit Period completed for a stale report; ignored the result set.")

            return

        series_key = request["series_key"]

        fit_result = result.results.get(series_key) if hasattr(result, "results") else None

        if not isinstance(fit_result, FitPeriodInferenceResult):

            self.statusBar().showMessage("Unable to fit a period for the selected series.")

            return

        self._apply_fit_period_result(request, fit_result)

    def _handle_fit_period_worker_failed(self, message: str) -> None:

        self._fit_period_worker = None

        self._pending_fit_period_request = None

        self._set_fit_period_button_busy_state(False)

        self.statusBar().showMessage("Fit Period failed.")

        self._append_work_log(f"Fit Period failed: {message}")

    def _apply_fit_period_result(self, request: dict[str, object], fit_result: FitPeriodInferenceResult) -> None:

        selected_series = request["selected_series"]

        series = request["series"]

        series_key = request["series_key"]

        cached_result = request["cached_result"]

        has_segment_override = bool(request["has_segment_override"])

        restored_origin = str(request["restored_origin"])

        has_remembered_override = bool(request["has_remembered_override"])

        use_cached_best_fit = bool(request["use_cached_best_fit"])

        override_saved = False

        override_previous_match: float | None = None

        override_new_match: float | None = None

        if has_segment_override:

            override_saved, override_previous_match, override_new_match = self._maybe_store_manual_segment_period_override(

                selected_series,

                fit_result,

            )

        stored_inferred_period = False

        if not use_cached_best_fit and not has_segment_override:

            self._store_fit_period_result(selected_series, fit_result)

            stored_inferred_period = True

        if not self._fit_curve_checkbox.isChecked():

            self._fit_curve_checkbox.blockSignals(True)

            self._fit_curve_checkbox.setChecked(True)

            self._fit_curve_checkbox.blockSignals(False)

            self._sync_fit_period_button_state()

        self._fit_period_spin.blockSignals(True)

        self._fit_period_spin.setValue(fit_result.period_hours * _MINUTES_PER_HOUR)

        self._fit_period_spin.blockSignals(False)

        self._update_fit_period_summary_label()

        if fit_result.periodic_harmonics is not None:

            self._fit_harmonics_spin.blockSignals(True)

            self._fit_harmonics_spin.setValue(fit_result.periodic_harmonics)

            self._fit_harmonics_spin.blockSignals(False)

            harmonic_summary = f"; harmonics = {fit_result.periodic_harmonics}"

        else:

            harmonic_summary = ""

        self._update_fit_control_visibility()

        self._plot_selected_series()

        if use_cached_best_fit:

            if series_key in self._manual_period_override_series_keys:

                cached_message = f"Recalled cached manual period override for {series.source_name} [{series.filter_name}] = {fit_result.period_hours * _MINUTES_PER_HOUR:.2f} min ({fit_result.period_hours:.2f} hr, {fit_result.period_hours / 24.0:.4f} d){harmonic_summary}"

            elif restored_origin == "legacy_cached":

                cached_message = f"Recalled cached saved period for {series.source_name} [{series.filter_name}] = {fit_result.period_hours * _MINUTES_PER_HOUR:.2f} min ({fit_result.period_hours:.2f} hr, {fit_result.period_hours / 24.0:.4f} d){harmonic_summary}"

            else:

                cached_message = f"Recalled cached Find Better Fit period for {series.source_name} [{series.filter_name}] = {fit_result.period_hours * _MINUTES_PER_HOUR:.2f} min ({fit_result.period_hours:.2f} hr, {fit_result.period_hours / 24.0:.4f} d){harmonic_summary}"

            self.statusBar().showMessage(cached_message)

            self._append_work_log(cached_message)

        elif has_segment_override and override_saved:

            previous_text = "-" if override_previous_match is None else f"{override_previous_match:.1f}"

            new_text = "-" if override_new_match is None else f"{override_new_match:.1f}"

            self.statusBar().showMessage(

                f"Saved manual period override for {series.source_name} [{series.filter_name}] = {fit_result.period_hours * _MINUTES_PER_HOUR:.2f} min ({fit_result.period_hours:.2f} hr, {fit_result.period_hours / 24.0:.4f} d){harmonic_summary}; match index improved from {previous_text} to {new_text}."

            )

        elif has_segment_override and has_remembered_override:

            current_match = self._current_period_match_for_series(selected_series, cached_result)

            current_text = "-" if current_match is None else f"{current_match:.1f}"

            candidate_text = "-" if override_new_match is None else f"{override_new_match:.1f}"

            self.statusBar().showMessage(

                f"Fit-inferred {self._current_period_search_method_display_name()} period for the selected {len(series.points)}-point segment of {series.source_name} [{series.filter_name}] = {fit_result.period_hours * _MINUTES_PER_HOUR:.2f} min ({fit_result.period_hours:.2f} hr, {fit_result.period_hours / 24.0:.4f} d){harmonic_summary}; retained cached score {current_text} because the segment score {candidate_text} was not better."

            )

        else:

            self.statusBar().showMessage(

                f"Fit-inferred {self._current_period_search_method_display_name()} period for {series.source_name} [{series.filter_name}] = {fit_result.period_hours * _MINUTES_PER_HOUR:.2f} min ({fit_result.period_hours:.2f} hr, {fit_result.period_hours / 24.0:.4f} d){harmonic_summary}"

            )

        result_period_summary = self._format_period_summary(period_hours=fit_result.period_hours)

        self._append_work_log(

            f"Fit Period finished for {series.source_name} [{series.filter_name}]. Updated value: {result_period_summary}."

        )

    def _series_has_active_segment(self, series: LightCurveSeries) -> bool:

        return bool(

            self._active_light_curve_segment_series_key == self._series_identity(series)

            and self._active_light_curve_segment_keys

        )

    def _series_literature_period_result(self, series: LightCurveSeries) -> LiteraturePeriodResult | None:

        report = self._current_processing_report

        if report is None:

            return None

        measurement_catalog = next(

            (

                measurement.catalog

                for measurement in report.measurements

                if measurement.source_id == series.source_id and (measurement.filter_name or "-") == series.filter_name

            ),

            None,

        )

        if measurement_catalog is None:

            return None

        return self._literature_period_results.get((measurement_catalog, series.source_id))

    def _current_period_match_for_series(

        self,

        series: LightCurveSeries,

        period_result: FitPeriodInferenceResult | None,

    ) -> float | None:

        return self._period_match_index_value(self._series_literature_period_result(series), period_result)

    def _store_fit_period_result(self, series: LightCurveSeries, fit_result: FitPeriodInferenceResult) -> None:

        series_key = self._series_identity(series)

        self._calculated_period_results[series_key] = fit_result

        self._comparison_fit_cached_series_keys.discard(series_key)

        self._manual_period_override_series_keys.discard(series_key)

        self._refresh_calculated_period_views()

        self._persist_period_result_cache()

    def _maybe_store_manual_segment_period_override(

        self,

        series: LightCurveSeries,

        fit_result: FitPeriodInferenceResult,

    ) -> tuple[bool, float | None, float | None]:

        series_key = self._series_identity(series)

        cached_result = self._calculated_period_results.get(series_key)

        if cached_result is None:

            return False, None, None

        if (

            series_key not in self._comparison_fit_cached_series_keys

            and series_key not in self._manual_period_override_series_keys

        ):

            return False, None, None

        previous_match = self._current_period_match_for_series(series, cached_result)

        candidate_match = self._current_period_match_for_series(series, fit_result)

        if candidate_match is None:

            return False, previous_match, candidate_match

        if previous_match is not None and candidate_match <= previous_match:

            return False, previous_match, candidate_match

        self._calculated_period_results[series_key] = fit_result

        self._comparison_fit_cached_series_keys.discard(series_key)

        self._manual_period_override_series_keys.add(series_key)

        self._refresh_calculated_period_views()

        self._persist_period_result_cache()

        self._append_work_log(

            f"Saved manual period override for {series.source_name} [{series.filter_name}] from the active light-curve segment: period={fit_result.period_hours / 24.0:.4f} d, match={candidate_match:.2f}."

        )

        return True, previous_match, candidate_match

    def _toggle_fold_selected_series(self) -> None:

        if self._light_curve_fold_active:

            self._unfold_selected_series()

            return



        selected_series = self._series_selector.currentData()

        if not isinstance(selected_series, LightCurveSeries):

            self.statusBar().showMessage("Select a light-curve series before using Fold.")

            return



        series = self._active_series_for_plotting(selected_series)

        if series is None or len(series.points) < 2:

            self.statusBar().showMessage("Select at least two points in the active light-curve segment before using Fold.")

            return



        fold_period = self._best_fold_period_hours(selected_series)

        if fold_period is None:

            self.statusBar().showMessage(

                "No period is available for the selected series. Pull literature period data or calculate a period first."

            )

            return



        period_hours, period_source = fold_period

        self._fit_period_spin.blockSignals(True)

        self._fit_period_spin.setValue(period_hours * _MINUTES_PER_HOUR)

        self._fit_period_spin.blockSignals(False)



        current_x_axis_mode = self._current_light_curve_x_axis_mode()

        if current_x_axis_mode != "phase":

            self._light_curve_unfold_x_axis_mode = current_x_axis_mode

        phase_index = self._light_curve_x_axis_selector.findData("phase")

        self._light_curve_x_axis_selector.blockSignals(True)

        if phase_index >= 0:

            self._light_curve_x_axis_selector.setCurrentIndex(phase_index)

        self._light_curve_x_axis_selector.blockSignals(False)



        self._set_fold_active(True)

        self._update_fit_control_visibility()

        self._update_fit_period_summary_label()

        self._plot_selected_series()

        self.statusBar().showMessage(

            f"Fold enabled for {series.source_name} [{series.filter_name}] using {period_source} period {period_hours / 24.0:.4f} d."

        )

    def _unfold_selected_series(self) -> None:

        restore_mode = self._light_curve_unfold_x_axis_mode if self._light_curve_unfold_x_axis_mode != "phase" else "jd"

        restore_index = self._light_curve_x_axis_selector.findData(restore_mode)

        self._light_curve_x_axis_selector.blockSignals(True)

        if restore_index >= 0:

            self._light_curve_x_axis_selector.setCurrentIndex(restore_index)

        self._light_curve_x_axis_selector.blockSignals(False)

        self._set_fold_active(False)

        self._update_fit_control_visibility()

        self._update_fit_period_summary_label()

        self._plot_selected_series()

        self.statusBar().showMessage("Fold disabled; restored the original light-curve view.")

    def _set_fold_active(self, active: bool) -> None:

        self._light_curve_fold_active = active

        self._fold_plot_button.setText("Unfold" if active else "Fold")

        self._sync_light_curve_toolbar_button_widths()

    def _sync_fold_button_state(self) -> None:

        if self._current_light_curve_x_axis_mode() != "phase" and self._light_curve_fold_active:

            self._set_fold_active(False)

    def _best_fold_period_hours(self, series: LightCurveSeries) -> tuple[float, str] | None:

        report = self._current_processing_report

        if report is None:

            return None



        measurement_catalog = next(

            (

                measurement.catalog

                for measurement in report.measurements

                if measurement.source_id == series.source_id and (measurement.filter_name or "-") == series.filter_name

            ),

            None,

        )

        if measurement_catalog is not None:

            literature_result = self._literature_period_results.get((measurement_catalog, series.source_id))

            if literature_result is not None and literature_result.period_days is not None and np.isfinite(literature_result.period_days) and literature_result.period_days > 0:

                return literature_result.period_days * 24.0, "literature"



        calculated_result = self._calculated_period_results.get((series.source_id, series.filter_name))

        if calculated_result is not None and np.isfinite(calculated_result.period_hours) and calculated_result.period_hours > 0:

            return calculated_result.period_hours, "calculated"



        return None

    def _current_light_curve_y_axis_mode(self) -> str:

        return str(self._light_curve_y_axis_selector.currentData() or "calibrated_magnitude")

    def _format_period_summary(

        self,

        *,

        period_hours: float | None = None,

        period_minutes: float | None = None,

    ) -> str:

        if period_hours is None:

            minutes_value = 0.0 if period_minutes is None else float(period_minutes)

            hours_value = minutes_value / _MINUTES_PER_HOUR

        else:

            hours_value = float(period_hours)

            minutes_value = hours_value * _MINUTES_PER_HOUR

        days_value = hours_value / 24.0

        return f"{minutes_value:.2f} min ({hours_value:.2f} hr, {days_value:.4f} d)"

    def _sync_light_curve_toolbar_button_widths(self) -> None:

        if not hasattr(self, "_fold_plot_button") or not hasattr(self, "_light_curve_filter_button"):

            return

        target_width = max(self._fold_plot_button.sizeHint().width(), self._light_curve_filter_button.sizeHint().width())

        self._fold_plot_button.setFixedWidth(target_width)

        self._light_curve_filter_button.setFixedWidth(target_width)

    def _update_fit_period_summary_label(self) -> None:

        if not hasattr(self, "_light_curve_widget"):

            return

        self._light_curve_widget.set_fit_period_badge_text(self._current_fit_period_badge_text())

    def _current_fit_period_badge_text(self) -> str | None:

        if not self._fit_curve_checkbox.isChecked():

            return None

        period_minutes = float(self._fit_period_spin.value())

        if period_minutes <= 0:

            return None

        return f"Fit Period  {period_minutes:.2f} min"

    def _current_light_curve_x_axis_mode(self) -> str:

        return str(self._light_curve_x_axis_selector.currentData() or "datetime")

    def _light_curve_export_default_path(self, series: LightCurveSeries, *, scientific_style: bool, export_format: str) -> Path:

        root_path = Path(self._root_path_input.text()).expanduser()

        base_dir = root_path / "Exports" / self._current_processing_report.object_name if self._current_processing_report is not None else root_path

        safe_name = re.sub(r"[^A-Za-z0-9._-]+", "_", f"{series.source_name}_{series.filter_name or 'unknown'}").strip("_") or "light_curve"

        style_suffix = "scientific" if scientific_style else "theme"

        normalized_format = str(export_format).strip().lower() or "png"

        return base_dir / f"{safe_name}_{self._current_light_curve_x_axis_mode()}_{self._current_light_curve_y_axis_mode()}_{style_suffix}.{normalized_format}"

    def _light_curve_export_filter_for_format(self, format_name: str) -> str:

        normalized = str(format_name).strip().lower()

        if normalized == "gif":

            return "GIF Files (*.gif)"

        if normalized in {"still", "styled", "png", "pdf", "svg", "jpg", "jpeg"}:

            return "PNG Files (*.png);;PDF Files (*.pdf);;SVG Files (*.svg);;JPG Files (*.jpg *.jpeg);;All Files (*)"

        if normalized == "pdf":

            return "PDF Files (*.pdf)"

        if normalized == "svg":

            return "SVG Files (*.svg)"

        return "PNG Files (*.png)"

    def _resolved_light_curve_export_path(self, selected_path: str, selected_filter: str) -> Path:

        output_path = Path(selected_path)

        if output_path.suffix:

            return output_path

        normalized_filter = selected_filter.lower()

        if "gif" in normalized_filter:

            return output_path.with_suffix(".gif")

        if "pdf" in normalized_filter:

            return output_path.with_suffix(".pdf")

        if "svg" in normalized_filter:

            return output_path.with_suffix(".svg")

        if "jpg" in normalized_filter or "jpeg" in normalized_filter:

            return output_path.with_suffix(".jpg")

        return output_path.with_suffix(".png")

    def _light_curve_export_figure_size_inches(self) -> tuple[float, float]:

        aspect_ratio = self._light_curve_widget.current_plot_aspect_ratio()

        width_inches = 12.0

        return width_inches, max(3.0, width_inches / max(0.1, aspect_ratio))

    def _scientific_pdf_figure_size_inches(self) -> tuple[float, float]:

        settings = self._active_settings()

        paper_size = "Letter" if settings is None else str(settings.scientific_light_curve_pdf_paper_size).strip() or "Letter"

        page_sizes = {

            "Letter": (11.0, 8.5),

            "A4": (11.69, 8.27),

            "Legal": (14.0, 8.5),

        }

        width_inches, height_inches = page_sizes.get(paper_size, page_sizes["Letter"])

        if self._light_curve_widget.current_plot_aspect_ratio() < 1.0:

            return min(width_inches, height_inches), max(width_inches, height_inches)

        return max(width_inches, height_inches), min(width_inches, height_inches)

    def _scientific_pdf_dpi(self) -> int:

        settings = self._active_settings()

        if settings is None:

            return 300

        return max(72, min(1200, int(settings.scientific_light_curve_pdf_dpi)))

    def _selected_active_light_curve_for_export(self) -> LightCurveSeries | None:

        if self._current_processing_report is None:

            QMessageBox.information(self, "Nothing to export", "Process an object before exporting a light curve.")

            return None

        selected_series = self._series_selector.currentData()

        if not isinstance(selected_series, LightCurveSeries):

            QMessageBox.information(self, "No light curve selected", "Select a light-curve series before exporting.")

            return None

        active_series = self._active_series_for_plotting(selected_series)

        if active_series is None:

            QMessageBox.information(self, "No light curve selected", "Select a light-curve series before exporting.")

            return None

        return active_series

    def _export_active_light_curve(self) -> None:

        self._export_active_light_curve_theme_based("png")

    def _export_active_light_curve_theme_based(self, export_format: str = "png") -> None:

        self._export_active_light_curve_with_style(scientific_style=False, export_format=export_format)

    def _export_active_light_curve_scientific(self, export_format: str = "png") -> None:

        self._export_active_light_curve_with_style(scientific_style=True, export_format=export_format)

    def _export_active_light_curve_animated_gif(self) -> None:

        active_series = self._selected_active_light_curve_for_export()

        if active_series is None:

            return

        default_path = self._light_curve_export_default_path(
            active_series,
            scientific_style=False,
            export_format="gif",
        )

        default_path.parent.mkdir(parents=True, exist_ok=True)

        selected, selected_filter = QFileDialog.getSaveFileName(
            self,
            "Export animated light curve",
            str(default_path),
            "GIF Files (*.gif);;All Files (*)",
            self._light_curve_export_filter_for_format("gif"),
        )

        if not selected:

            return

        output_path = self._resolved_light_curve_export_path(selected, selected_filter)
        view_ranges = self._light_curve_widget.current_view_ranges()
        x_limits = None if view_ranges is None else view_ranges[0]
        y_limits = None if view_ranges is None else view_ranges[1]
        progress_dialog = QProgressDialog("Preparing animated light curve...", "Cancel", 0, 1, self)
        progress_dialog.setWindowTitle("Export Animated GIF")
        progress_dialog.setMinimumDuration(0)
        progress_dialog.setAutoClose(False)
        progress_dialog.setAutoReset(False)
        progress_dialog.setWindowModality(Qt.WindowModality.ApplicationModal)
        progress_dialog.setValue(0)
        progress_dialog.canceled.connect(self._cancel_light_curve_gif_export)
        progress_dialog.show()

        self._light_curve_gif_progress_dialog = progress_dialog
        self._append_work_log(f"Started animated light-curve export for {active_series.source_name} [{active_series.filter_name}] to {output_path}.")
        self.statusBar().showMessage("Exporting animated light curve...")

        self._light_curve_gif_cancel_requested = False

        try:

            frame_payloads = self._light_curve_animation_frame_payloads(
                active_series,
                frame_duration_ms=_LIGHT_CURVE_GIF_FRAME_DURATION_MS,
                minimum_duration_seconds=_LIGHT_CURVE_GIF_MINIMUM_DURATION_SECONDS,
            )

            progress_total = len(frame_payloads) + 1

            progress_dialog.setMaximum(max(1, progress_total))

            frames = self._render_light_curve_animation_payloads_current_view(
                frame_payloads,
                x_limits=x_limits,
                y_limits=y_limits,
                badge_text=self._current_fit_period_badge_text(),
                progress_dialog=progress_dialog,
            )

            if frames is None:

                self._handle_light_curve_gif_export_cancelled("Animated light-curve export canceled.")

                return

            progress_dialog.setValue(len(frame_payloads))

            progress_dialog.setLabelText("Encoding animated GIF...")

            self.statusBar().showMessage("Encoding animated GIF...")

            QApplication.processEvents()

            export_qimages_to_gif(
                frames,
                output_path,
                frame_duration_ms=_LIGHT_CURVE_GIF_FRAME_DURATION_MS,
                loop_count=0,
            )

            progress_dialog.setValue(progress_total)

            self._handle_light_curve_gif_export_completed(output_path)

        except Exception as exc:

            self._handle_light_curve_gif_export_failed(str(exc))

    def _handle_light_curve_gif_export_progress(self, completed: int, total: int, message: str) -> None:

        progress_dialog = self._light_curve_gif_progress_dialog

        if progress_dialog is not None and qt_object_is_valid(progress_dialog):

            progress_dialog.setMaximum(max(1, int(total)))

            progress_dialog.setValue(min(max(0, int(completed)), max(1, int(total))))

            progress_dialog.setLabelText(message)

        self.statusBar().showMessage(message)

    def _handle_light_curve_gif_export_completed(self, result: object) -> None:

        self._light_curve_gif_export_worker = None

        self._close_light_curve_gif_progress_dialog()

        output_path = result if isinstance(result, Path) else None

        if output_path is None:

            self._handle_light_curve_gif_export_failed("Animated light-curve export returned an unexpected result.")

            return

        message = f"Exported animated light curve to {output_path}."

        self.statusBar().showMessage(message, 5000)

        self._append_work_log(message)

    def _handle_light_curve_gif_export_failed(self, message: str) -> None:

        self._light_curve_gif_export_worker = None

        self._close_light_curve_gif_progress_dialog()

        self.statusBar().showMessage("Animated light-curve export failed.", 5000)

        self._append_work_log(f"Animated light-curve export failed: {message}")

        QMessageBox.warning(self, "Animated GIF export failed", message)

    def _handle_light_curve_gif_export_cancelled(self, message: str) -> None:

        self._light_curve_gif_export_worker = None

        self._close_light_curve_gif_progress_dialog()

        cancellation_message = message or "Animated light-curve export canceled."

        self.statusBar().showMessage(cancellation_message, 5000)

        self._append_work_log(cancellation_message)

    def _cancel_light_curve_gif_export(self) -> None:

        worker = self._light_curve_gif_export_worker

        progress_dialog = self._light_curve_gif_progress_dialog

        self._light_curve_gif_cancel_requested = True

        if worker is None:

            if progress_dialog is not None and qt_object_is_valid(progress_dialog):

                progress_dialog.setLabelText("Canceling animated light-curve export...")

            self.statusBar().showMessage("Canceling animated light-curve export...")

            return

        worker.request_cancel()

        if progress_dialog is not None and qt_object_is_valid(progress_dialog):

            progress_dialog.setLabelText("Canceling animated light-curve export...")

        self.statusBar().showMessage("Canceling animated light-curve export...")

    def _close_light_curve_gif_progress_dialog(self) -> None:

        progress_dialog = self._light_curve_gif_progress_dialog

        self._light_curve_gif_progress_dialog = None

        if progress_dialog is not None and qt_object_is_valid(progress_dialog):

            progress_dialog.close()

            progress_dialog.deleteLater()

    def _light_curve_animation_frame_payloads(

        self,

        series: LightCurveSeries,

        *,

        frame_duration_ms: int,

        minimum_duration_seconds: float,

    ) -> list[LightCurvePlotPayload]:

        payload = build_light_curve_plot_payload(
            series,
            "No light-curve points are available for animation.",
            fit_config=self._current_fit_config(),
            y_axis_mode=self._current_light_curve_y_axis_mode(),
            x_axis_mode=self._current_light_curve_x_axis_mode(),
            phase_period_hours=self._fit_period_spin.value() / _MINUTES_PER_HOUR,
            phase_anchor_mode=self._current_phase_anchor_mode(),
        )

        baseline_target_frames = 125
        point_count = len(payload.points)
        fit_point_count = 0 if payload.fit_x_values is None else int(len(payload.fit_x_values))
        fit_stage_frames = 0 if fit_point_count <= 1 else _LIGHT_CURVE_GIF_FIT_STAGE_TARGET_FRAMES
        point_stage_frames = max(
            point_count,
            max(0, baseline_target_frames - _LIGHT_CURVE_GIF_INITIAL_HOLD_FRAMES - _LIGHT_CURVE_GIF_FINAL_HOLD_FRAMES - fit_stage_frames),
        )
        minimum_duration_ms = max(0.0, float(minimum_duration_seconds)) * 1000.0
        minimum_frame_duration_ms = max(20, int(frame_duration_ms))
        required_total_frames = max(1, int(math.ceil(minimum_duration_ms / minimum_frame_duration_ms)))
        total_frames = _LIGHT_CURVE_GIF_INITIAL_HOLD_FRAMES + point_stage_frames + fit_stage_frames + _LIGHT_CURVE_GIF_FINAL_HOLD_FRAMES
        final_hold_frames = _LIGHT_CURVE_GIF_FINAL_HOLD_FRAMES + max(0, required_total_frames - total_frames)

        frame_payloads: list[LightCurvePlotPayload] = []
        empty_payload = replace(payload, points=(), fit_x_values=None, fit_y_values=None)
        frame_payloads.extend([empty_payload] * _LIGHT_CURVE_GIF_INITIAL_HOLD_FRAMES)

        if point_stage_frames > 0:
            for frame_index in range(point_stage_frames):
                visible_point_count = point_count if point_count <= 0 else min(point_count, max(1, int(math.ceil(((frame_index + 1) * point_count) / point_stage_frames))))
                frame_payloads.append(
                    replace(
                        payload,
                        points=tuple(payload.points[:visible_point_count]),
                        fit_x_values=None,
                        fit_y_values=None,
                        empty_message=None,
                    )
                )

        if fit_stage_frames > 0 and payload.fit_x_values is not None and payload.fit_y_values is not None:
            for frame_index in range(fit_stage_frames):
                visible_fit_count = min(fit_point_count, max(2, int(math.ceil(((frame_index + 1) * fit_point_count) / fit_stage_frames))))
                frame_payloads.append(
                    replace(
                        payload,
                        fit_x_values=np.asarray(payload.fit_x_values[:visible_fit_count], dtype=float),
                        fit_y_values=np.asarray(payload.fit_y_values[:visible_fit_count], dtype=float),
                        empty_message=None,
                    )
                )

        final_payload = replace(payload, empty_message=None)
        frame_payloads.extend([final_payload] * max(1, final_hold_frames))
        return frame_payloads

    def _render_light_curve_animation_payloads_current_view(

        self,

        frame_payloads: Sequence[LightCurvePlotPayload],

        *,

        x_limits: tuple[float, float] | None,

        y_limits: tuple[float, float] | None,

        badge_text: str | None,

        progress_dialog: QProgressDialog,

    ) -> list[QImage] | None:

        export_widget = LightCurvePlotWidget(self)
        frames: list[QImage] = []

        try:
            export_widget.resize(self._light_curve_widget.size())
            export_widget.set_theme(self._current_theme_name(), self._current_custom_theme_colors())
            export_widget.set_fit_period_badge_text(badge_text)

            for index, payload in enumerate(frame_payloads, start=1):
                if self._light_curve_gif_cancel_requested:
                    return None

                export_widget.show_payload(
                    payload,
                    phase_opacity_floor=float(self._phase_opacity_floor_spin.value()),
                    recent_period_error_bars_only=self._phase_recent_error_bars_only_checkbox.isChecked(),
                )
                export_widget.set_view_ranges(x_limits=x_limits, y_limits=y_limits)
                QApplication.processEvents()
                frames.append(export_widget.current_view_image(scale_factor=1.0))

                progress_dialog.setValue(index)
                progress_dialog.setLabelText(f"Rendering animation frame {index}/{len(frame_payloads)}...")
                self.statusBar().showMessage(f"Rendering animation frame {index}/{len(frame_payloads)}...")
                QApplication.processEvents()

                if self._light_curve_gif_cancel_requested:
                    return None

            return frames
        finally:
            export_widget.close()

    def _export_active_light_curve_with_style(self, *, scientific_style: bool, export_format: str) -> None:

        active_series = self._selected_active_light_curve_for_export()

        if active_series is None:

            return


        default_path = self._light_curve_export_default_path(
            active_series,
            scientific_style=scientific_style,
            export_format=export_format,
        )

        default_path.parent.mkdir(parents=True, exist_ok=True)

        selected, _selected_filter = QFileDialog.getSaveFileName(

            self,

            "Export light curve",

            str(default_path),

            self._light_curve_export_filter_for_format("still"),

            self._light_curve_export_filter_for_format(export_format),

        )

        if not selected:

            return



        output_path = self._resolved_light_curve_export_path(selected, _selected_filter)

        if scientific_style:

            view_ranges = self._light_curve_widget.current_view_ranges()

            x_limits = None if view_ranges is None else view_ranges[0]

            y_limits = None if view_ranges is None else view_ranges[1]

            export_light_curve_plot(

                active_series,

                output_path,

                fit_config=self._current_fit_config(),

                y_axis_mode=self._current_light_curve_y_axis_mode(),

                x_axis_mode=self._current_light_curve_x_axis_mode(),

                phase_period_hours=self._fit_period_spin.value() / _MINUTES_PER_HOUR,

                phase_anchor_mode=self._current_phase_anchor_mode(),

                export_style="scientific",

                x_limits=x_limits,

                y_limits=y_limits,

                figure_size_inches=(self._scientific_pdf_figure_size_inches() if output_path.suffix.lower() == ".pdf" else self._light_curve_export_figure_size_inches()),

                dpi=(self._scientific_pdf_dpi() if output_path.suffix.lower() == ".pdf" else None),

            )

            self.statusBar().showMessage(f"Exported scientific light curve for {active_series.source_name} [{active_series.filter_name}] to {output_path}.")

            self._append_work_log(f"Exported scientific light curve for {active_series.source_name} [{active_series.filter_name}] to {output_path}.")

            return



        self._light_curve_widget.export_current_view(str(output_path))

        self.statusBar().showMessage(f"Exported theme-based light curve for {active_series.source_name} [{active_series.filter_name}] to {output_path}.")

        self._append_work_log(f"Exported theme-based light curve for {active_series.source_name} [{active_series.filter_name}] to {output_path}.")

    def _current_phase_anchor_mode(self) -> str:

        return str(self._phase_anchor_selector.currentData() or "primary_minimum")

    def _current_period_search_method(self) -> str:

        return str(self._period_search_method_selector.currentData() or "harmonic_fit")

    def _current_period_convention(self) -> str:

        return str(self._period_convention_selector.currentData() or "standard")

    def _current_period_search_method_display_name(self) -> str:

        return self._period_search_method_selector.currentText().strip() or "Harmonic Fit"

    def _handle_source_selection_changed(self) -> None:

        if self._current_preview is not None and self._current_processing_report is None:

            selected_source_keys = self._selected_source_keys()

            object_name = self._current_preview.object_name

            if self._settings is None:

                root_path = Path(self._root_path_input.text()).expanduser()

                if root_path.exists():

                    self._settings = AppSettings.from_root(root_path)

            if self._settings is not None:

                selected_sources = self._settings.selected_catalog_source_ids or {}

                if selected_source_keys:

                    selected_sources[object_name] = selected_source_keys

                else:

                    selected_sources.pop(object_name, None)

                self._settings.selected_catalog_source_ids = selected_sources

                self._save_settings_snapshot()

            self._render_selected_details()

            self._sync_differential_training_controls(None)

            self._refresh_source_comparison_summary_table()

            self._update_target_browser_buttons()

            self._update_source_period_button_state()

            self.statusBar().showMessage(

                f"Selected {len(selected_source_keys)} source(s) for {object_name}. Click Process Selected to continue."

            )

            return

        self._image_context_source = "source"
        source_target = self._selected_source_target()

        if source_target is not None:

            self._sync_series_selection_for_source_target(*source_target)

        self._update_source_table_comparison_highlights()

        self._refresh_source_comparison_summary_table()

        self._update_source_period_button_state()

        self._render_selected_details()

        self._sync_differential_training_controls()

        self._update_target_browser_buttons()

        self._render_image_panel()

        if self._image_auto_center_object_enabled:

            self._center_image_view_on_selected_source(show_status_message=False)

        selected_count = len(self._selected_source_targets())

        if selected_count > 0:

            self.statusBar().showMessage(f"Selected {selected_count} source(s); light-curve target synced without filtering the full target list.")

    def _handle_measurement_selection_changed(self) -> None:

        self._image_context_source = "measurement"

        measurement = self._selected_measurement_row()

        if measurement is not None:

            self._sync_series_selection_for_measurement(measurement)

        self._render_selected_details()

        self._update_target_browser_buttons()

        self._render_image_panel()

    def _handle_results_tab_changed(self, _index: int) -> None:

        current_tab = self._results_tabs.currentWidget()

        self._sync_results_filter_button_state()

        if current_tab is self._measurement_table:

            self._image_context_source = "measurement"

            if self._measurement_table_refresh_pending:

                self._handle_measure_button_clicked()

        elif current_tab is self._processing_file_table:

            self._image_context_source = "processing-file"

        elif current_tab is self._source_table:

            self._image_context_source = "source"

            if self._source_name_filter.text().strip():

                self._refresh_source_filters()

                return

        self._render_selected_details()

        self._update_target_browser_buttons()

        self._render_image_panel()

    def _handle_scan_file_selection_changed(self) -> None:

        self._image_context_source = "scan"

        self._update_target_browser_buttons()

        self._render_image_panel()

    def _handle_processing_file_selection_changed(self) -> None:

        self._image_context_source = "processing-file"

        self._render_selected_details()

        self._update_target_browser_buttons()

        self._render_image_panel()

    def _populate_processing_file_table(self, report: ProcessingReport) -> None:

        grouped_measurements: dict[str, list[object]] = {}

        visible_source_keys: set[tuple[str, str]] | None = None

        if self._results_filtering_active():

            visible_source_keys = {

                (entry.catalog, entry.source_id)

                for entry in self._filtered_source_entries(report)

            }

        for measurement in report.measurements:

            if visible_source_keys is not None and (measurement.catalog, measurement.source_id) not in visible_source_keys:

                continue

            grouped_measurements.setdefault(measurement.file_path.name, []).append(measurement)



        file_names = sorted(set(report.file_notes) | set(grouped_measurements))

        self._processing_file_table.setRowCount(len(file_names))

        for row_index, file_name in enumerate(file_names):

            rows = grouped_measurements.get(file_name, [])

            filter_name = rows[0].filter_name if rows else "-"

            variable_count = sum(1 for row in rows if row.is_variable)

            flagged_count = sum(1 for row in rows if row.flags)

            notes = " | ".join(report.file_notes.get(file_name, [])) or "-"

            values = [

                file_name,

                filter_name or "-",

                str(len(rows)),

                str(variable_count),

                str(flagged_count),

                notes,

            ]

            for column_index, value in enumerate(values):

                self._processing_file_table.setItem(row_index, column_index, QTableWidgetItem(value))

        self._sync_results_filter_button_state()

    def _populate_source_table(self, report: ProcessingReport) -> None:

        selected_targets = set(self._selected_source_targets())

        sorting_enabled = self._source_table.isSortingEnabled()

        self._source_table.setSortingEnabled(False)

        self._source_table.blockSignals(True)

        self._differential_training_predictions.clear()

        ordered_entries = self._filtered_source_entries(report)

        self._source_table.setRowCount(len(ordered_entries))

        selection_model = self._source_table.selectionModel()

        measurement_map = self._source_measurement_map(report)

        candidate_scores = self._source_candidate_scores(report)

        current_row = -1

        for row_index, entry in enumerate(ordered_entries):

            row_payload = self._source_table_row_payload(report, entry, measurement_map, candidate_scores)

            values = row_payload["values"]

            literature_result = row_payload["literature_result"]

            calculated_result = row_payload["calculated_result"]

            for column_index, value in enumerate(values):

                if isinstance(value, tuple):

                    cell_text, sort_value = value

                else:

                    cell_text = value

                    sort_value = self._source_table_sort_value(column_index, value, literature_result, calculated_result)

                item = _SourceResultsTableItem(cell_text, sort_value=sort_value)

                if column_index == 0:

                    item.setData(Qt.ItemDataRole.UserRole, self._catalog_source_key(entry))

                self._source_table.setItem(row_index, column_index, item)

            if (entry.name, entry.catalog) in selected_targets:

                if current_row < 0:

                    current_row = row_index

                if selection_model is not None:

                    selection_model.select(

                        self._source_table.model().index(row_index, 0),

                        QItemSelectionModel.SelectionFlag.Select | QItemSelectionModel.SelectionFlag.Rows,

                    )

        if current_row < 0 and ordered_entries:

            current_row = 0

            if selection_model is not None:

                selection_model.select(

                    self._source_table.model().index(current_row, 0),

                    QItemSelectionModel.SelectionFlag.Select | QItemSelectionModel.SelectionFlag.Rows,

                )

        if current_row >= 0:

            self._source_table.setCurrentCell(current_row, 0)

        else:

            self._source_table.clearSelection()

        self._source_table.blockSignals(False)

        self._source_table.setSortingEnabled(sorting_enabled)

        self._update_source_table_comparison_highlights()

        self._refresh_source_comparison_summary_table()

        self._sync_results_filter_button_state()

    def _populate_preview_source_table(self, preview: VariableSelectionPreview) -> None:

        preselected_keys = set(preview.preselected_source_keys)

        source_type = self._source_category_filter_combo.currentData() or "all"

        source_name_filter = self._active_results_search_text("source")

        entries = list(preview.candidate_sources)

        if source_type != "all":

            entries = [entry for entry in entries if self._source_role(entry).lower() == source_type]

        if source_name_filter:

            entries = [entry for entry in entries if source_name_filter in entry.name.lower()]



        self._source_table.blockSignals(True)

        self._source_table.clearSelection()

        self._source_table.setRowCount(len(entries))

        for row_index, entry in enumerate(entries):

            source_type = self._source_type_label(entry)

            magnitude = f"{entry.magnitude:.2f}" if entry.magnitude is not None else "-"

            values = [

                entry.name,

                source_type,

                entry.catalog,

                magnitude,

                "-",

                "-",

                "-",

                "-",

                "-",

                "-",

                "-",

                "-",

                "-",

                "-",

            ]

            for column_index, value in enumerate(values):

                item = _SourceResultsTableItem(value)

                if column_index == 0:

                    item.setData(Qt.ItemDataRole.UserRole, self._catalog_source_key(entry))

                self._source_table.setItem(row_index, column_index, item)

            if self._catalog_source_key(entry) in preselected_keys:

                self._source_table.selectionModel().select(

                    self._source_table.model().index(row_index, 0),

                    QItemSelectionModel.SelectionFlag.Select | QItemSelectionModel.SelectionFlag.Rows,

                )

        self._source_table.blockSignals(False)

        self._refresh_source_comparison_summary_table()

    def _filtered_source_entries(self, report: ProcessingReport) -> list[CatalogStar]:

        unique_entries: dict[tuple[str, str], CatalogStar] = {}

        for entry in self._source_catalog_entries(report):

            entry_key = (entry.catalog, entry.source_id)

            existing_entry = unique_entries.get(entry_key)

            if existing_entry is not None and self._source_role(existing_entry) != "Reference":

                continue

            unique_entries[entry_key] = entry



        source_type = self._source_category_filter_combo.currentData() or "all"

        source_name_filter = self._active_results_search_text("source")

        filtered_entries = list(unique_entries.values())

        if source_type != "all":

            filtered_entries = [entry for entry in filtered_entries if self._source_role(entry).lower() == source_type]

        if source_name_filter:

            filtered_entries = [entry for entry in filtered_entries if source_name_filter in entry.name.lower()]

        if self._results_filtering_active():

            measurement_map = self._source_measurement_map(report)

            candidate_scores = self._source_candidate_scores(report)

            filtered_entries = [

                entry

                for entry in filtered_entries

                if self._source_entry_passes_results_filter(

                    entry,

                    self._source_table_row_payload(report, entry, measurement_map, candidate_scores),

                )

            ]



        role_order = {"Candidate": 0, "Variable": 1, "Check": 2, "Exoplanet": 3, "Reference": 4}

        candidate_scores = self._source_candidate_scores(report)

        return sorted(

            filtered_entries,

            key=lambda item: (

                role_order.get(self._source_role(item), 99),

                -candidate_scores.get((item.catalog, item.source_id), -1.0),

                item.name.lower(),

            ),

        )

    def _source_candidate_scores(self, report: ProcessingReport) -> dict[tuple[str, str], float]:

        scores_by_source_id: dict[str, float] = {}

        for series in report.light_curves:

            current_score = scores_by_source_id.get(series.source_id)

            if current_score is None or series.candidate_score > current_score:

                scores_by_source_id[series.source_id] = series.candidate_score

        return {

            (entry.catalog, entry.source_id): score

            for entry in self._source_catalog_entries(report)

            if (score := scores_by_source_id.get(entry.source_id)) is not None

        }

    def _source_measurement_map(self, report: ProcessingReport) -> dict[tuple[str, str], list[PhotometryMeasurement]]:

        cache_key = (id(report), len(report.measurements))

        if self._source_measurement_map_cache_key == cache_key:

            return self._source_measurement_map_cache

        measurement_map: dict[tuple[str, str], list[PhotometryMeasurement]] = {}

        for measurement in report.measurements:

            measurement_map.setdefault((measurement.catalog, measurement.source_id), []).append(measurement)

        self._source_measurement_map_cache_key = cache_key

        self._source_measurement_map_cache = measurement_map

        return measurement_map

    def _source_table_row_payload(

        self,

        report: ProcessingReport,

        entry: CatalogStar,

        measurement_map: dict[tuple[str, str], list[PhotometryMeasurement]],

        candidate_scores: dict[tuple[str, str], float],

    ) -> dict[str, object]:

        source_type = self._source_type_label(entry)

        magnitude = f"{entry.magnitude:.2f}" if entry.magnitude is not None else "-"

        measurements = measurement_map.get((entry.catalog, entry.source_id), [])

        filters = sorted({row.filter_name or "-" for row in measurements})

        flagged = sum(1 for row in measurements if row.flags)

        snr_values = [float(row.snr) for row in measurements if row.snr is not None and np.isfinite(row.snr)]

        source_snr = float(np.median(snr_values)) if snr_values else None

        candidate_score = candidate_scores.get((entry.catalog, entry.source_id))

        calculated_results = [

            self._calculated_period_results.get((entry.source_id, filter_name))

            for filter_name in filters

            if filter_name != "-"

        ]

        calculated_result = next((result for result in calculated_results if result is not None), None)

        literature_result = self._literature_period_results.get((entry.catalog, entry.source_id))

        return {

            "values": [

                entry.name,

                source_type,

                entry.catalog,

                magnitude,

                ", ".join(filters) if filters else "-",

                str(len(measurements)),

                str(flagged),

                f"{source_snr:.1f}" if source_snr is not None else "-",

                self._literature_period_text(literature_result),

                self._calculated_period_text(calculated_result),

                self._period_match_index_text(literature_result, calculated_result),

                f"{candidate_score:.1f}" if candidate_score is not None else "-",

                self._differential_training_label_cell(entry),

                self._differential_training_prediction_cell(entry),

            ],

            "source_snr": source_snr,

            "candidate_score": candidate_score,

            "literature_result": literature_result,

            "calculated_result": calculated_result,

        }

    def _results_filtering_active(self) -> bool:

        return self._results_view_filter_settings.has_active_filters()

    def _active_results_filter_settings(self) -> ResultsViewFilterSettings | None:

        if not self._results_filtering_active():

            return None

        return self._results_view_filter_settings.normalized()

    def _source_entry_passes_results_filter(self, entry: CatalogStar, row_payload: dict[str, object]) -> bool:

        settings = self._active_results_filter_settings()

        if settings is None:

            return True

        source_snr = row_payload.get("source_snr")

        if settings.min_snr_enabled and (source_snr is None or float(source_snr) < settings.min_snr):

            return False

        candidate_score = row_payload.get("candidate_score")

        if settings.min_var_score_enabled and (candidate_score is None or float(candidate_score) < settings.min_var_score):

            return False

        if settings.ml_label:

            prediction = self._differential_training_prediction(entry)

            if prediction is None or str(prediction.label or "").strip() != settings.ml_label:

                return False

        if settings.magnitude_filter_enabled:

            if entry.magnitude is None:

                return False

            if settings.min_magnitude is not None and float(entry.magnitude) < settings.min_magnitude:

                return False

            if settings.max_magnitude is not None and float(entry.magnitude) > settings.max_magnitude:

                return False

        return True

    def _source_catalog_entries(self, report: ProcessingReport) -> list[CatalogStar]:

        usable_source_keys = {

            (measurement.catalog, measurement.source_id)

            for measurement in report.measurements

            if measurement_has_usable_value(measurement)

        }

        entries: list[CatalogStar] = []

        if report.field_catalog is not None:

            entries.extend(

                entry for entry in report.field_catalog.variable_stars if (entry.catalog, entry.source_id) in usable_source_keys

            )

            entries.extend(

                entry for entry in report.field_catalog.exoplanets if (entry.catalog, entry.source_id) in usable_source_keys

            )

        entries.extend(entry for entry in report.reference_stars if (entry.catalog, entry.source_id) in usable_source_keys)

        return entries

    def _source_role(self, entry: CatalogStar) -> str:

        if entry.metadata.get("discover_candidate"):

            return "Candidate"

        if entry.object_type == "exoplanet":

            return "Exoplanet"

        if entry.metadata.get("manual_role") == ManualSourceRole.CHECK.value:

            return "Check"

        return "Variable" if entry.is_variable else "Reference"

    def _source_type_label(self, entry: CatalogStar) -> str:

        if entry.metadata.get("discover_candidate"):

            return str(entry.metadata.get("discover_type") or "candidate")

        return self._source_role(entry).lower()

    def _measurement_role(self, measurement: PhotometryMeasurement) -> str:

        if measurement.is_check:

            return "Check"

        return "Variable" if measurement.is_variable else "Reference"

    def _clear_measurement_table_view(self) -> None:

        self._displayed_measurements = []

        self._measurement_table.clearSelection()

        self._measurement_table.setRowCount(0)

    def _pending_measurement_row_count(self) -> int:

        report = self._current_processing_report

        if report is None:

            return 0

        return len(self._filtered_measurements())

    def _mark_measurement_table_pending(self) -> None:

        self._measurement_table_refresh_pending = self._current_processing_report is not None

        self._clear_measurement_table_view()

        self._update_measure_button_state()

    def _update_measure_button_state(self) -> None:

        report_loaded = self._current_processing_report is not None

        self._measurements_load_button.setEnabled(report_loaded)

        if not report_loaded:

            self._measurements_load_button.setToolTip("Process an object before opening the Measurements tab.")

            return

        pending_rows = self._pending_measurement_row_count()

        if pending_rows <= 0:

            self._measurements_load_button.setToolTip("No measurement rows match the current filters.")

            return

        self._measurements_load_button.setToolTip(

            f"Open the Measurements tab to load {pending_rows:,} filtered measurement row(s). Large result sets can take time."

        )

    def _handle_measure_button_clicked(self) -> None:

        report = self._current_processing_report

        if report is None:

            QMessageBox.information(self, "No measurements available", "Process an object before opening the Measurements tab.")

            return

        pending_rows = self._pending_measurement_row_count()

        if pending_rows <= 0:

            self._measurement_table_refresh_pending = False

            self._clear_measurement_table_view()

            self._update_measure_button_state()

            self._render_selected_details()

            self.statusBar().showMessage("No measurement rows match the current filters.", 5000)

            return

        decision = QMessageBox.question(

            self,

            "Load Measurements Table",

            (

                f"This will load {pending_rows:,} measurement row(s) into the Measurements table.\n\n"

                "Large result sets can take time and may briefly block the UI. Continue?"

            ),

            QMessageBox.StandardButton.Yes | QMessageBox.StandardButton.No,

            QMessageBox.StandardButton.No,

        )

        if decision != QMessageBox.StandardButton.Yes:

            return

        self._populate_measurement_table(report)

        self._render_selected_details()

        self.statusBar().showMessage(f"Loaded {pending_rows:,} measurement row(s) into the Measurements table.", 5000)

        self._append_work_log(f"Loaded {pending_rows} measurement row(s) into the Measurements table.")

    def _refresh_source_filters(self) -> None:

        if self._current_preview is not None and self._current_processing_report is None:

            self._populate_preview_source_table(self._current_preview)

            self._render_selected_details()

            self._update_source_period_button_state()

            return

        if self._current_processing_report is None:

            return

        self._populate_processing_file_table(self._current_processing_report)

        self._populate_source_table(self._current_processing_report)

        self._refresh_processing_views(refresh_source_table=False)

        self._update_source_period_button_state()

    def _populate_measurement_table(self, report: ProcessingReport) -> None:

        ordered_measurements = self._sorted_measurements(self._filtered_measurements())

        self._displayed_measurements = ordered_measurements

        self._measurement_table_refresh_pending = False

        self._measurement_table.setRowCount(len(ordered_measurements))

        science_metadata = science_export_metadata_from_settings(self._settings) if self._settings is not None else None

        for row_index, measurement in enumerate(ordered_measurements):

            role = self._measurement_role(measurement)

            time_text = measurement.observation_time.isoformat(sep=" ") if measurement.observation_time else "-"

            flux_text = f"{measurement.flux:.2f}" if measurement.flux is not None else "-"

            diff_text = f"{measurement.differential_magnitude:.4f}" if measurement.differential_magnitude is not None else "-"

            diff_error_text = f"{measurement.differential_magnitude_error:.4f}" if measurement.differential_magnitude_error is not None else "-"

            airmass = measurement_airmass(measurement, science_metadata)

            airmass_text = f"{airmass:.3f}" if airmass is not None else "-"

            quality_text = f"{measurement.quality_score:.2f}"

            used_text = "No" if measurement.excluded_from_analysis else "Yes"

            saturation_text = self._measurement_saturation_text(measurement)

            values = [

                time_text,

                measurement.file_path.name,

                measurement.source_name,

                measurement.filter_name or "-",

                role,

                flux_text,

                diff_text,

                diff_error_text,

                airmass_text,

                quality_text,

                used_text,

                saturation_text,

                " | ".join(measurement.flags) if measurement.flags else "OK",

                measurement.catalog,

            ]

            for column_index, value in enumerate(values):

                self._measurement_table.setItem(row_index, column_index, QTableWidgetItem(value))

        self._update_measure_button_state()

    def _populate_measurement_filter_options(self, report: ProcessingReport) -> None:

        filters = sorted({measurement.filter_name or "-" for measurement in report.measurements})

        self._set_measurement_filter_options(filters)

    def _set_measurement_filter_options(self, filters: list[str], *, preserve_current: bool = True) -> None:

        current_filter = self._measurement_filter_combo.currentData() if preserve_current else ""

        self._measurement_filter_combo.blockSignals(True)

        self._measurement_filter_combo.clear()

        self._measurement_filter_combo.addItem("All", "")

        for filter_name in filters:

            self._measurement_filter_combo.addItem(filter_name, filter_name)

        if current_filter:

            index = self._measurement_filter_combo.findData(current_filter)

            if index >= 0:

                self._measurement_filter_combo.setCurrentIndex(index)

        self._measurement_filter_combo.blockSignals(False)

        self._update_workspace_active_object_label()

    def _populate_workspace_filter_options_for_selected_object(self) -> None:

        if self._current_report is None:

            self._set_measurement_filter_options([], preserve_current=False)

            return

        selected_row = self._object_table.currentRow()

        if selected_row < 0 or selected_row >= len(self._current_report.object_summaries):

            self._set_measurement_filter_options([], preserve_current=False)

            return

        summary = self._current_report.object_summaries[selected_row]

        filters = sorted({result.metadata.filter_name or "-" for result in summary.files})

        self._set_measurement_filter_options(filters)

    def _handle_workspace_filter_changed(self, _index: int) -> None:

        self._update_workspace_active_object_label()

        self._refresh_measurement_filters()

    def _refresh_measurement_filters(self) -> None:

        if self._current_processing_report is None:

            return

        self._mark_measurement_table_pending()

        self._refresh_processing_views(refresh_source_table=False)

    def _light_curve_filtering_active(self) -> bool:

        return bool(

            self._light_curve_filter_enabled_checkbox.isChecked()

            and self._light_curve_filter_settings.has_active_filters()

        )

    def _active_light_curve_filter_settings(self) -> LightCurveFilterSettings | None:

        if not self._light_curve_filtering_active():

            return None

        return self._light_curve_filter_settings.normalized()

    def _open_light_curve_filter_settings(self) -> None:

        self._sync_light_curve_filter_button_state()

        dialog = LightCurveFilterDialog(self._light_curve_filter_settings, self)

        if dialog.exec() != QDialog.DialogCode.Accepted:

            self._sync_light_curve_filter_button_state()

            return

        self._light_curve_filter_settings = dialog.build_settings()

        enable_filters = self._light_curve_filter_settings.has_active_filters()

        self._light_curve_filter_enabled_checkbox.blockSignals(True)

        self._light_curve_filter_enabled_checkbox.setChecked(enable_filters)

        self._light_curve_filter_enabled_checkbox.blockSignals(False)

        self._sync_light_curve_filter_button_state()

        self._refresh_measurement_filters()

    def _open_results_filter_settings(self) -> None:

        self._sync_results_filter_button_state()

        dialog = ResultsViewFilterDialog(

            self._results_view_filter_settings,

            ml_label_options=_DIFFERENTIAL_DETECTABILITY_LABEL_OPTIONS,

            parent=self,

        )

        if dialog.exec() != QDialog.DialogCode.Accepted:

            self._sync_results_filter_button_state()

            return

        self._results_view_filter_settings = dialog.build_settings()

        self._refresh_results_filter_views()

    def _sync_results_filter_button_state(self) -> None:

        self._results_filter_button.blockSignals(True)

        self._results_filter_button.setChecked(self._results_filtering_active())

        self._results_filter_button.blockSignals(False)

        current_tab = self._results_tabs.currentWidget()

        can_filter_results = self._current_processing_report is not None and current_tab in {self._source_table, self._processing_file_table}

        self._results_filter_button.setEnabled(can_filter_results)

        if can_filter_results:

            self._results_filter_button.setToolTip("Filter the Source Results and File Results tables by source metrics.")

        else:

            self._results_filter_button.setToolTip("Open Source Results or File Results after processing an object to filter rows.")

    def _refresh_results_filter_views(self) -> None:

        self._sync_results_filter_button_state()

        report = self._current_processing_report

        if report is None:

            self._refresh_source_comparison_summary_table()

            return

        self._populate_processing_file_table(report)

        self._populate_source_table(report)

        self._populate_series_selector(self._filtered_light_curves())

        source_target = self._selected_source_target()

        if source_target is not None:

            self._sync_series_selection_for_source_target(*source_target)

        self._update_source_period_button_state()

        self._render_selected_details()

        self._sync_differential_training_controls()

        self._update_target_browser_buttons()

        self._render_image_panel()

    def _handle_light_curve_filter_enabled_changed(self, _state: int) -> None:

        if self._light_curve_filter_enabled_checkbox.isChecked() and not self._light_curve_filter_settings.has_active_filters():

            self._light_curve_filter_enabled_checkbox.blockSignals(True)

            self._light_curve_filter_enabled_checkbox.setChecked(False)

            self._light_curve_filter_enabled_checkbox.blockSignals(False)

            self._sync_light_curve_filter_button_state()

            self._open_light_curve_filter_settings()

            return

        self._sync_light_curve_filter_button_state()

        self._refresh_measurement_filters()

    def _select_previous_source_result(self) -> None:

        self._navigate_source_result_selection(-1)

    def _select_next_source_result(self) -> None:

        self._navigate_source_result_selection(1)

    def _navigate_source_result_selection(self, step: int) -> None:

        row_count = self._source_table.rowCount()

        if row_count <= 0:

            return

        current_row = self._source_table.currentRow()

        if current_row < 0:

            current_row = 0 if step >= 0 else row_count - 1

        next_row = max(0, min(row_count - 1, current_row + step))

        if next_row == current_row:

            return

        self._source_table.blockSignals(True)

        try:

            self._source_table.clearSelection()

            self._source_table.setCurrentCell(next_row, 0)

            self._source_table.selectRow(next_row)

        finally:

            self._source_table.blockSignals(False)

        self._image_context_source = "source"

        source_key = self._source_row_key(next_row)

        if source_key:

            _catalog_name, _separator, source_id = source_key.partition(":")

            for index in range(self._series_selector.count()):

                series = self._series_selector.itemData(index)

                if not isinstance(series, LightCurveSeries):

                    continue

                if series.source_id == source_id:

                    if self._series_selector.currentIndex() != index:

                        self._series_selector.setCurrentIndex(index)

                    break

        else:

            source_target = self._source_target_for_row(next_row)

            if source_target is not None:

                self._sync_series_selection_for_source_target(*source_target)

        self._update_source_table_comparison_highlights()

        self._refresh_source_comparison_summary_table()

        self._update_source_period_button_state()

        self._render_selected_details()

        self._update_target_browser_buttons()

        self._render_image_panel()

        if self._image_auto_center_object_enabled:

            self._center_image_view_on_selected_source(show_status_message=False)

    def _measurement_filter_magnitude(self, measurement: PhotometryMeasurement) -> float | None:

        if measurement.calibrated_magnitude is not None:

            return float(measurement.calibrated_magnitude)

        if measurement.differential_magnitude is not None:

            return float(measurement.differential_magnitude)

        return None

    def _measurement_filter_error(self, measurement: PhotometryMeasurement) -> float | None:

        if measurement.calibrated_magnitude_error is not None:

            return float(measurement.calibrated_magnitude_error)

        if measurement.differential_magnitude_error is not None:

            return float(measurement.differential_magnitude_error)

        return None

    def _measurement_passes_light_curve_filters(self, measurement: PhotometryMeasurement) -> bool:

        settings = self._active_light_curve_filter_settings()

        if settings is None:

            return True

        if settings.hide_excluded and measurement.excluded_from_analysis:

            return False

        error_value = self._measurement_filter_error(measurement)

        if settings.max_error_enabled and error_value is not None and error_value > settings.max_error_magnitude:

            return False

        magnitude_value = self._measurement_filter_magnitude(measurement)

        if settings.outlier_filter_enabled and magnitude_value is not None:

            if settings.min_magnitude is not None and magnitude_value < settings.min_magnitude:

                return False

            if settings.max_magnitude is not None and magnitude_value > settings.max_magnitude:

                return False

        return True

    def _reset_measurement_filters(self) -> None:

        self._measurement_filter_combo.setCurrentIndex(0)

        self._light_curve_filter_settings = LightCurveFilterSettings()

        self._light_curve_filter_enabled_checkbox.setChecked(False)

    def _filtered_measurements(self) -> list[object]:

        report = self._current_processing_report

        if report is None:

            return []



        source_filter = self._active_results_search_text("measurement")

        selected_filter = self._measurement_filter_combo.currentData() or ""



        filtered = []

        for measurement in report.measurements:

            if source_filter and source_filter not in measurement.source_name.lower():

                continue

            if selected_filter and (measurement.filter_name or "-") != selected_filter:

                continue

            if not self._measurement_passes_light_curve_filters(measurement):

                continue

            filtered.append(measurement)

        return filtered

    def _filtered_light_curves(self) -> list[LightCurveSeries]:

        report = self._current_processing_report

        if report is None:

            return []



        visible_measurements = self._filtered_measurements()

        visible_keys = {

            (

                measurement.source_id,

                measurement.filter_name or "-",

                measurement.file_path.name,

                measurement.observation_time.isoformat(sep=" ") if measurement.observation_time else "-",

            )

            for measurement in visible_measurements

            if not measurement.is_reference

        }



        filtered_series: list[LightCurveSeries] = []

        for series in report.light_curves:

            filtered_points = []

            for point in series.points:

                key = (

                    series.source_id,

                    series.filter_name,

                    point.file_path.name,

                    point.observation_time.isoformat(sep=" ") if point.observation_time else "-",

                )

                if key in visible_keys:

                    filtered_points.append(point)

            if filtered_points:

                filtered_series.append(

                    LightCurveSeries(

                        object_name=series.object_name,

                        source_id=series.source_id,

                        source_name=series.source_name,

                        filter_name=series.filter_name,

                        points=filtered_points,

                    )

                )

        return filtered_series

    def _sorted_measurements(self, measurements: list[object]) -> list[object]:

        return sorted(

            measurements,

            key=lambda item: (

                item.observation_time or _MIN_UTC_DATETIME,

                item.file_path.name,

                item.source_name.lower(),

            ),

        )

    def _resolve_export_selection(self) -> tuple[list[object] | None, list[LightCurveSeries] | None, str | None]:

        if self._current_processing_report is None:

            return None, None, None



        preset = self._export_preset_combo.currentData() or "filtered"

        report = self._current_processing_report



        if preset == "full":

            return report.measurements, report.light_curves, None



        if preset == "flagged":

            measurements = [measurement for measurement in report.measurements if measurement.flags]

            return measurements, self._light_curves_for_measurements(measurements), "flagged_only"



        if preset == "selected-source":

            targets = self._selected_source_targets()

            if not targets:

                target = self._selected_source_target()

                targets = [target] if target is not None else []

            if not targets:

                QMessageBox.information(self, "No source selected", "Select one or more source rows or a measurement row for the source export preset.")

                return None, None, None

            target_set = set(targets)

            measurements = [

                measurement

                for measurement in report.measurements

                if (measurement.source_name, measurement.catalog) in target_set

            ]

            export_suffix = f"source_{targets[0][0]}" if len(targets) == 1 else "selected_sources"

            return measurements, self._light_curves_for_measurements(measurements), export_suffix



        if preset == "selected-filter":

            filter_name = self._selected_filter_target()

            if not filter_name:

                QMessageBox.information(self, "No filter selected", "Choose a measurement filter or select a measurement row for the selected-filter export preset.")

                return None, None, None

            measurements = [measurement for measurement in report.measurements if (measurement.filter_name or "-") == filter_name]

            return measurements, self._light_curves_for_measurements(measurements), f"filter_{filter_name}"



        measurements = self._filtered_measurements()

        return measurements, self._filtered_light_curves(), self._current_export_suffix(measurements)

    def _selected_source_target(self) -> tuple[str, str] | None:

        selected_targets = self._selected_source_targets()

        if selected_targets:

            return selected_targets[0]



        source_row = self._source_table.currentRow()

        if source_row >= 0:

            target = self._source_target_for_row(source_row)

            if target is not None:

                return target



        measurement_row = self._measurement_table.currentRow()

        if 0 <= measurement_row < len(self._displayed_measurements):

            measurement = self._displayed_measurements[measurement_row]

            return measurement.source_name, measurement.catalog



        return None

    def _selected_source_targets(self) -> list[tuple[str, str]]:

        selection_model = self._source_table.selectionModel()

        if selection_model is None:

            return []



        targets: list[tuple[str, str]] = []

        for index in selection_model.selectedRows():

            target = self._source_target_for_row(index.row())

            if target is None:

                continue

            if target not in targets:

                targets.append(target)

        return targets

    def _source_target_for_row(self, row_index: int) -> tuple[str, str] | None:

        source_item = self._source_table.item(row_index, 0)

        if source_item is None:

            return None

        source_key = self._source_row_key(row_index)

        if source_key:

            catalog_name, _separator, source_id = source_key.partition(":")

            if catalog_name:

                report = self._current_processing_report

                if report is not None:

                    entry = next(

                        (

                            catalog_entry

                            for catalog_entry in self._source_catalog_entries(report)

                            if catalog_entry.catalog == catalog_name and catalog_entry.source_id == source_id

                        ),

                        None,

                    )

                    if entry is not None:

                        return entry.name, entry.catalog

                preview = self._current_preview

                if preview is not None:

                    entry = next(

                        (

                            catalog_entry

                            for catalog_entry in preview.candidate_sources

                            if catalog_entry.catalog == catalog_name and catalog_entry.source_id == source_id

                        ),

                        None,

                    )

                    if entry is not None:

                        return entry.name, entry.catalog

                return source_item.text(), catalog_name

        catalog_item = self._source_table.item(row_index, 2)

        if catalog_item is None:

            catalog_item = self._source_table.item(row_index, 1)

        if catalog_item is None:

            return None

        return source_item.text(), catalog_item.text()

    def _catalog_target_for_source_row(self, row_index: int) -> tuple[str, str, str, float, float, str] | None:

        source_key = self._source_row_key(row_index)

        catalog_name = ""

        source_id = ""

        if source_key:

            catalog_name, _separator, source_id = source_key.partition(":")

        report = self._current_processing_report

        if report is not None:

            if catalog_name and source_id:

                entry = next(

                    (

                        catalog_entry

                        for catalog_entry in self._source_catalog_entries(report)

                        if catalog_entry.catalog == catalog_name and catalog_entry.source_id == source_id

                    ),

                    None,

                )

            else:

                source_target = self._source_target_for_row(row_index)

                if source_target is None:

                    return None

                entry = self._source_entry(report, source_target[0], source_target[1])

            if entry is not None:

                return (

                    entry.catalog,

                    entry.source_id,

                    entry.name,

                    entry.ra_deg,

                    entry.dec_deg,

                    entry.object_type,

                )

        preview = self._current_preview

        if preview is None:

            return None

        preview_entry = next(

            (

                catalog_entry

                for catalog_entry in preview.candidate_sources

                if (not catalog_name or catalog_entry.catalog == catalog_name)

                and (not source_id or catalog_entry.source_id == source_id)

            ),

            None,

        )

        if preview_entry is None:

            source_target = self._source_target_for_row(row_index)

            if source_target is None:

                return None

            preview_entry = next(

                (

                    catalog_entry

                    for catalog_entry in preview.candidate_sources

                    if catalog_entry.name == source_target[0] and catalog_entry.catalog == source_target[1]

                ),

                None,

            )

        if preview_entry is None:

            return None

        return (

            preview_entry.catalog,

            preview_entry.source_id,

            preview_entry.name,

            preview_entry.ra_deg,

            preview_entry.dec_deg,

            preview_entry.object_type,

        )

    def _selected_source_measurements(self) -> list[PhotometryMeasurement]:

        report = self._current_processing_report

        if report is None:

            return []



        selected_keys = self._selected_source_keys()

        if not selected_keys:

            measurement = self._selected_source_measurement()

            return [] if measurement is None else [measurement]



        measurement_map = self._source_measurement_map(report)

        selected_measurements: list[PhotometryMeasurement] = []

        seen_keys: set[tuple[str, str, str, str]] = set()

        for source_key in selected_keys:

            catalog_name, separator, source_id = source_key.partition(":")

            if not separator:

                continue

            matching_measurements = measurement_map.get((catalog_name, source_id), [])

            if not matching_measurements:

                continue

            measurement = sorted(

                matching_measurements,

                key=lambda item: (item.observation_time or _MIN_UTC_DATETIME, item.file_path.name),

            )[0]

            measurement_key = self._measurement_key(measurement)

            if measurement_key in seen_keys:

                continue

            seen_keys.add(measurement_key)

            selected_measurements.append(measurement)

        return selected_measurements

    def _selected_source_comparison_rows(self) -> dict[str, set[str]]:

        report = self._current_processing_report

        if report is None:

            return {}



        highlighted_rows: dict[str, set[str]] = {}

        for measurement in self._selected_source_measurements():

            if not measurement.comparison_source_ids:

                continue

            comparison_ids = set(measurement.comparison_source_ids)

            for reference_measurement in report.measurements:

                if not reference_measurement.is_reference or reference_measurement.source_id not in comparison_ids:

                    continue

                row_key = f"{reference_measurement.catalog}:{reference_measurement.source_id}"

                highlighted_rows.setdefault(row_key, set()).add(measurement.source_name)

        return highlighted_rows

    def _refresh_source_comparison_summary_table(self) -> None:

        table = self._source_comparison_summary_table

        table.clearContents()

        table.setRowCount(0)

        self._source_comparison_overlay.hide()

        report = self._current_processing_report

        if report is None:

            return

        selected_measurements = self._selected_source_measurements()

        if not selected_measurements:

            return

        measurement_map = self._source_measurement_map(report)

        candidate_scores = self._source_candidate_scores(report)

        highlighted_rows = self._selected_source_comparison_rows()


        summary_rows: list[tuple[int | None, CatalogStar, list[str]]] = []

        seen_rows: set[tuple[str, str]] = set()

        for measurement in selected_measurements:

            for comparison_measurement in self._comparison_measurements_for(measurement):

                comparison_entry = self._source_entry(report, comparison_measurement.source_name, comparison_measurement.catalog)

                if comparison_entry is None:

                    continue


                comparison_key = (comparison_entry.catalog, comparison_entry.source_id)

                if comparison_key in seen_rows:

                    continue

                seen_rows.add(comparison_key)


                source_key = f"{comparison_entry.catalog}:{comparison_entry.source_id}"

                summary_rows.append((
                    self._source_row_index_for_key(source_key),
                    comparison_entry,
                    sorted(highlighted_rows.get(source_key, ())),
                ))

        if not summary_rows:

            return

        summary_rows.sort(key=lambda item: (item[0] if item[0] is not None else self._source_table.rowCount(), item[1].name.casefold()))

        table.setRowCount(len(summary_rows))

        highlight_brush = self._source_table_comparison_highlight_brush()


        for row_index, (source_row_index, entry, highlighted_for) in enumerate(summary_rows):

            row_payload = self._source_table_row_payload(report, entry, measurement_map, candidate_scores)

            values = row_payload["values"]

            if len(highlighted_for) == 1:

                tooltip = f"Comparison/reference star used for selected source: {highlighted_for[0]}"

            elif highlighted_for:

                tooltip = f"Comparison/reference star used for selected sources: {', '.join(highlighted_for)}"

            else:

                tooltip = ""

            header_item = QTableWidgetItem("" if source_row_index is None else str(source_row_index + 1))

            header_item.setTextAlignment(Qt.AlignmentFlag.AlignLeft | Qt.AlignmentFlag.AlignVCenter)

            header_item.setBackground(highlight_brush)

            header_item.setToolTip(tooltip)

            table.setVerticalHeaderItem(row_index, header_item)

            for column_index, value in enumerate(values):

                cell_text = value[0] if isinstance(value, tuple) else str(value)

                item = QTableWidgetItem(cell_text)

                item.setBackground(highlight_brush)

                item.setToolTip(tooltip)

                table.setItem(row_index, column_index, item)

        self._sync_source_comparison_overlay_columns()

        self._sync_source_comparison_overlay_scroll()

        self._update_source_comparison_overlay_geometry()

        self._source_comparison_overlay.show()

    def _sync_source_comparison_overlay_columns(self, *_args) -> None:

        source_header = self._source_table.horizontalHeader()

        overlay_header = self._source_comparison_summary_table.horizontalHeader()

        self._source_comparison_summary_table.verticalHeader().setFixedWidth(self._source_table.verticalHeader().width())

        for column_index in range(self._source_table.columnCount()):

            column_width = source_header.sectionSize(column_index)

            self._source_comparison_summary_table.setColumnWidth(column_index, column_width)

            overlay_header.resizeSection(column_index, column_width)

        self._update_source_comparison_overlay_geometry()

    def _sync_source_comparison_overlay_scroll(self, *_args) -> None:

        self._source_comparison_summary_table.horizontalScrollBar().setValue(self._source_table.horizontalScrollBar().value())

    def _update_source_comparison_overlay_geometry(self) -> None:

        if not hasattr(self, "_source_comparison_overlay") or not qt_object_is_valid(self._source_comparison_overlay):

            return

        if self._source_comparison_summary_table.rowCount() <= 0:

            self._source_comparison_overlay.hide()

            return

        viewport_geometry = self._source_table.viewport().geometry()

        overlay_width = viewport_geometry.x() + viewport_geometry.width()

        content_height = sum(self._source_comparison_summary_table.rowHeight(row_index) for row_index in range(self._source_comparison_summary_table.rowCount()))

        minimum_height = self._source_comparison_summary_table.verticalHeader().defaultSectionSize() + (self._source_comparison_summary_table.frameWidth() * 2)

        overlay_height = max(minimum_height, content_height + (self._source_comparison_summary_table.frameWidth() * 2))

        overlay_height = min(overlay_height, viewport_geometry.height())

        overlay_top = max(viewport_geometry.y(), viewport_geometry.y() + viewport_geometry.height() - overlay_height)

        overlay_height = (viewport_geometry.y() + viewport_geometry.height()) - overlay_top

        self._source_comparison_overlay.setGeometry(0, overlay_top, overlay_width, overlay_height)

        self._source_comparison_summary_table.setGeometry(0, 0, overlay_width, overlay_height)

        self._source_comparison_overlay.raise_()

    def eventFilter(self, watched: object, event: QEvent) -> bool:

        if watched is self._source_table.viewport() and event.type() in {
            QEvent.Type.Resize,
            QEvent.Type.Show,
            QEvent.Type.Paint,
        }:

            self._update_source_comparison_overlay_geometry()

        return super().eventFilter(watched, event)

    def _source_table_comparison_highlight_brush(self) -> QBrush:

        base_color = self.palette().color(QPalette.ColorRole.Base)

        accent_color = self.palette().color(QPalette.ColorRole.Highlight)

        blend_ratio = 0.22 if base_color.lightness() >= 128 else 0.36

        highlight_color = QColor(

            int(round(base_color.red() + ((accent_color.red() - base_color.red()) * blend_ratio))),

            int(round(base_color.green() + ((accent_color.green() - base_color.green()) * blend_ratio))),

            int(round(base_color.blue() + ((accent_color.blue() - base_color.blue()) * blend_ratio))),

        )

        return QBrush(highlight_color)

    def _asteroid_results_highlight_brush(self) -> QBrush:

        base_color = self.palette().color(QPalette.ColorRole.Base)

        accent_color = self.palette().color(QPalette.ColorRole.Highlight)

        blend_ratio = 0.14 if base_color.lightness() >= 128 else 0.24

        highlight_color = QColor(

            int(round(base_color.red() + ((accent_color.red() - base_color.red()) * blend_ratio))),

            int(round(base_color.green() + ((accent_color.green() - base_color.green()) * blend_ratio))),

            int(round(base_color.blue() + ((accent_color.blue() - base_color.blue()) * blend_ratio))),

        )

        return QBrush(highlight_color)

    def _update_source_table_comparison_highlights(self) -> None:

        highlighted_rows = self._selected_source_comparison_rows()

        previous_highlighted_rows = self._source_comparison_highlighted_rows

        highlight_brush = self._source_table_comparison_highlight_brush()

        empty_brush = QBrush()

        changed_row_keys = set(previous_highlighted_rows) | set(highlighted_rows)

        for row_index in range(self._source_table.rowCount()):

            row_key = self._source_row_key(row_index)

            if row_key not in changed_row_keys:

                continue

            highlighted_for = sorted(highlighted_rows.get(row_key, ())) if row_key is not None else []

            if len(highlighted_for) == 1:

                tooltip = f"Comparison/reference star used for selected source: {highlighted_for[0]}"

            elif highlighted_for:

                tooltip = f"Comparison/reference star used for selected sources: {', '.join(highlighted_for)}"

            else:

                tooltip = ""

            for column_index in range(self._source_table.columnCount()):

                item = self._source_table.item(row_index, column_index)

                if item is None:

                    continue

                item.setBackground(highlight_brush if highlighted_for else empty_brush)

                item.setToolTip(tooltip)

        self._source_comparison_highlighted_rows = {key: set(value) for key, value in highlighted_rows.items()}

    def _clear_source_selection(self) -> None:

        self._source_table.clearSelection()

        if self._current_preview is not None and self._current_processing_report is None:

            self._clear_saved_source_selection_for_object(self._current_preview.object_name)

            self._render_selected_details()

            self._sync_differential_training_controls(None)

            self._refresh_source_comparison_summary_table()

            self._update_target_browser_buttons()

            self._update_source_period_button_state()

            self.statusBar().showMessage("No preview sources selected.")

            return

        object_name = self._selected_object_name()

        cleared_saved_selection = self._clear_saved_source_selection_for_object(object_name)

        self._refresh_processing_views(refresh_source_table=False)

        self._sync_differential_training_controls(None)

        self._refresh_source_comparison_summary_table()

        self._update_source_period_button_state()

        self._update_target_browser_buttons()

        if cleared_saved_selection:

            self.statusBar().showMessage("Cleared the saved source subset; future Generates will use the default source list again.")

            return

        self.statusBar().showMessage("Showing all sources in measurements and light curves.")

    def _active_settings(self) -> AppSettings | None:

        if self._settings is not None:

            return self._settings

        root_path = Path(self._root_path_input.text()).expanduser()

        if root_path.exists():

            self._settings = AppSettings.from_root(root_path)

        return self._settings

    def _selected_source_series(self, entry: CatalogStar) -> LightCurveSeries | None:

        current_series = self._series_selector.currentData()

        if isinstance(current_series, LightCurveSeries) and current_series.source_id == entry.source_id:

            return current_series

        report = self._current_processing_report

        if report is None:

            return None

        for series in report.light_curves:

            if series.source_id == entry.source_id:

                return series

        return None

    def _selected_source_actual_period_days(self, entry: CatalogStar) -> float | None:

        literature_result = self._literature_period_results.get((entry.catalog, entry.source_id))

        if literature_result is not None and literature_result.period_days is not None and np.isfinite(literature_result.period_days) and literature_result.period_days > 0:

            return float(literature_result.period_days)

        for metadata_key in ("literature_period_days", "orbital_period_days"):

            metadata_value = entry.metadata.get(metadata_key)

            try:

                numeric_value = float(metadata_value)

            except (TypeError, ValueError):

                continue

            if np.isfinite(numeric_value) and numeric_value > 0:

                return numeric_value

        return None

    def _selected_source_catalog_entry(self) -> CatalogStar | None:

        report = self._current_processing_report

        source_target = self._selected_source_target()

        if report is None or source_target is None:

            return None

        return self._source_entry(report, source_target[0], source_target[1])

    def _differential_training_root_path(self) -> Path:

        root_text = self._root_path_input.text().strip()

        return Path(root_text).expanduser() if root_text else Path.cwd()

    def _differential_training_measurements(self, entry: CatalogStar) -> list[PhotometryMeasurement]:

        report = self._current_processing_report

        if report is None:

            return []

        return [

            measurement

            for measurement in report.measurements

            if measurement.catalog == entry.catalog and measurement.source_id == entry.source_id

        ]

    def _differential_training_series_list(self, entry: CatalogStar) -> list[LightCurveSeries]:

        report = self._current_processing_report

        if report is None:

            return []

        return [series for series in report.light_curves if series.source_id == entry.source_id]

    def _differential_training_scan_results(self, measurements: list[PhotometryMeasurement]) -> list[FileScanResult]:

        scan_results: list[FileScanResult] = []

        seen_paths: set[Path] = set()

        for measurement in measurements:

            scan_result = self._scan_file_result_for_path(measurement.file_path)

            if scan_result is None:

                continue

            resolved_path = scan_result.path.resolve()

            if resolved_path in seen_paths:

                continue

            seen_paths.add(resolved_path)

            scan_results.append(scan_result)

        return scan_results

    def _differential_training_key(self, entry: CatalogStar) -> str:

        report = self._current_processing_report

        object_name = "" if report is None else report.object_name

        return differential_source_training_key(

            self._differential_training_root_path(),

            object_name,

            entry,

            self._differential_training_measurements(entry),

        )

    def _differential_training_label_record(self, entry: CatalogStar):

        return self._candidate_training_store.label_for_key(TRAINING_MODE_DIFFERENTIAL, self._differential_training_key(entry))

    def _differential_training_prediction(self, entry: CatalogStar) -> CandidatePrediction | None:

        key = self._differential_training_key(entry)

        prediction = self._differential_training_predictions.get(key)

        if prediction is not None:

            return prediction

        measurements = self._differential_training_measurements(entry)

        prediction = self._candidate_training_store.predict(

            TRAINING_MODE_DIFFERENTIAL,

            differential_source_training_features(

                entry=entry,

                measurements=measurements,

                series_list=self._differential_training_series_list(entry),

                settings=self._active_settings(),

                scan_results=self._differential_training_scan_results(measurements),

            ),

        )

        if prediction is not None:

            self._differential_training_predictions[key] = prediction

        return prediction

    def _differential_training_label_cell(self, entry: CatalogStar) -> tuple[str, str]:

        label_record = self._differential_training_label_record(entry)

        if label_record is None:

            return "-", ""

        return self._format_differential_training_label(label_record.label), label_record.label

    def _differential_training_prediction_cell(self, entry: CatalogStar) -> tuple[str, float]:

        prediction = self._differential_training_prediction(entry)

        if prediction is None:

            return "-", (99, -1.0)

        label_order = {

            label_value: index

            for index, (_label_text, label_value) in enumerate(_DIFFERENTIAL_DETECTABILITY_LABEL_OPTIONS)

        }

        return (

            f"{self._format_differential_training_label(prediction.label)} {prediction.confidence:.0%}",

            (label_order.get(prediction.label, len(label_order)), prediction.confidence),

        )

    def _format_differential_training_label(self, label: str) -> str:

        return str(label or "").replace("_", " ").title()

    def _differential_quick_label_entries(self) -> list[CatalogStar]:

        report = self._current_processing_report

        if report is None:

            return []

        return [entry for entry in self._filtered_source_entries(report) if self._differential_training_measurements(entry)]

    def _differential_review_series(self, entry: CatalogStar) -> LightCurveSeries | None:

        current_series = self._series_selector.currentData()

        if isinstance(current_series, LightCurveSeries) and current_series.source_id == entry.source_id:

            return self._active_series_for_plotting(current_series)

        series_list = self._differential_training_series_list(entry)

        if not series_list:

            return None

        best_series = max(series_list, key=lambda item: (float(item.candidate_score), item.filter_name.lower()))

        return self._active_series_for_plotting(best_series)

    def _differential_training_detail_text(self, entry: CatalogStar) -> str:

        measurements = self._differential_training_measurements(entry)

        series_list = self._differential_training_series_list(entry)

        lines = [

            f"Source: {entry.name}",

            f"Catalog: {entry.catalog}",

            f"Type: {self._source_role(entry)}",

            f"Measurements: {len(measurements)}",

            f"Magnitude: {'-' if entry.magnitude is None else f'{entry.magnitude:.2f}'}",

            f"Sky Position: ({entry.ra_deg:.6f}, {entry.dec_deg:.6f})",

        ]

        label_record = self._differential_training_label_record(entry)

        if label_record is not None:

            lines.append(f"Training Label: {self._format_differential_training_label(label_record.label)}")

        prediction = self._differential_training_prediction(entry)

        if prediction is not None:

            lines.append(f"ML Score: {self._format_differential_training_label(prediction.label)} ({prediction.confidence:.0%})")

        if series_list:

            lines.append(f"Best Candidate Score: {max(series.candidate_score for series in series_list):.1f}")

            lines.append("Variability Metrics:")

            for series in series_list:

                metrics = series.variability_metrics

                lines.append(

                    f"- {series.filter_name}: score={series.candidate_score:.1f}, "

                    f"MAD={metrics.get('mad', float('nan')):.4f}, RMS={metrics.get('rms', float('nan')):.4f}, "

                    f"amp={metrics.get('amplitude', float('nan')):.4f}, chi2={metrics.get('reduced_chi2', float('nan')):.2f}, "

                    f"VN={metrics.get('von_neumann', float('nan')):.2f}, J={metrics.get('stetson_j', float('nan')):.2f}"

                )

        if measurements:

            flagged_count = sum(1 for measurement in measurements if measurement.flags)

            excluded_count = sum(1 for measurement in measurements if measurement.excluded_from_analysis)

            finite_snr = [float(measurement.snr) for measurement in measurements if measurement.snr is not None and np.isfinite(float(measurement.snr))]

            lines.append(f"Flagged: {flagged_count}")

            lines.append(f"Excluded: {excluded_count}")

            if finite_snr:

                lines.append(f"Median SNR: {float(np.median(finite_snr)):.1f}")

        return "\n".join(lines)

    def _open_differential_quick_label_dialog(self) -> None:

        entries = self._differential_quick_label_entries()

        if not entries:

            QMessageBox.information(self, "No source rows", "Process an object and keep at least one visible Source Results row before opening the fast labeling window.")

            return

        dialog = DifferentialQuickLabelDialog(

            entries=entries,

            label_options=_DIFFERENTIAL_DETECTABILITY_LABEL_OPTIONS,

            label_lookup=lambda entry: (record.label if (record := self._differential_training_label_record(entry)) is not None else None),

            save_label=lambda entry, label: self._record_differential_training_label(entry, label, announce=False),

            series_lookup=self._differential_review_series,

            details_lookup=self._differential_training_detail_text,

            fit_config=self._current_fit_config(),

            y_axis_mode=self._current_light_curve_y_axis_mode(),

            x_axis_mode=self._current_light_curve_x_axis_mode(),

            phase_period_hours=self._fit_period_spin.value() / _MINUTES_PER_HOUR,

            phase_anchor_mode=self._current_phase_anchor_mode(),

            phase_opacity_floor=float(self._phase_opacity_floor_spin.value()),

            recent_period_error_bars_only=self._phase_recent_error_bars_only_checkbox.isChecked(),

            theme=self._current_theme_name(),

            custom_theme_colors=(self._current_custom_theme_colors() if self._current_theme_name() == _THEME_CUSTOM else None),

            parent=self,

        )

        dialog_result = dialog.exec()

        if dialog.saved_count:

            self._append_work_log(f"Fast labeling saved {dialog.saved_count} Differential detectability label(s).")

            self.statusBar().showMessage(f"Saved {dialog.saved_count} Differential detectability label(s).", 5000)

        if dialog_result == QDialog.DialogCode.Accepted:

            self._train_differential_candidate_model()

            return

        self._refresh_differential_training_summary()

    def _refresh_differential_training_summary(self) -> None:

        if hasattr(self, "_differential_training_status_label"):

            self._differential_training_status_label.setText(self._candidate_training_store.training_summary(TRAINING_MODE_DIFFERENTIAL))

    def _sync_differential_training_controls(self, entry: CatalogStar | None = None) -> None:

        if not hasattr(self, "_differential_training_label_combo"):

            return

        if entry is None:

            entry = self._selected_source_catalog_entry()

        has_entry = entry is not None

        quick_label_entries = self._differential_quick_label_entries()

        self._differential_training_label_combo.setEnabled(has_entry)

        self._differential_save_label_button.setEnabled(has_entry)

        self._differential_quick_label_button.setEnabled(bool(quick_label_entries))

        self._differential_train_model_button.setEnabled(bool(quick_label_entries))

        selected_label = ""

        if entry is not None:

            label_record = self._differential_training_label_record(entry)

            selected_label = "" if label_record is None else label_record.label

        label_index = self._differential_training_label_combo.findData(selected_label)

        self._differential_training_label_combo.setCurrentIndex(0 if label_index < 0 else label_index)

        self._refresh_differential_training_summary()

    def _save_differential_training_label(self) -> None:

        entry = self._selected_source_catalog_entry()

        if entry is None:

            self.statusBar().showMessage("Select a source result row before saving a detectability label.", 5000)

            return

        label = str(self._differential_training_label_combo.currentData() or "")

        if not label:

            self.statusBar().showMessage("Choose a detectability label before saving.", 5000)

            return

        self._record_differential_training_label(entry, label, announce=True)

    def _record_differential_training_label(self, entry: CatalogStar, label: str, *, announce: bool = False) -> None:

        report = self._current_processing_report

        if report is None:

            return

        measurements = self._differential_training_measurements(entry)

        self._candidate_training_store.record_label(

            mode=TRAINING_MODE_DIFFERENTIAL,

            candidate_key=self._differential_training_key(entry),

            features=differential_source_training_features(

                entry=entry,

                measurements=measurements,

                series_list=self._differential_training_series_list(entry),

                settings=self._active_settings(),

                scan_results=self._differential_training_scan_results(measurements),

            ),

            payload=differential_source_training_payload(

                root_path=self._differential_training_root_path(),

                object_name=report.object_name,

                entry=entry,

                measurements=measurements,

                series_list=self._differential_training_series_list(entry),

                settings=self._active_settings(),

                scan_results=self._differential_training_scan_results(measurements),

            ),

            label=label,

        )

        self._update_differential_training_cells_for_entry(entry)

        self._refresh_differential_training_summary()

        selected_entry = self._selected_source_catalog_entry()

        if selected_entry is not None and selected_entry.catalog == entry.catalog and selected_entry.source_id == entry.source_id:

            self._sync_differential_training_controls(entry)

            self._render_source_details()

        message = f"Saved Differential detectability label {self._format_differential_training_label(label)} for {entry.name}."

        if announce:

            self._append_work_log(message)

            self.statusBar().showMessage(message, 5000)

    def _update_differential_training_cells_for_entry(self, entry: CatalogStar) -> None:

        row_index = self._source_row_index_for_catalog_entry(entry)

        if row_index is None:

            return

        label_text, label_sort = self._differential_training_label_cell(entry)

        score_text, score_sort = self._differential_training_prediction_cell(entry)

        self._source_table.setItem(row_index, 12, _SourceResultsTableItem(label_text, label_sort))

        self._source_table.setItem(row_index, 13, _SourceResultsTableItem(score_text, score_sort))

    def _source_row_index_for_catalog_entry(self, entry: CatalogStar) -> int | None:

        source_key = self._catalog_source_key(entry)

        for row_index in range(self._source_table.rowCount()):

            if self._source_row_key(row_index) == source_key:

                return row_index

        return None

    def _train_differential_candidate_model(self) -> None:

        result = self._candidate_training_store.train_model(TRAINING_MODE_DIFFERENTIAL)

        self._differential_training_predictions.clear()

        self._refresh_processing_views(refresh_source_table=True)

        self._sync_differential_training_controls()

        self._append_work_log(result.message)

        self.statusBar().showMessage(result.message, 5000)

    def _reference_source_magnitudes(self, report: ProcessingReport) -> dict[str, float]:

        magnitudes: dict[str, float] = {}

        for entry in report.reference_stars:

            if entry.magnitude is None:

                continue

            try:

                numeric_value = float(entry.magnitude)

            except (TypeError, ValueError):

                continue

            if np.isfinite(numeric_value):

                magnitudes[entry.source_id] = numeric_value

        return magnitudes

    def _comparison_fit_context_for_target(

        self,

        report: ProcessingReport,

        source_target: tuple[str, str],

        reference_source_magnitudes: dict[str, float],

    ) -> _ComparisonFitContext | None:

        entry = self._source_entry(report, source_target[0], source_target[1])

        if entry is None:

            return None

        target_series = self._selected_source_series(entry)

        if target_series is None:

            return None

        actual_period_days = self._selected_source_actual_period_days(entry)

        if actual_period_days is None:

            return None

        target_filter = target_series.filter_name or "unknown"

        target_measurements = [

            measurement

            for measurement in report.measurements

            if not measurement.is_reference and measurement.source_id == target_series.source_id and (measurement.filter_name or "unknown") == target_filter

        ]

        if len(target_measurements) < 2:

            return None

        reference_measurements = [

            measurement

            for measurement in report.measurements

            if measurement.is_reference and (measurement.filter_name or "unknown") == target_filter

        ]

        if not reference_measurements:

            return None

        target_magnitude: float | None = None

        if entry.magnitude is not None:

            try:

                numeric_magnitude = float(entry.magnitude)

            except (TypeError, ValueError):

                numeric_magnitude = None

            if numeric_magnitude is not None and np.isfinite(numeric_magnitude):

                target_magnitude = numeric_magnitude

        return _ComparisonFitContext(

            target_entry=entry,

            target_series=target_series,

            target_measurements=target_measurements,

            reference_measurements=reference_measurements,

            actual_period_days=actual_period_days,

            target_magnitude=target_magnitude,

            reference_source_magnitudes=reference_source_magnitudes,

        )

    def _selected_source_comparison_fit_contexts(self) -> list[_ComparisonFitContext]:

        report = self._current_processing_report

        if report is None:

            return []

        selected_targets = self._selected_source_targets()

        if not selected_targets:

            selected_target = self._selected_source_target()

            if selected_target is not None:

                selected_targets = [selected_target]

        if not selected_targets:

            return []

        reference_source_magnitudes = self._reference_source_magnitudes(report)

        contexts: list[_ComparisonFitContext] = []

        seen_series: set[tuple[str, str]] = set()

        for source_target in selected_targets:

            context = self._comparison_fit_context_for_target(report, source_target, reference_source_magnitudes)

            if context is None:

                continue

            series_key = (context.target_series.source_id, context.target_series.filter_name or "unknown")

            if series_key in seen_series:

                continue

            seen_series.add(series_key)

            contexts.append(context)

        return contexts

    def _comparison_fit_allows_multiple_targets(self) -> bool:

        settings = self._active_settings()

        return bool(settings is not None and settings.comparison_fit_allow_multiple_targets)

    def _selected_source_comparison_fit_context(self) -> _ComparisonFitContext | None:

        contexts = self._selected_source_comparison_fit_contexts()

        if len(contexts) != 1:

            return None

        return contexts[0]

    def _selected_filter_target(self) -> str | None:

        selected_filter = self._measurement_filter_combo.currentData() or ""

        if selected_filter:

            return selected_filter



        measurement_row = self._measurement_table.currentRow()

        if 0 <= measurement_row < len(self._displayed_measurements):

            return self._displayed_measurements[measurement_row].filter_name or "-"



        return None

    def _measurement_saturation_text(self, measurement: PhotometryMeasurement) -> str:

        status = measurement.saturation_status

        if status != "OK":

            return status

        if measurement.saturation_threshold is None:

            return "-"

        return status

    def _measurement_series_key(self, measurement: PhotometryMeasurement) -> tuple[str, str]:

        return (measurement.source_id, measurement.filter_name or "unknown")

    def _calculated_period_text(self, result: FitPeriodInferenceResult | None) -> str:

        if result is None or not np.isfinite(result.period_hours) or result.period_hours <= 0:

            return "-"

        return f"{result.period_hours / 24.0:.4f}"

    def _literature_period_text(self, result: LiteraturePeriodResult | None) -> str:

        if result is None or result.period_days is None or not np.isfinite(result.period_days) or result.period_days <= 0:

            return "-"

        return f"{result.period_days:.4f}"

    def _period_match_index_value(

        self,

        literature_result: LiteraturePeriodResult | None,

        calculated_result: FitPeriodInferenceResult | None,

    ) -> float | None:

        if literature_result is None or literature_result.period_days is None or not np.isfinite(literature_result.period_days) or literature_result.period_days <= 0:

            return None

        if calculated_result is None or not np.isfinite(calculated_result.period_hours) or calculated_result.period_hours <= 0:

            return None

        calculated_period_days = calculated_result.period_hours / 24.0

        relative_difference = abs(calculated_period_days - literature_result.period_days) / literature_result.period_days

        return max(0.0, 100.0 * (1.0 - relative_difference))

    def _period_match_index_text(

        self,

        literature_result: LiteraturePeriodResult | None,

        calculated_result: FitPeriodInferenceResult | None,

    ) -> str:

        match_index = self._period_match_index_value(literature_result, calculated_result)

        if match_index is None:

            return "-"

        return f"{match_index:.1f}"

    def _period_job_active(self) -> bool:

        return (

            self._calculate_period_worker is not None

            or self._fit_period_worker is not None

            or self._literature_period_worker is not None

            or self._comparison_fit_worker is not None

            or self._discover_sources_worker is not None

            or self._increase_snr_worker is not None

        )

    def _handle_calculate_period_button_clicked(self) -> None:

        if self._calculate_period_worker is not None:

            if self._calculate_period_worker.cancellation_requested():

                self.statusBar().showMessage("Calculated period cancellation is already in progress.")

                return

            self._calculate_period_worker.request_cancel()

            self._append_work_log("Cancellation requested for calculated period job.")

            self.statusBar().showMessage("Cancellation requested for calculated period job.")

            self._update_source_period_button_state()

            return

        self._calculate_period_data()

    def _handle_pull_period_button_clicked(self) -> None:

        if self._literature_period_worker is not None:

            if self._literature_period_worker.cancellation_requested():

                self.statusBar().showMessage("Literature period cancellation is already in progress.")

                return

            self._literature_period_worker.request_cancel()

            self._append_work_log("Cancellation requested for literature period job.")

            self.statusBar().showMessage("Cancellation requested for literature period job.")

            self._update_source_period_button_state()

            return

        self._pull_literature_period_data()

    def _handle_increase_snr_button_clicked(self) -> None:

        if self._increase_snr_worker is not None:

            if self._increase_snr_worker.cancellation_requested():

                self.statusBar().showMessage("Increase SNR cancellation is already in progress.")

                return

            self._increase_snr_worker.request_cancel()

            self._append_work_log("Cancellation requested for Increase SNR.")

            self.statusBar().showMessage("Cancellation requested for Increase SNR.")

            self._update_source_period_button_state()

            return

        reset_entries = self._selected_source_reset_snr_entries()

        if reset_entries:

            self._reset_selected_sources_snr(reset_entries)

            return

        self._increase_selected_sources_snr()

    def _current_processed_object_files(self) -> list[FileScanResult]:

        report = self._current_processing_report

        scan_report = self._current_report

        if report is None or scan_report is None:

            return []

        summary = next(

            (item for item in scan_report.object_summaries if item.object_name == report.object_name),

            None,

        )

        return [] if summary is None else list(summary.files)

    def _handle_discover_button_clicked(self) -> None:

        if self._discover_sources_worker is not None:

            if self._discover_sources_worker.cancellation_requested():

                self.statusBar().showMessage("Discover cancellation is already in progress.")

                return

            self._discover_sources_worker.request_cancel()

            self._append_work_log("Cancellation requested for Discover.")

            self.statusBar().showMessage("Cancellation requested for Discover.")

            self._update_source_period_button_state()

            return

        options = self._prompt_differential_discover_run_options()

        if options is None:

            return

        self._apply_differential_discover_run_options(options)

        self._start_discover_sources()

    def _prompt_differential_discover_run_options(self) -> _DifferentialDiscoverRunOptions | None:

        current_image_path, _measurement, _comparison_measurements, _status_text = self._image_context()

        current_selection = self._discover_roi_selection if self._discover_roi_matches_image(current_image_path) else None

        preview_display: AnnotatedImageDisplay | None = None

        image_width: int | None = None

        image_height: int | None = None

        roi_available = False

        roi_hint_text = "Optional ROI on the current Differential frame."

        preview_message = "Open a Differential frame to preview Discover here."

        if current_image_path is not None and current_image_path.exists():

            try:

                preview_display = self._cached_annotated_image_display(current_image_path)

            except Exception as exc:

                preview_message = f"Preview unavailable for {current_image_path.name}: {exc}"

                roi_hint_text = preview_message

            else:

                image_height, image_width = preview_display.normalized_data.shape[:2]

                roi_available = image_width > 3 and image_height > 3

                if roi_available:

                    roi_hint_text = (

                        f"ROI applies to the currently displayed frame: {current_image_path.name} "

                        f"({image_width} x {image_height} px). Shift-drag in the preview to define it."

                    )

                    preview_message = "Shift-drag draws the ROI. Plain drag pans. Mouse wheel zooms."

                else:

                    preview_message = f"Preview is loaded, but {current_image_path.name} is too small for a practical ROI."

                    roi_hint_text = preview_message

        settings = self._ensure_settings()

        palette = self.palette()

        theme_colors = self._resolved_theme_editor_colors()

        dialog_background = QColor(theme_colors.get("window_bg", palette.color(QPalette.ColorRole.Window).name()))

        panel_background = QColor(theme_colors.get("panel_bg", palette.color(QPalette.ColorRole.Base).name()))

        text_color = QColor(theme_colors.get("text", palette.color(QPalette.ColorRole.WindowText).name()))

        accent_color = QColor(theme_colors.get("accent", palette.color(QPalette.ColorRole.Highlight).name()))

        border_seed = QColor(theme_colors.get("gridline", palette.color(QPalette.ColorRole.Mid).name()))

        dark_surface = dialog_background.lightnessF() < 0.5

        hero_start = QColor(panel_background).lighter(112 if dark_surface else 103)

        hero_end = QColor(accent_color)

        hero_end.setAlphaF(0.18 if dark_surface else 0.08)

        border_color = QColor(border_seed).lighter(135 if dark_surface else 108)

        muted_text = QColor(text_color)

        muted_text.setAlphaF(0.76 if dark_surface else 0.72)

        hint_text = QColor(text_color)

        hint_text.setAlphaF(0.62 if dark_surface else 0.64)

        button_background = QColor(panel_background).lighter(122) if dark_surface else QColor(panel_background).darker(103)

        button_hover = QColor(button_background).lighter(110 if dark_surface else 103)

        button_pressed = QColor(button_background).darker(112 if dark_surface else 106)

        dialog = QDialog(self)

        dialog.setWindowTitle("Run Discover")

        dialog.setModal(True)

        dialog.setMinimumSize(1080, 760)

        dialog.setObjectName("discoverRunDialog")

        dialog.setStyleSheet(

            "QDialog#discoverRunDialog {"

            f"background-color: {dialog_background.name().lower()};"

            f"color: {text_color.name().lower()};"

            "}"

            "QWidget#discoverHero {"

            "background: qlineargradient(x1:0, y1:0, x2:1, y2:1, "

            f"stop:0 {hero_start.name().lower()}, stop:1 {hero_end.name(QColor.NameFormat.HexArgb).lower()});"

            f"border: 1px solid {border_color.name().lower()};"

            "border-radius: 14px;"

            "}"

            "QLabel#discoverTitle {"

            f"color: {text_color.name().lower()};"

            "font-size: 22px;"

            "font-weight: 700;"

            "background: transparent;"

            "}"

            "QLabel#discoverSubtitle {"

            f"color: {muted_text.name(QColor.NameFormat.HexArgb).lower()};"

            "font-size: 13px;"

            "background: transparent;"

            "}"

            "QLabel#discoverMeta, QLabel#discoverPreviewHint, QLabel#discoverPreviewStatus {"

            f"color: {hint_text.name(QColor.NameFormat.HexArgb).lower()};"

            "font-size: 12px;"

            "background: transparent;"

            "}"

            "QGroupBox#discoverPreviewGroup {"

            f"background-color: {panel_background.name().lower()};"

            f"border: 1px solid {border_color.name().lower()};"

            "border-radius: 14px;"

            "margin-top: 14px;"

            "padding-top: 14px;"

            "font-weight: 600;"

            f"color: {text_color.name().lower()};"

            "}"

            "QGroupBox#discoverPreviewGroup::title {"

            "subcontrol-origin: margin;"

            "left: 12px;"

            "padding: 0 4px;"

            f"color: {text_color.name().lower()};"

            "}"

            "QPushButton {"

            f"background-color: {button_background.name().lower()};"

            f"border: 1px solid {border_color.name().lower()};"

            "border-radius: 10px;"

            "padding: 7px 14px;"

            f"color: {text_color.name().lower()};"

            "font-weight: 600;"

            "}"

            "QPushButton:hover {"

            f"background-color: {button_hover.name().lower()};"

            f"border-color: {accent_color.name().lower()};"

            "}"

            "QPushButton:pressed {"

            f"background-color: {button_pressed.name().lower()};"

            "}"

            "QPushButton:disabled {"

            f"background-color: {panel_background.darker(105 if dark_surface else 100).name().lower()};"

            f"border-color: {border_color.name().lower()};"

            f"color: {muted_text.name(QColor.NameFormat.HexArgb).lower()};"

            "}"

        )

        layout = QVBoxLayout(dialog)

        layout.setContentsMargins(12, 12, 12, 12)

        layout.setSpacing(10)

        content_layout = QVBoxLayout()

        content_layout.setContentsMargins(0, 0, 0, 0)

        content_layout.setSpacing(12)

        details_widget = QWidget(dialog)

        details_widget.setObjectName("discoverHero")

        details_widget.setAttribute(Qt.WidgetAttribute.WA_StyledBackground, True)

        details_layout = QVBoxLayout(details_widget)

        details_layout.setContentsMargins(16, 16, 16, 16)

        details_layout.setSpacing(6)

        summary_label = QLabel(

            "Run Discover",

            details_widget,

        )

        summary_label.setObjectName("discoverTitle")

        summary_label.setWordWrap(True)

        caution_label = QLabel(

            "Build raw light curves for stars outside the current Generate target list.",

            details_widget,

        )

        caution_label.setObjectName("discoverSubtitle")

        caution_label.setWordWrap(True)

        roi_label = QLabel(roi_hint_text, details_widget)

        roi_label.setObjectName("discoverMeta")

        roi_label.setWordWrap(True)

        instructions_label = QLabel(

            "Comparison stars are reused from the field reference pool and ranked by sky position plus magnitude. Enable multi-pool search to try alternate comparison-star groups.",

            details_widget,

        )

        instructions_label.setObjectName("discoverMeta")

        instructions_label.setWordWrap(True)

        comparison_search_checkbox = QCheckBox("Try multiple comparison-star pools", details_widget)

        comparison_search_checkbox.setChecked(self._discover_search_multiple_comparison_groups)

        comparison_search_checkbox.setToolTip(

            "When enabled, Discover tests multiple comparison-star groups for each candidate. When disabled, it uses only the top-ranked group for a faster run."

        )

        details_layout.addWidget(summary_label)

        details_layout.addWidget(caution_label)

        details_layout.addWidget(roi_label)

        details_layout.addWidget(instructions_label)

